    async def _execute_lmdb(
        self,
        config: dict,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        if lmdb is None:
            raise RuntimeError("LMDB dependency is not installed. Install with: pip install lmdb")

        should_abort_cb = None
        raise_if_aborted_cb = None
        if isinstance(execution_context, dict):
            if callable(execution_context.get("should_abort")):
                should_abort_cb = execution_context.get("should_abort")
            if callable(execution_context.get("raise_if_aborted")):
                raise_if_aborted_cb = execution_context.get("raise_if_aborted")

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted during LMDB source read.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        raw_path = (
            config.get("env_path")
            or config.get("file_path")
            or config.get("path")
            or ""
        )
        env_path = self._resolve_lmdb_env_path(str(raw_path))

        db_name = str(config.get("db_name", "") or "").strip()
        value_format = str(config.get("value_format", "auto") or "auto").strip().lower() or "auto"
        flatten_json_values = bool(config.get("flatten_json_values", True))
        expand_profile_documents = bool(config.get("expand_profile_documents", True))
        include_entity_meta = bool(config.get("include_entity_meta", False))
        include_value_kind = bool(config.get("include_value_kind", True))
        key_contains = str(config.get("key_contains", "") or "").strip()
        value_contains = str(config.get("value_contains", "") or "").strip().lower()
        key_prefix = str(config.get("key_prefix", "") or "").strip()
        start_key = str(config.get("start_key", "") or "").strip()
        end_key = str(config.get("end_key", "") or "").strip()
        global_filter_column = str(config.get("global_filter_column", "") or "").strip()
        raw_global_filter_values = config.get("global_filter_values", None)
        if raw_global_filter_values is None:
            fallback_value = str(config.get("global_filter_value", "") or "").strip()
            raw_global_filter_values = [fallback_value] if fallback_value else []
        if isinstance(raw_global_filter_values, str):
            try:
                parsed = json.loads(raw_global_filter_values)
                if isinstance(parsed, list):
                    raw_global_filter_values = parsed
                else:
                    raw_global_filter_values = [raw_global_filter_values]
            except Exception:
                raw_global_filter_values = [raw_global_filter_values]
        elif not isinstance(raw_global_filter_values, (list, tuple, set)):
            raw_global_filter_values = [raw_global_filter_values]
        global_filter_values: List[str] = []
        global_filter_seen = set()
        for item in list(raw_global_filter_values):
            text = str(item if item is not None else "").strip()
            if not text or text in global_filter_seen:
                continue
            global_filter_seen.add(text)
            global_filter_values.append(text)
        raw_column_filters = config.get("column_filters", {})
        if isinstance(raw_column_filters, str):
            try:
                raw_column_filters = json.loads(raw_column_filters)
            except Exception:
                raw_column_filters = {}
        if not isinstance(raw_column_filters, dict):
            raw_column_filters = {}
        column_filters: Dict[str, set] = {}
        for raw_name, raw_values in raw_column_filters.items():
            col_name = str(raw_name or "").strip()
            if not col_name:
                continue
            if isinstance(raw_values, (list, tuple, set)):
                values_iter = list(raw_values)
            else:
                values_iter = [raw_values]
            normalized_values = []
            for item in values_iter:
                text = str(item if item is not None else "").strip()
                if text:
                    normalized_values.append(text)
            if normalized_values:
                column_filters[col_name] = set(normalized_values)

        raw_limit = config.get("limit", 1000)
        try:
            if raw_limit is None or str(raw_limit).strip() == "":
                limit = 1000
            else:
                limit = int(raw_limit)
        except Exception:
            limit = 1000
        # limit <= 0 means no cap (read all matching records).
        if limit < 0:
            limit = 0
        try:
            preview_offset = int(config.get("preview_offset", 0) or 0)
        except Exception:
            preview_offset = 0
        preview_offset = max(0, preview_offset)
        preview_compact = bool(config.get("preview_compact", False))
        try:
            preview_max_cell_chars = int(config.get("preview_max_cell_chars", 2000) or 2000)
        except Exception:
            preview_max_cell_chars = 2000
        preview_max_cell_chars = max(200, min(preview_max_cell_chars, 20000))
        try:
            preview_max_collection_items = int(config.get("preview_max_collection_items", 64) or 64)
        except Exception:
            preview_max_collection_items = 64
        preview_max_collection_items = max(8, min(preview_max_collection_items, 500))
        preview_max_depth = 6

        try:
            max_dbs = int(config.get("max_dbs", 16) or 16)
        except Exception:
            max_dbs = 16
        max_dbs = max(1, min(max_dbs, 256))

        rows: List[Dict[str, Any]] = []
        matched_rows = 0
        seen_profile_entities: set = set()
        env = None

        def _to_cell_text(value: Any) -> str:
            if value is None:
                return ""
            if isinstance(value, str):
                return value
            if isinstance(value, (int, float, bool)):
                return str(value)
            try:
                return json.dumps(value, ensure_ascii=False, default=str)
            except Exception:
                return str(value)

        def _row_matches_filters(row: Dict[str, Any]) -> bool:
            if global_filter_values:
                if global_filter_column and global_filter_column != "__ALL__":
                    targets = [global_filter_column]
                else:
                    targets = list(row.keys())
                matched = False
                for name in targets:
                    text = _to_cell_text(row.get(name)).strip()
                    text_lower = text.lower()
                    for query in global_filter_values:
                        if query == "__LMDB_EMPTY__":
                            if text == "":
                                matched = True
                                break
                        elif query.lower() in text_lower:
                            matched = True
                            break
                    if matched:
                        break
                if not matched:
                    return False

            if column_filters:
                for name, allowed_values in column_filters.items():
                    text = _to_cell_text(row.get(name)).strip()
                    if "__LMDB_EMPTY__" in allowed_values and text == "":
                        continue
                    if text in allowed_values:
                        continue
                    return False
            return True

        def _compact_preview_value(value: Any, depth: int = 0) -> Any:
            safe = self._json_safe_value(value)
            if not preview_compact:
                return safe
            if isinstance(safe, str):
                if len(safe) > preview_max_cell_chars:
                    return safe[:preview_max_cell_chars] + "..."
                return safe
            if isinstance(safe, dict):
                if depth >= preview_max_depth:
                    return f"{{... {len(safe)} keys ...}}"
                out: Dict[str, Any] = {}
                total = len(safe)
                for idx, (k, v) in enumerate(safe.items()):
                    if idx >= preview_max_collection_items:
                        out["__truncated_items__"] = max(0, total - preview_max_collection_items)
                        break
                    out[str(k)] = _compact_preview_value(v, depth + 1)
                return out
            if isinstance(safe, list):
                if depth >= preview_max_depth:
                    return f"[... {len(safe)} items ...]"
                out = [_compact_preview_value(v, depth + 1) for v in safe[:preview_max_collection_items]]
                if len(safe) > preview_max_collection_items:
                    out.append({"__truncated_items__": len(safe) - preview_max_collection_items})
                return out
            return safe

        def _prepare_output_row(row: Dict[str, Any]) -> Dict[str, Any]:
            if not preview_compact:
                return self._json_safe_value(row)
            out: Dict[str, Any] = {}
            for key, value in row.items():
                out[str(key)] = _compact_preview_value(value, 0)
            return out

        try:
            _raise_if_aborted()
            env = lmdb.open(
                env_path,
                readonly=True,
                lock=False,
                readahead=False,
                max_dbs=max_dbs,
                subdir=True,
            )

            dbi = None
            if db_name:
                dbi = env.open_db(db_name.encode("utf-8"), create=False)

            prefix_bytes = key_prefix.encode("utf-8") if key_prefix else None
            start_bytes = start_key.encode("utf-8") if start_key else None
            end_bytes = end_key.encode("utf-8") if end_key else None

            with env.begin(write=False, db=dbi) as txn:
                cursor = txn.cursor()
                if start_bytes is not None:
                    has_item = cursor.set_range(start_bytes)
                elif prefix_bytes is not None:
                    has_item = cursor.set_range(prefix_bytes)
                else:
                    has_item = cursor.first()

                while has_item and (limit == 0 or len(rows) < limit):
                    _raise_if_aborted()
                    key_bytes, value_bytes = cursor.item()

                    if prefix_bytes is not None and not key_bytes.startswith(prefix_bytes):
                        break
                    if end_bytes is not None and key_bytes > end_bytes:
                        break

                    key_text = key_bytes.decode("utf-8", errors="replace")
                    if key_contains and key_contains not in key_text:
                        has_item = cursor.next()
                        continue

                    decoded_value, value_kind = self._decode_lmdb_value(value_bytes, value_format)
                    if value_contains:
                        try:
                            if isinstance(decoded_value, str):
                                haystack = decoded_value
                            else:
                                haystack = json.dumps(decoded_value, ensure_ascii=False)
                        except Exception:
                            haystack = str(decoded_value)
                        if value_contains not in haystack.lower():
                            has_item = cursor.next()
                            continue

                    if flatten_json_values and expand_profile_documents:
                        expanded_rows = self._expand_lmdb_profile_documents(
                            key_text,
                            decoded_value,
                            include_entity_meta=include_entity_meta,
                            include_value_kind=include_value_kind,
                            value_kind=value_kind,
                        )
                        if expanded_rows:
                            for expanded_row in expanded_rows:
                                _raise_if_aborted()
                                if not _row_matches_filters(expanded_row):
                                    continue
                                dedupe_key = self._profile_row_dedupe_key(expanded_row)
                                if dedupe_key:
                                    if dedupe_key in seen_profile_entities:
                                        continue
                                    seen_profile_entities.add(dedupe_key)
                                if matched_rows < preview_offset:
                                    matched_rows += 1
                                    continue
                                if limit > 0 and len(rows) >= limit:
                                    break
                                rows.append(_prepare_output_row(expanded_row))
                                matched_rows += 1
                            if limit > 0 and len(rows) >= limit:
                                break
                            has_item = cursor.next()
                            continue

                    if flatten_json_values and isinstance(decoded_value, dict):
                        row: Dict[str, Any] = {"lmdb_key": key_text, **decoded_value}
                        if include_value_kind:
                            row["_lmdb_value_kind"] = value_kind
                    else:
                        row = {"lmdb_key": key_text, "lmdb_value": decoded_value}
                        if include_value_kind:
                            row["_lmdb_value_kind"] = value_kind

                    if not _row_matches_filters(row):
                        has_item = cursor.next()
                        continue

                    if matched_rows < preview_offset:
                        matched_rows += 1
                        has_item = cursor.next()
                        continue
                    rows.append(_prepare_output_row(row))
                    matched_rows += 1
                    has_item = cursor.next()

        except ExecutionAbortedError:
            raise
        except Exception as exc:
            raise RuntimeError(f"Failed to read LMDB source: {exc}")
        finally:
            if env is not None:
                try:
                    env.close()
                except Exception:
                    pass

        return rows

    async def _execute_rocksdb(
        self,
        config: dict,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        if _rocksdict is None:
            raise RuntimeError("RocksDB dependency is not installed. Install with: pip install rocksdict")

        should_abort_cb = None
        raise_if_aborted_cb = None
        if isinstance(execution_context, dict):
            if callable(execution_context.get("should_abort")):
                should_abort_cb = execution_context.get("should_abort")
            if callable(execution_context.get("raise_if_aborted")):
                raise_if_aborted_cb = execution_context.get("raise_if_aborted")

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted during RocksDB source read.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        raw_path = (
            config.get("env_path")
            or config.get("file_path")
            or config.get("path")
            or ""
        )
        db_path = self._resolve_rocksdb_env_path(str(raw_path))

        value_format = str(config.get("value_format", "auto") or "auto").strip().lower() or "auto"
        flatten_json_values = bool(config.get("flatten_json_values", True))
        expand_profile_documents = bool(config.get("expand_profile_documents", True))
        include_entity_meta = bool(config.get("include_entity_meta", False))
        include_value_kind = bool(config.get("include_value_kind", True))
        key_contains = str(config.get("key_contains", "") or "").strip()
        value_contains = str(config.get("value_contains", "") or "").strip().lower()
        key_prefix = str(config.get("key_prefix", "") or "").strip()
        start_key = str(config.get("start_key", "") or "").strip()
        end_key = str(config.get("end_key", "") or "").strip()
        global_filter_column = str(config.get("global_filter_column", "") or "").strip()
        raw_global_filter_values = config.get("global_filter_values", None)
        if raw_global_filter_values is None:
            fallback_value = str(config.get("global_filter_value", "") or "").strip()
            raw_global_filter_values = [fallback_value] if fallback_value else []
        if isinstance(raw_global_filter_values, str):
            try:
                parsed = json.loads(raw_global_filter_values)
                if isinstance(parsed, list):
                    raw_global_filter_values = parsed
                else:
                    raw_global_filter_values = [raw_global_filter_values]
            except Exception:
                raw_global_filter_values = [raw_global_filter_values]
        elif not isinstance(raw_global_filter_values, (list, tuple, set)):
            raw_global_filter_values = [raw_global_filter_values]
        global_filter_values: List[str] = []
        global_filter_seen = set()
        for item in list(raw_global_filter_values):
            text = str(item if item is not None else "").strip()
            if not text or text in global_filter_seen:
                continue
            global_filter_seen.add(text)
            global_filter_values.append(text)
        raw_column_filters = config.get("column_filters", {})
        if isinstance(raw_column_filters, str):
            try:
                raw_column_filters = json.loads(raw_column_filters)
            except Exception:
                raw_column_filters = {}
        if not isinstance(raw_column_filters, dict):
            raw_column_filters = {}
        column_filters: Dict[str, set] = {}
        for raw_name, raw_values in raw_column_filters.items():
            col_name = str(raw_name or "").strip()
            if not col_name:
                continue
            if isinstance(raw_values, (list, tuple, set)):
                values_iter = list(raw_values)
            else:
                values_iter = [raw_values]
            normalized_values = []
            for item in values_iter:
                text = str(item if item is not None else "").strip()
                if text:
                    normalized_values.append(text)
            if normalized_values:
                column_filters[col_name] = set(normalized_values)

        raw_limit = config.get("limit", 1000)
        try:
            if raw_limit is None or str(raw_limit).strip() == "":
                limit = 1000
            else:
                limit = int(raw_limit)
        except Exception:
            limit = 1000
        if limit < 0:
            limit = 0
        try:
            preview_offset = int(config.get("preview_offset", 0) or 0)
        except Exception:
            preview_offset = 0
        preview_offset = max(0, preview_offset)
        preview_compact = bool(config.get("preview_compact", False))
        try:
            preview_max_cell_chars = int(config.get("preview_max_cell_chars", 2000) or 2000)
        except Exception:
            preview_max_cell_chars = 2000
        preview_max_cell_chars = max(200, min(preview_max_cell_chars, 20000))
        try:
            preview_max_collection_items = int(config.get("preview_max_collection_items", 64) or 64)
        except Exception:
            preview_max_collection_items = 64
        preview_max_collection_items = max(8, min(preview_max_collection_items, 500))
        preview_max_depth = 6

        rows: List[Dict[str, Any]] = []
        matched_rows = 0
        store = None
        store_should_close = False
        prefix_bytes = key_prefix.encode("utf-8") if key_prefix else None
        start_bytes = start_key.encode("utf-8") if start_key else None
        end_bytes = end_key.encode("utf-8") if end_key else None

        def _to_cell_text(value: Any) -> str:
            if value is None:
                return ""
            if isinstance(value, str):
                return value
            if isinstance(value, (int, float, bool)):
                return str(value)
            try:
                return json.dumps(value, ensure_ascii=False, default=str)
            except Exception:
                return str(value)

        def _row_matches_filters(row: Dict[str, Any]) -> bool:
            if global_filter_values:
                if global_filter_column and global_filter_column != "__ALL__":
                    targets = [global_filter_column]
                else:
                    targets = list(row.keys())
                matched = False
                for name in targets:
                    text = _to_cell_text(row.get(name)).strip()
                    text_lower = text.lower()
                    for query in global_filter_values:
                        if query == "__LMDB_EMPTY__":
                            if text == "":
                                matched = True
                                break
                        elif query.lower() in text_lower:
                            matched = True
                            break
                    if matched:
                        break
                if not matched:
                    return False

            if column_filters:
                for name, allowed_values in column_filters.items():
                    text = _to_cell_text(row.get(name)).strip()
                    if "__LMDB_EMPTY__" in allowed_values and text == "":
                        continue
                    if text in allowed_values:
                        continue
                    return False
            return True

        def _compact_preview_value(value: Any, depth: int = 0) -> Any:
            safe = self._json_safe_value(value)
            if not preview_compact:
                return safe
            if isinstance(safe, str):
                if len(safe) > preview_max_cell_chars:
                    return safe[:preview_max_cell_chars] + "..."
                return safe
            if isinstance(safe, dict):
                if depth >= preview_max_depth:
                    return f"{{... {len(safe)} keys ...}}"
                out: Dict[str, Any] = {}
                total = len(safe)
                for idx, (k, v) in enumerate(safe.items()):
                    if idx >= preview_max_collection_items:
                        out["__truncated_items__"] = max(0, total - preview_max_collection_items)
                        break
                    out[str(k)] = _compact_preview_value(v, depth + 1)
                return out
            if isinstance(safe, list):
                if depth >= preview_max_depth:
                    return f"[... {len(safe)} items ...]"
                out = [_compact_preview_value(v, depth + 1) for v in safe[:preview_max_collection_items]]
                if len(safe) > preview_max_collection_items:
                    out.append({"__truncated_items__": len(safe) - preview_max_collection_items})
                return out
            return safe

        def _prepare_output_row(row: Dict[str, Any]) -> Dict[str, Any]:
            if not preview_compact:
                return self._json_safe_value(row)
            out: Dict[str, Any] = {}
            for key, value in row.items():
                out[str(key)] = _compact_preview_value(value, 0)
            return out

        try:
            _raise_if_aborted()
            store, store_should_close = self._acquire_rocksdb_store(db_path)

            for raw_key, raw_value in self._rocksdb_iter_items(store):
                _raise_if_aborted()
                if limit > 0 and len(rows) >= limit:
                    break

                key_text = self._rocksdb_key_to_text(raw_key)
                key_bytes = key_text.encode("utf-8", errors="replace")

                if prefix_bytes is not None and not key_bytes.startswith(prefix_bytes):
                    continue
                if start_bytes is not None and key_bytes < start_bytes:
                    continue
                if end_bytes is not None and key_bytes > end_bytes:
                    continue
                if key_contains and key_contains not in key_text:
                    continue

                value_bytes = self._rocksdb_value_to_bytes(raw_value)
                decoded_value, value_kind = self._decode_lmdb_value(value_bytes, value_format)
                if value_contains:
                    try:
                        if isinstance(decoded_value, str):
                            haystack = decoded_value
                        else:
                            haystack = json.dumps(decoded_value, ensure_ascii=False)
                    except Exception:
                        haystack = str(decoded_value)
                    if value_contains not in haystack.lower():
                        continue

                if flatten_json_values and expand_profile_documents:
                    expanded_rows = self._expand_lmdb_profile_documents(
                        key_text,
                        decoded_value,
                        include_entity_meta=include_entity_meta,
                        include_value_kind=include_value_kind,
                        value_kind=value_kind,
                    )
                    if expanded_rows:
                        for expanded_row in expanded_rows:
                            _raise_if_aborted()
                            if not _row_matches_filters(expanded_row):
                                continue
                            if matched_rows < preview_offset:
                                matched_rows += 1
                                continue
                            if limit > 0 and len(rows) >= limit:
                                break
                            rows.append(_prepare_output_row(expanded_row))
                            matched_rows += 1
                        continue

                if flatten_json_values and isinstance(decoded_value, dict):
                    row: Dict[str, Any] = {"lmdb_key": key_text, **decoded_value}
                    if include_value_kind:
                        row["_lmdb_value_kind"] = value_kind
                else:
                    row = {"lmdb_key": key_text, "lmdb_value": decoded_value}
                    if include_value_kind:
                        row["_lmdb_value_kind"] = value_kind

                if not _row_matches_filters(row):
                    continue

                if matched_rows < preview_offset:
                    matched_rows += 1
                    continue
                rows.append(_prepare_output_row(row))
                matched_rows += 1

        except ExecutionAbortedError:
            raise
        except Exception as exc:
            raise RuntimeError(f"Failed to read RocksDB source: {exc}")
        finally:
            if store is not None and store_should_close:
                self._close_rocksdb_store(store)

        return rows

    async def _summarize_lmdb(self, config: dict) -> Dict[str, Any]:
        if lmdb is None:
            raise RuntimeError("LMDB dependency is not installed. Install with: pip install lmdb")

        raw_path = (
            config.get("env_path")
            or config.get("file_path")
            or config.get("path")
            or ""
        )
        env_path = self._resolve_lmdb_env_path(str(raw_path))

        db_name = str(config.get("db_name", "") or "").strip()
        value_format = str(config.get("value_format", "auto") or "auto").strip().lower() or "auto"
        flatten_json_values = bool(config.get("flatten_json_values", True))
        expand_profile_documents = bool(config.get("expand_profile_documents", True))
        include_entity_meta = bool(config.get("include_entity_meta", False))
        include_value_kind = bool(config.get("include_value_kind", True))
        key_contains = str(config.get("key_contains", "") or "").strip()
        value_contains = str(config.get("value_contains", "") or "").strip().lower()
        key_prefix = str(config.get("key_prefix", "") or "").strip()
        start_key = str(config.get("start_key", "") or "").strip()
        end_key = str(config.get("end_key", "") or "").strip()
        global_filter_column = str(config.get("global_filter_column", "") or "").strip()
        raw_global_filter_values = config.get("global_filter_values", None)
        if raw_global_filter_values is None:
            fallback_value = str(config.get("global_filter_value", "") or "").strip()
            raw_global_filter_values = [fallback_value] if fallback_value else []
        if isinstance(raw_global_filter_values, str):
            try:
                parsed = json.loads(raw_global_filter_values)
                if isinstance(parsed, list):
                    raw_global_filter_values = parsed
                else:
                    raw_global_filter_values = [raw_global_filter_values]
            except Exception:
                raw_global_filter_values = [raw_global_filter_values]
        elif not isinstance(raw_global_filter_values, (list, tuple, set)):
            raw_global_filter_values = [raw_global_filter_values]
        global_filter_values: List[str] = []
        global_filter_seen = set()
        for item in list(raw_global_filter_values):
            text = str(item if item is not None else "").strip()
            if not text or text in global_filter_seen:
                continue
            global_filter_seen.add(text)
            global_filter_values.append(text)

        raw_column_filters = config.get("column_filters", {})
        if isinstance(raw_column_filters, str):
            try:
                raw_column_filters = json.loads(raw_column_filters)
            except Exception:
                raw_column_filters = {}
        if not isinstance(raw_column_filters, dict):
            raw_column_filters = {}
        column_filters: Dict[str, set] = {}
        for raw_name, raw_values in raw_column_filters.items():
            col_name = str(raw_name or "").strip()
            if not col_name:
                continue
            if isinstance(raw_values, (list, tuple, set)):
                values_iter = list(raw_values)
            else:
                values_iter = [raw_values]
            normalized_values = []
            for item in values_iter:
                text = str(item if item is not None else "").strip()
                if text:
                    normalized_values.append(text)
            if normalized_values:
                column_filters[col_name] = set(normalized_values)

        try:
            summary_scan_limit = int(config.get("summary_scan_limit", 0) or 0)
        except Exception:
            summary_scan_limit = 0
        summary_scan_limit = max(0, summary_scan_limit)

        try:
            max_dbs = int(config.get("max_dbs", 16) or 16)
        except Exception:
            max_dbs = 16
        max_dbs = max(1, min(max_dbs, 256))

        env = None
        scan_started_at = datetime.utcnow()
        scan_capped = False
        scanned_entries = 0
        matched_rows = 0
        seen_profile_entities: set = set()
        profile_rows = 0
        non_profile_rows = 0
        unique_keys: set = set()
        unique_entities: set = set()
        profile_like_keys: set = set()
        txn_latency_samples = 0
        txn_latency_sum_ms = 0.0
        txn_latency_min_ms: Optional[float] = None
        txn_latency_max_ms: Optional[float] = None
        node_incremental_stats_by_key: Dict[str, Dict[str, int]] = {}

        def _to_cell_text(value: Any) -> str:
            if value is None:
                return ""
            if isinstance(value, str):
                return value
            if isinstance(value, (int, float, bool)):
                return str(value)
            try:
                return json.dumps(value, ensure_ascii=False, default=str)
            except Exception:
                return str(value)

        def _row_matches_filters(row: Dict[str, Any]) -> bool:
            if global_filter_values:
                if global_filter_column and global_filter_column != "__ALL__":
                    targets = [global_filter_column]
                else:
                    targets = list(row.keys())
                matched = False
                for name in targets:
                    text = _to_cell_text(row.get(name)).strip()
                    text_lower = text.lower()
                    for query in global_filter_values:
                        if query == "__LMDB_EMPTY__":
                            if text == "":
                                matched = True
                                break
                        elif query.lower() in text_lower:
                            matched = True
                            break
                    if matched:
                        break
                if not matched:
                    return False

            if column_filters:
                for name, allowed_values in column_filters.items():
                    text = _to_cell_text(row.get(name)).strip()
                    if "__LMDB_EMPTY__" in allowed_values and text == "":
                        continue
                    if text in allowed_values:
                        continue
                    return False
            return True

        latency_ms_fields = (
            "latency_ms",
            "processing_latency_ms",
            "transaction_latency_ms",
            "txn_latency_ms",
            "response_time_ms",
            "duration_ms",
            "elapsed_ms",
            "processing_time_ms",
            "latency",
            "duration",
            "response_time",
            "processing_time",
        )
        latency_seconds_fields = (
            "latency_seconds",
            "duration_seconds",
            "elapsed_seconds",
            "response_time_seconds",
            "processing_time_seconds",
        )
        latency_time_pairs = (
            ("request_time", "response_time"),
            ("start_time", "end_time"),
            ("start_ts", "end_ts"),
            ("txn_start_time", "txn_end_time"),
            ("transaction_start_time", "transaction_end_time"),
            ("mintime", "maxtime"),
            ("min_txndate", "max_txndate"),
        )

        def _to_float(value: Any) -> Optional[float]:
            if value is None or isinstance(value, bool):
                return None
            if isinstance(value, (int, float)):
                if math.isfinite(float(value)):
                    return float(value)
                return None
            if isinstance(value, str):
                text = value.strip()
                if not text:
                    return None
                text = text.replace(",", "")
                try:
                    parsed = float(text)
                    if math.isfinite(parsed):
                        return parsed
                except Exception:
                    return None
            return None

        def _to_non_negative_int(value: Any) -> Optional[int]:
            parsed = _to_float(value)
            if parsed is None:
                return None
            try:
                as_int = int(parsed)
            except Exception:
                return None
            if as_int < 0:
                return None
            return as_int

        def _extract_transaction_latency_ms(row: Dict[str, Any]) -> Optional[float]:
            normalized: Dict[str, Any] = {}
            for raw_key, raw_value in row.items():
                key = str(raw_key or "").strip().lower()
                if not key:
                    continue
                normalized[key] = raw_value

            def _collect_nested_named_values(
                value: Any,
                wanted_keys: set,
                out: Dict[str, List[Any]],
                depth: int,
                budget: List[int],
            ) -> None:
                if budget[0] <= 0 or depth > 6:
                    return
                if isinstance(value, dict):
                    for raw_name, raw_child in value.items():
                        if budget[0] <= 0:
                            break
                        budget[0] -= 1
                        name = str(raw_name or "").strip().lower()
                        if name in wanted_keys and not isinstance(raw_child, (dict, list)):
                            bucket = out.get(name)
                            if bucket is None:
                                out[name] = [raw_child]
                            elif len(bucket) < 32:
                                bucket.append(raw_child)
                        if isinstance(raw_child, (dict, list)):
                            _collect_nested_named_values(raw_child, wanted_keys, out, depth + 1, budget)
                    return
                if isinstance(value, list):
                    for item in value:
                        if budget[0] <= 0:
                            break
                        budget[0] -= 1
                        if isinstance(item, (dict, list)):
                            _collect_nested_named_values(item, wanted_keys, out, depth + 1, budget)

            def _get_value_candidates(name: str, nested_map: Dict[str, List[Any]]) -> List[Any]:
                candidates: List[Any] = []
                if name in normalized:
                    candidates.append(normalized.get(name))
                nested_values = nested_map.get(name) or []
                if nested_values:
                    candidates.extend(nested_values)
                return candidates

            wanted_keys = set(latency_ms_fields) | set(latency_seconds_fields)
            for start_field, end_field in latency_time_pairs:
                wanted_keys.add(start_field)
                wanted_keys.add(end_field)
            nested_candidates: Dict[str, List[Any]] = {}

            def _ensure_nested_candidates() -> Dict[str, List[Any]]:
                nonlocal nested_candidates
                if nested_candidates:
                    return nested_candidates
                budget = [800]
                _collect_nested_named_values(row, wanted_keys, nested_candidates, 0, budget)
                return nested_candidates

            for field_name in latency_ms_fields:
                candidates = [normalized.get(field_name)] if field_name in normalized else []
                if not candidates:
                    candidates = _ensure_nested_candidates().get(field_name, [])
                for candidate in candidates:
                    parsed = _to_float(candidate)
                    if parsed is not None and parsed >= 0:
                        return parsed

            for field_name in latency_seconds_fields:
                candidates = [normalized.get(field_name)] if field_name in normalized else []
                if not candidates:
                    candidates = _ensure_nested_candidates().get(field_name, [])
                for candidate in candidates:
                    parsed = _to_float(candidate)
                    if parsed is not None and parsed >= 0:
                        return parsed * 1000.0

            nested_map = _ensure_nested_candidates()
            for start_field, end_field in latency_time_pairs:
                start_candidates = _get_value_candidates(start_field, nested_map)
                end_candidates = _get_value_candidates(end_field, nested_map)
                if not start_candidates or not end_candidates:
                    continue

                # Prefer index-wise pairing when both fields come from repeated structures.
                pair_len = min(len(start_candidates), len(end_candidates), 16)
                for idx in range(pair_len):
                    start_dt = self._parse_profile_event_time(start_candidates[idx])
                    end_dt = self._parse_profile_event_time(end_candidates[idx])
                    if start_dt is None or end_dt is None:
                        continue
                    delta_ms = (end_dt - start_dt).total_seconds() * 1000.0
                    if math.isfinite(delta_ms) and delta_ms >= 0:
                        return delta_ms

                # Fallback to first parsable pair.
                for start_value in start_candidates[:8]:
                    start_dt = self._parse_profile_event_time(start_value)
                    if start_dt is None:
                        continue
                    for end_value in end_candidates[:8]:
                        end_dt = self._parse_profile_event_time(end_value)
                        if end_dt is None:
                            continue
                        delta_ms = (end_dt - start_dt).total_seconds() * 1000.0
                        if math.isfinite(delta_ms) and delta_ms >= 0:
                            return delta_ms
            return None

        def _track_row(row: Dict[str, Any]) -> None:
            nonlocal matched_rows, profile_rows, non_profile_rows
            nonlocal txn_latency_samples, txn_latency_sum_ms, txn_latency_min_ms, txn_latency_max_ms
            matched_rows += 1

            key_text = str(row.get("lmdb_key") or "").strip()
            if key_text:
                unique_keys.add(key_text)
                if "profile" in key_text.lower():
                    profile_like_keys.add(key_text)

            entity_key = str(row.get("lmdb_entity_key") or "").strip()
            profile_source = str(row.get("_lmdb_profile_source") or "").strip().lower()
            is_profile_row = bool(entity_key) or profile_source in {"documents", "document", "profile"}
            if is_profile_row:
                profile_rows += 1
            else:
                non_profile_rows += 1
            if entity_key:
                unique_entities.add(entity_key)

            latency_ms = _extract_transaction_latency_ms(row)
            if latency_ms is not None:
                txn_latency_samples += 1
                txn_latency_sum_ms += latency_ms
                if txn_latency_min_ms is None or latency_ms < txn_latency_min_ms:
                    txn_latency_min_ms = latency_ms
                if txn_latency_max_ms is None or latency_ms > txn_latency_max_ms:
                    txn_latency_max_ms = latency_ms

            node_stats = row.get("_lmdb_node_stats")
            if isinstance(node_stats, dict):
                processed = _to_non_negative_int(node_stats.get("custom_fields_incremental_processed_rows"))
                validated = _to_non_negative_int(node_stats.get("custom_fields_incremental_validated_rows"))
                output_rows = _to_non_negative_int(node_stats.get("custom_fields_incremental_output_rows"))
                if processed is not None or validated is not None or output_rows is not None:
                    stats_key = key_text or str(row.get("lmdb_entity_key") or "") or "__lmdb_default__"
                    existing = node_incremental_stats_by_key.get(stats_key)
                    if not isinstance(existing, dict):
                        existing = {"processed": 0, "validated": 0, "output_rows": 0}
                    if processed is not None:
                        existing["processed"] = max(int(existing.get("processed") or 0), int(processed))
                    if validated is not None:
                        existing["validated"] = max(int(existing.get("validated") or 0), int(validated))
                    if output_rows is not None:
                        existing["output_rows"] = max(int(existing.get("output_rows") or 0), int(output_rows))
                    node_incremental_stats_by_key[stats_key] = existing

        try:
            env = lmdb.open(
                env_path,
                readonly=True,
                lock=False,
                readahead=False,
                max_dbs=max_dbs,
                subdir=True,
            )

            dbi = None
            if db_name:
                dbi = env.open_db(db_name.encode("utf-8"), create=False)

            prefix_bytes = key_prefix.encode("utf-8") if key_prefix else None
            start_bytes = start_key.encode("utf-8") if start_key else None
            end_bytes = end_key.encode("utf-8") if end_key else None

            with env.begin(write=False, db=dbi) as txn:
                cursor = txn.cursor()
                if start_bytes is not None:
                    has_item = cursor.set_range(start_bytes)
                elif prefix_bytes is not None:
                    has_item = cursor.set_range(prefix_bytes)
                else:
                    has_item = cursor.first()

                while has_item:
                    scanned_entries += 1
                    key_bytes, value_bytes = cursor.item()

                    if prefix_bytes is not None and not key_bytes.startswith(prefix_bytes):
                        break
                    if end_bytes is not None and key_bytes > end_bytes:
                        break

                    key_text = key_bytes.decode("utf-8", errors="replace")
                    if key_contains and key_contains not in key_text:
                        has_item = cursor.next()
                        continue

                    decoded_value, value_kind = self._decode_lmdb_value(value_bytes, value_format)
                    if value_contains:
                        try:
                            if isinstance(decoded_value, str):
                                haystack = decoded_value
                            else:
                                haystack = json.dumps(decoded_value, ensure_ascii=False)
                        except Exception:
                            haystack = str(decoded_value)
                        if value_contains not in haystack.lower():
                            has_item = cursor.next()
                            continue

                    if flatten_json_values and expand_profile_documents:
                        expanded_rows = self._expand_lmdb_profile_documents(
                            key_text,
                            decoded_value,
                            include_entity_meta=include_entity_meta,
                            include_value_kind=include_value_kind,
                            value_kind=value_kind,
                        )
                        if expanded_rows:
                            for expanded_row in expanded_rows:
                                if not _row_matches_filters(expanded_row):
                                    continue
                                dedupe_key = self._profile_row_dedupe_key(expanded_row)
                                if dedupe_key:
                                    if dedupe_key in seen_profile_entities:
                                        continue
                                    seen_profile_entities.add(dedupe_key)
                                _track_row(expanded_row)
                                if summary_scan_limit > 0 and matched_rows >= summary_scan_limit:
                                    scan_capped = True
                                    break
                            if scan_capped:
                                break
                            has_item = cursor.next()
                            continue

                    if flatten_json_values and isinstance(decoded_value, dict):
                        row: Dict[str, Any] = {"lmdb_key": key_text, **decoded_value}
                        if include_value_kind:
                            row["_lmdb_value_kind"] = value_kind
                    else:
                        row = {"lmdb_key": key_text, "lmdb_value": decoded_value}
                        if include_value_kind:
                            row["_lmdb_value_kind"] = value_kind

                    if not _row_matches_filters(row):
                        has_item = cursor.next()
                        continue

                    _track_row(row)
                    if summary_scan_limit > 0 and matched_rows >= summary_scan_limit:
                        scan_capped = True
                        break
                    has_item = cursor.next()

        except Exception as exc:
            raise RuntimeError(f"Failed to summarize LMDB source: {exc}")
        finally:
            if env is not None:
                try:
                    env.close()
                except Exception:
                    pass

        scan_elapsed_seconds = max(0.0, (datetime.utcnow() - scan_started_at).total_seconds())
        processing_latency_rps = (
            (matched_rows / scan_elapsed_seconds)
            if scan_elapsed_seconds > 0 and matched_rows >= 0
            else None
        )
        custom_fields_incremental_processed_rows = sum(
            int((stats or {}).get("processed") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )
        custom_fields_incremental_validated_rows = sum(
            int((stats or {}).get("validated") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )
        custom_fields_incremental_output_rows = sum(
            int((stats or {}).get("output_rows") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )

        return {
            "total_rows": matched_rows,
            "profile_rows": profile_rows,
            "non_profile_rows": non_profile_rows,
            "unique_keys": len(unique_keys),
            "unique_entities": len(unique_entities),
            "profile_like_keys": len(profile_like_keys),
            "txn_latency_samples": txn_latency_samples,
            "txn_latency_avg_ms": (txn_latency_sum_ms / txn_latency_samples) if txn_latency_samples > 0 else None,
            "txn_latency_min_ms": txn_latency_min_ms,
            "txn_latency_max_ms": txn_latency_max_ms,
            "processing_latency_rps": processing_latency_rps,
            "records_processed_per_second": processing_latency_rps,
            "scan_elapsed_seconds": scan_elapsed_seconds,
            "scan_capped": scan_capped,
            "scan_limit": summary_scan_limit,
            "scanned_entries": scanned_entries,
            "custom_fields_incremental_processed_rows": custom_fields_incremental_processed_rows,
            "custom_fields_incremental_validated_rows": custom_fields_incremental_validated_rows,
            "custom_fields_incremental_output_rows": custom_fields_incremental_output_rows,
            "generated_at": datetime.utcnow().isoformat(),
        }

    async def _summarize_rocksdb(self, config: dict) -> Dict[str, Any]:
        if _rocksdict is None:
            raise RuntimeError("RocksDB dependency is not installed. Install with: pip install rocksdict")

        raw_path = (
            config.get("env_path")
            or config.get("file_path")
            or config.get("path")
            or ""
        )
        db_path = self._resolve_rocksdb_env_path(str(raw_path))

        value_format = str(config.get("value_format", "auto") or "auto").strip().lower() or "auto"
        flatten_json_values = bool(config.get("flatten_json_values", True))
        expand_profile_documents = bool(config.get("expand_profile_documents", True))
        include_entity_meta = bool(config.get("include_entity_meta", False))
        include_value_kind = bool(config.get("include_value_kind", True))
        key_contains = str(config.get("key_contains", "") or "").strip()
        value_contains = str(config.get("value_contains", "") or "").strip().lower()
        key_prefix = str(config.get("key_prefix", "") or "").strip()
        start_key = str(config.get("start_key", "") or "").strip()
        end_key = str(config.get("end_key", "") or "").strip()
        global_filter_column = str(config.get("global_filter_column", "") or "").strip()
        raw_global_filter_values = config.get("global_filter_values", None)
        if raw_global_filter_values is None:
            fallback_value = str(config.get("global_filter_value", "") or "").strip()
            raw_global_filter_values = [fallback_value] if fallback_value else []
        if isinstance(raw_global_filter_values, str):
            try:
                parsed = json.loads(raw_global_filter_values)
                if isinstance(parsed, list):
                    raw_global_filter_values = parsed
                else:
                    raw_global_filter_values = [raw_global_filter_values]
            except Exception:
                raw_global_filter_values = [raw_global_filter_values]
        elif not isinstance(raw_global_filter_values, (list, tuple, set)):
            raw_global_filter_values = [raw_global_filter_values]
        global_filter_values: List[str] = []
        global_filter_seen = set()
        for item in list(raw_global_filter_values):
            text = str(item if item is not None else "").strip()
            if not text or text in global_filter_seen:
                continue
            global_filter_seen.add(text)
            global_filter_values.append(text)

        raw_column_filters = config.get("column_filters", {})
        if isinstance(raw_column_filters, str):
            try:
                raw_column_filters = json.loads(raw_column_filters)
            except Exception:
                raw_column_filters = {}
        if not isinstance(raw_column_filters, dict):
            raw_column_filters = {}
        column_filters: Dict[str, set] = {}
        for raw_name, raw_values in raw_column_filters.items():
            col_name = str(raw_name or "").strip()
            if not col_name:
                continue
            if isinstance(raw_values, (list, tuple, set)):
                values_iter = list(raw_values)
            else:
                values_iter = [raw_values]
            normalized_values = []
            for item in values_iter:
                text = str(item if item is not None else "").strip()
                if text:
                    normalized_values.append(text)
            if normalized_values:
                column_filters[col_name] = set(normalized_values)

        try:
            summary_scan_limit = int(config.get("summary_scan_limit", 0) or 0)
        except Exception:
            summary_scan_limit = 0
        summary_scan_limit = max(0, summary_scan_limit)

        store = None
        store_should_close = False
        scan_started_at = datetime.utcnow()
        scan_capped = False
        scanned_entries = 0
        matched_rows = 0
        profile_rows = 0
        non_profile_rows = 0
        unique_keys: set = set()
        unique_entities: set = set()
        profile_like_keys: set = set()
        txn_latency_samples = 0
        txn_latency_sum_ms = 0.0
        txn_latency_min_ms: Optional[float] = None
        txn_latency_max_ms: Optional[float] = None
        node_incremental_stats_by_key: Dict[str, Dict[str, int]] = {}

        prefix_bytes = key_prefix.encode("utf-8") if key_prefix else None
        start_bytes = start_key.encode("utf-8") if start_key else None
        end_bytes = end_key.encode("utf-8") if end_key else None

        def _to_cell_text(value: Any) -> str:
            if value is None:
                return ""
            if isinstance(value, str):
                return value
            if isinstance(value, (int, float, bool)):
                return str(value)
            try:
                return json.dumps(value, ensure_ascii=False, default=str)
            except Exception:
                return str(value)

        def _row_matches_filters(row: Dict[str, Any]) -> bool:
            if global_filter_values:
                if global_filter_column and global_filter_column != "__ALL__":
                    targets = [global_filter_column]
                else:
                    targets = list(row.keys())
                matched = False
                for name in targets:
                    text = _to_cell_text(row.get(name)).strip()
                    text_lower = text.lower()
                    for query in global_filter_values:
                        if query == "__LMDB_EMPTY__":
                            if text == "":
                                matched = True
                                break
                        elif query.lower() in text_lower:
                            matched = True
                            break
                    if matched:
                        break
                if not matched:
                    return False

            if column_filters:
                for name, allowed_values in column_filters.items():
                    text = _to_cell_text(row.get(name)).strip()
                    if "__LMDB_EMPTY__" in allowed_values and text == "":
                        continue
                    if text in allowed_values:
                        continue
                    return False
            return True

        latency_ms_fields = (
            "latency_ms",
            "processing_latency_ms",
            "transaction_latency_ms",
            "txn_latency_ms",
            "response_time_ms",
            "duration_ms",
            "elapsed_ms",
            "processing_time_ms",
            "latency",
            "duration",
            "response_time",
            "processing_time",
        )
        latency_seconds_fields = (
            "latency_seconds",
            "duration_seconds",
            "elapsed_seconds",
            "response_time_seconds",
            "processing_time_seconds",
        )
        latency_time_pairs = (
            ("request_time", "response_time"),
            ("start_time", "end_time"),
            ("start_ts", "end_ts"),
            ("txn_start_time", "txn_end_time"),
            ("transaction_start_time", "transaction_end_time"),
            ("mintime", "maxtime"),
            ("min_txndate", "max_txndate"),
        )

        def _to_float(value: Any) -> Optional[float]:
            if value is None or isinstance(value, bool):
                return None
            if isinstance(value, (int, float)):
                if math.isfinite(float(value)):
                    return float(value)
                return None
            if isinstance(value, str):
                text = value.strip()
                if not text:
                    return None
                text = text.replace(",", "")
                try:
                    parsed = float(text)
                    if math.isfinite(parsed):
                        return parsed
                except Exception:
                    return None
            return None

        def _to_non_negative_int(value: Any) -> Optional[int]:
            parsed = _to_float(value)
            if parsed is None:
                return None
            try:
                as_int = int(parsed)
            except Exception:
                return None
            if as_int < 0:
                return None
            return as_int

        def _extract_transaction_latency_ms(row: Dict[str, Any]) -> Optional[float]:
            normalized: Dict[str, Any] = {}
            for raw_key, raw_value in row.items():
                key = str(raw_key or "").strip().lower()
                if not key:
                    continue
                normalized[key] = raw_value

            def _collect_nested_named_values(
                value: Any,
                wanted_keys: set,
                out: Dict[str, List[Any]],
                depth: int,
                budget: List[int],
            ) -> None:
                if budget[0] <= 0 or depth > 6:
                    return
                if isinstance(value, dict):
                    for raw_name, raw_child in value.items():
                        if budget[0] <= 0:
                            break
                        budget[0] -= 1
                        name = str(raw_name or "").strip().lower()
                        if name in wanted_keys and not isinstance(raw_child, (dict, list)):
                            bucket = out.get(name)
                            if bucket is None:
                                out[name] = [raw_child]
                            elif len(bucket) < 32:
                                bucket.append(raw_child)
                        if isinstance(raw_child, (dict, list)):
                            _collect_nested_named_values(raw_child, wanted_keys, out, depth + 1, budget)
                    return
                if isinstance(value, list):
                    for item in value:
                        if budget[0] <= 0:
                            break
                        budget[0] -= 1
                        if isinstance(item, (dict, list)):
                            _collect_nested_named_values(item, wanted_keys, out, depth + 1, budget)

            def _get_value_candidates(name: str, nested_map: Dict[str, List[Any]]) -> List[Any]:
                candidates: List[Any] = []
                if name in normalized:
                    candidates.append(normalized.get(name))
                nested_values = nested_map.get(name) or []
                if nested_values:
                    candidates.extend(nested_values)
                return candidates

            wanted_keys = set(latency_ms_fields) | set(latency_seconds_fields)
            for start_field, end_field in latency_time_pairs:
                wanted_keys.add(start_field)
                wanted_keys.add(end_field)
            nested_candidates: Dict[str, List[Any]] = {}

            def _ensure_nested_candidates() -> Dict[str, List[Any]]:
                nonlocal nested_candidates
                if nested_candidates:
                    return nested_candidates
                budget = [800]
                _collect_nested_named_values(row, wanted_keys, nested_candidates, 0, budget)
                return nested_candidates

            for field_name in latency_ms_fields:
                candidates = [normalized.get(field_name)] if field_name in normalized else []
                if not candidates:
                    candidates = _ensure_nested_candidates().get(field_name, [])
                for candidate in candidates:
                    parsed = _to_float(candidate)
                    if parsed is not None and parsed >= 0:
                        return parsed

            for field_name in latency_seconds_fields:
                candidates = [normalized.get(field_name)] if field_name in normalized else []
                if not candidates:
                    candidates = _ensure_nested_candidates().get(field_name, [])
                for candidate in candidates:
                    parsed = _to_float(candidate)
                    if parsed is not None and parsed >= 0:
                        return parsed * 1000.0

            nested_map = _ensure_nested_candidates()
            for start_field, end_field in latency_time_pairs:
                start_candidates = _get_value_candidates(start_field, nested_map)
                end_candidates = _get_value_candidates(end_field, nested_map)
                if not start_candidates or not end_candidates:
                    continue

                pair_len = min(len(start_candidates), len(end_candidates), 16)
                for idx in range(pair_len):
                    start_dt = self._parse_profile_event_time(start_candidates[idx])
                    end_dt = self._parse_profile_event_time(end_candidates[idx])
                    if start_dt is None or end_dt is None:
                        continue
                    delta_ms = (end_dt - start_dt).total_seconds() * 1000.0
                    if math.isfinite(delta_ms) and delta_ms >= 0:
                        return delta_ms

                for start_value in start_candidates[:8]:
                    start_dt = self._parse_profile_event_time(start_value)
                    if start_dt is None:
                        continue
                    for end_value in end_candidates[:8]:
                        end_dt = self._parse_profile_event_time(end_value)
                        if end_dt is None:
                            continue
                        delta_ms = (end_dt - start_dt).total_seconds() * 1000.0
                        if math.isfinite(delta_ms) and delta_ms >= 0:
                            return delta_ms
            return None

        def _track_row(row: Dict[str, Any]) -> None:
            nonlocal matched_rows, profile_rows, non_profile_rows
            nonlocal txn_latency_samples, txn_latency_sum_ms, txn_latency_min_ms, txn_latency_max_ms
            matched_rows += 1

            key_text = str(row.get("lmdb_key") or "").strip()
            if key_text:
                unique_keys.add(key_text)
                if "profile" in key_text.lower():
                    profile_like_keys.add(key_text)

            entity_key = str(row.get("lmdb_entity_key") or "").strip()
            profile_source = str(row.get("_lmdb_profile_source") or "").strip().lower()
            is_profile_row = bool(entity_key) or profile_source in {"documents", "document", "profile"}
            if is_profile_row:
                profile_rows += 1
            else:
                non_profile_rows += 1
            if entity_key:
                unique_entities.add(entity_key)

            latency_ms = _extract_transaction_latency_ms(row)
            if latency_ms is not None:
                txn_latency_samples += 1
                txn_latency_sum_ms += latency_ms
                if txn_latency_min_ms is None or latency_ms < txn_latency_min_ms:
                    txn_latency_min_ms = latency_ms
                if txn_latency_max_ms is None or latency_ms > txn_latency_max_ms:
                    txn_latency_max_ms = latency_ms

            node_stats = row.get("_lmdb_node_stats")
            if isinstance(node_stats, dict):
                processed = _to_non_negative_int(node_stats.get("custom_fields_incremental_processed_rows"))
                validated = _to_non_negative_int(node_stats.get("custom_fields_incremental_validated_rows"))
                output_rows = _to_non_negative_int(node_stats.get("custom_fields_incremental_output_rows"))
                if processed is not None or validated is not None or output_rows is not None:
                    stats_key = key_text or str(row.get("lmdb_entity_key") or "") or "__rocksdb_default__"
                    existing = node_incremental_stats_by_key.get(stats_key)
                    if not isinstance(existing, dict):
                        existing = {"processed": 0, "validated": 0, "output_rows": 0}
                    if processed is not None:
                        existing["processed"] = max(int(existing.get("processed") or 0), int(processed))
                    if validated is not None:
                        existing["validated"] = max(int(existing.get("validated") or 0), int(validated))
                    if output_rows is not None:
                        existing["output_rows"] = max(int(existing.get("output_rows") or 0), int(output_rows))
                    node_incremental_stats_by_key[stats_key] = existing

        try:
            store, store_should_close = self._acquire_rocksdb_store(db_path)
            for raw_key, raw_value in self._rocksdb_iter_items(store):
                scanned_entries += 1
                key_text = self._rocksdb_key_to_text(raw_key)
                key_bytes = key_text.encode("utf-8", errors="replace")

                if prefix_bytes is not None and not key_bytes.startswith(prefix_bytes):
                    continue
                if start_bytes is not None and key_bytes < start_bytes:
                    continue
                if end_bytes is not None and key_bytes > end_bytes:
                    continue
                if key_contains and key_contains not in key_text:
                    continue

                value_bytes = self._rocksdb_value_to_bytes(raw_value)
                decoded_value, value_kind = self._decode_lmdb_value(value_bytes, value_format)
                if value_contains:
                    try:
                        if isinstance(decoded_value, str):
                            haystack = decoded_value
                        else:
                            haystack = json.dumps(decoded_value, ensure_ascii=False)
                    except Exception:
                        haystack = str(decoded_value)
                    if value_contains not in haystack.lower():
                        continue

                if flatten_json_values and expand_profile_documents:
                    expanded_rows = self._expand_lmdb_profile_documents(
                        key_text,
                        decoded_value,
                        include_entity_meta=include_entity_meta,
                        include_value_kind=include_value_kind,
                        value_kind=value_kind,
                    )
                    if expanded_rows:
                        for expanded_row in expanded_rows:
                            if not _row_matches_filters(expanded_row):
                                continue
                            _track_row(expanded_row)
                            if summary_scan_limit > 0 and matched_rows >= summary_scan_limit:
                                scan_capped = True
                                break
                        if scan_capped:
                            break
                        continue

                if flatten_json_values and isinstance(decoded_value, dict):
                    row: Dict[str, Any] = {"lmdb_key": key_text, **decoded_value}
                    if include_value_kind:
                        row["_lmdb_value_kind"] = value_kind
                else:
                    row = {"lmdb_key": key_text, "lmdb_value": decoded_value}
                    if include_value_kind:
                        row["_lmdb_value_kind"] = value_kind

                if not _row_matches_filters(row):
                    continue

                _track_row(row)
                if summary_scan_limit > 0 and matched_rows >= summary_scan_limit:
                    scan_capped = True
                    break

        except Exception as exc:
            raise RuntimeError(f"Failed to summarize RocksDB source: {exc}")
        finally:
            if store is not None and store_should_close:
                self._close_rocksdb_store(store)

        scan_elapsed_seconds = max(0.0, (datetime.utcnow() - scan_started_at).total_seconds())
        processing_latency_rps = (
            (matched_rows / scan_elapsed_seconds)
            if scan_elapsed_seconds > 0 and matched_rows >= 0
            else None
        )
        custom_fields_incremental_processed_rows = sum(
            int((stats or {}).get("processed") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )
        custom_fields_incremental_validated_rows = sum(
            int((stats or {}).get("validated") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )
        custom_fields_incremental_output_rows = sum(
            int((stats or {}).get("output_rows") or 0)
            for stats in node_incremental_stats_by_key.values()
            if isinstance(stats, dict)
        )

        return {
            "total_rows": matched_rows,
            "profile_rows": profile_rows,
            "non_profile_rows": non_profile_rows,
            "unique_keys": len(unique_keys),
            "unique_entities": len(unique_entities),
            "profile_like_keys": len(profile_like_keys),
            "txn_latency_samples": txn_latency_samples,
            "txn_latency_avg_ms": (txn_latency_sum_ms / txn_latency_samples) if txn_latency_samples > 0 else None,
            "txn_latency_min_ms": txn_latency_min_ms,
            "txn_latency_max_ms": txn_latency_max_ms,
            "processing_latency_rps": processing_latency_rps,
            "records_processed_per_second": processing_latency_rps,
            "scan_elapsed_seconds": scan_elapsed_seconds,
            "scan_capped": scan_capped,
            "scan_limit": summary_scan_limit,
            "scanned_entries": scanned_entries,
            "custom_fields_incremental_processed_rows": custom_fields_incremental_processed_rows,
            "custom_fields_incremental_validated_rows": custom_fields_incremental_validated_rows,
            "custom_fields_incremental_output_rows": custom_fields_incremental_output_rows,
            "generated_at": datetime.utcnow().isoformat(),
        }

    async def _execute_rest_api(self, config: dict) -> list:
        try:
            import httpx
            method = config.get("method", "GET").upper()
            url = config.get("url", "")
            headers = self._parse_request_object(config.get("headers", {}))
            params = self._parse_request_object(config.get("params", {}), allow_query_string=True)
            body_payload = self._parse_request_payload(config.get("body"))

            request_kwargs = {
                "method": method,
                "url": url,
                "timeout": 30,
            }
            if headers:
                request_kwargs["headers"] = headers
            if params:
                request_kwargs["params"] = params
            if body_payload is not None and method not in {"GET", "HEAD", "OPTIONS"}:
                request_kwargs["json"] = body_payload

            async with httpx.AsyncClient() as client:
                resp = await client.request(**request_kwargs)
                data = resp.json()
                json_path = str(config.get("json_path", "") or "").strip()
                selected = self._extract_json_path_value(data, json_path)
                rows = self._rows_from_json_value(selected)
                if rows:
                    # If a leaf array path was picked (e.g. daily.temperature_2m_max),
                    # promote to parent object when it contains richer tabular fields.
                    if json_path and self._is_single_value_rows(rows):
                        parent_path = self._parent_json_path(json_path)
                        if parent_path:
                            parent_selected = self._extract_json_path_value(data, parent_path)
                            parent_rows = self._rows_from_json_value(parent_selected)
                            if parent_rows and not self._is_single_value_rows(parent_rows):
                                return parent_rows
                    return rows
                rows = self._rows_from_json_value(data)
                if rows:
                    return rows
                return []
        except Exception as e:
            return self._mock_data(config, "rest_api")

    async def _execute_graphql(self, config: dict) -> list:
        try:
            import httpx
            headers = self._parse_request_object(config.get("headers", {}))
            variables = self._parse_request_object(config.get("variables", {}))
            async with httpx.AsyncClient() as client:
                resp = await client.post(
                    config.get("endpoint", ""),
                    json={"query": config.get("query", "{ __typename }"),
                          "variables": variables},
                    headers=headers
                )
                data = resp.json().get("data", {})
                for v in data.values():
                    if isinstance(v, list):
                        return v
                return [data]
        except Exception:
            return self._mock_data(config, "graphql")

    async def _execute_s3(self, config: dict) -> list:
        try:
            import boto3, io, pandas as pd
            s3 = boto3.client(
                "s3",
                aws_access_key_id=config.get("access_key"),
                aws_secret_access_key=config.get("secret_key"),
                region_name=config.get("region", "us-east-1")
            )
            obj = s3.get_object(Bucket=config.get("bucket"), Key=config.get("key"))
            content = obj["Body"].read()
            ext = config.get("key", "").split(".")[-1].lower()
            if ext == "csv":
                df = pd.read_csv(io.BytesIO(content))
            elif ext == "json":
                df = pd.read_json(io.BytesIO(content))
            elif ext == "parquet":
                df = pd.read_parquet(io.BytesIO(content))
            else:
                df = pd.read_csv(io.BytesIO(content))
            return df.to_dict(orient="records")
        except Exception:
            return self._mock_data(config, "s3")

    async def _execute_kafka(self, config: dict) -> list:
        try:
            from kafka import KafkaConsumer
            consumer = KafkaConsumer(
                config.get("topic"),
                bootstrap_servers=config.get("bootstrap_servers", "localhost:9092"),
                auto_offset_reset="earliest",
                enable_auto_commit=False,
                consumer_timeout_ms=5000,
                value_deserializer=lambda x: json.loads(x.decode("utf-8"))
            )
            messages = []
            for msg in consumer:
                messages.append(msg.value)
                if len(messages) >= int(config.get("max_records", 100)):
                    break
            consumer.close()
            return messages
        except Exception:
            return self._mock_data(config, "kafka")

    # ─── TRANSFORM IMPLEMENTATIONS ─────────────────────────────────────────────

    def _transform_filter(self, data: list, config: dict) -> list:
        if isinstance(config, dict) and str(config.get("condition_routing_mode") or "").strip().lower() == "case":
            split = self._flow_condition_case_routes_split(data, config)
            return split.get("output") if isinstance(split.get("output"), list) else []
        passed_rows, _ = self._flow_condition_split(data, config)
        return passed_rows

    async def _transform_profile_query(
        self,
        data: list,
        config: dict,
        incoming_by_source: Optional[Dict[str, list]] = None,
        incoming_order: Optional[List[str]] = None,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        rows = data if isinstance(data, list) else []
        incoming_by_source = incoming_by_source or {}
        incoming_order = incoming_order or []

        should_abort_cb = (
            execution_context.get("should_abort")
            if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        node_warnings = execution_context.get("node_warnings") if isinstance(execution_context, dict) else None

        def _warn(msg: str) -> None:
            logger.warning(msg)
            if isinstance(node_warnings, list) and msg not in node_warnings:
                node_warnings.append(msg)

        safe_config = dict(config) if isinstance(config, dict) else {}
        query_mode = self._normalize_profile_query_mode(safe_config.get("query_mode", "hybrid"))
        rules = self._normalize_profile_query_rules(safe_config)
        if rules:
            safe_config["criteria"] = rules

        criteria_mode = str(safe_config.get("criteria_mode") or "all").strip().lower()
        if criteria_mode not in {"all", "any"}:
            criteria_mode = "all"
        safe_config["criteria_mode"] = criteria_mode

        try:
            offset = max(0, int(safe_config.get("offset", 0) or 0))
        except Exception:
            offset = 0
        try:
            limit = int(safe_config.get("limit", 0) or 0)
        except Exception:
            limit = 0
        if limit < 0:
            limit = 0

        selected_fields = self._parse_selected_fields(safe_config.get("select_fields", ""))
        select_fields_sort = str(safe_config.get("select_fields_sort") or "none").strip().lower()
        if select_fields_sort == "asc":
            selected_fields = sorted(selected_fields, key=lambda x: str(x or "").lower())
        elif select_fields_sort == "desc":
            selected_fields = sorted(selected_fields, key=lambda x: str(x or "").lower(), reverse=True)
        select_field_sorts = self._parse_select_field_sorts(
            safe_config.get("select_field_sorts"),
            selected_fields,
        )
        select_field_aliases = self._parse_select_field_aliases(safe_config.get("select_field_aliases"))
        array_output_mode = self._normalize_profile_query_array_output_mode(
            safe_config.get("array_output_mode", "list")
        )
        array_match_mode = self._normalize_profile_query_array_match_mode(
            safe_config.get("array_match_mode", "all_elements")
        )
        case_sensitive = bool(safe_config.get("case_sensitive", False))
        include_original_row = self._parse_bool_like(safe_config.get("include_original_row", True), True)
        array_rules_by_root = self._group_profile_query_rules_by_array_root(rules)
        profile_patch_enabled = self._parse_bool_like(safe_config.get("profile_patch_enabled"), False)
        profile_patch_stage = str(safe_config.get("profile_patch_stage") or "post").strip().lower()
        profile_patch_reflect_output = self._parse_bool_like(
            safe_config.get("profile_patch_reflect_output"),
            True,
        )
        profile_patch_ops_for_output = (
            self._normalize_profile_query_patch_operations(safe_config)
            if profile_patch_enabled and profile_patch_reflect_output
            else []
        )

        # Default path: use upstream rows.
        candidate_rows = rows
        pushdown_used = False
        pushdown_window_applied = False
        if query_mode in {"pushdown", "hybrid"}:
            source_type, source_cfg, source_id = self._profile_query_get_source_context(
                incoming_order,
                execution_context,
            )
            dialect = ""
            if source_type == "oracle_source":
                dialect = "oracle"
            elif source_type == "postgres_source":
                dialect = "postgres"
            elif source_type == "mysql_source":
                dialect = "mysql"
            if source_type and dialect:
                base_query = str(source_cfg.get("query", "") or "").strip().rstrip(";")
                if not base_query and source_type == "oracle_source":
                    table = str(source_cfg.get("table", "") or "").strip()
                    if table:
                        base_query = f"SELECT * FROM {table}"
                if base_query:
                    plan = self._build_profile_query_pushdown_query(
                        base_query=base_query,
                        rules=rules,
                        criteria_mode=criteria_mode,
                        dialect=dialect,
                        select_fields=selected_fields,
                        offset=offset,
                        limit=limit,
                    )
                    if plan:
                        sql, params, pushable_rules, engine_only_rules, pushdown_window_applied = plan
                        try:
                            pushed_rows = await self._profile_query_run_pushdown_sql(
                                source_type=source_type,
                                source_cfg=source_cfg,
                                sql=sql,
                                params=params,
                            )
                            candidate_rows = pushed_rows
                            pushdown_used = True
                            if query_mode == "pushdown" and engine_only_rules:
                                _warn(
                                    "Profile Query pushdown mode: some rules were not pushdown-safe; "
                                    "final in-engine refinement was applied for correctness."
                                )
                            if query_mode == "hybrid":
                                safe_config["criteria"] = rules
                        except Exception as exc:
                            _warn(
                                f"Profile Query pushdown failed for upstream source '{source_type}'"
                                f" (node={source_id or 'unknown'}): {exc}. Falling back to upstream rows."
                            )
                    else:
                        if query_mode == "pushdown":
                            _warn(
                                "Profile Query pushdown mode: no pushdown-safe criteria detected; "
                                "fallback to in-engine filtering."
                            )
                else:
                    _warn(
                        f"Profile Query pushdown skipped: upstream source '{source_type}' has no query/table configured."
                    )
            elif query_mode == "pushdown":
                _warn(
                    "Profile Query pushdown mode is supported only when directly connected to "
                    "PostgreSQL/MySQL/Oracle source node. Falling back to in-engine filtering."
                )

        _raise_if_aborted()
        filtered_rows: List[Any] = []
        for idx, row in enumerate(candidate_rows):
            if idx == 0 or idx % 500 == 0:
                _raise_if_aborted()
            try:
                matched = self._flow_condition_match_row(row, safe_config)
            except Exception:
                matched = False
            if matched:
                filtered_rows.append(row)

        if select_field_sorts and filtered_rows:
            filtered_rows = self._profile_query_sort_rows(filtered_rows, select_field_sorts)

        if not pushdown_used or not pushdown_window_applied:
            sliced_rows = filtered_rows[offset:] if offset > 0 else filtered_rows
            if limit > 0:
                sliced_rows = sliced_rows[:limit]
        else:
            sliced_rows = filtered_rows

        projection_input_rows = sliced_rows
        if profile_patch_ops_for_output and profile_patch_stage == "pre":
            reflected_rows: List[Any] = []
            for row in sliced_rows:
                if not isinstance(row, dict):
                    reflected_rows.append(row)
                    continue
                row_copy = self._json_safe_value(row)
                if not isinstance(row_copy, dict):
                    reflected_rows.append(row)
                    continue
                next_row, applied_ops, _ = self._profile_query_apply_patch_operations_to_doc(
                    row_copy,
                    row_copy,
                    profile_patch_ops_for_output,
                )
                reflected_rows.append(next_row if applied_ops > 0 else row_copy)
            projection_input_rows = reflected_rows

        if not selected_fields:
            result_rows = projection_input_rows
            try:
                self._apply_profile_query_patch_updates(
                    pre_rows=sliced_rows,
                    post_rows=result_rows,
                    config=safe_config,
                    execution_context=execution_context if isinstance(execution_context, dict) else {},
                    warn_cb=_warn,
                )
            except Exception as exc:
                _warn(f"Profile Query patch update failed: {exc}")
            if profile_patch_ops_for_output and profile_patch_stage != "pre":
                reflected_rows: List[Any] = []
                for row in result_rows:
                    if not isinstance(row, dict):
                        reflected_rows.append(row)
                        continue
                    row_copy = self._json_safe_value(row)
                    if not isinstance(row_copy, dict):
                        reflected_rows.append(row)
                        continue
                    next_row, applied_ops, _ = self._profile_query_apply_patch_operations_to_doc(
                        row_copy,
                        row_copy,
                        profile_patch_ops_for_output,
                    )
                    reflected_rows.append(next_row if applied_ops > 0 else row_copy)
                result_rows = reflected_rows
            return result_rows

        selected_field_array_roots: Dict[str, str] = {}
        for field_path in selected_fields:
            out_key = str(select_field_aliases.get(field_path) or field_path).strip() or field_path
            parsed_root = self._profile_query_array_root_and_suffix(field_path)
            if parsed_root and parsed_root[0]:
                selected_field_array_roots[out_key] = parsed_root[0]

        projected_rows: List[Dict[str, Any]] = []
        matched_projection_count = 0
        for idx, row in enumerate(projection_input_rows):
            if idx == 0 or idx % 500 == 0:
                _raise_if_aborted()
            out_row: Dict[str, Any] = {}
            if include_original_row:
                if isinstance(row, dict):
                    out_row.update(dict(row))
                else:
                    out_row["value"] = row
            for field_path in selected_fields:
                if array_match_mode == "matched_elements_only":
                    value, found = self._extract_profile_query_projection_value_matched_arrays(
                        row,
                        field_path,
                        array_rules_by_root,
                        criteria_mode,
                        case_sensitive,
                    )
                else:
                    value, found = self._extract_row_value_by_path(row, field_path)
                if found:
                    out_key = str(select_field_aliases.get(field_path) or field_path).strip() or field_path
                    out_row[out_key] = value
                    matched_projection_count += 1
            if array_output_mode == "explode_rows":
                projected_rows.extend(
                    self._explode_projected_row_arrays(
                        out_row,
                        array_field_roots=selected_field_array_roots,
                        max_combinations=5000,
                    )
                )
            else:
                projected_rows.append(out_row)

        if matched_projection_count == 0 and sliced_rows:
            logger.warning("Data Query select_fields matched zero fields; returning filtered rows unchanged")
            result_rows = sliced_rows if include_original_row else []
        else:
            result_rows = projected_rows

        try:
            self._apply_profile_query_patch_updates(
                pre_rows=sliced_rows,
                post_rows=result_rows,
                config=safe_config,
                execution_context=execution_context if isinstance(execution_context, dict) else {},
                warn_cb=_warn,
            )
        except Exception as exc:
            _warn(f"Profile Query patch update failed: {exc}")

        if profile_patch_ops_for_output and profile_patch_stage != "pre":
            reflected_rows: List[Any] = []
            for row in result_rows:
                if not isinstance(row, dict):
                    reflected_rows.append(row)
                    continue
                row_copy = self._json_safe_value(row)
                if not isinstance(row_copy, dict):
                    reflected_rows.append(row)
                    continue
                next_row, applied_ops, _ = self._profile_query_apply_patch_operations_to_doc(
                    row_copy,
                    row_copy,
                    profile_patch_ops_for_output,
                )
                reflected_rows.append(next_row if applied_ops > 0 else row_copy)
            result_rows = reflected_rows

        return result_rows

    def _profile_query_deep_merge_docs(self, base_doc: Dict[str, Any], patch_doc: Dict[str, Any]) -> Dict[str, Any]:
        base = dict(base_doc) if isinstance(base_doc, dict) else {}
        for key, raw_value in (patch_doc or {}).items():
            if isinstance(raw_value, dict) and isinstance(base.get(key), dict):
                base[key] = self._profile_query_deep_merge_docs(
                    base.get(key) if isinstance(base.get(key), dict) else {},
                    raw_value,
                )
            else:
                base[key] = self._json_safe_value(raw_value)
        return base

    def _profile_query_get_pipeline_node_payload(
        self,
        execution_context: Optional[Dict[str, Any]],
        node_id: str,
    ) -> Optional[Dict[str, Any]]:
        if not isinstance(execution_context, dict):
            return None
        node_key = str(node_id or "").strip()
        if not node_key:
            return None
        pipeline_nodes = execution_context.get("pipeline_nodes")
        if isinstance(pipeline_nodes, dict):
            node_payload = pipeline_nodes.get(node_key)
            if isinstance(node_payload, dict):
                return node_payload
            return None
        if isinstance(pipeline_nodes, list):
            for raw_node in pipeline_nodes:
                if not isinstance(raw_node, dict):
                    continue
                raw_id = str(raw_node.get("id") or "").strip()
                if raw_id and raw_id == node_key:
                    return raw_node
        return None

    def _profile_query_default_patch_payload(self, row_obj: Dict[str, Any]) -> Dict[str, Any]:
        if not isinstance(row_obj, dict):
            return {}
        out: Dict[str, Any] = {}
        for raw_key, raw_value in row_obj.items():
            key = str(raw_key or "").strip()
            if not key:
                continue
            key_lower = key.lower()
            if key_lower in {"lmdb_key", "lmdb_value"}:
                continue
            if key_lower.startswith("_lmdb_"):
                continue
            out[key] = self._json_safe_value(raw_value)
        return out

    def _profile_query_coerce_patch_value_literal(self, raw_value: Any) -> Any:
        if raw_value is None:
            return None
        if isinstance(raw_value, (bool, int, float, dict, list)):
            return self._json_safe_value(raw_value)
        text = str(raw_value).strip()
        if text == "":
            return ""
        lowered = text.lower()
        if lowered in {"null", "none"}:
            return None
        if lowered in {"true", "false"}:
            return lowered == "true"
        try:
            if re.fullmatch(r"-?\d+", text):
                return int(text)
            if re.fullmatch(r"-?\d+\.\d+", text):
                return float(text)
        except Exception:
            pass
        if text.startswith("{") or text.startswith("["):
            try:
                return self._json_safe_value(json.loads(text))
            except Exception:
                pass
        return text

    def _profile_query_resolve_patch_value_from_row_target(
        self,
        row_obj: Dict[str, Any],
        patch_target_path: str,
    ) -> Tuple[Any, bool]:
        if not isinstance(row_obj, dict):
            return None, False
        tokens = self._split_profile_path(patch_target_path)
        leaf = None
        for token in reversed(tokens):
            if isinstance(token, str) and str(token).strip():
                leaf = str(token).strip()
                break
        if leaf:
            direct_val, direct_found = self._extract_row_value_by_path(row_obj, leaf)
            if direct_found:
                return self._json_safe_value(direct_val), True
            if leaf in row_obj:
                return self._json_safe_value(row_obj.get(leaf)), True

        candidates: List[Any] = []
        for raw_key, raw_val in row_obj.items():
            key = str(raw_key or "").strip()
            if not key:
                continue
            key_lower = key.lower()
            if key_lower in {"lmdb_key", "lmdb_value"} or key_lower.startswith("_lmdb_"):
                continue
            candidates.append(raw_val)
        if len(candidates) == 1:
            return self._json_safe_value(candidates[0]), True
        return None, False

    def _profile_query_pick_patch_value(
        self,
        row_obj: Dict[str, Any],
        patch_source_path: str,
        patch_target_path: str,
        patch_value_mode: str,
        patch_value_literal: Any,
    ) -> Tuple[Any, bool]:
        mode = str(patch_value_mode or "row").strip().lower()
        if mode == "fixed":
            return self._profile_query_coerce_patch_value_literal(patch_value_literal), True

        if patch_source_path:
            patch_value, patch_found = self._extract_row_value_by_path(row_obj, patch_source_path)
            if not patch_found and patch_source_path in row_obj:
                patch_value = row_obj.get(patch_source_path)
                patch_found = True
            if patch_found:
                return patch_value, True
            return None, False

        if patch_target_path:
            target_value, target_found = self._profile_query_resolve_patch_value_from_row_target(
                row_obj,
                patch_target_path,
            )
            if target_found:
                return target_value, True

        if "lmdb_value" in row_obj:
            return row_obj.get("lmdb_value"), True

        default_patch = self._profile_query_default_patch_payload(row_obj)
        if default_patch:
            return default_patch, True
        return row_obj, True

    def _normalize_profile_query_patch_operations(self, config: Dict[str, Any]) -> List[Dict[str, Any]]:
        safe_cfg = dict(config) if isinstance(config, dict) else {}
        raw_ops = safe_cfg.get("profile_patch_ops")
        if isinstance(raw_ops, str):
            text = raw_ops.strip()
            if text:
                try:
                    raw_ops = json.loads(text)
                except Exception:
                    raw_ops = []
            else:
                raw_ops = []

        out: List[Dict[str, Any]] = []
        if isinstance(raw_ops, list):
            for idx, raw in enumerate(raw_ops):
                if not isinstance(raw, dict):
                    continue
                op_raw = str(raw.get("op") or raw.get("operation") or raw.get("type") or "set").strip().lower()
                if op_raw not in {"set", "set_where", "unset", "inc", "append", "remove", "rename"}:
                    op_raw = "set"

                target_path = str(raw.get("target_path") or raw.get("path") or raw.get("target") or "").strip()
                source_path = str(raw.get("source_path") or raw.get("document_path") or "").strip()
                value_mode = str(raw.get("value_mode") or "row").strip().lower()
                if value_mode not in {"row", "fixed"}:
                    value_mode = "row"
                merge_mode = str(raw.get("merge_mode") or safe_cfg.get("profile_patch_merge_mode") or "merge").strip().lower()
                if merge_mode not in {"merge", "replace"}:
                    merge_mode = "merge"
                rename_to = str(raw.get("rename_to") or raw.get("new_name") or raw.get("new_key") or "").strip()
                where_field = str(raw.get("where_field") or raw.get("match_field") or "").strip()
                where_value_mode = str(raw.get("where_value_mode") or raw.get("match_value_mode") or "row").strip().lower()
                if where_value_mode not in {"row", "fixed"}:
                    where_value_mode = "row"
                where_source_path = str(raw.get("where_source_path") or raw.get("match_source_path") or "").strip()

                out.append({
                    "id": str(raw.get("id") or f"op_{idx + 1}"),
                    "op": op_raw,
                    "target_path": target_path,
                    "source_path": source_path,
                    "value_mode": value_mode,
                    "value": raw.get("value"),
                    "where_field": where_field,
                    "where_value_mode": where_value_mode,
                    "where_source_path": where_source_path,
                    "where_value": raw.get("where_value", raw.get("match_value")),
                    "rename_to": rename_to,
                    "merge_mode": merge_mode,
                })

        if out:
            return out

        # Backward compatibility with legacy single-patch configuration.
        patch_source_path = str(safe_cfg.get("profile_patch_document_path") or "").strip()
        patch_target_path = str(safe_cfg.get("profile_patch_target_path") or "").strip()
        patch_value_mode = str(safe_cfg.get("profile_patch_value_mode") or "row").strip().lower()
        if patch_value_mode not in {"row", "fixed"}:
            patch_value_mode = "row"
        patch_value = safe_cfg.get("profile_patch_value")
        merge_mode = str(safe_cfg.get("profile_patch_merge_mode") or "merge").strip().lower()
        if merge_mode not in {"merge", "replace"}:
            merge_mode = "merge"
        if patch_target_path or patch_source_path or patch_value_mode == "fixed":
            return [{
                "id": "op_1",
                "op": "set",
                "target_path": patch_target_path,
                "source_path": patch_source_path,
                "value_mode": patch_value_mode,
                "value": patch_value,
                "rename_to": "",
                "merge_mode": merge_mode,
            }]
        return []

    def _profile_query_collect_patch_targets_with_wildcards(
        self,
        data: Any,
        path: Any,
        create_missing: bool = False,
    ) -> List[Tuple[Any, Any]]:
        tokens = self._split_profile_path_with_wildcards(path)
        if not tokens:
            return []
        targets: List[Tuple[Any, Any]] = []

        def _walk(current: Any, idx: int) -> None:
            token = tokens[idx]
            is_last = idx == len(tokens) - 1
            next_token = tokens[idx + 1] if not is_last else None

            if token == "*":
                if not isinstance(current, list):
                    return
                if is_last:
                    for i in range(len(current)):
                        targets.append((current, i))
                    return
                for i in range(len(current)):
                    child = current[i]
                    if create_missing:
                        if next_token == "*" or isinstance(next_token, int):
                            if not isinstance(child, list):
                                child = []
                                current[i] = child
                        else:
                            if not isinstance(child, dict):
                                child = {}
                                current[i] = child
                    if isinstance(child, (dict, list)):
                        _walk(child, idx + 1)
                return

            if isinstance(token, int):
                if not isinstance(current, list):
                    return
                if create_missing:
                    while len(current) <= token:
                        current.append({} if not (next_token == "*" or isinstance(next_token, int)) else [])
                if token < 0 or token >= len(current):
                    return
                if is_last:
                    targets.append((current, token))
                    return
                child = current[token]
                if create_missing:
                    if next_token == "*" or isinstance(next_token, int):
                        if not isinstance(child, list):
                            child = []
                            current[token] = child
                    else:
                        if not isinstance(child, dict):
                            child = {}
                            current[token] = child
                if isinstance(child, (dict, list)):
                    _walk(child, idx + 1)
                return

            key = str(token)
            if not isinstance(current, dict):
                return
            if is_last:
                targets.append((current, key))
                return
            child = current.get(key)
            if create_missing:
                if next_token == "*" or isinstance(next_token, int):
                    if not isinstance(child, list):
                        child = []
                        current[key] = child
                else:
                    if not isinstance(child, dict):
                        child = {}
                        current[key] = child
            if isinstance(child, (dict, list)):
                _walk(child, idx + 1)

        _walk(data, 0)
        return targets

    def _profile_query_coerce_numeric_value(self, value: Any) -> Optional[float]:
        if value is None:
            return None
        if isinstance(value, bool):
            return float(int(value))
        if isinstance(value, (int, float)):
            try:
                return float(value)
            except Exception:
                return None
        text = str(value).strip().replace(",", "")
        if not text:
            return None
        try:
            return float(text)
        except Exception:
            return None

    def _profile_query_apply_single_patch_operation_to_doc(
        self,
        base_doc: Any,
        row_obj: Dict[str, Any],
        op_cfg: Dict[str, Any],
    ) -> Tuple[Any, bool]:
        current_doc = dict(base_doc) if isinstance(base_doc, dict) else {}
        op_type = str(op_cfg.get("op") or "set").strip().lower()
        target_path = str(op_cfg.get("target_path") or "").strip()
        source_path = str(op_cfg.get("source_path") or "").strip()
        value_mode = str(op_cfg.get("value_mode") or "row").strip().lower()
        value_literal = op_cfg.get("value")
        where_field = str(op_cfg.get("where_field") or "").strip()
        where_value_mode = str(op_cfg.get("where_value_mode") or "row").strip().lower()
        if where_value_mode not in {"row", "fixed"}:
            where_value_mode = "row"
        where_source_path = str(op_cfg.get("where_source_path") or "").strip()
        where_value_literal = op_cfg.get("where_value")
        rename_to = str(op_cfg.get("rename_to") or "").strip()
        merge_mode = str(op_cfg.get("merge_mode") or "merge").strip().lower()
        if merge_mode not in {"merge", "replace"}:
            merge_mode = "merge"

        if op_type == "set_where":
            if not target_path or not where_field:
                return current_doc, False
            patch_value, patch_found = self._profile_query_pick_patch_value(
                row_obj=row_obj,
                patch_source_path=source_path,
                patch_target_path=target_path,
                patch_value_mode=value_mode,
                patch_value_literal=value_literal,
            )
            if not patch_found:
                return current_doc, False

            if where_value_mode == "fixed":
                where_value = self._profile_query_coerce_patch_value_literal(where_value_literal)
                where_found = True
            else:
                where_value = None
                where_found = False
                where_row_path = str(where_source_path or where_field).strip()
                if where_row_path:
                    where_value, where_found = self._extract_row_value_by_path(row_obj, where_row_path)
                    if not where_found and where_row_path in row_obj:
                        where_value = row_obj.get(where_row_path)
                        where_found = True
            if not where_found:
                return current_doc, False

            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=True)
            if not targets:
                return current_doc, False

            changed = False
            for parent, key in targets:
                left_value: Any = None
                left_found = False

                if isinstance(parent, dict):
                    left_value, left_found = self._extract_row_value_by_path(parent, where_field)
                elif isinstance(parent, list) and isinstance(key, int) and 0 <= key < len(parent):
                    element = parent[key]
                    if isinstance(element, (dict, list)):
                        left_value, left_found = self._extract_row_value_by_path(element, where_field)

                if not left_found and isinstance(row_obj, dict):
                    left_value, left_found = self._extract_row_value_by_path(row_obj, where_field)
                    if not left_found and where_field in row_obj:
                        left_value = row_obj.get(where_field)
                        left_found = True

                if not left_found:
                    continue
                if not self._flow_condition_eval_operator(left_value, "equals", where_value, False):
                    continue

                value_to_set = self._json_safe_value(patch_value)
                if isinstance(parent, dict):
                    parent[key] = value_to_set
                    changed = True
                elif isinstance(parent, list) and isinstance(key, int):
                    while len(parent) <= key:
                        parent.append(None)
                    parent[key] = value_to_set
                    changed = True
            return current_doc, changed

        if op_type == "set":
            patch_value, patch_found = self._profile_query_pick_patch_value(
                row_obj=row_obj,
                patch_source_path=source_path,
                patch_target_path=target_path,
                patch_value_mode=value_mode,
                patch_value_literal=value_literal,
            )
            if not patch_found:
                return current_doc, False
            next_doc = self._profile_query_apply_patch_to_doc(
                current_doc,
                patch_value,
                target_path,
                merge_mode,
            )
            if isinstance(next_doc, dict):
                return next_doc, True
            return current_doc, False

        if op_type == "unset":
            if not target_path:
                return current_doc, False
            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=False)
            if not targets:
                return current_doc, False
            changed = False
            list_targets: Dict[int, Tuple[List[Any], set[int]]] = {}
            for parent, key in targets:
                if isinstance(parent, dict):
                    if key in parent:
                        del parent[key]
                        changed = True
                elif isinstance(parent, list) and isinstance(key, int) and 0 <= key < len(parent):
                    entry = list_targets.get(id(parent))
                    if entry is None:
                        entry = (parent, set())
                        list_targets[id(parent)] = entry
                    entry[1].add(key)
            for parent, idxs in list_targets.values():
                for idx in sorted(idxs, reverse=True):
                    if 0 <= idx < len(parent):
                        parent.pop(idx)
                        changed = True
            return current_doc, changed

        if op_type == "inc":
            if not target_path:
                return current_doc, False
            delta_value, delta_found = self._profile_query_pick_patch_value(
                row_obj=row_obj,
                patch_source_path=source_path,
                patch_target_path=target_path,
                patch_value_mode=value_mode,
                patch_value_literal=value_literal,
            )
            if not delta_found:
                return current_doc, False
            delta = self._profile_query_coerce_numeric_value(delta_value)
            if delta is None:
                return current_doc, False
            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=True)
            if not targets:
                return current_doc, False
            changed = False
            for parent, key in targets:
                current_val: Any = None
                found_existing = False
                if isinstance(parent, dict):
                    if key in parent:
                        current_val = parent.get(key)
                        found_existing = True
                elif isinstance(parent, list) and isinstance(key, int) and 0 <= key < len(parent):
                    current_val = parent[key]
                    found_existing = True
                base_num = self._profile_query_coerce_numeric_value(current_val) if found_existing else 0.0
                if base_num is None:
                    base_num = 0.0
                next_num = base_num + delta
                if float(next_num).is_integer():
                    next_value: Any = int(next_num)
                else:
                    next_value = float(next_num)
                if isinstance(parent, dict):
                    parent[key] = self._json_safe_value(next_value)
                    changed = True
                elif isinstance(parent, list) and isinstance(key, int):
                    while len(parent) <= key:
                        parent.append(None)
                    parent[key] = self._json_safe_value(next_value)
                    changed = True
            return current_doc, changed

        if op_type == "append":
            if not target_path:
                return current_doc, False
            append_value, append_found = self._profile_query_pick_patch_value(
                row_obj=row_obj,
                patch_source_path=source_path,
                patch_target_path=target_path,
                patch_value_mode=value_mode,
                patch_value_literal=value_literal,
            )
            if not append_found:
                return current_doc, False
            append_safe = self._json_safe_value(append_value)
            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=True)
            if not targets:
                return current_doc, False
            changed = False
            for parent, key in targets:
                exists = False
                existing: Any = None
                if isinstance(parent, dict):
                    if key in parent:
                        existing = parent.get(key)
                        exists = True
                elif isinstance(parent, list) and isinstance(key, int) and 0 <= key < len(parent):
                    existing = parent[key]
                    exists = True
                if not exists or existing is None:
                    next_list = [append_safe]
                elif isinstance(existing, list):
                    next_list = list(existing)
                    next_list.append(append_safe)
                else:
                    next_list = [self._json_safe_value(existing), append_safe]
                if isinstance(parent, dict):
                    parent[key] = next_list
                    changed = True
                elif isinstance(parent, list) and isinstance(key, int):
                    while len(parent) <= key:
                        parent.append(None)
                    parent[key] = next_list
                    changed = True
            return current_doc, changed

        if op_type == "remove":
            if not target_path:
                return current_doc, False
            remove_value, remove_found = self._profile_query_pick_patch_value(
                row_obj=row_obj,
                patch_source_path=source_path,
                patch_target_path=target_path,
                patch_value_mode=value_mode,
                patch_value_literal=value_literal,
            )
            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=False)
            if not targets:
                return current_doc, False
            changed = False
            if not remove_found:
                # No compare value means remove target node itself.
                return self._profile_query_apply_single_patch_operation_to_doc(
                    current_doc,
                    row_obj,
                    {
                        "op": "unset",
                        "target_path": target_path,
                    },
                )
            remove_safe = self._json_safe_value(remove_value)
            for parent, key in targets:
                exists = False
                current_val: Any = None
                if isinstance(parent, dict):
                    if key in parent:
                        current_val = parent.get(key)
                        exists = True
                elif isinstance(parent, list) and isinstance(key, int) and 0 <= key < len(parent):
                    current_val = parent[key]
                    exists = True
                if not exists:
                    continue
                if isinstance(current_val, list):
                    filtered = [item for item in current_val if item != remove_safe]
                    if len(filtered) != len(current_val):
                        if isinstance(parent, dict):
                            parent[key] = filtered
                        elif isinstance(parent, list) and isinstance(key, int):
                            parent[key] = filtered
                        changed = True
                    continue
                if isinstance(current_val, dict):
                    rm_key = str(remove_safe).strip()
                    if rm_key and rm_key in current_val:
                        next_dict = dict(current_val)
                        next_dict.pop(rm_key, None)
                        if isinstance(parent, dict):
                            parent[key] = next_dict
                        elif isinstance(parent, list) and isinstance(key, int):
                            parent[key] = next_dict
                        changed = True
                    continue
                if current_val == remove_safe:
                    _, unset_changed = self._profile_query_apply_single_patch_operation_to_doc(
                        current_doc,
                        row_obj,
                        {
                            "op": "unset",
                            "target_path": target_path,
                        },
                    )
                    changed = changed or unset_changed
            return current_doc, changed

        if op_type == "rename":
            if not target_path or not rename_to:
                return current_doc, False
            targets = self._profile_query_collect_patch_targets_with_wildcards(current_doc, target_path, create_missing=False)
            if not targets:
                return current_doc, False
            changed = False
            for parent, key in targets:
                if not isinstance(parent, dict):
                    continue
                src_key = str(key)
                if src_key not in parent:
                    continue
                if src_key == rename_to:
                    continue
                parent[rename_to] = parent.pop(src_key)
                changed = True
            return current_doc, changed

        return current_doc, False

    def _profile_query_apply_patch_operations_to_doc(
        self,
        base_doc: Any,
        row_obj: Dict[str, Any],
        patch_ops: List[Dict[str, Any]],
    ) -> Tuple[Any, int, int]:
        current_doc = dict(base_doc) if isinstance(base_doc, dict) else {}
        applied = 0
        invalid = 0
        for op_cfg in patch_ops or []:
            if not isinstance(op_cfg, dict):
                invalid += 1
                continue
            next_doc, changed = self._profile_query_apply_single_patch_operation_to_doc(
                current_doc,
                row_obj,
                op_cfg,
            )
            if not changed:
                invalid += 1
                continue
            current_doc = next_doc if isinstance(next_doc, dict) else current_doc
            applied += 1
        return current_doc, applied, invalid

    def _profile_query_apply_patch_operations_to_lmdb_payload(
        self,
        current_value: Any,
        row_obj: Dict[str, Any],
        patch_ops: List[Dict[str, Any]],
    ) -> Tuple[Any, int, int]:
        profile_source = str(row_obj.get("_lmdb_profile_source") or "").strip().lower()
        entity_key = str(row_obj.get("lmdb_entity_key") or "").strip()

        if isinstance(current_value, dict):
            if profile_source == "document" and "document" in current_value:
                wrapper = dict(current_value)
                base_doc = wrapper.get("document")
                next_doc, applied, invalid = self._profile_query_apply_patch_operations_to_doc(
                    base_doc if isinstance(base_doc, dict) else {},
                    row_obj,
                    patch_ops,
                )
                if applied <= 0:
                    return current_value, 0, invalid
                wrapper["document"] = next_doc
                return wrapper, applied, invalid

            docs_obj = current_value.get("documents")
            if profile_source == "documents" and isinstance(docs_obj, dict) and entity_key:
                wrapper = dict(current_value)
                docs_copy = dict(docs_obj)
                base_doc = docs_copy.get(entity_key)
                next_doc, applied, invalid = self._profile_query_apply_patch_operations_to_doc(
                    base_doc if isinstance(base_doc, dict) else {},
                    row_obj,
                    patch_ops,
                )
                if applied <= 0:
                    return current_value, 0, invalid
                docs_copy[entity_key] = next_doc
                wrapper["documents"] = docs_copy
                return wrapper, applied, invalid

        next_doc, applied, invalid = self._profile_query_apply_patch_operations_to_doc(
            current_value if isinstance(current_value, dict) else {},
            row_obj,
            patch_ops,
        )
        if applied <= 0:
            return current_value, 0, invalid
        return next_doc, applied, invalid

    def _profile_query_apply_patch_to_doc(
        self,
        base_doc: Any,
        patch_value: Any,
        patch_target_path: str,
        merge_mode: str,
    ) -> Any:
        mode = str(merge_mode or "merge").strip().lower()
        if mode not in {"merge", "replace"}:
            mode = "merge"

        if mode == "replace":
            if patch_target_path:
                next_doc = dict(base_doc) if isinstance(base_doc, dict) else {}
                self._set_profile_path_value_with_wildcards(
                    next_doc,
                    patch_target_path,
                    self._json_safe_value(patch_value),
                )
                return next_doc
            if isinstance(patch_value, dict):
                return self._json_safe_value(dict(patch_value))
            return self._json_safe_value(patch_value)

        if patch_target_path:
            next_doc = dict(base_doc) if isinstance(base_doc, dict) else {}
            self._set_profile_path_value_with_wildcards(
                next_doc,
                patch_target_path,
                self._json_safe_value(patch_value),
            )
            return next_doc
        if isinstance(patch_value, dict):
            return self._profile_query_deep_merge_docs(
                dict(base_doc) if isinstance(base_doc, dict) else {},
                patch_value,
            )
        return self._json_safe_value(patch_value)

    def _profile_query_apply_patch_to_lmdb_payload(
        self,
        current_value: Any,
        row_obj: Dict[str, Any],
        patch_value: Any,
        patch_target_path: str,
        merge_mode: str,
    ) -> Any:
        profile_source = str(row_obj.get("_lmdb_profile_source") or "").strip().lower()
        entity_key = str(row_obj.get("lmdb_entity_key") or "").strip()

        if isinstance(current_value, dict):
            if profile_source == "document" and "document" in current_value:
                wrapper = dict(current_value)
                base_doc = wrapper.get("document")
                wrapper["document"] = self._profile_query_apply_patch_to_doc(
                    base_doc if isinstance(base_doc, dict) else {},
                    patch_value,
                    patch_target_path,
                    merge_mode,
                )
                return wrapper

            docs_obj = current_value.get("documents")
            if (
                profile_source == "documents"
                and isinstance(docs_obj, dict)
                and entity_key
            ):
                wrapper = dict(current_value)
                docs_copy = dict(docs_obj)
                base_doc = docs_copy.get(entity_key)
                if base_doc is None and entity_key in docs_obj:
                    base_doc = docs_obj.get(entity_key)
                docs_copy[entity_key] = self._profile_query_apply_patch_to_doc(
                    base_doc if isinstance(base_doc, dict) else {},
                    patch_value,
                    patch_target_path,
                    merge_mode,
                )
                wrapper["documents"] = docs_copy
                return wrapper

        return self._profile_query_apply_patch_to_doc(
            current_value if isinstance(current_value, dict) else {},
            patch_value,
            patch_target_path,
            merge_mode,
        )

    def _encode_lmdb_value_for_patch(self, value: Any, preferred_kind: str) -> bytes:
        kind = str(preferred_kind or "json").strip().lower() or "json"
        if kind == "base64":
            if isinstance(value, (bytes, bytearray)):
                return bytes(value)
            if isinstance(value, str):
                return base64.b64decode(value.encode("ascii"), validate=True)
            raise ValueError("Base64 LMDB value requires bytes or base64 string.")
        if kind == "text":
            if isinstance(value, (dict, list)):
                return json.dumps(self._json_safe_value(value), ensure_ascii=False).encode("utf-8")
            if value is None:
                return b""
            return str(value).encode("utf-8", errors="replace")
        return json.dumps(self._json_safe_value(value), ensure_ascii=False).encode("utf-8")

    def _profile_query_extract_oracle_source_table(self, config: Dict[str, Any]) -> str:
        table = str(
            (config or {}).get("custom_profile_oracle_table")
            or (config or {}).get("profile_table")
            or (config or {}).get("table")
            or ""
        ).strip()
        if table:
            return table
        query = str((config or {}).get("query") or "").strip()
        match = re.search(
            r"\bfrom\s+([A-Za-z_][\w$#]*(?:\.[A-Za-z_][\w$#]*)?)",
            query,
            flags=re.IGNORECASE,
        )
        return str(match.group(1)).strip() if match else "ETL_PROFILE_STATE"

    def _profile_query_extract_oracle_source_profile_node_id(self, config: Dict[str, Any]) -> str:
        explicit = str(
            (config or {}).get("profile_node_id")
            or (config or {}).get("target_profile_node_id")
            or (config or {}).get("custom_profile_node_id")
            or (config or {}).get("custom_profile_oracle_node_id")
            or ""
        ).strip()
        if explicit:
            return explicit
        query = str((config or {}).get("query") or "").strip()
        match = re.search(
            r"\bnode_id\s*=\s*'([^']+)'",
            query,
            flags=re.IGNORECASE,
        )
        return str(match.group(1)).strip() if match else ""

    def _profile_query_extract_oracle_source_profile_pipeline_id(self, config: Dict[str, Any]) -> str:
        explicit = str(
            (config or {}).get("profile_pipeline_id")
            or (config or {}).get("target_profile_pipeline_id")
            or (config or {}).get("custom_profile_pipeline_id")
            or (config or {}).get("custom_profile_oracle_pipeline_id")
            or ""
        ).strip()
        if explicit:
            return explicit
        query = str((config or {}).get("query") or "").strip()
        match = re.search(
            r"\bpipeline_id\s*=\s*'([^']+)'",
            query,
            flags=re.IGNORECASE,
        )
        return str(match.group(1)).strip() if match else ""

    def _profile_query_rows_have_first_value(
        self,
        rows: List[Any],
        field_paths: List[str],
        sample_limit: int = 25,
    ) -> bool:
        for raw_row in (rows or [])[: max(1, int(sample_limit or 25))]:
            row_obj = raw_row if isinstance(raw_row, dict) else {"value": raw_row}
            value, found = self._profile_query_extract_first_row_value(row_obj, field_paths)
            if found and value is not None and str(value).strip():
                return True
        return False

    def _profile_query_oracle_profile_cfg_from_source_config(self, config: Dict[str, Any]) -> Dict[str, Any]:
        cfg = dict(config or {})
        return {
            "custom_profile_oracle_host": cfg.get("custom_profile_oracle_host") or cfg.get("host"),
            "custom_profile_oracle_port": cfg.get("custom_profile_oracle_port") or cfg.get("port"),
            "custom_profile_oracle_service_name": (
                cfg.get("custom_profile_oracle_service_name")
                or cfg.get("service_name")
            ),
            "custom_profile_oracle_sid": cfg.get("custom_profile_oracle_sid") or cfg.get("sid"),
            "custom_profile_oracle_user": cfg.get("custom_profile_oracle_user") or cfg.get("user"),
            "custom_profile_oracle_password": (
                cfg.get("custom_profile_oracle_password")
                or cfg.get("password")
            ),
            "custom_profile_oracle_dsn": cfg.get("custom_profile_oracle_dsn") or cfg.get("dsn"),
            "custom_profile_oracle_table": self._profile_query_extract_oracle_source_table(cfg),
            "custom_profile_oracle_write_strategy": (
                cfg.get("custom_profile_oracle_write_strategy")
                or cfg.get("write_strategy")
            ),
            "custom_profile_oracle_parallel_workers": (
                cfg.get("custom_profile_oracle_parallel_workers")
                or cfg.get("parallel_workers")
            ),
            "custom_profile_oracle_parallel_min_tokens": (
                cfg.get("custom_profile_oracle_parallel_min_tokens")
                or cfg.get("parallel_min_tokens")
            ),
            "custom_profile_oracle_merge_batch_size": (
                cfg.get("custom_profile_oracle_merge_batch_size")
                or cfg.get("merge_batch_size")
            ),
            "custom_profile_oracle_parallel_force": (
                cfg.get("custom_profile_oracle_parallel_force")
                or cfg.get("parallel_force")
            ),
        }

    def _profile_query_patch_ops_for_stored_profile_document(
        self,
        patch_ops: List[Dict[str, Any]],
        strip_document_json: bool = False,
    ) -> List[Dict[str, Any]]:
        if not strip_document_json:
            return patch_ops
        out: List[Dict[str, Any]] = []
        for raw_op in patch_ops or []:
            if not isinstance(raw_op, dict):
                continue
            op = dict(raw_op)
            target_path = str(op.get("target_path") or "").strip()
            if target_path.lower().startswith("document_json."):
                op["target_path"] = target_path[len("DOCUMENT_JSON."):]
            out.append(op)
        return out

    def _lmdb_write_map_size_for_patch(self, env_path: str, config: Dict[str, Any]) -> int:
        raw_size = (
            (config or {}).get("profile_patch_lmdb_map_size")
            or (config or {}).get("lmdb_map_size")
            or (config or {}).get("map_size")
            or os.getenv("PROFILE_PATCH_LMDB_MAP_SIZE")
            or os.getenv("PROFILE_LMDB_MAP_SIZE")
            or ""
        )
        configured_size = 0
        try:
            configured_size = int(raw_size or 0)
        except Exception:
            configured_size = 0

        data_path = os.path.join(str(env_path or ""), "data.mdb")
        current_size = 0
        try:
            if os.path.isfile(data_path):
                current_size = int(os.path.getsize(data_path) or 0)
        except Exception:
            current_size = 0

        default_size = 4 * 1024 * 1024 * 1024
        min_growth_size = current_size * 4 if current_size > 0 else 0
        return max(configured_size, min_growth_size, default_size)

    def _profile_query_extract_first_row_value(
        self,
        row_obj: Dict[str, Any],
        paths: List[str],
    ) -> Tuple[Any, bool]:
        if not isinstance(row_obj, dict):
            return None, False
        for raw_path in paths or []:
            path = str(raw_path or "").strip()
            if not path:
                continue
            value, found = self._extract_row_value_by_path(row_obj, path)
            if not found and path in row_obj:
                value = row_obj.get(path)
                found = True
            if found and value is not None and str(value).strip() != "":
                return value, True
        return None, False

    def _profile_query_json_dict_from_row_value(self, value: Any) -> Tuple[Dict[str, Any], bool]:
        if isinstance(value, dict):
            return self._json_safe_value(value), True
        if isinstance(value, str):
            text = value.strip()
            if text.startswith("{") and text.endswith("}"):
                try:
                    parsed = json.loads(text)
                    if isinstance(parsed, dict):
                        return self._json_safe_value(parsed), True
                except Exception:
                    pass
        return {}, False

    def _profile_query_oracle_source_doc_from_row(
        self,
        row_obj: Dict[str, Any],
    ) -> Tuple[Dict[str, Any], Dict[str, Any], bool]:
        if not isinstance(row_obj, dict):
            return {}, {}, False

        doc_value, doc_found = self._profile_query_extract_first_row_value(
            row_obj,
            [
                "DOCUMENT_JSON",
                "document_json",
                "documentJson",
            ],
        )
        doc, parsed_doc = self._profile_query_json_dict_from_row_value(doc_value) if doc_found else ({}, False)

        meta_value, meta_found = self._profile_query_extract_first_row_value(
            row_obj,
            [
                "META_JSON",
                "meta_json",
                "metaJson",
            ],
        )
        meta, parsed_meta = self._profile_query_json_dict_from_row_value(meta_value) if meta_found else ({}, False)
        return doc, meta if parsed_meta else {}, parsed_doc

    def _profile_query_extract_row_or_document_path(
        self,
        row_obj: Dict[str, Any],
        path: str,
    ) -> Tuple[Any, bool]:
        if not isinstance(row_obj, dict):
            return None, False
        path_text = str(path or "").strip()
        if not path_text:
            return None, False

        value, found = self._extract_row_value_by_path(row_obj, path_text)
        if not found and path_text in row_obj:
            value = row_obj.get(path_text)
            found = True
        if found:
            return value, True

        doc_value, doc_found = self._profile_query_extract_first_row_value(
            row_obj,
            [
                "DOCUMENT_JSON",
                "document_json",
                "documentJson",
            ],
        )
        doc, parsed_doc = self._profile_query_json_dict_from_row_value(doc_value) if doc_found else ({}, False)
        if not parsed_doc:
            return None, False
        if path_text.lower().startswith("document_json."):
            path_text = path_text[len("DOCUMENT_JSON."):]
        value, found = self._extract_row_value_by_path(doc, path_text)
        if not found and path_text in doc:
            value = doc.get(path_text)
            found = True
        return value, found

    def _profile_query_set_where_row_matches(
        self,
        row_obj: Dict[str, Any],
        op_cfg: Dict[str, Any],
    ) -> Optional[bool]:
        if not isinstance(row_obj, dict) or not isinstance(op_cfg, dict):
            return None
        if str(op_cfg.get("op") or "").strip().lower() != "set_where":
            return None
        where_field = str(op_cfg.get("where_field") or "").strip()
        if not where_field:
            return None
        where_value_mode = str(op_cfg.get("where_value_mode") or "row").strip().lower()
        if where_value_mode != "fixed":
            return None
        where_value = self._profile_query_coerce_patch_value_literal(op_cfg.get("where_value"))
        left_value, left_found = self._profile_query_extract_row_or_document_path(row_obj, where_field)
        if not left_found:
            return None
        return bool(self._flow_condition_eval_operator(left_value, "equals", where_value, False))

    def _profile_query_patch_ops_can_apply_to_row(
        self,
        row_obj: Dict[str, Any],
        patch_ops: List[Dict[str, Any]],
    ) -> bool:
        saw_conclusive_where = False
        for op_cfg in patch_ops or []:
            if not isinstance(op_cfg, dict):
                continue
            if str(op_cfg.get("op") or "set").strip().lower() != "set_where":
                return True
            where_match = self._profile_query_set_where_row_matches(row_obj, op_cfg)
            if where_match is None:
                return True
            saw_conclusive_where = True
            if where_match:
                return True
        return not saw_conclusive_where

    def _profile_query_oracle_partial_update_enabled(self, config: Dict[str, Any]) -> bool:
        raw_value = (
            (config or {}).get("profile_patch_oracle_partial_update_enabled")
            if isinstance(config, dict)
            else None
        )
        if raw_value is None and isinstance(config, dict):
            raw_value = (config or {}).get("profile_patch_oracle_partial_update")
        if raw_value is None:
            raw_value = os.getenv("PROFILE_PATCH_ORACLE_PARTIAL_UPDATE_ENABLED", "true")
        return self._parse_bool_like(raw_value, True)

    def _profile_query_oracle_full_document_fallback_enabled(self, config: Dict[str, Any]) -> bool:
        raw_value = None
        if isinstance(config, dict):
            raw_value = config.get("profile_patch_oracle_full_document_fallback")
            if raw_value is None:
                raw_value = config.get("profile_patch_oracle_fallback")
        if raw_value is None:
            raw_value = os.getenv("PROFILE_PATCH_ORACLE_FULL_DOCUMENT_FALLBACK", "true")
        return self._parse_bool_like(raw_value, True)

    def _profile_query_oracle_json_transform_path(self, raw_path: Any) -> str:
        path_text = self._normalize_json_path_expr(str(raw_path or "").strip())
        if path_text.lower().startswith("document_json."):
            path_text = path_text[len("DOCUMENT_JSON."):]
        tokens = self._split_profile_path(path_text)
        if not tokens:
            return ""
        path_parts: List[str] = []
        for token in tokens:
            if not isinstance(token, str):
                return ""
            part = str(token or "").strip()
            if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", part):
                return ""
            path_parts.append(part)
        return "$." + ".".join(path_parts) if path_parts else ""

    def _profile_query_oracle_partial_bind_scalar(
        self,
        raw_value: Any,
        *,
        numeric: bool = False,
    ) -> Tuple[Any, bool]:
        value = self._json_safe_value(raw_value)
        if numeric:
            number_value = self._profile_query_coerce_numeric_value(value)
            if number_value is None:
                return None, False
            return int(number_value) if float(number_value).is_integer() else float(number_value), True
        if value is None or isinstance(value, bool):
            return None, False
        if isinstance(value, int):
            return int(value), True
        if isinstance(value, float):
            if math.isnan(value) or math.isinf(value):
                return None, False
            return float(value), True
        if isinstance(value, str):
            return value, True
        return None, False

    def _profile_query_oracle_partial_where_bind(
        self,
        raw_value: Any,
    ) -> Tuple[str, bool]:
        value = self._json_safe_value(raw_value)
        if value is None or isinstance(value, (dict, list, tuple, set)):
            return "", False
        if isinstance(value, bool):
            return "true" if value else "false", True
        if isinstance(value, float):
            if math.isnan(value) or math.isinf(value):
                return "", False
        return str(value), True

    def _profile_query_oracle_partial_update_sql(
        self,
        table_sql: str,
        patch_ops: List[Dict[str, Any]],
        has_hash_columns: bool,
        require_pipeline_id: bool = True,
    ) -> Tuple[str, List[Dict[str, Any]], str]:
        if not patch_ops:
            return "", [], "patch operations are empty"

        op_specs: List[Dict[str, Any]] = []
        transform_ops: List[str] = []
        where_clauses: List[str] = []
        set_where_count = 0
        seen_targets: set = set()

        for idx, raw_op in enumerate(patch_ops or []):
            if not isinstance(raw_op, dict):
                return "", [], "patch operation is not an object"
            op_cfg = dict(raw_op)
            op_type = str(op_cfg.get("op") or "set").strip().lower()
            if op_type not in {"set", "unset", "inc", "set_where"}:
                return "", [], f"operation {op_type or 'unknown'} requires full-document fallback"

            target_json_path = self._profile_query_oracle_json_transform_path(op_cfg.get("target_path"))
            if not target_json_path:
                return "", [], "target path is not a simple Oracle JSON object path"
            if target_json_path in seen_targets:
                return "", [], "multiple patch operations target the same JSON path"
            seen_targets.add(target_json_path)

            bind_name = f"patch_value_{idx}"
            spec: Dict[str, Any] = {
                "op": op_type,
                "target_json_path": target_json_path,
                "bind_name": bind_name,
                "op_cfg": op_cfg,
            }
            if op_type == "set":
                transform_ops.append(f"SET '{target_json_path}' = :{bind_name}")
            elif op_type == "unset":
                transform_ops.append(f"REMOVE '{target_json_path}'")
            elif op_type == "inc":
                transform_ops.append(
                    f"SET '{target_json_path}' = "
                    f"COALESCE(JSON_VALUE(DOCUMENT_JSON, '{target_json_path}' RETURNING NUMBER NULL ON ERROR), 0) "
                    f"+ :{bind_name}"
                )
            elif op_type == "set_where":
                set_where_count += 1
                if len(patch_ops) != 1:
                    return "", [], "set_where partial update cannot be mixed with other operations"
                where_json_path = self._profile_query_oracle_json_transform_path(op_cfg.get("where_field"))
                if not where_json_path:
                    return "", [], "set_where field is not a simple Oracle JSON object path"
                where_bind_name = f"where_value_{idx}"
                spec["where_json_path"] = where_json_path
                spec["where_bind_name"] = where_bind_name
                transform_ops.append(f"SET '{target_json_path}' = :{bind_name}")
                where_clauses.append(
                    f"JSON_VALUE(DOCUMENT_JSON, '{where_json_path}' RETURNING VARCHAR2(4000) NULL ON ERROR) "
                    f"= :{where_bind_name}"
                )
            op_specs.append(spec)

        if set_where_count > 1:
            return "", [], "only one set_where operation can use Oracle partial update"

        set_fragments = [
            "DOCUMENT_JSON = JSON_TRANSFORM("
            "NVL(DOCUMENT_JSON, TO_CLOB('{}')), "
            f"{', '.join(transform_ops)} RETURNING CLOB"
            ")",
            "UPDATED_AT = SYSTIMESTAMP",
        ]
        if has_hash_columns:
            set_fragments.append("DOC_SHA1 = NULL")

        key_clauses = []
        if require_pipeline_id:
            key_clauses.append("PIPELINE_ID = :pipeline_id")
        key_clauses.extend(
            [
                "NODE_ID = :node_id",
                "ENTITY_TOKEN = :entity_token",
            ]
        )
        sql = f"UPDATE {table_sql} SET " + ", ".join(set_fragments) + " WHERE " + " AND ".join(key_clauses)
        if where_clauses:
            sql += " AND " + " AND ".join(where_clauses)
        return sql, op_specs, ""

    def _profile_query_oracle_partial_update_binds(
        self,
        rows: List[Any],
        patch_ops: List[Dict[str, Any]],
        op_specs: List[Dict[str, Any]],
        primary_key_field: str,
        default_pipeline_id: str,
        default_node_id: str,
        use_row_pipeline_id: bool = False,
        use_row_node_id: bool = False,
    ) -> Tuple[List[Dict[str, Any]], int, int, str]:
        binds: List[Dict[str, Any]] = []
        skipped_missing_key = 0
        skipped_invalid_patch = 0

        for raw_row in rows or []:
            row_obj = raw_row if isinstance(raw_row, dict) else {"value": raw_row}
            token_value, token_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    primary_key_field,
                    "ENTITY_TOKEN",
                    "entity_token",
                    "entityToken",
                ],
            )
            token = str(token_value).strip() if token_found and token_value is not None else ""
            row_pipeline_value, row_pipeline_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    "PIPELINE_ID",
                    "pipeline_id",
                    "pipelineId",
                ],
            )
            row_node_value, row_node_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    "NODE_ID",
                    "node_id",
                    "nodeId",
                ],
            )
            row_pipeline_id = (
                str(row_pipeline_value).strip()
                if use_row_pipeline_id and row_pipeline_found and row_pipeline_value is not None
                else str(default_pipeline_id or "").strip()
            )
            row_node_id = (
                str(row_node_value).strip()
                if use_row_node_id and row_node_found and row_node_value is not None
                else str(default_node_id or "").strip()
            )
            if not token or not row_pipeline_id or not row_node_id:
                skipped_missing_key += 1
                continue

            bind_row: Dict[str, Any] = {
                "pipeline_id": row_pipeline_id,
                "node_id": row_node_id,
                "entity_token": token,
            }
            row_supported = True
            row_invalid = False
            for spec in op_specs:
                op_cfg = spec.get("op_cfg") if isinstance(spec.get("op_cfg"), dict) else {}
                op_type = str(spec.get("op") or "").strip().lower()
                if op_type == "unset":
                    continue
                patch_value, patch_found = self._profile_query_pick_patch_value(
                    row_obj=row_obj,
                    patch_source_path=str(op_cfg.get("source_path") or "").strip(),
                    patch_target_path=str(op_cfg.get("target_path") or "").strip(),
                    patch_value_mode=str(op_cfg.get("value_mode") or "row").strip().lower(),
                    patch_value_literal=op_cfg.get("value"),
                )
                if not patch_found:
                    row_invalid = True
                    break
                bind_value, scalar_supported = self._profile_query_oracle_partial_bind_scalar(
                    patch_value,
                    numeric=op_type == "inc",
                )
                if not scalar_supported:
                    row_supported = False
                    break
                bind_row[str(spec.get("bind_name"))] = bind_value

                if op_type == "set_where":
                    where_value_mode = str(op_cfg.get("where_value_mode") or "row").strip().lower()
                    if where_value_mode == "fixed":
                        where_value = self._profile_query_coerce_patch_value_literal(op_cfg.get("where_value"))
                        where_found = True
                    else:
                        where_row_path = str(
                            op_cfg.get("where_source_path")
                            or op_cfg.get("where_field")
                            or ""
                        ).strip()
                        where_value, where_found = self._extract_row_value_by_path(row_obj, where_row_path)
                        if not where_found and where_row_path in row_obj:
                            where_value = row_obj.get(where_row_path)
                            where_found = True
                    if not where_found:
                        row_invalid = True
                        break
                    where_bind_value, where_supported = self._profile_query_oracle_partial_where_bind(where_value)
                    if not where_supported:
                        row_supported = False
                        break
                    bind_row[str(spec.get("where_bind_name"))] = where_bind_value

            if not row_supported:
                return [], skipped_missing_key, skipped_invalid_patch, "patch value is not a scalar supported by Oracle partial update"
            if row_invalid:
                skipped_invalid_patch += 1
                continue
            binds.append(bind_row)

        return binds, skipped_missing_key, skipped_invalid_patch, ""

    def _apply_profile_query_patch_updates_oracle_source_partial(
        self,
        rows: List[Any],
        patch_ops: List[Dict[str, Any]],
        config: Dict[str, Any],
        profile_cfg: Dict[str, Any],
        primary_key_field: str,
        default_pipeline_id: str,
        default_node_id: str,
        use_row_pipeline_id: bool = False,
        use_row_node_id: bool = False,
        allow_any_pipeline_id: bool = False,
        warn_cb: Optional[Any] = None,
    ) -> Tuple[int, int, int, str, str]:
        if not self._profile_query_oracle_partial_update_enabled(config):
            return 0, 0, 0, "unsupported", "Oracle partial update is disabled"

        session: Optional[Dict[str, Any]] = None
        cursor = None
        try:
            session = self._open_oracle_profile_session(profile_cfg, require_write_schema=True)
            conn = session.get("conn")
            table_sql = str(session.get("table_sql") or "ETL_PROFILE_STATE")
            column_specs = session.get("column_specs") if isinstance(session.get("column_specs"), dict) else {}
            has_hash_columns = self._oracle_profile_hash_columns_available(column_specs)
            update_sql, op_specs, unsupported_reason = self._profile_query_oracle_partial_update_sql(
                table_sql,
                patch_ops,
                has_hash_columns,
            )
            if unsupported_reason:
                return 0, 0, 0, "unsupported", unsupported_reason

            binds, skipped_missing_key, skipped_invalid_patch, bind_reason = (
                self._profile_query_oracle_partial_update_binds(
                    rows,
                    patch_ops,
                    op_specs,
                    primary_key_field,
                    default_pipeline_id,
                    default_node_id,
                    use_row_pipeline_id=use_row_pipeline_id,
                    use_row_node_id=use_row_node_id,
                )
            )
            if bind_reason:
                return 0, skipped_missing_key, skipped_invalid_patch, "unsupported", bind_reason
            if not binds:
                return 0, skipped_missing_key, skipped_invalid_patch, "applied", ""

            cursor = conn.cursor()
            cursor.executemany(update_sql, binds)
            updated_count = int(cursor.rowcount or 0)
            if updated_count <= 0 and allow_any_pipeline_id:
                update_sql_any_pipeline, _, any_pipeline_reason = self._profile_query_oracle_partial_update_sql(
                    table_sql,
                    patch_ops,
                    has_hash_columns,
                    require_pipeline_id=False,
                )
                if update_sql_any_pipeline and not any_pipeline_reason:
                    any_pipeline_binds = [
                        {key: value for key, value in bind_row.items() if key != "pipeline_id"}
                        for bind_row in binds
                    ]
                    cursor.executemany(update_sql_any_pipeline, any_pipeline_binds)
                    updated_count = int(cursor.rowcount or 0)
            if updated_count <= 0 and callable(warn_cb):
                warn_cb(
                    "Profile Query Oracle partial update matched zero rows: "
                    f"bind_rows={len(binds)}, target_node_id={default_node_id or 'missing'}, "
                    f"target_pipeline_id={default_pipeline_id or 'missing'}, "
                    f"use_row_pipeline_id={str(bool(use_row_pipeline_id)).lower()}, "
                    f"use_row_node_id={str(bool(use_row_node_id)).lower()}, "
                    f"allow_any_pipeline_id={str(bool(allow_any_pipeline_id)).lower()}."
                )
            self._close_oracle_profile_session(session, commit=True)
            session = None
            return updated_count, skipped_missing_key, skipped_invalid_patch, "applied", ""
        except Exception as exc:
            try:
                if session is not None:
                    self._close_oracle_profile_session(session, commit=False, rollback_on_error=True)
                    session = None
            except Exception:
                pass
            if callable(warn_cb):
                warn_cb(f"Profile Query Oracle partial update failed: {exc}")
            return 0, 0, 0, "failed", str(exc)
        finally:
            if cursor is not None:
                try:
                    cursor.close()
                except Exception:
                    pass
            if session is not None:
                try:
                    self._close_oracle_profile_session(session, commit=False)
                except Exception:
                    pass

    def _apply_profile_query_patch_updates_lmdb_source(
        self,
        rows: List[Any],
        config: Dict[str, Any],
        lmdb_source_config: Dict[str, Any],
        pipeline_id: str = "",
        target_node_id: str = "",
        warn_cb: Optional[Any] = None,
    ) -> Tuple[int, int, int]:
        if lmdb is None:
            if callable(warn_cb):
                warn_cb("Profile Query patch skipped: LMDB dependency is unavailable.")
            return 0, 0, 0
        if not isinstance(rows, list) or not rows:
            return 0, 0, 0

        raw_path = (
            lmdb_source_config.get("env_path")
            or lmdb_source_config.get("file_path")
            or lmdb_source_config.get("path")
            or ""
        )
        env_path = self._resolve_lmdb_env_path(str(raw_path))
        db_name = str(lmdb_source_config.get("db_name", "") or "").strip()
        value_format = str(lmdb_source_config.get("value_format", "auto") or "auto").strip().lower() or "auto"
        try:
            max_dbs = int(lmdb_source_config.get("max_dbs", 16) or 16)
        except Exception:
            max_dbs = 16
        max_dbs = max(1, min(max_dbs, 256))

        patch_ops = self._normalize_profile_query_patch_operations(config)
        if not patch_ops:
            if callable(warn_cb):
                warn_cb("Profile Query direct LMDB patch skipped: patch operations are empty.")
            return 0, 0, 0
        primary_key_field = str(config.get("profile_patch_primary_key_field") or "").strip()

        updated_rows = 0
        skipped_missing_key = 0
        skipped_invalid_patch = 0
        env = None
        try:
            map_size = self._lmdb_write_map_size_for_patch(
                env_path,
                {**dict(lmdb_source_config or {}), **dict(config or {})},
            )
            env = lmdb.open(
                env_path,
                readonly=False,
                lock=True,
                readahead=False,
                map_size=map_size,
                max_dbs=max_dbs,
                subdir=True,
            )
            dbi = None
            if db_name:
                dbi = env.open_db(db_name.encode("utf-8"), create=False)
            with env.begin(write=True, db=dbi) as txn:
                for raw_row in rows:
                    row_obj = raw_row if isinstance(raw_row, dict) else {"value": raw_row}
                    key_text = str(row_obj.get("lmdb_key") or "").strip()
                    if not key_text and primary_key_field:
                        pk_value, pk_found = self._extract_row_value_by_path(row_obj, primary_key_field)
                        if not pk_found:
                            pk_value = row_obj.get(primary_key_field)
                        key_text = str(pk_value).strip() if pk_value is not None else ""
                    if not key_text:
                        entity_key = str(row_obj.get("lmdb_entity_key") or "").strip()
                        pipeline_key = str(pipeline_id or "").strip()
                        node_key = str(target_node_id or "").strip()
                        if entity_key and pipeline_key and node_key:
                            key_text = self._profile_lmdb_entity_key(
                                pipeline_key,
                                node_key,
                                entity_key,
                            ).decode("utf-8", errors="replace")
                    if not key_text:
                        skipped_missing_key += 1
                        continue

                    key_bytes = key_text.encode("utf-8", errors="replace")
                    current_bytes = txn.get(key_bytes)
                    if current_bytes is None:
                        skipped_missing_key += 1
                        continue

                    current_value, current_kind = self._decode_lmdb_value(current_bytes, value_format)
                    next_value, applied_ops, invalid_ops = self._profile_query_apply_patch_operations_to_lmdb_payload(
                        current_value=current_value,
                        row_obj=row_obj,
                        patch_ops=patch_ops,
                    )
                    if applied_ops <= 0:
                        skipped_invalid_patch += 1
                        continue
                    if invalid_ops > 0:
                        skipped_invalid_patch += invalid_ops

                    preferred_kind = str(row_obj.get("_lmdb_value_kind") or current_kind or "json").strip().lower() or "json"
                    try:
                        encoded = self._encode_lmdb_value_for_patch(next_value, preferred_kind)
                    except Exception:
                        skipped_invalid_patch += 1
                        continue
                    txn.put(key_bytes, encoded)
                    updated_rows += 1
        finally:
            if env is not None:
                try:
                    env.close()
                except Exception:
                    pass
        return updated_rows, skipped_missing_key, skipped_invalid_patch

    def _apply_profile_query_patch_updates_oracle_source(
        self,
        rows: List[Any],
        config: Dict[str, Any],
        oracle_source_config: Dict[str, Any],
        pipeline_id: str = "",
        target_node_id: str = "",
        warn_cb: Optional[Any] = None,
    ) -> Tuple[int, int, int]:
        if not isinstance(rows, list) or not rows:
            return 0, 0, 0

        patch_ops = self._profile_query_patch_ops_for_stored_profile_document(
            self._normalize_profile_query_patch_operations(config),
            strip_document_json=True,
        )
        if not patch_ops:
            if callable(warn_cb):
                warn_cb("Profile Query Oracle patch skipped: patch operations are empty.")
            return 0, 0, 0

        primary_key_field = str(config.get("profile_patch_primary_key_field") or "").strip()
        if not primary_key_field:
            primary_key_field = "ENTITY_TOKEN"

        profile_cfg = self._profile_query_oracle_profile_cfg_from_source_config(oracle_source_config)
        query_node_id = self._profile_query_extract_oracle_source_profile_node_id(oracle_source_config)
        query_pipeline_id = self._profile_query_extract_oracle_source_profile_pipeline_id(oracle_source_config)
        default_node_id = str(query_node_id or target_node_id or "").strip()
        default_pipeline_id = str(query_pipeline_id or pipeline_id or "").strip()
        fallback_enabled = self._profile_query_oracle_full_document_fallback_enabled(config)
        default_use_row_pipeline_id = (
            not bool(query_pipeline_id)
            and self._profile_query_rows_have_first_value(
                rows,
                [
                    "PIPELINE_ID",
                    "pipeline_id",
                    "pipelineId",
                ],
            )
        )
        default_use_row_node_id = (
            not bool(query_node_id)
            and self._profile_query_rows_have_first_value(
                rows,
                [
                    "NODE_ID",
                    "node_id",
                    "nodeId",
                ],
            )
        )
        use_row_pipeline_id = self._parse_bool_like(
            config.get("profile_patch_use_row_pipeline_id"),
            default_use_row_pipeline_id,
        )
        use_row_node_id = self._parse_bool_like(
            config.get("profile_patch_use_row_node_id"),
            default_use_row_node_id,
        )
        allow_any_pipeline_id = self._parse_bool_like(
            config.get("profile_patch_oracle_allow_any_pipeline_id"),
            bool(query_node_id) and not bool(query_pipeline_id) and not bool(use_row_pipeline_id),
        )

        partial_updated_count, partial_missing_key, partial_invalid_patch, partial_status, partial_reason = (
            self._apply_profile_query_patch_updates_oracle_source_partial(
                rows,
                patch_ops,
                config,
                profile_cfg,
                primary_key_field,
                default_pipeline_id,
                default_node_id,
                use_row_pipeline_id=use_row_pipeline_id,
                use_row_node_id=use_row_node_id,
                allow_any_pipeline_id=allow_any_pipeline_id,
                warn_cb=warn_cb,
            )
        )
        if partial_status == "applied":
            return partial_updated_count, partial_missing_key, partial_invalid_patch
        if not fallback_enabled:
            if callable(warn_cb):
                warn_cb(
                    "Profile Query Oracle full-document fallback disabled; "
                    f"partial update not used ({partial_reason or partial_status})."
                )
            return partial_updated_count, partial_missing_key, partial_invalid_patch
        if callable(warn_cb) and partial_reason:
            warn_cb(
                "Profile Query Oracle partial update unavailable; "
                f"falling back to full-document patch ({partial_reason})."
            )

        docs_by_group: Dict[Tuple[str, str], Dict[str, Dict[str, Any]]] = {}
        meta_by_group: Dict[Tuple[str, str], Dict[str, Dict[str, Any]]] = {}
        changed_by_group: Dict[Tuple[str, str], List[str]] = {}
        skipped_missing_key = 0
        skipped_invalid_patch = 0

        for raw_row in rows:
            row_obj = raw_row if isinstance(raw_row, dict) else {"value": raw_row}
            if not self._profile_query_patch_ops_can_apply_to_row(row_obj, patch_ops):
                continue

            token_value, token_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    primary_key_field,
                    "ENTITY_TOKEN",
                    "entity_token",
                    "entityToken",
                ],
            )
            token = str(token_value).strip() if token_found and token_value is not None else ""
            row_pipeline_value, row_pipeline_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    "PIPELINE_ID",
                    "pipeline_id",
                    "pipelineId",
                ],
            )
            row_node_value, row_node_found = self._profile_query_extract_first_row_value(
                row_obj,
                [
                    "NODE_ID",
                    "node_id",
                    "nodeId",
                ],
            )
            row_pipeline_id = (
                str(row_pipeline_value).strip()
                if use_row_pipeline_id and row_pipeline_found and row_pipeline_value is not None
                else default_pipeline_id
            )
            row_node_id = (
                str(row_node_value).strip()
                if use_row_node_id and row_node_found and row_node_value is not None
                else default_node_id
            )

            if not token or not row_pipeline_id or not row_node_id:
                skipped_missing_key += 1
                continue

            group_key = (row_pipeline_id, row_node_id)
            docs_store = docs_by_group.setdefault(group_key, {})
            meta_store = meta_by_group.setdefault(group_key, {})
            changed_tokens = changed_by_group.setdefault(group_key, [])

            if token in docs_store:
                base_doc = docs_store.get(token) if isinstance(docs_store.get(token), dict) else {}
                base_meta = meta_store.get(token) if isinstance(meta_store.get(token), dict) else {}
            else:
                row_doc, row_meta, row_doc_found = self._profile_query_oracle_source_doc_from_row(row_obj)
                if row_doc_found:
                    base_doc = row_doc
                    base_meta = row_meta
                else:
                    base_doc_loaded, base_meta_loaded = self._load_profile_state_single_entity(
                        row_pipeline_id,
                        row_node_id,
                        token,
                        storage="oracle",
                        profile_cfg=profile_cfg,
                    )
                    base_doc = base_doc_loaded if isinstance(base_doc_loaded, dict) else {}
                    base_meta = base_meta_loaded if isinstance(base_meta_loaded, dict) else {}

            next_doc, applied_ops, invalid_ops = self._profile_query_apply_patch_operations_to_doc(
                base_doc,
                row_obj,
                patch_ops,
            )
            if applied_ops <= 0:
                skipped_invalid_patch += 1
                continue
            if invalid_ops > 0:
                skipped_invalid_patch += invalid_ops

            docs_store[token] = next_doc if isinstance(next_doc, dict) else {}
            meta_store[token] = base_meta if isinstance(base_meta, dict) else {}
            if token not in changed_tokens:
                changed_tokens.append(token)

        updated_count = 0
        for (group_pipeline_id, group_node_id), changed_tokens in changed_by_group.items():
            if not changed_tokens:
                continue
            node_state = {
                "documents": docs_by_group.get((group_pipeline_id, group_node_id), {}),
                "meta": meta_by_group.get((group_pipeline_id, group_node_id), {}),
                "stats": {
                    "profile_query_patch_updated_at": datetime.utcnow().isoformat(),
                    "profile_query_patch_updated_count": len(changed_tokens),
                },
            }
            persisted = self._save_profile_state_single_node_by_storage(
                group_pipeline_id,
                group_node_id,
                node_state,
                changed_tokens=changed_tokens,
                storage="oracle",
                profile_cfg=profile_cfg,
            )
            if persisted:
                updated_count += len(changed_tokens)
            elif callable(warn_cb):
                warn_cb(
                    "Profile Query Oracle patch failed to persist updates "
                    f"(pipeline={group_pipeline_id}, node={group_node_id}, updated={len(changed_tokens)})."
                )

        return updated_count, skipped_missing_key, skipped_invalid_patch

    def _apply_profile_query_patch_updates(
        self,
        pre_rows: List[Any],
        post_rows: List[Any],
        config: Dict[str, Any],
        execution_context: Dict[str, Any],
        warn_cb: Optional[Any] = None,
    ) -> None:
        safe_cfg = dict(config) if isinstance(config, dict) else {}
        enabled = self._parse_bool_like(safe_cfg.get("profile_patch_enabled"), False)
        if not enabled:
            return

        pipeline_id = str(execution_context.get("pipeline_id") or "").strip() if isinstance(execution_context, dict) else ""
        if not pipeline_id:
            if callable(warn_cb):
                warn_cb("Profile Query patch skipped: missing pipeline context.")
            return

        patch_stage = str(safe_cfg.get("profile_patch_stage") or "post").strip().lower()
        source_rows = pre_rows if patch_stage == "pre" else post_rows
        if not isinstance(source_rows, list) or len(source_rows) <= 0:
            return

        storage = self._normalize_profile_storage(safe_cfg.get("profile_patch_storage", "lmdb"))
        target_node_id = str(
            safe_cfg.get("profile_patch_node_id")
            or execution_context.get("node_id")
            or ""
        ).strip()
        if not target_node_id:
            if callable(warn_cb):
                warn_cb("Profile Query patch skipped: target profile node is empty.")
            return

        target_node = self._profile_query_get_pipeline_node_payload(execution_context, target_node_id)
        target_node_data = target_node.get("data") if isinstance(target_node, dict) else None
        target_node_type = str(
            target_node_data.get("nodeType")
            if isinstance(target_node_data, dict)
            else ""
        ).strip().lower()
        target_node_config = (
            target_node_data.get("config")
            if isinstance(target_node_data, dict) and isinstance(target_node_data.get("config"), dict)
            else {}
        )
        if not isinstance(target_node_config, dict):
            target_node_config = {}

        if target_node_type == "lmdb_source":
            updated_count, skipped_missing_key, skipped_invalid_patch = self._apply_profile_query_patch_updates_lmdb_source(
                source_rows,
                safe_cfg,
                target_node_config,
                pipeline_id=pipeline_id,
                target_node_id=target_node_id,
                warn_cb=warn_cb,
            )
            if (
                updated_count <= 0
                and patch_stage == "post"
                and isinstance(pre_rows, list)
                and len(pre_rows) > 0
                and pre_rows is not source_rows
            ):
                updated_count, skipped_missing_key, skipped_invalid_patch = self._apply_profile_query_patch_updates_lmdb_source(
                    pre_rows,
                    safe_cfg,
                    target_node_config,
                    pipeline_id=pipeline_id,
                    target_node_id=target_node_id,
                    warn_cb=warn_cb,
                )
            if updated_count <= 0:
                if callable(warn_cb):
                    warn_cb(
                        "Profile Query direct LMDB patch skipped: "
                        f"updated=0, missing_key={skipped_missing_key}, invalid_patch={skipped_invalid_patch}."
                    )
                return
            if callable(warn_cb) and (skipped_missing_key > 0 or skipped_invalid_patch > 0):
                warn_cb(
                    "Profile Query direct LMDB patch completed with skips: "
                    f"updated={updated_count}, missing_key={skipped_missing_key}, invalid_patch={skipped_invalid_patch}."
                )
            return

        if target_node_type == "oracle_source" and storage == "oracle":
            updated_count, skipped_missing_key, skipped_invalid_patch = self._apply_profile_query_patch_updates_oracle_source(
                source_rows,
                safe_cfg,
                target_node_config,
                pipeline_id=pipeline_id,
                target_node_id=target_node_id,
                warn_cb=warn_cb,
            )
            if (
                updated_count <= 0
                and patch_stage == "post"
                and isinstance(pre_rows, list)
                and len(pre_rows) > 0
                and pre_rows is not source_rows
            ):
                updated_count, skipped_missing_key, skipped_invalid_patch = self._apply_profile_query_patch_updates_oracle_source(
                    pre_rows,
                    safe_cfg,
                    target_node_config,
                    pipeline_id=pipeline_id,
                    target_node_id=target_node_id,
                    warn_cb=warn_cb,
                )
            if updated_count <= 0:
                if callable(warn_cb):
                    warn_cb(
                        "Profile Query Oracle patch skipped: "
                        f"updated=0, missing_key={skipped_missing_key}, invalid_patch={skipped_invalid_patch}."
                    )
                return
            if callable(warn_cb) and (skipped_missing_key > 0 or skipped_invalid_patch > 0):
                warn_cb(
                    "Profile Query Oracle patch completed with skips: "
                    f"updated={updated_count}, missing_key={skipped_missing_key}, invalid_patch={skipped_invalid_patch}."
                )
            return

        primary_key_field = str(safe_cfg.get("profile_patch_primary_key_field") or "").strip()
        if not primary_key_field:
            if callable(warn_cb):
                warn_cb("Profile Query patch skipped: primary key field is empty.")
            return

        patch_ops = self._profile_query_patch_ops_for_stored_profile_document(
            self._normalize_profile_query_patch_operations(safe_cfg),
            strip_document_json=storage == "oracle",
        )
        if not patch_ops:
            if callable(warn_cb):
                warn_cb("Profile Query patch skipped: patch operations are empty.")
            return

        profile_cfg: Optional[Dict[str, Any]] = None
        if storage == "oracle":
            node_config = target_node_config if isinstance(target_node_config, dict) else {}
            profile_cfg = {
                "custom_profile_oracle_host": node_config.get("custom_profile_oracle_host"),
                "custom_profile_oracle_port": node_config.get("custom_profile_oracle_port"),
                "custom_profile_oracle_service_name": node_config.get("custom_profile_oracle_service_name"),
                "custom_profile_oracle_sid": node_config.get("custom_profile_oracle_sid"),
                "custom_profile_oracle_user": node_config.get("custom_profile_oracle_user"),
                "custom_profile_oracle_password": node_config.get("custom_profile_oracle_password"),
                "custom_profile_oracle_dsn": node_config.get("custom_profile_oracle_dsn"),
                "custom_profile_oracle_table": node_config.get("custom_profile_oracle_table"),
                "custom_profile_oracle_write_strategy": node_config.get("custom_profile_oracle_write_strategy"),
                "custom_profile_oracle_parallel_workers": node_config.get("custom_profile_oracle_parallel_workers"),
                "custom_profile_oracle_parallel_min_tokens": node_config.get("custom_profile_oracle_parallel_min_tokens"),
                "custom_profile_oracle_merge_batch_size": node_config.get("custom_profile_oracle_merge_batch_size"),
                "custom_profile_oracle_parallel_force": node_config.get("custom_profile_oracle_parallel_force"),
            }

        def _collect_patch_changes(
            rows_to_patch: List[Any],
        ) -> Tuple[Dict[str, Dict[str, Any]], Dict[str, Dict[str, Any]], List[str], int, int]:
            docs_store_local: Dict[str, Dict[str, Any]] = {}
            meta_store_local: Dict[str, Dict[str, Any]] = {}
            changed_tokens_local: List[str] = []
            skipped_missing_key_local = 0
            skipped_invalid_patch_local = 0

            for idx, row in enumerate(rows_to_patch):
                if idx == 0 or idx % 500 == 0:
                    # no-op cancel check guard by caller context; keep loop lightweight.
                    pass
                row_obj = row if isinstance(row, dict) else {"value": row}
                pk_value, pk_found = self._extract_row_value_by_path(row_obj, primary_key_field)
                if not pk_found:
                    pk_value = row_obj.get(primary_key_field)
                token = str(pk_value).strip() if pk_value is not None else ""
                if not token:
                    skipped_missing_key_local += 1
                    continue

                if token in docs_store_local:
                    base_doc = docs_store_local.get(token) if isinstance(docs_store_local.get(token), dict) else {}
                    base_meta = meta_store_local.get(token) if isinstance(meta_store_local.get(token), dict) else {}
                else:
                    base_doc_loaded, base_meta_loaded = self._load_profile_state_single_entity(
                        pipeline_id,
                        target_node_id,
                        token,
                        storage=storage,
                        profile_cfg=profile_cfg,
                    )
                    base_doc = base_doc_loaded if isinstance(base_doc_loaded, dict) else {}
                    base_meta = base_meta_loaded if isinstance(base_meta_loaded, dict) else {}

                next_doc, applied_ops, invalid_ops = self._profile_query_apply_patch_operations_to_doc(
                    base_doc,
                    row_obj,
                    patch_ops,
                )
                if applied_ops <= 0:
                    skipped_invalid_patch_local += 1
                    continue
                if invalid_ops > 0:
                    skipped_invalid_patch_local += invalid_ops

                current_pk, current_pk_found = self._extract_row_value_by_path(next_doc, primary_key_field)
                if (not current_pk_found) or current_pk is None or str(current_pk).strip() == "":
                    self._set_profile_path_value(next_doc, primary_key_field, self._json_safe_value(pk_value))

                docs_store_local[token] = next_doc if isinstance(next_doc, dict) else {}
                meta_store_local[token] = base_meta if isinstance(base_meta, dict) else {}
                if token not in changed_tokens_local:
                    changed_tokens_local.append(token)

            return (
                docs_store_local,
                meta_store_local,
                changed_tokens_local,
                skipped_missing_key_local,
                skipped_invalid_patch_local,
            )

        docs_store, meta_store, changed_tokens, skipped_missing_key, skipped_invalid_patch = _collect_patch_changes(source_rows)
        if (
            not changed_tokens
            and patch_stage == "post"
            and isinstance(pre_rows, list)
            and len(pre_rows) > 0
            and pre_rows is not source_rows
        ):
            (
                docs_store,
                meta_store,
                changed_tokens,
                skipped_missing_key,
                skipped_invalid_patch,
            ) = _collect_patch_changes(pre_rows)

        if not changed_tokens:
            if skipped_missing_key > 0 and callable(warn_cb):
                warn_cb(
                    "Profile Query patch skipped all rows: missing key value for "
                    f"'{primary_key_field}' (rows={skipped_missing_key})."
                )
            return

        node_state = {
            "documents": docs_store,
            "meta": meta_store,
            "stats": {
                "profile_query_patch_updated_at": datetime.utcnow().isoformat(),
                "profile_query_patch_updated_count": len(changed_tokens),
            },
        }
        persisted = self._save_profile_state_single_node_by_storage(
            pipeline_id,
            target_node_id,
            node_state,
            changed_tokens=changed_tokens,
            storage=storage,
            profile_cfg=profile_cfg,
        )
        if not persisted and callable(warn_cb):
            warn_cb(
                "Profile Query patch failed to persist updates to "
                f"{storage} (node={target_node_id}, updated={len(changed_tokens)})."
            )
        elif callable(warn_cb) and skipped_invalid_patch > 0:
            warn_cb(
                "Profile Query patch completed with skipped rows: "
                f"invalid patch payload rows={skipped_invalid_patch}."
            )

    def _flow_condition_split(self, data: list, config: dict) -> tuple[list, list]:
        rows = data if isinstance(data, list) else []
        if not rows:
            return [], []
        true_rows: list = []
        false_rows: list = []
        for row in rows:
            try:
                matched = self._flow_condition_match_row(row, config)
            except Exception:
                matched = False
            if matched:
                true_rows.append(row)
            else:
                false_rows.append(row)
        return true_rows, false_rows

    def _normalize_condition_case_handle_id(self, route_id: Any) -> str:
        import re
        raw = str(route_id or "").strip().lower()
        safe = re.sub(r"[^a-z0-9_]+", "_", raw).strip("_")
        if not safe:
            safe = "route"
        return f"case_{safe}"

    def _flow_condition_case_routes_split(self, data: list, config: dict) -> Dict[str, list]:
        rows = data if isinstance(data, list) else []
        result: Dict[str, list] = {
            "output": [],
            "output_false": [],
        }
        if not rows or not isinstance(config, dict):
            return result

        raw_routes = config.get("case_routes")
        if isinstance(raw_routes, str):
            try:
                raw_routes = json.loads(raw_routes)
            except Exception:
                raw_routes = []
        if not isinstance(raw_routes, list):
            raw_routes = []

        def _to_num(v: Any) -> Optional[float]:
            try:
                if v is None:
                    return None
                if isinstance(v, bool):
                    return float(int(v))
                if isinstance(v, (int, float)):
                    return float(v)
                txt = str(v).strip().replace(",", "")
                if txt == "":
                    return None
                return float(txt)
            except Exception:
                return None

        def _normalize_case_condition(raw_condition: Any, fallback_id: str) -> Optional[Dict[str, Any]]:
            if not isinstance(raw_condition, dict):
                return None
            field_name = str(raw_condition.get("field") or raw_condition.get("leftField") or "").strip()
            if not field_name:
                return None
            condition_mode = str(
                raw_condition.get("match_mode")
                or raw_condition.get("matchMode")
                or raw_condition.get("mode")
                or "range"
            ).strip().lower()
            if condition_mode not in {"range", "condition"}:
                condition_mode = "range"
            operator = str(raw_condition.get("operator") or "equals").strip().lower() or "equals"
            right_mode = str(raw_condition.get("right_mode") or raw_condition.get("rightMode") or "literal").strip().lower()
            if right_mode not in {"literal", "field"}:
                right_mode = "literal"
            right_value = raw_condition.get("right_value")
            if right_value is None:
                right_value = raw_condition.get("rightValue")
            min_raw = raw_condition.get("min_value")
            if min_raw is None:
                min_raw = raw_condition.get("minValue")
            max_raw = raw_condition.get("max_value")
            if max_raw is None:
                max_raw = raw_condition.get("maxValue")
            include_min = raw_condition.get("include_min")
            if include_min is None:
                include_min = raw_condition.get("includeMin")
            include_max = raw_condition.get("include_max")
            if include_max is None:
                include_max = raw_condition.get("includeMax")

            min_num = _to_num(min_raw)
            max_num = _to_num(max_raw)
            if min_num is not None and max_num is not None and min_num > max_num:
                min_num, max_num = max_num, min_num

            return {
                "id": str(raw_condition.get("id") or fallback_id).strip() or fallback_id,
                "field": field_name,
                "match_mode": condition_mode,
                "operator": operator,
                "right_mode": right_mode,
                "right_value": right_value,
                "min_num": min_num,
                "max_num": max_num,
                "include_min": bool(True if include_min is None else include_min),
                "include_max": bool(True if include_max is None else include_max),
            }

        normalized_routes: List[Dict[str, Any]] = []
        for index, item in enumerate(raw_routes):
            if not isinstance(item, dict):
                continue
            route_id = str(item.get("id") or f"route_{index + 1}").strip() or f"route_{index + 1}"
            handle_id = str(item.get("handle_id") or self._normalize_condition_case_handle_id(route_id)).strip()
            if not handle_id:
                handle_id = self._normalize_condition_case_handle_id(route_id)
            route_match_mode = str(
                item.get("route_match_mode")
                or item.get("criteria_mode")
                or item.get("logic")
                or item.get("join")
                or "all"
            ).strip().lower()
            if route_match_mode not in {"all", "any"}:
                route_match_mode = "all"

            raw_conditions = item.get("conditions")
            if isinstance(raw_conditions, str):
                try:
                    raw_conditions = json.loads(raw_conditions)
                except Exception:
                    raw_conditions = []
            conditions: List[Dict[str, Any]] = []
            if isinstance(raw_conditions, list):
                for cond_idx, raw_cond in enumerate(raw_conditions):
                    normalized_cond = _normalize_case_condition(raw_cond, f"cond_{route_id}_{cond_idx + 1}")
                    if normalized_cond:
                        conditions.append(normalized_cond)
            if not conditions:
                # Backward compatibility: single-condition route stored at root level.
                legacy_cond = _normalize_case_condition(item, f"cond_{route_id}_1")
                if legacy_cond:
                    conditions.append(legacy_cond)
            if not conditions:
                continue

            normalized_routes.append({
                "id": route_id,
                "handle_id": handle_id,
                "route_match_mode": route_match_mode,
                "conditions": conditions,
            })
            result.setdefault(handle_id, [])

        if not normalized_routes:
            result["output_false"] = list(rows)
            return result

        for row in rows:
            row_obj = row if isinstance(row, dict) else {"value": row}
            matched = False
            for route in normalized_routes:
                route_conditions = route.get("conditions") if isinstance(route.get("conditions"), list) else []
                if not route_conditions:
                    continue
                condition_outcomes: List[bool] = []
                for cond in route_conditions:
                    if not isinstance(cond, dict):
                        continue
                    field_name = str(cond.get("field") or "").strip()
                    if not field_name:
                        condition_outcomes.append(False)
                        continue
                    left_value, found = self._extract_row_value_by_path(row_obj, field_name)
                    if not found:
                        left_value = row_obj.get(field_name)
                    cond_mode = str(cond.get("match_mode") or "range").strip().lower()
                    matched_condition = False
                    if cond_mode == "condition":
                        right_mode = str(cond.get("right_mode") or "literal").strip().lower()
                        right_value = cond.get("right_value")
                        if right_mode == "field":
                            ref_path = str(right_value or "").strip()
                            if ref_path:
                                ref_value, ref_found = self._extract_row_value_by_path(row_obj, ref_path)
                                if ref_found:
                                    right_value = ref_value
                                else:
                                    right_value = row_obj.get(ref_path)
                        case_sensitive = bool(config.get("case_sensitive", False))
                        matched_condition = self._flow_condition_eval_operator(
                            left_value,
                            str(cond.get("operator") or "equals"),
                            right_value,
                            case_sensitive,
                        )
                    else:
                        left_candidates = list(left_value) if isinstance(left_value, (list, tuple, set)) else [left_value]
                        min_num = cond.get("min_num")
                        max_num = cond.get("max_num")
                        include_min = bool(cond.get("include_min", True))
                        include_max = bool(cond.get("include_max", True))
                        matched_condition = False
                        for candidate in left_candidates:
                            try:
                                left_num = float(str(candidate).strip().replace(",", ""))
                            except Exception:
                                left_num = None
                            if left_num is None:
                                continue
                            within = True
                            if min_num is not None:
                                if include_min:
                                    if left_num < float(min_num):
                                        within = False
                                elif left_num <= float(min_num):
                                    within = False
                            if within and max_num is not None:
                                if include_max:
                                    if left_num > float(max_num):
                                        within = False
                                elif left_num >= float(max_num):
                                    within = False
                            if within:
                                matched_condition = True
                                break
                    condition_outcomes.append(bool(matched_condition))

                if not condition_outcomes:
                    continue
                route_logic = str(route.get("route_match_mode") or "all").strip().lower()
                matched_route = any(condition_outcomes) if route_logic == "any" else all(condition_outcomes)
                if not matched_route:
                    continue

                handle_id = str(route.get("handle_id") or "").strip() or "output"
                result.setdefault(handle_id, []).append(row)
                result.setdefault("output", []).append(row)
                matched = True
                break

            if not matched:
                result.setdefault("output_false", []).append(row)

        return result

    def _flow_condition_match_row(self, row: Any, config: dict) -> bool:
        if not isinstance(config, dict):
            return True

        raw_rules = config.get("criteria")
        if raw_rules is None:
            raw_rules = config.get("conditions")
        if isinstance(raw_rules, str):
            try:
                parsed_rules = json.loads(raw_rules)
                raw_rules = parsed_rules
            except Exception:
                raw_rules = []
        if not isinstance(raw_rules, list):
            raw_rules = []

        rules: List[Dict[str, Any]] = []
        for item in raw_rules:
            if not isinstance(item, dict):
                continue
            field_name = str(item.get("field") or item.get("leftField") or "").strip()
            operator = str(item.get("operator") or "equals").strip().lower() or "equals"
            right_mode = str(item.get("rightMode") or item.get("right_mode") or "literal").strip().lower() or "literal"
            right_raw = item.get("value")
            if right_raw is None:
                right_raw = item.get("rightValue")
            if right_raw is None:
                right_raw = item.get("right_value")
            if not field_name and operator != "raw":
                continue
            rules.append({
                "field": field_name,
                "operator": operator,
                "right_mode": right_mode,
                "right_value": right_raw,
            })

        if not rules:
            legacy_field = str(config.get("field") or "").strip()
            if not legacy_field:
                return True
            rules = [{
                "field": legacy_field,
                "operator": str(config.get("operator") or "equals").strip().lower() or "equals",
                "right_mode": "literal",
                "right_value": config.get("value"),
            }]

        match_mode = str(config.get("criteria_mode") or config.get("match_mode") or "all").strip().lower()
        if match_mode not in {"all", "any"}:
            match_mode = "all"
        case_sensitive = bool(config.get("case_sensitive", False))

        outcomes: List[bool] = []
        for rule in rules:
            field_name = str(rule.get("field") or "").strip()
            operator = str(rule.get("operator") or "equals").strip().lower() or "equals"
            right_mode = str(rule.get("right_mode") or "literal").strip().lower() or "literal"
            right_value = rule.get("right_value")
            left_value: Any = None
            left_found = False
            if isinstance(row, dict):
                if field_name in row:
                    left_value = row.get(field_name)
                    left_found = True
                elif field_name:
                    left_value, left_found = self._extract_row_value_by_path(row, field_name)
            if not left_found:
                left_value = None

            if operator == "raw":
                outcomes.append(bool(right_value))
                continue

            if right_mode == "field":
                ref_path = str(right_value or "").strip()
                if isinstance(row, dict) and ref_path:
                    ref_value, ref_found = self._extract_row_value_by_path(row, ref_path)
                    if ref_found:
                        right_value = ref_value
                    else:
                        right_value = row.get(ref_path)

            outcomes.append(self._flow_condition_eval_operator(left_value, operator, right_value, case_sensitive))

        if not outcomes:
            return True
        if match_mode == "any":
            return any(outcomes)
        return all(outcomes)

    def _flow_condition_eval_operator(
        self,
        left_value: Any,
        operator: str,
        right_value: Any,
        case_sensitive: bool = False,
    ) -> bool:
        op = str(operator or "equals").strip().lower() or "equals"
        if op in {"eq", "=="}:
            op = "equals"
        elif op in {"ne", "!="}:
            op = "not_equals"
        elif op in {"gt", ">"}:
            op = "greater_than"
        elif op in {"gte", ">="}:
            op = "greater_or_equal"
        elif op in {"lt", "<"}:
            op = "less_than"
        elif op in {"lte", "<="}:
            op = "less_or_equal"

        def _is_collection(v: Any) -> bool:
            return isinstance(v, (list, tuple, set))

        if _is_collection(left_value) or _is_collection(right_value):
            left_items = list(left_value) if _is_collection(left_value) else [left_value]
            right_items = list(right_value) if _is_collection(right_value) else [right_value]
            if op == "is_null":
                return any(item is None for item in left_items)
            if op == "is_not_null":
                return any(item is not None for item in left_items)
            negative_ops = {"not_equals", "not_contains", "not_in", "not_in_list"}
            if op in negative_ops:
                for lv in left_items:
                    for rv in right_items:
                        if self._flow_condition_eval_operator(lv, op.replace("not_", "", 1), rv, case_sensitive):
                            return False
                return True
            for lv in left_items:
                for rv in right_items:
                    if self._flow_condition_eval_operator(lv, op, rv, case_sensitive):
                        return True
            return False

        if op == "is_null":
            return left_value is None
        if op == "is_not_null":
            return left_value is not None

        def _num(v: Any) -> Optional[float]:
            try:
                if v is None:
                    return None
                if isinstance(v, bool):
                    return float(int(v))
                if isinstance(v, (int, float)):
                    return float(v)
                txt = str(v).strip().replace(",", "")
                if txt == "":
                    return None
                return float(txt)
            except Exception:
                return None

        left_num = _num(left_value)
        right_num = _num(right_value)
        if op in {"greater_than", "greater_or_equal", "less_than", "less_or_equal"}:
            if left_num is None or right_num is None:
                return False
            if op == "greater_than":
                return left_num > right_num
            if op == "greater_or_equal":
                return left_num >= right_num
            if op == "less_than":
                return left_num < right_num
            return left_num <= right_num
        if op == "between":
            if left_num is None:
                return False
            min_num: Optional[float] = None
            max_num: Optional[float] = None
            if isinstance(right_value, (list, tuple)) and len(right_value) >= 2:
                min_num = _num(right_value[0])
                max_num = _num(right_value[1])
            else:
                raw = "" if right_value is None else str(right_value)
                parts = [p.strip() for p in raw.split(",") if p.strip()]
                if len(parts) >= 2:
                    min_num = _num(parts[0])
                    max_num = _num(parts[1])
            if min_num is None or max_num is None:
                return False
            if min_num > max_num:
                min_num, max_num = max_num, min_num
            return min_num <= left_num <= max_num

        left_text = "" if left_value is None else str(left_value)
        right_text = "" if right_value is None else str(right_value)
        left_cmp = left_text if case_sensitive else left_text.lower()
        right_cmp = right_text if case_sensitive else right_text.lower()

        if op == "equals":
            return left_cmp == right_cmp
        if op == "not_equals":
            return left_cmp != right_cmp
        if op == "contains":
            return right_cmp in left_cmp
        if op in {"not_contains"}:
            return right_cmp not in left_cmp
        if op in {"starts_with", "startswith"}:
            return left_cmp.startswith(right_cmp)
        if op in {"ends_with", "endswith"}:
            return left_cmp.endswith(right_cmp)
        if op in {"in", "in_list"}:
            tokens = [t.strip() for t in right_text.split(",") if t.strip()]
            token_cmp = [t if case_sensitive else t.lower() for t in tokens]
            return left_cmp in token_cmp
        if op in {"not_in", "not_in_list"}:
            tokens = [t.strip() for t in right_text.split(",") if t.strip()]
            token_cmp = [t if case_sensitive else t.lower() for t in tokens]
            return left_cmp not in token_cmp

        return left_cmp == right_cmp

    def _parse_selected_fields(self, value: Any) -> List[str]:
        if isinstance(value, list):
            parts = [str(v).strip() for v in value]
        else:
            import re
            parts = [p.strip() for p in re.split(r"[,\n]", str(value or ""))]
        out: List[str] = []
        seen = set()
        for part in parts:
            if not part:
                continue
            key = part.lower()
            if key in seen:
                continue
            seen.add(key)
            out.append(part)
        return out

    def _parse_select_field_sorts(
        self,
        value: Any,
        selected_fields: Optional[List[str]] = None,
    ) -> List[Tuple[str, str]]:
        raw = value
        if isinstance(raw, str):
            text = raw.strip()
            if not text:
                return []
            try:
                raw = json.loads(text)
            except Exception:
                return []

        sort_map: Dict[str, str] = {}

        def _normalize_mode(mode_value: Any) -> str:
            mode = str(mode_value or "").strip().lower()
            if mode in {"asc", "desc"}:
                return mode
            return "none"

        if isinstance(raw, dict):
            for k, v in raw.items():
                path = str(k or "").strip()
                if not path:
                    continue
                mode = _normalize_mode(v)
                if mode in {"asc", "desc"}:
                    sort_map[path] = mode
        elif isinstance(raw, list):
            for item in raw:
                if not isinstance(item, dict):
                    continue
                path = str(
                    item.get("field")
                    or item.get("path")
                    or item.get("name")
                    or ""
                ).strip()
                if not path:
                    continue
                mode = _normalize_mode(
                    item.get("order")
                    or item.get("mode")
                    or item.get("direction")
                    or "none"
                )
                if mode in {"asc", "desc"}:
                    sort_map[path] = mode
        else:
            return []

        if not sort_map:
            return []

        out: List[Tuple[str, str]] = []
        seen = set()
        for field in selected_fields or []:
            path = str(field or "").strip()
            if not path or path in seen:
                continue
            mode = sort_map.get(path)
            if mode in {"asc", "desc"}:
                out.append((path, mode))
                seen.add(path)
        for path, mode in sort_map.items():
            if path in seen:
                continue
            out.append((path, mode))
            seen.add(path)
        return out

    def _parse_select_field_aliases(self, value: Any) -> Dict[str, str]:
        raw = value
        if isinstance(raw, str):
            text = raw.strip()
            if not text:
                return {}
            try:
                raw = json.loads(text)
            except Exception:
                return {}
        if not isinstance(raw, dict):
            return {}
        out: Dict[str, str] = {}
        for k, v in raw.items():
            path = str(k or "").strip()
            alias = str(v or "").strip()
            if not path or not alias:
                continue
            out[path] = alias
        return out

    def _normalize_profile_query_array_output_mode(self, value: Any) -> str:
        mode = str(value or "list").strip().lower()
        if mode in {"explode", "explode_rows", "row", "rows"}:
            return "explode_rows"
        return "list"

    def _normalize_profile_query_array_match_mode(self, value: Any) -> str:
        mode = str(value or "all_elements").strip().lower()
        if mode in {"matched_elements_only", "matched_only", "match_only"}:
            return "matched_elements_only"
        return "all_elements"

    def _profile_query_split_path_segments(self, path: Any) -> List[str]:
        expr = self._normalize_json_path_expr(str(path or ""))
        if not expr:
            return []
        tokenized = re.sub(r"\[(\d+)\]", lambda m: f".#{m.group(1)}", expr)
        tokenized = tokenized.replace("[]", ".#all")
        return [t for t in str(tokenized or "").split(".") if t]

    def _profile_query_tokens_to_path(self, tokens: List[str]) -> str:
        parts: List[str] = []
        for tok in tokens:
            text = str(tok or "").strip()
            if not text:
                continue
            if text.startswith("#"):
                if not parts:
                    continue
                if text == "#all":
                    parts[-1] = f"{parts[-1]}[]"
                else:
                    parts[-1] = f"{parts[-1]}[{text[1:]}]"
                continue
            parts.append(text)
        return ".".join(parts)

    def _profile_query_array_root_and_suffix(self, path: Any) -> Optional[Tuple[str, str]]:
        segments = self._profile_query_split_path_segments(path)
        if not segments:
            return None
        try:
            idx = segments.index("#all")
        except ValueError:
            return None
        root_tokens = segments[:idx]
        if not root_tokens:
            return None
        suffix_tokens = segments[idx + 1 :]
        root_path = self._profile_query_tokens_to_path(root_tokens)
        suffix_path = self._profile_query_tokens_to_path(suffix_tokens)
        if not root_path:
            return None
        return root_path, suffix_path

    def _group_profile_query_rules_by_array_root(self, rules: Any) -> Dict[str, List[Dict[str, Any]]]:
        out: Dict[str, List[Dict[str, Any]]] = {}
        if not isinstance(rules, list):
            return out
        for raw_rule in rules:
            if not isinstance(raw_rule, dict):
                continue
            field_name = str(raw_rule.get("field") or "").strip()
            if not field_name:
                continue
            parsed = self._profile_query_array_root_and_suffix(field_name)
            if not parsed:
                continue
            root_path, _ = parsed
            out.setdefault(root_path, []).append(raw_rule)
        return out

    def _profile_query_pick_object_key(self, obj: Dict[str, Any], segment: str) -> str:
        seg = str(segment or "").strip()
        if seg in obj:
            return seg
        seg_norm = seg.lower()
        for key in obj.keys():
            if str(key or "").strip().lower() == seg_norm:
                return key
        return seg

    def _profile_query_clone_row_with_array_root(
        self,
        row: Dict[str, Any],
        root_path: str,
        items: List[Any],
    ) -> Dict[str, Any]:
        if not isinstance(row, dict):
            return {}
        segments = [seg for seg in self._profile_query_split_path_segments(root_path) if not str(seg).startswith("#")]
        if not segments:
            return dict(row)

        cloned_root: Dict[str, Any] = dict(row)
        clone_cursor: Dict[str, Any] = cloned_root
        source_cursor: Any = row
        for idx, seg in enumerate(segments):
            is_last = idx == len(segments) - 1
            source_obj = source_cursor if isinstance(source_cursor, dict) else {}
            actual_key = self._profile_query_pick_object_key(source_obj, seg)
            if is_last:
                clone_cursor[actual_key] = list(items)
                break
            source_next = source_obj.get(actual_key)
            next_clone: Dict[str, Any]
            if isinstance(source_next, dict):
                next_clone = dict(source_next)
            else:
                next_clone = {}
            clone_cursor[actual_key] = next_clone
            clone_cursor = next_clone
            source_cursor = source_next

        return cloned_root

    def _extract_profile_query_projection_value_matched_arrays(
        self,
        row: Any,
        field_path: str,
        array_rules_by_root: Dict[str, List[Dict[str, Any]]],
        criteria_mode: str,
        case_sensitive: bool,
    ) -> Tuple[Any, bool]:
        if not isinstance(row, dict):
            return self._extract_row_value_by_path(row, field_path)
        parsed = self._profile_query_array_root_and_suffix(field_path)
        if not parsed:
            return self._extract_row_value_by_path(row, field_path)
        root_path, suffix_path = parsed
        root_rules = array_rules_by_root.get(root_path) or []
        if not root_rules:
            return self._extract_row_value_by_path(row, field_path)

        root_items = self._extract_json_path_value(row, f"{root_path}[]")
        if not isinstance(root_items, list):
            return None, False
        if not root_items:
            return None, False

        mode = str(criteria_mode or "all").strip().lower()
        if mode not in {"all", "any"}:
            mode = "all"

        matched_items: List[Any] = []
        for item in root_items:
            probe_row = self._profile_query_clone_row_with_array_root(row, root_path, [item])
            outcomes: List[bool] = []
            for rule in root_rules:
                operator = str(rule.get("operator") or "equals").strip().lower() or "equals"
                right_mode = str(rule.get("right_mode") or "literal").strip().lower() or "literal"
                right_value = rule.get("right_value")
                field_name = str(rule.get("field") or "").strip()
                left_value: Any = None
                left_found = False
                if field_name:
                    left_value, left_found = self._extract_row_value_by_path(probe_row, field_name)
                if not left_found:
                    left_value = None
                if right_mode == "field":
                    ref_path = str(right_value or "").strip()
                    if ref_path:
                        ref_value, ref_found = self._extract_row_value_by_path(probe_row, ref_path)
                        if ref_found:
                            right_value = ref_value
                        else:
                            right_value = probe_row.get(ref_path)
                outcomes.append(self._flow_condition_eval_operator(left_value, operator, right_value, case_sensitive))

            if not outcomes:
                continue
            item_ok = any(outcomes) if mode == "any" else all(outcomes)
            if item_ok:
                matched_items.append(item)

        if not matched_items:
            return None, False

        if not suffix_path:
            return matched_items, True

        out_values: List[Any] = []
        for item in matched_items:
            extracted = self._extract_json_path_value(item, suffix_path)
            if isinstance(extracted, list):
                out_values.extend(extracted)
            elif extracted is not None:
                out_values.append(extracted)

        if not out_values:
            return None, False

        deduped: List[Any] = []
        seen = set()
        for value in out_values:
            token = self._stable_json_token(value)
            if token in seen:
                continue
            seen.add(token)
            deduped.append(value)
        return deduped, True

    def _profile_query_sort_scalar(self, value: Any) -> Any:
        if isinstance(value, list):
            if not value:
                return None
            return self._profile_query_sort_scalar(value[0])
        if isinstance(value, tuple):
            if not value:
                return None
            return self._profile_query_sort_scalar(value[0])
        if isinstance(value, dict):
            try:
                return json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
            except Exception:
                return str(value)
        return value

    def _profile_query_compare_values(self, left: Any, right: Any) -> int:
        if left is None and right is None:
            return 0
        if left is None:
            return 1
        if right is None:
            return -1

        left_num = self._to_number(left)
        right_num = self._to_number(right)
        if left_num is not None and right_num is not None:
            if left_num == right_num:
                return 0
            return -1 if left_num < right_num else 1

        left_text = str(left).lower()
        right_text = str(right).lower()
        if left_text == right_text:
            return 0
        return -1 if left_text < right_text else 1

    def _profile_query_sort_rows(
        self,
        rows: List[Any],
        sort_specs: List[Tuple[str, str]],
    ) -> List[Any]:
        if not rows or not sort_specs:
            return rows

        from functools import cmp_to_key

        def _cmp(left_row: Any, right_row: Any) -> int:
            for field_path, mode in sort_specs:
                left_val, left_found = self._extract_row_value_by_path(left_row, field_path)
                right_val, right_found = self._extract_row_value_by_path(right_row, field_path)
                left_scalar = self._profile_query_sort_scalar(left_val if left_found else None)
                right_scalar = self._profile_query_sort_scalar(right_val if right_found else None)
                result = self._profile_query_compare_values(left_scalar, right_scalar)
                if result == 0:
                    continue
                return result if mode == "asc" else -result
            return 0

        try:
            return sorted(rows, key=cmp_to_key(_cmp))
        except Exception:
            return rows

    def _explode_projected_row_arrays(
        self,
        row: Dict[str, Any],
        *,
        array_field_roots: Optional[Dict[str, str]] = None,
        max_combinations: int = 5000,
    ) -> List[Dict[str, Any]]:
        if not isinstance(row, dict):
            return [row]

        def _coerce_list(value: Any) -> Optional[List[Any]]:
            if isinstance(value, list):
                return value
            if isinstance(value, tuple):
                return list(value)
            if isinstance(value, str):
                text = str(value or "").strip()
                if not (text.startswith("[") and text.endswith("]")):
                    return None
                try:
                    parsed_json = json.loads(text)
                    if isinstance(parsed_json, list):
                        return parsed_json
                except Exception:
                    pass
                try:
                    parsed_literal = ast.literal_eval(text)
                    if isinstance(parsed_literal, (list, tuple)):
                        return list(parsed_literal)
                except Exception:
                    return None
            return None

        normalized_row: Dict[str, Any] = dict(row)
        array_fields: List[str] = []
        for key, val in list(normalized_row.items()):
            coerced = _coerce_list(val)
            if coerced is None:
                continue
            normalized_row[key] = coerced
            array_fields.append(key)
        if not array_fields:
            return [row]

        root_map = array_field_roots if isinstance(array_field_roots, dict) else {}
        grouped_fields: Dict[str, List[str]] = {}
        for field_name in array_fields:
            root_path = str(root_map.get(field_name) or "").strip()
            group_key = f"root::{root_path}" if root_path else f"field::{field_name}"
            grouped_fields.setdefault(group_key, []).append(field_name)

        expanded: List[Dict[str, Any]] = [dict(normalized_row)]
        for _, group in grouped_fields.items():
            if len(group) <= 0:
                continue

            next_rows: List[Dict[str, Any]] = []
            if len(group) == 1:
                field_name = group[0]
                values = normalized_row.get(field_name)
                if not isinstance(values, list):
                    continue
                normalized = values if values else [None]
                for base in expanded:
                    for item in normalized:
                        out = dict(base)
                        out[field_name] = item
                        next_rows.append(out)
                        if len(next_rows) >= max_combinations:
                            break
                    if len(next_rows) >= max_combinations:
                        break
            else:
                value_lists: Dict[str, List[Any]] = {}
                max_len = 0
                for field_name in group:
                    vals = normalized_row.get(field_name)
                    arr = list(vals) if isinstance(vals, list) else []
                    if not arr:
                        arr = [None]
                    value_lists[field_name] = arr
                    if len(arr) > max_len:
                        max_len = len(arr)
                if max_len <= 0:
                    max_len = 1
                for base in expanded:
                    for idx in range(max_len):
                        out = dict(base)
                        for field_name in group:
                            arr = value_lists.get(field_name) or [None]
                            out[field_name] = arr[idx] if idx < len(arr) else None
                        next_rows.append(out)
                        if len(next_rows) >= max_combinations:
                            break
                    if len(next_rows) >= max_combinations:
                        break

            expanded = next_rows
            if len(expanded) >= max_combinations:
                break
        return expanded

    def _path_variants(self, field_path: str) -> List[str]:
        import re

        raw = str(field_path or "").strip()
        if not raw:
            return []
        cached = self._path_variants_cache.get(raw)
        if cached is not None:
            return list(cached)
        normalized = self._normalize_json_path_expr(raw)
        if not normalized:
            return []

        variants: List[str] = [normalized]
        parts = [p for p in normalized.split(".") if p]
        for i in range(1, len(parts)):
            variants.append(".".join(parts[i:]))

        stripped = [re.sub(r"\[(?:\d+|\*|)\]", "", v).replace("[]", "") for v in variants]
        variants.extend(stripped)

        deduped: List[str] = []
        seen = set()
        for v in variants:
            text = str(v or "").strip(". ")
            if not text:
                continue
            if text in seen:
                continue
            seen.add(text)
            deduped.append(text)
        if len(self._path_variants_cache) > 4096:
            self._path_variants_cache.clear()
        self._path_variants_cache[raw] = list(deduped)
        return deduped

    def _extract_row_value_by_path(self, row: Any, field_path: str) -> tuple[Any, bool]:
        path = str(field_path or "").strip()
        if not path:
            return None, False
        variants = self._path_variants(path)
        if not variants:
            return None, False

        if isinstance(row, list):
            for variant in variants:
                value = self._extract_json_path_value(row, variant)
                if value is not None:
                    return value, True
            return None, False

        if not isinstance(row, dict):
            return None, False

        # Direct key hit first.
        if path in row:
            return row.get(path), True

        # Fast variant direct-hit path for common flattened schemas.
        for variant in variants:
            if variant in row:
                return row.get(variant), True

        # Build case-insensitive lookup only when exact direct lookup misses.
        row_key_lookup: Dict[str, Any] = {}
        for rk in row.keys():
            key_norm = str(rk or "").strip().lower()
            if key_norm and key_norm not in row_key_lookup:
                row_key_lookup[key_norm] = rk

        direct_norm = path.strip().lower()
        if direct_norm in row_key_lookup:
            return row.get(row_key_lookup[direct_norm]), True

        for variant in variants:
            variant_norm = str(variant or "").strip().lower()
            if variant_norm in row_key_lookup:
                return row.get(row_key_lookup[variant_norm]), True

            # Common flattened-key variant: "a.b.c" => "a_b_c"
            underscored = variant_norm.replace(".", "_")
            if underscored in row_key_lookup:
                return row.get(row_key_lookup[underscored]), True
            value = self._extract_json_path_value(row, variant)
            if value is not None:
                return value, True

        # Common case: user selects root-qualified path (e.g. daily.time)
        # while rows already represent that nested object (key is time).
        import re
        normalized = variants[0] if variants else self._normalize_json_path_expr(path)
        if normalized and "." in normalized:
            leaf = normalized.split(".")[-1]
            leaf = re.sub(r"\[(?:\d+|\*|)\]", "", leaf).replace("[]", "").strip()
            if leaf in row:
                return row.get(leaf), True
            leaf_norm = leaf.lower()
            if leaf_norm in row_key_lookup:
                return row.get(row_key_lookup[leaf_norm]), True

        # If user picked an array container (e.g. items[]) and upstream already
        # flattened to row-level records, keep the current row instead of empty output.
        if normalized and re.search(r"\[(?:\d+|\*|)\]$", normalized):
            return row, True

        return None, False

    def _normalize_single_value_output(self, value: Any) -> str:
        mode = str(value or "").strip().lower()
        if mode in {"plain_text", "text", "plain", "string", "str"}:
            return "plain_text"
        return "json"

    def _apply_single_value_output_mode(self, value: Any, mode: Any) -> Any:
        output_mode = self._normalize_single_value_output(mode)
        safe_value = self._json_safe_value(value)
        if output_mode == "plain_text":
            if safe_value is None:
                return ""
            if isinstance(safe_value, (dict, list)):
                try:
                    return json.dumps(safe_value, ensure_ascii=False)
                except Exception:
                    return str(safe_value)
            return str(safe_value)
        return safe_value

    def _parse_custom_fields_config(self, value: Any) -> List[dict]:
        raw = value
        if isinstance(raw, str):
            text = raw.strip()
            if not text:
                return []
            try:
                raw = json.loads(text)
            except Exception:
                return []
        if not isinstance(raw, list):
            return []

        parsed: List[dict] = []
        seen = set()
        for item in raw:
            if not isinstance(item, dict):
                continue
            name = str(item.get("name") or item.get("field") or "").strip()
            if not name:
                continue
            key = name.lower()
            if key in seen:
                continue
            seen.add(key)

            mode = str(item.get("kind") or item.get("mode") or item.get("type") or "value").strip().lower()
            if mode not in {"value", "json"}:
                mode = "value"

            expression = str(item.get("expression") or item.get("expr") or "").strip()
            json_template = item.get("json_template", item.get("template"))
            single_value_output = self._normalize_single_value_output(
                item.get("single_value_output", item.get("value_output", item.get("output_format")))
            )
            enabled_raw = item.get("enabled", True)
            if isinstance(enabled_raw, bool):
                enabled = enabled_raw
            elif isinstance(enabled_raw, (int, float)):
                enabled = enabled_raw != 0
            elif isinstance(enabled_raw, str):
                norm = enabled_raw.strip().lower()
                if norm in {"0", "false", "no", "off", "n"}:
                    enabled = False
                elif norm in {"1", "true", "yes", "on", "y"}:
                    enabled = True
                else:
                    enabled = True
            else:
                enabled = True
            if not enabled:
                continue

            parsed.append(
                {
                    "name": name,
                    "mode": mode,
                    "single_value_output": single_value_output,
                    "expression": expression,
                    "json_template": json_template,
                }
            )
        return parsed

    def _to_number(self, value: Any) -> Optional[float]:
        if value is None:
            return None
        if isinstance(value, bool):
            return float(int(value))
        if isinstance(value, (int, float)):
            return float(value)
        text = str(value).strip()
        if not text:
            return None
        try:
            return float(text.replace(",", ""))
        except Exception:
            return None

    def _stable_json_token(self, value: Any) -> str:
        if value is None:
            return "null"
        if isinstance(value, bool):
            return "b:1" if value else "b:0"
        if isinstance(value, int):
            return f"i:{value}"
        if isinstance(value, float):
            if math.isnan(value):
                return "f:nan"
            return f"f:{value:.17g}"
        if isinstance(value, str):
            return f"s:{value}"
        if isinstance(value, datetime):
            return f"dt:{value.isoformat()}"
        if isinstance(value, date):
            return f"d:{value.isoformat()}"
        if isinstance(value, time):
            return f"t:{value.isoformat()}"
        try:
            return json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        except Exception:
            return str(value)

    def _json_safe_value(self, value: Any, _depth: int = 0) -> Any:
        if _depth > 8:
            try:
                text = str(value)
            except Exception:
                return None
            return text[:20000] + ("..." if len(text) > 20000 else "")
        if value is None:
            return None
        if isinstance(value, float) and math.isnan(value):
            return None
        if isinstance(value, str):
            text = value
            stripped = text.strip()
            # Preserve large JSON-like payloads for downstream field discovery.
            if (stripped.startswith("{") and stripped.endswith("}")) or (
                stripped.startswith("[") and stripped.endswith("]")
            ):
                if len(text) > 2_000_000:
                    return text[:2_000_000]
                return text
            if len(text) > 200000:
                return text[:200000]
            return text
        if isinstance(value, (int, float, bool)):
            return value

        to_py = getattr(value, "to_pydatetime", None)
        if callable(to_py):
            try:
                value = to_py()
            except Exception:
                pass

        if isinstance(value, (bytes, bytearray, memoryview)):
            try:
                text = bytes(value).decode("utf-8")
                if len(text) > 20000:
                    return text[:20000] + "..."
                return text
            except Exception:
                try:
                    encoded = base64.b64encode(bytes(value)).decode("ascii")
                    if len(encoded) > 20000:
                        encoded = encoded[:20000] + "..."
                    return f"base64:{encoded}"
                except Exception:
                    try:
                        return str(value)
                    except Exception:
                        return None

        # Oracle LOB / stream-like objects
        if hasattr(value, "read"):
            try:
                return self._json_safe_value(value.read(), _depth + 1)
            except Exception:
                try:
                    text = str(value)
                except Exception:
                    return None
                return text[:20000] + ("..." if len(text) > 20000 else "")

        if isinstance(value, datetime):
            if (
                value.hour == 0
                and value.minute == 0
                and value.second == 0
                and value.microsecond == 0
            ):
                return value.date().isoformat()
            return value.strftime("%Y-%m-%d %H:%M:%S")
        if isinstance(value, date):
            return value.isoformat()
        if isinstance(value, time):
            return value.isoformat()
        if isinstance(value, dict):
            return {str(k): self._json_safe_value(v, _depth + 1) for k, v in value.items()}
        if isinstance(value, (list, tuple, set)):
            return [self._json_safe_value(v, _depth + 1) for v in value]
        try:
            text = str(value)
        except Exception:
            return None
        return text[:20000] + ("..." if len(text) > 20000 else "")

    def _split_profile_path(self, path: Any) -> List[Any]:
        import re

        text = str(path or "").strip()
        if not text:
            return []
        cached = self._profile_path_tokens_cache.get(text)
        if cached is not None:
            return cached
        out: List[Any] = []
        for part in text.split("."):
            token = part.strip()
            if not token:
                continue
            pieces = re.findall(r"([^\[\]]+)|\[(\d+)\]", token)
            if not pieces:
                out.append(token)
                continue
            for name, idx in pieces:
                if name:
                    out.append(name)
                elif idx:
                    try:
                        out.append(int(idx))
                    except Exception:
                        out.append(idx)
        if len(self._profile_path_tokens_cache) > 8192:
            self._profile_path_tokens_cache.clear()
        self._profile_path_tokens_cache[text] = out
        return out

    def _get_profile_path_value(self, data: Any, path: Any, default: Any = None) -> Any:
        tokens = self._split_profile_path(path)
        if not tokens:
            return data if data is not None else default

        current = data
        for token in tokens:
            if isinstance(token, int):
                if isinstance(current, list) and 0 <= token < len(current):
                    current = current[token]
                    continue
                return default

            if isinstance(current, dict):
                if token in current:
                    current = current[token]
                    continue
                token_norm = str(token).strip().lower()
                matched_key = None
                for k in current.keys():
                    if str(k).strip().lower() == token_norm:
                        matched_key = k
                        break
                if matched_key is None:
                    return default
                current = current.get(matched_key)
                continue

            return default

        return current if current is not None else default

    def _set_profile_path_value(self, data: Dict[str, Any], path: Any, value: Any) -> None:
        tokens = self._split_profile_path(path)
        if not tokens:
            return

        current: Any = data
        for idx, token in enumerate(tokens):
            is_last = idx == len(tokens) - 1
            next_token = tokens[idx + 1] if not is_last else None

            if isinstance(token, int):
                if not isinstance(current, list):
                    return
                while len(current) <= token:
                    current.append({} if not isinstance(next_token, int) else [])
                if is_last:
                    current[token] = value
                else:
                    nxt = current[token]
                    if isinstance(next_token, int) and not isinstance(nxt, list):
                        nxt = []
                        current[token] = nxt
                    elif not isinstance(next_token, int) and not isinstance(nxt, dict):
                        nxt = {}
                        current[token] = nxt
                    current = nxt
                continue

            key = str(token)
            if not isinstance(current, dict):
                return
            if is_last:
                current[key] = value
                return

            nxt = current.get(key)
            if isinstance(next_token, int):
                if not isinstance(nxt, list):
                    nxt = []
                    current[key] = nxt
            else:
                if not isinstance(nxt, dict):
                    nxt = {}
                    current[key] = nxt
            current = nxt

    def _split_profile_path_with_wildcards(self, path: Any) -> List[Any]:
        text = str(path or "").strip()
        if not text:
            return []
        out: List[Any] = []
        for part in text.split("."):
            token = part.strip()
            if not token:
                continue
            pieces = re.findall(r"([^\[\]]+)|\[(\d*|\*)\]", token)
            if not pieces:
                out.append(token)
                continue
            for name, idx in pieces:
                if name:
                    out.append(name)
                elif idx == "*" or idx == "":
                    out.append("*")
                elif idx:
                    try:
                        out.append(int(idx))
                    except Exception:
                        out.append(idx)
        return out

    def _set_profile_path_value_with_wildcards(self, data: Dict[str, Any], path: Any, value: Any) -> None:
        if not isinstance(data, dict):
            return
        tokens = self._split_profile_path_with_wildcards(path)
        if not tokens:
            return

        def _walk(current: Any, idx: int) -> None:
            token = tokens[idx]
            is_last = idx == len(tokens) - 1
            next_token = tokens[idx + 1] if not is_last else None

            if token == "*":
                if not isinstance(current, list):
                    return
                if is_last:
                    for i in range(len(current)):
                        current[i] = self._json_safe_value(value)
                    return
                for i, item in enumerate(list(current)):
                    child = item
                    if isinstance(next_token, (int, str)) and (next_token == "*" or isinstance(next_token, int)):
                        if not isinstance(child, list):
                            child = []
                            current[i] = child
                    else:
                        if not isinstance(child, dict):
                            child = {}
                            current[i] = child
                    _walk(child, idx + 1)
                return

            if isinstance(token, int):
                if not isinstance(current, list):
                    return
                while len(current) <= token:
                    current.append({} if not (next_token == "*" or isinstance(next_token, int)) else [])
                if is_last:
                    current[token] = self._json_safe_value(value)
                    return
                child = current[token]
                if next_token == "*" or isinstance(next_token, int):
                    if not isinstance(child, list):
                        child = []
                        current[token] = child
                else:
                    if not isinstance(child, dict):
                        child = {}
                        current[token] = child
                _walk(child, idx + 1)
                return

            key = str(token)
            if not isinstance(current, dict):
                return
            if is_last:
                current[key] = self._json_safe_value(value)
                return
            child = current.get(key)
            if next_token == "*" or isinstance(next_token, int):
                if not isinstance(child, list):
                    child = []
                    current[key] = child
            else:
                if not isinstance(child, dict):
                    child = {}
                    current[key] = child
            _walk(child, idx + 1)

        _walk(data, 0)

    def _parse_profile_event_time(self, value: Any) -> Optional[datetime]:
        if value is None:
            return None

        cache = self._profile_event_time_cache
        _missing = object()

        def _cache_get(key: Any) -> Any:
            if key is None:
                return _missing
            return cache.get(key, _missing)

        def _cache_put(key: Any, parsed: Optional[datetime]) -> Optional[datetime]:
            if key is not None:
                if len(cache) > 200000:
                    cache.clear()
                cache[key] = parsed
            return parsed

        to_py = getattr(value, "to_pydatetime", None)
        if callable(to_py):
            try:
                value = to_py()
            except Exception:
                pass

        if isinstance(value, datetime):
            return value
        if isinstance(value, date):
            key = ("d", value.toordinal())
            cached = _cache_get(key)
            if cached is not _missing:
                return cached
            return _cache_put(key, datetime.combine(value, time.min))
        if isinstance(value, (int, float)):
            key = ("n", float(value))
            cached = _cache_get(key)
            if cached is not _missing:
                return cached
            try:
                ts = float(value)
                # Support epoch-millis as well.
                if ts > 1_000_000_000_000:
                    ts = ts / 1000.0
                return _cache_put(key, datetime.utcfromtimestamp(ts))
            except Exception:
                return _cache_put(key, None)
        if isinstance(value, str):
            text = " ".join(value.strip().split())
            if not text:
                return None
            key = ("s", text)
            cached = _cache_get(key)
            if cached is not _missing:
                return cached
            normalized = self._profile_fractional_seconds_re.sub(
                lambda m: "." + m.group(1)[:6].ljust(6, "0"),
                text,
                count=1,
            )
            candidates = [normalized]
            if normalized.endswith("Z"):
                candidates.append(normalized[:-1] + "+00:00")

            formats = (
                "%Y-%m-%d",
                "%Y%m%d",
                "%d-%m-%Y",
                "%d-%m-%y",
                "%d/%m/%Y",
                "%d/%m/%y",
                "%m/%d/%Y",
                "%m/%d/%y",
                "%Y-%m-%d %H:%M:%S",
                "%Y-%m-%d %H:%M:%S.%f",
                "%Y-%d-%m %H:%M:%S",
                "%Y-%d-%m %H:%M:%S.%f",
                "%d-%m-%Y %H:%M:%S",
                "%d-%m-%Y %H:%M:%S.%f",
                "%d-%m-%y %H:%M:%S",
                "%d-%m-%y %H:%M:%S.%f",
                "%d/%m/%Y %H:%M:%S",
                "%d/%m/%Y %H:%M:%S.%f",
                "%d/%m/%y %H:%M:%S",
                "%d/%m/%y %H:%M:%S.%f",
                "%d-%m-%Y %I:%M:%S %p",
                "%d-%m-%Y %I:%M:%S.%f %p",
                "%d-%m-%y %I:%M:%S %p",
                "%d-%m-%y %I:%M:%S.%f %p",
                "%d/%m/%Y %I:%M:%S %p",
                "%d/%m/%Y %I:%M:%S.%f %p",
                "%d/%m/%y %I:%M:%S %p",
                "%d/%m/%y %I:%M:%S.%f %p",
            )
            for candidate in candidates:
                # Fast path for ISO-like strings.
                try:
                    parsed_iso = datetime.fromisoformat(candidate)
                    return _cache_put(key, parsed_iso)
                except Exception:
                    pass
                for fmt in formats:
                    try:
                        return _cache_put(key, datetime.strptime(candidate, fmt))
                    except Exception:
                        continue
        return _cache_put(("s", str(value)), None)

    def _parse_profile_windows(self, value: Any, default_windows: Optional[List[int]] = None) -> List[int]:
        fallback = default_windows if isinstance(default_windows, list) and default_windows else [1, 7, 30]
        raw_parts: List[Any] = []
        if isinstance(value, list):
            raw_parts = list(value)
        elif isinstance(value, tuple):
            raw_parts = list(value)
        elif isinstance(value, (int, float)):
            raw_parts = [value]
        elif isinstance(value, str):
            text = value.strip()
            if text:
                try:
                    parsed = json.loads(text)
                    if isinstance(parsed, list):
                        raw_parts = list(parsed)
                    else:
                        raw_parts = [p.strip() for p in text.replace("\n", ",").split(",")]
                except Exception:
                    raw_parts = [p.strip() for p in text.replace("\n", ",").split(",")]

        out: List[int] = []
        seen = set()
        for item in raw_parts:
            try:
                day = int(float(item))
            except Exception:
                continue
            if day <= 0:
                continue
            if day in seen:
                continue
            seen.add(day)
            out.append(day)
        if not out:
            out = [int(v) for v in fallback if int(v) > 0]
        out.sort()
        return out

    def _build_expression_context(
        self,
        row: Any,
        custom_values: Dict[str, Any],
        dataset_rows: Optional[List[Any]] = None,
        row_index: Optional[int] = None,
        extra_context: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        if isinstance(row, (dict, list)):
            row_scope: Any = row
        else:
            row_scope = {"value": row}
        row_obj = row_scope if isinstance(row_scope, dict) else {}
        group_size = len(row_scope) if isinstance(row_scope, list) else 1

        def _flatten_sequence(values: Any) -> List[Any]:
            if values is None:
                return []
            out: List[Any] = []
            stack = [values]
            while stack:
                current = stack.pop()
                if isinstance(current, (list, tuple, set)):
                    stack.extend(reversed(list(current)))
                    continue
                out.append(current)
            return out

        def _numeric_sequence(values: Any) -> List[float]:
            nums: List[float] = []
            for value in _flatten_sequence(values):
                num = self._to_number(value)
                if num is not None:
                    nums.append(num)
            return nums

        def _looks_date_only_text(text: str) -> bool:
            import re as _re
            t = str(text or "").strip()
            if not t:
                return False
            if _re.fullmatch(r"\d{8}", t):
                return True
            if _re.fullmatch(r"\d{4}-\d{2}-\d{2}", t):
                return True
            if _re.fullmatch(r"\d{2}-\d{2}-\d{2,4}", t):
                return True
            if _re.fullmatch(r"\d{1,2}/\d{1,2}/\d{2,4}", t):
                return True
            return False

        def _parse_temporal_value(value: Any) -> Optional[datetime]:
            # Reuse global parser with cache so repeated temporal tokens in
            # expressions (for example min/max over datetime fields) stay fast.
            return self._parse_profile_event_time(value)

        def _format_temporal_output(value: Any, date_only_hint: bool = False) -> Any:
            to_py = getattr(value, "to_pydatetime", None)
            if callable(to_py):
                try:
                    value = to_py()
                except Exception:
                    pass
            if isinstance(value, datetime):
                is_midnight = (
                    value.hour == 0
                    and value.minute == 0
                    and value.second == 0
                    and value.microsecond == 0
                )
                if date_only_hint or is_midnight:
                    return value.date().isoformat()
                return value.strftime("%Y-%d-%m %H:%M:%S")
            if isinstance(value, date):
                return value.isoformat()
            if isinstance(value, time):
                return value.isoformat()
            return value

        def _temporal_sequence(values: Any) -> Tuple[List[datetime], bool]:
            import re as _re
            parsed: List[datetime] = []
            all_date_only = True
            flat = _flatten_sequence(values)
            for raw in flat:
                if raw is None:
                    continue
                dt_value = _parse_temporal_value(raw)
                if dt_value is None:
                    return [], False
                parsed.append(dt_value)

                explicit_time = False
                if isinstance(raw, str):
                    text = raw.strip()
                    if _looks_date_only_text(text):
                        explicit_time = False
                    else:
                        explicit_time = bool(
                            _re.search(r"([Tt ]\d{1,2}:)|\bAM\b|\bPM\b", text, flags=_re.IGNORECASE)
                        )
                if explicit_time or not (
                    dt_value.hour == 0
                    and dt_value.minute == 0
                    and dt_value.second == 0
                    and dt_value.microsecond == 0
                ):
                    all_date_only = False
            return parsed, all_date_only

        _missing = object()
        scalar_cache: Dict[str, Tuple[bool, Any]] = {}
        series_cache: Dict[str, List[Any]] = {}

        def _series_for_key(key: str) -> List[Any]:
            cached = series_cache.get(key)
            if cached is not None:
                return cached
            values: List[Any] = []
            if key and isinstance(row_scope, list):
                values = self._extract_series_from_rows(row_scope, key)
            elif key and isinstance(dataset_rows, list) and dataset_rows and not isinstance(row_scope, list):
                values = self._extract_series_from_rows(dataset_rows, key)
            series_cache[key] = values
            return values

        def _field(path: Any, default: Any = None) -> Any:
            key = str(path or "").strip()
            if not key:
                return default
            if key in custom_values:
                return custom_values.get(key)
            cached = scalar_cache.get(key, _missing)
            if cached is not _missing:
                found_cached, value_cached = cached
                if found_cached:
                    return value_cached
                return default
            # In grouped scope, field() is scalar accessor (first value),
            # while values() returns full series.
            if isinstance(row_scope, list):
                series = _series_for_key(key)
                if series:
                    scalar_cache[key] = (True, series[0])
                    return series[0]
                scalar_cache[key] = (False, None)
                return default
            value, found = self._extract_row_value_by_path(row_scope, key)
            if found:
                scalar_cache[key] = (True, value)
                return value
            scalar_cache[key] = (False, None)
            return default

        def _values(path: Any, default: Optional[List[Any]] = None) -> List[Any]:
            fallback: List[Any] = default if isinstance(default, list) else []
            key = str(path or "").strip()
            if key:
                series_values = _series_for_key(key)
                if series_values:
                    return series_values
            value = _field(path, fallback)
            if value is None:
                return fallback
            if isinstance(value, list):
                return value
            return [value]

        def _coalesce(*args: Any) -> Any:
            for arg in args:
                if arg is not None and arg != "":
                    return arg
            return None

        def _to_int(value: Any, default: int = 0) -> int:
            num = self._to_number(value)
            return int(num) if num is not None else int(default)

        def _to_float(value: Any, default: float = 0.0) -> float:
            num = self._to_number(value)
            return float(num) if num is not None else float(default)

        def _mean(values: Any) -> Optional[float]:
            nums = _numeric_sequence(values)
            if not nums:
                return None
            return sum(nums) / len(nums)

        def _sum(values: Any) -> float:
            nums = _numeric_sequence(values)
            return float(sum(nums)) if nums else 0.0

        def _min_value(*args: Any) -> Any:
            seq = args[0] if len(args) == 1 else list(args)
            flat = [v for v in _flatten_sequence(seq) if v is not None]
            if not flat:
                return None
            if len(flat) == 1:
                single = flat[0]
                single_dt = _parse_temporal_value(single)
                if single_dt is not None:
                    return _format_temporal_output(
                        single_dt,
                        _looks_date_only_text(single) if isinstance(single, str) else False,
                    )
                single_num = self._to_number(single)
                if single_num is not None:
                    return single_num
                return single
            temporal_values, temporal_date_only = _temporal_sequence(flat)
            if len(temporal_values) == len(flat) and temporal_values:
                return _format_temporal_output(min(temporal_values), temporal_date_only)
            nums = _numeric_sequence(flat)
            if len(nums) == len(flat):
                return min(nums)
            try:
                return min(flat)
            except Exception:
                return min([str(v) for v in flat])

        def _max_value(*args: Any) -> Any:
            seq = args[0] if len(args) == 1 else list(args)
            flat = [v for v in _flatten_sequence(seq) if v is not None]
            if not flat:
                return None
            if len(flat) == 1:
                single = flat[0]
                single_dt = _parse_temporal_value(single)
                if single_dt is not None:
                    return _format_temporal_output(
                        single_dt,
                        _looks_date_only_text(single) if isinstance(single, str) else False,
                    )
                single_num = self._to_number(single)
                if single_num is not None:
                    return single_num
                return single
            temporal_values, temporal_date_only = _temporal_sequence(flat)
            if len(temporal_values) == len(flat) and temporal_values:
                return _format_temporal_output(max(temporal_values), temporal_date_only)
            nums = _numeric_sequence(flat)
            if len(nums) == len(flat):
                return max(nums)
            try:
                return max(flat)
            except Exception:
                return max([str(v) for v in flat])

        def _count(values: Any = None) -> int:
            if values is None:
                return int(group_size)
            # Hot path for profile/incremental expressions:
            # count(append_unique(...)) is common and should stay O(1)
            # as collections grow.
            if isinstance(values, dict):
                return len(values)
            if isinstance(values, (list, tuple, set)):
                return len(values)
            return len(_flatten_sequence(values))

        def _distinct(values: Any) -> List[Any]:
            seq = _flatten_sequence(values)
            out: List[Any] = []
            seen = set()
            for value in seq:
                token = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                if token in seen:
                    continue
                seen.add(token)
                out.append(value)
            return out

        def _conditional_values(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> List[Any]:
            import re as _re

            value_field = str(value_path or "").strip()
            condition_field = str(condition_path or "").strip()
            if not value_field or not condition_field:
                return []

            if isinstance(row_scope, list):
                source_rows: List[Any] = row_scope
            elif isinstance(dataset_rows, list) and dataset_rows:
                source_rows = dataset_rows
            else:
                source_rows = [row_scope]

            # Backward compatibility for old count_if signature:
            # count_if(value_path, condition_path, expected_value, include_null_values=False, case_sensitive=False)
            if isinstance(op, bool):
                sensitive = bool(include_null_values)
                keep_nulls = bool(op)
                op_name = "eq"
            else:
                sensitive = bool(case_sensitive)
                keep_nulls = bool(include_null_values)
                op_name = str(op or "eq").strip().lower()

            def _normalize_cmp(value: Any) -> Any:
                if value is None:
                    return None
                if isinstance(value, (int, float, bool)):
                    return value
                text = str(value).strip()
                return text if sensitive else text.lower()

            def _to_text(value: Any) -> str:
                if value is None:
                    return ""
                text = str(value).strip()
                return text if sensitive else text.lower()

            if isinstance(expected_value, (list, tuple, set)):
                expected_list = list(expected_value)
            else:
                expected_list = [expected_value]

            expected_tokens = {_normalize_cmp(v) for v in expected_list}
            expected_texts = [_to_text(v) for v in expected_list if v is not None]

            negate = False
            if op_name in {"not", "ne", "!=", "<>", "not_eq", "neq", "is_not"}:
                negate = True
                base_op = "eq"
            elif op_name in {"not_contains", "ncontains", "!contains", "does_not_contain"}:
                negate = True
                base_op = "contains"
            elif op_name in {"not_like", "nlike", "!like"}:
                negate = True
                base_op = "like"
            elif op_name in {"not_in", "nin"}:
                negate = True
                base_op = "in"
            elif op_name in {"not_startswith", "not_starts_with"}:
                negate = True
                base_op = "startswith"
            elif op_name in {"not_endswith", "not_ends_with"}:
                negate = True
                base_op = "endswith"
            elif op_name in {"not_regex", "not_matches"}:
                negate = True
                base_op = "regex"
            else:
                base_op = op_name

            if base_op in {"", "eq", "=", "==", "is"}:
                base_op = "eq"
            elif base_op in {"contains", "has"}:
                base_op = "contains"
            elif base_op in {"like", "sql_like"}:
                base_op = "like"
            elif base_op in {"in", "one_of"}:
                base_op = "in"
            elif base_op in {"startswith", "starts_with", "prefix"}:
                base_op = "startswith"
            elif base_op in {"endswith", "ends_with", "suffix"}:
                base_op = "endswith"
            elif base_op in {"regex", "re", "matches"}:
                base_op = "regex"
            else:
                base_op = "eq"

            regex_cache: Dict[str, Any] = {}

            def _sql_like_to_regex(pattern: str) -> Any:
                cached = regex_cache.get(pattern)
                if cached is not None:
                    return cached
                escaped = _re.escape(pattern)
                rx = "^" + escaped.replace("%", ".*").replace("_", ".") + "$"
                flags = 0 if sensitive else _re.IGNORECASE
                compiled = _re.compile(rx, flags)
                regex_cache[pattern] = compiled
                return compiled

            def _match_single(condition_value: Any) -> bool:
                cond_token = _normalize_cmp(condition_value)
                cond_text = _to_text(condition_value)

                if base_op == "eq":
                    return cond_token in expected_tokens
                if base_op == "in":
                    return cond_token in expected_tokens
                if base_op == "contains":
                    if not expected_texts:
                        return False
                    return any(exp in cond_text for exp in expected_texts)
                if base_op == "startswith":
                    if not expected_texts:
                        return False
                    return any(cond_text.startswith(exp) for exp in expected_texts)
                if base_op == "endswith":
                    if not expected_texts:
                        return False
                    return any(cond_text.endswith(exp) for exp in expected_texts)
                if base_op == "like":
                    if not expected_texts:
                        return False
                    return any(bool(_sql_like_to_regex(pat).match(cond_text)) for pat in expected_texts)
                if base_op == "regex":
                    if not expected_texts:
                        return False
                    flags = 0 if sensitive else _re.IGNORECASE
                    for pat in expected_texts:
                        try:
                            if _re.search(pat, cond_text, flags):
                                return True
                        except Exception:
                            continue
                    return False
                return cond_token in expected_tokens

            out: List[Any] = []
            for src in source_rows:
                if not isinstance(src, dict):
                    continue
                condition_raw, condition_found = self._extract_row_value_by_path(src, condition_field)
                if not condition_found:
                    continue

                condition_values = _flatten_sequence(condition_raw)
                if not condition_values:
                    condition_values = [condition_raw]

                matched = any(_match_single(v) for v in condition_values)
                if negate:
                    matched = not matched
                if not matched:
                    continue

                value_raw, value_found = self._extract_row_value_by_path(src, value_field)
                if not value_found:
                    continue

                values_flat = _flatten_sequence(value_raw)
                if not values_flat:
                    if value_raw is None and keep_nulls:
                        out.append(None)
                    continue
                for item in values_flat:
                    if item is None and not keep_nulls:
                        continue
                    if isinstance(item, str) and item.strip() == "" and not keep_nulls:
                        continue
                    out.append(item)
            return out

        def _agg_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            agg: Any = "sum",
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> Any:
            values = _conditional_values(
                value_path,
                condition_path,
                expected_value,
                op=op,
                include_null_values=include_null_values,
                case_sensitive=case_sensitive,
            )
            agg_name = str(agg or "sum").strip().lower()

            if agg_name in {"sum", "total"}:
                return _sum(values)
            if agg_name in {"avg", "average", "mean"}:
                return _mean(values)
            if agg_name in {"min", "minimum"}:
                return _min_value(values)
            if agg_name in {"max", "maximum"}:
                return _max_value(values)
            if agg_name in {"count", "size"}:
                return len(_flatten_sequence(values))
            if agg_name in {"count_non_null", "non_null_count"}:
                flat = _flatten_sequence(values)
                return len([v for v in flat if v is not None and str(v).strip() != ""])
            if agg_name in {"distinct", "unique"}:
                return _distinct(values)
            if agg_name in {"distinct_count", "nunique", "unique_count"}:
                return len(_distinct(values))
            if agg_name in {"first"}:
                flat = _flatten_sequence(values)
                return flat[0] if flat else None
            if agg_name in {"last"}:
                flat = _flatten_sequence(values)
                return flat[-1] if flat else None
            if agg_name in {"std", "stdev", "stddev"}:
                return _std(values)
            return _agg(values, agg_name)

        def _count_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> int:
            return int(
                _agg_if(
                    value_path,
                    condition_path,
                    expected_value,
                    agg="count",
                    op=op,
                    include_null_values=include_null_values,
                    case_sensitive=case_sensitive,
                ) or 0
            )

        def _sum_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> float:
            return float(
                _agg_if(
                    value_path,
                    condition_path,
                    expected_value,
                    agg="sum",
                    op=op,
                    include_null_values=include_null_values,
                    case_sensitive=case_sensitive,
                ) or 0.0
            )

        def _mean_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> Any:
            return _agg_if(
                value_path,
                condition_path,
                expected_value,
                agg="mean",
                op=op,
                include_null_values=include_null_values,
                case_sensitive=case_sensitive,
            )

        def _min_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> Any:
            return _agg_if(
                value_path,
                condition_path,
                expected_value,
                agg="min",
                op=op,
                include_null_values=include_null_values,
                case_sensitive=case_sensitive,
            )

        def _max_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> Any:
            return _agg_if(
                value_path,
                condition_path,
                expected_value,
                agg="max",
                op=op,
                include_null_values=include_null_values,
                case_sensitive=case_sensitive,
            )

        def _distinct_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> List[Any]:
            result = _agg_if(
                value_path,
                condition_path,
                expected_value,
                agg="distinct",
                op=op,
                include_null_values=include_null_values,
                case_sensitive=case_sensitive,
            )
            return result if isinstance(result, list) else []

        def _distinct_count_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> int:
            return int(
                _agg_if(
                    value_path,
                    condition_path,
                    expected_value,
                    agg="distinct_count",
                    op=op,
                    include_null_values=include_null_values,
                    case_sensitive=case_sensitive,
                ) or 0
            )

        def _count_non_null_if(
            value_path: Any,
            condition_path: Any,
            expected_value: Any,
            op: Any = "eq",
            include_null_values: Any = False,
            case_sensitive: Any = False,
        ) -> int:
            return int(
                _agg_if(
                    value_path,
                    condition_path,
                    expected_value,
                    agg="count_non_null",
                    op=op,
                    include_null_values=include_null_values,
                    case_sensitive=case_sensitive,
                ) or 0
            )

        def _agg(path_or_values: Any, func: Any = "sum") -> Any:
            func_name = str(func or "sum").strip().lower()
            values = _values(path_or_values, []) if isinstance(path_or_values, str) else path_or_values
            if func_name in {"sum", "total"}:
                return _sum(values)
            if func_name in {"avg", "average", "mean"}:
                return _mean(values)
            if func_name in {"min", "minimum"}:
                return _min_value(values)
            if func_name in {"max", "maximum"}:
                return _max_value(values)
            if func_name in {"count", "size"}:
                return _count(values)
            if func_name in {"distinct", "unique"}:
                return _distinct(values)
            if func_name in {"first"}:
                flat = _flatten_sequence(values)
                return flat[0] if flat else None
            if func_name in {"last"}:
                flat = _flatten_sequence(values)
                return flat[-1] if flat else None
            return None

        def _std(values: Any) -> Optional[float]:
            nums = _numeric_sequence(values)
            n = len(nums)
            if n <= 1:
                return 0.0 if n == 1 else None
            mean_val = sum(nums) / n
            variance = sum((x - mean_val) ** 2 for x in nums) / n
            return math.sqrt(variance)

        def _running(values: Any, func: Any = "sum", return_series: Any = False) -> Any:
            func_name = str(func or "sum").strip().lower()
            flat = _flatten_sequence(values)
            out: List[Any] = []
            window: List[Any] = []
            for value in flat:
                window.append(value)
                if func_name in {"sum", "total"}:
                    out.append(_sum(window))
                elif func_name in {"avg", "average", "mean"}:
                    out.append(_mean(window))
                elif func_name in {"min", "minimum"}:
                    out.append(_min_value(window))
                elif func_name in {"max", "maximum"}:
                    out.append(_max_value(window))
                elif func_name in {"count", "size"}:
                    out.append(_count(window))
                elif func_name in {"std", "stdev", "stddev"}:
                    out.append(_std(window))
                else:
                    out.append(_agg(window, func_name))
            if bool(return_series):
                return out
            if row_index is not None:
                if not out:
                    return None
                idx = max(0, min(int(row_index), len(out) - 1))
                return out[idx]
            return out

        def _rolling(
            values: Any,
            window: Any = 3,
            func: Any = "mean",
            min_periods: Any = 1,
            return_series: Any = False,
        ) -> Any:
            try:
                win = int(window)
            except Exception:
                win = 3
            try:
                minp = int(min_periods)
            except Exception:
                minp = 1
            win = max(1, win)
            minp = max(1, min(minp, win))
            func_name = str(func or "mean").strip().lower()
            flat = _flatten_sequence(values)
            out: List[Any] = []
            for idx in range(len(flat)):
                start = max(0, idx - win + 1)
                chunk = flat[start: idx + 1]
                if len(chunk) < minp:
                    out.append(None)
                    continue
                if func_name in {"sum", "total"}:
                    out.append(_sum(chunk))
                elif func_name in {"avg", "average", "mean"}:
                    out.append(_mean(chunk))
                elif func_name in {"min", "minimum"}:
                    out.append(_min_value(chunk))
                elif func_name in {"max", "maximum"}:
                    out.append(_max_value(chunk))
                elif func_name in {"count", "size"}:
                    out.append(_count(chunk))
                elif func_name in {"std", "stdev", "stddev"}:
                    out.append(_std(chunk))
                else:
                    out.append(_agg(chunk, func_name))
            if bool(return_series):
                return out
            if row_index is not None:
                if not out:
                    return None
                idx = max(0, min(int(row_index), len(out) - 1))
                return out[idx]
            return out

        def _last(values: Any, default: Any = None) -> Any:
            flat = _flatten_sequence(values)
            if not flat:
                return default
            return flat[-1]

        def _group_profile(
            key_path: Any,
            value_path: Any,
            agg_func: Any = "max",
            key_name: Any = "key",
            value_name: Any = "value",
            include_null_key: Any = False,
            count_name: Any = "",
        ) -> List[Dict[str, Any]]:
            key_field = str(key_path or "").strip()
            value_field = str(value_path or "").strip()
            if not key_field or not value_field:
                return []

            if isinstance(row_scope, list):
                source_rows: List[Any] = row_scope
            elif isinstance(dataset_rows, list) and dataset_rows:
                source_rows = dataset_rows
            else:
                source_rows = [row_scope]

            buckets: Dict[str, Dict[str, Any]] = {}
            order: List[str] = []
            keep_null_key = bool(include_null_key)

            for src in source_rows:
                if not isinstance(src, dict):
                    continue
                key_value, key_found = self._extract_row_value_by_path(src, key_field)
                if not key_found:
                    continue
                if key_value is None and not keep_null_key:
                    continue
                try:
                    token = json.dumps(key_value, ensure_ascii=False, sort_keys=True, default=str)
                except Exception:
                    token = str(key_value)
                if token not in buckets:
                    buckets[token] = {"key": key_value, "values": [], "row_count": 0}
                    order.append(token)
                buckets[token]["row_count"] = int(buckets[token].get("row_count", 0)) + 1
                value, value_found = self._extract_row_value_by_path(src, value_field)
                if value_found:
                    buckets[token]["values"].append(value)

            out: List[Dict[str, Any]] = []
            group_key_name = str(key_name or "key").strip() or "key"
            group_value_name = str(value_name or "value").strip() or "value"
            txn_count_name = str(count_name or "").strip()
            func_name = str(agg_func or "max").strip().lower()
            for token in order:
                bucket = buckets[token]
                agg_value = _agg(bucket.get("values", []), func_name)
                row_obj: Dict[str, Any] = {
                    group_key_name: bucket.get("key"),
                    group_value_name: agg_value,
                }
                if txn_count_name:
                    row_obj[txn_count_name] = int(bucket.get("row_count", 0))
                out.append(row_obj)
            return out

        def _group_profile_stats(
            key_path: Any,
            value_path: Any,
            key_name: Any = "customer",
            min_name: Any = "mintime",
            max_name: Any = "maxtime",
            count_name: Any = "transaction_count",
            count_path: Any = None,
            include_null_key: Any = False,
        ) -> List[Dict[str, Any]]:
            key_field = str(key_path or "").strip()
            value_field = str(value_path or "").strip()
            if not key_field or not value_field:
                return []

            if isinstance(row_scope, list):
                source_rows: List[Any] = row_scope
            elif isinstance(dataset_rows, list) and dataset_rows:
                source_rows = dataset_rows
            else:
                source_rows = [row_scope]

            count_field = str(count_path or "").strip()
            buckets: Dict[str, Dict[str, Any]] = {}
            order: List[str] = []
            keep_null_key = bool(include_null_key)

            for src in source_rows:
                if not isinstance(src, dict):
                    continue
                key_value, key_found = self._extract_row_value_by_path(src, key_field)
                if not key_found:
                    continue
                if key_value is None and not keep_null_key:
                    continue
                try:
                    token = json.dumps(key_value, ensure_ascii=False, sort_keys=True, default=str)
                except Exception:
                    token = str(key_value)
                if token not in buckets:
                    buckets[token] = {"key": key_value, "values": [], "row_count": 0}
                    order.append(token)

                should_count = True
                if count_field:
                    count_value, count_found = self._extract_row_value_by_path(src, count_field)
                    should_count = count_found and count_value is not None
                if should_count:
                    buckets[token]["row_count"] = int(buckets[token].get("row_count", 0)) + 1

                value, value_found = self._extract_row_value_by_path(src, value_field)
                if value_found:
                    buckets[token]["values"].append(value)

            out: List[Dict[str, Any]] = []
            group_key_name = str(key_name or "customer").strip() or "customer"
            min_field_name = str(min_name or "mintime").strip() or "mintime"
            max_field_name = str(max_name or "maxtime").strip() or "maxtime"
            txn_count_name = str(count_name or "transaction_count").strip() or "transaction_count"
            for token in order:
                bucket = buckets[token]
                values = bucket.get("values", [])
                row_obj: Dict[str, Any] = {
                    group_key_name: bucket.get("key"),
                    min_field_name: _agg(values, "min"),
                    max_field_name: _agg(values, "max"),
                }
                if txn_count_name:
                    row_obj[txn_count_name] = int(bucket.get("row_count", 0))
                out.append(row_obj)
            return out

        def _group_aggregate(
            key_path: Any,
            metrics: Any,
            key_name: Any = "key",
            include_null_key: Any = False,
        ) -> List[Dict[str, Any]]:
            key_field = str(key_path or "").strip()
            if not key_field:
                return []

            if isinstance(row_scope, list):
                source_rows: List[Any] = row_scope
            elif isinstance(dataset_rows, list) and dataset_rows:
                source_rows = dataset_rows
            else:
                source_rows = [row_scope]

            def _parse_metrics_config(raw_metrics: Any) -> List[Dict[str, Any]]:
                raw = raw_metrics
                if isinstance(raw, str):
                    text = raw.strip()
                    if not text:
                        return []
                    try:
                        raw = json.loads(text)
                    except Exception:
                        raw = [part.strip() for part in text.split(",") if part.strip()]

                specs: List[Dict[str, Any]] = []
                seen_names = set()

                def _add_spec(name: str, path: str, agg: str, default_value: Any = None, has_default: bool = False):
                    out_name = str(name or "").strip()
                    if not out_name:
                        return
                    key = out_name.lower()
                    if key in seen_names:
                        return
                    seen_names.add(key)
                    spec: Dict[str, Any] = {
                        "name": out_name,
                        "path": str(path or "").strip(),
                        "agg": str(agg or "count").strip().lower(),
                    }
                    if has_default:
                        spec["default"] = default_value
                    specs.append(spec)

                if isinstance(raw, dict):
                    for out_name, conf in raw.items():
                        metric_name = str(out_name or "").strip()
                        if not metric_name:
                            continue
                        if isinstance(conf, dict):
                            metric_path = str(
                                conf.get("path")
                                or conf.get("field")
                                or conf.get("column")
                                or ""
                            ).strip()
                            metric_agg = str(
                                conf.get("agg")
                                or conf.get("func")
                                or conf.get("op")
                                or "count"
                            ).strip().lower()
                            has_default = "default" in conf
                            _add_spec(metric_name, metric_path, metric_agg, conf.get("default"), has_default)
                        elif isinstance(conf, list):
                            metric_path = str(conf[0] if len(conf) > 0 else "").strip()
                            metric_agg = str(conf[1] if len(conf) > 1 else "count").strip().lower()
                            _add_spec(metric_name, metric_path, metric_agg)
                        elif isinstance(conf, str):
                            text = conf.strip()
                            if ":" in text:
                                metric_path, metric_agg = [p.strip() for p in text.split(":", 1)]
                            else:
                                metric_path, metric_agg = "", text
                            _add_spec(metric_name, metric_path, metric_agg)
                elif isinstance(raw, list):
                    for idx, item in enumerate(raw):
                        if isinstance(item, dict):
                            metric_name = str(
                                item.get("name")
                                or item.get("alias")
                                or item.get("output")
                                or ""
                            ).strip()
                            metric_path = str(
                                item.get("path")
                                or item.get("field")
                                or item.get("column")
                                or ""
                            ).strip()
                            metric_agg = str(
                                item.get("agg")
                                or item.get("func")
                                or item.get("op")
                                or "count"
                            ).strip().lower()
                            if not metric_name:
                                if metric_path:
                                    metric_name = f"{metric_path.split('.')[-1]}_{metric_agg}"
                                else:
                                    metric_name = f"metric_{idx + 1}"
                            has_default = "default" in item
                            _add_spec(metric_name, metric_path, metric_agg, item.get("default"), has_default)
                        elif isinstance(item, str):
                            text = item.strip()
                            if not text:
                                continue
                            metric_name = ""
                            metric_path = ""
                            metric_agg = "count"
                            if "=" in text:
                                metric_name, text = [p.strip() for p in text.split("=", 1)]
                            if ":" in text:
                                metric_path, metric_agg = [p.strip() for p in text.split(":", 1)]
                            else:
                                metric_agg = text
                            if not metric_name:
                                metric_name = (
                                    f"{metric_path.split('.')[-1]}_{metric_agg}"
                                    if metric_path else
                                    f"metric_{idx + 1}"
                                )
                            _add_spec(metric_name, metric_path, metric_agg)
                return specs

            metric_specs = _parse_metrics_config(metrics)
            if not metric_specs:
                return []

            runtime_specs: List[Dict[str, Any]] = []
            for spec in metric_specs:
                runtime_specs.append(
                    {
                        "name": str(spec.get("name") or "").strip(),
                        "path": str(spec.get("path") or "").strip(),
                        "agg": str(spec.get("agg") or "count").strip().lower(),
                        "has_default": "default" in spec,
                        "default": spec.get("default"),
                    }
                )

            def _init_metric_state(agg_name: str) -> Dict[str, Any]:
                op = str(agg_name or "count").strip().lower()
                if op in {"row_count", "rows", "size"}:
                    return {"kind": "row_count", "count": 0}
                if op in {"count_non_null", "non_null_count"}:
                    return {"kind": "count_non_null", "count": 0}
                if op in {"distinct_count", "nunique", "unique_count"}:
                    return {"kind": "distinct_count", "seen": set()}
                if op in {"distinct", "unique"}:
                    return {"kind": "distinct", "seen": set(), "values": []}
                if op in {"value_counts", "count_by_value", "frequency", "freq"}:
                    return {"kind": "value_counts", "items": {}, "order": []}
                if op in {"count"}:
                    return {"kind": "count", "count": 0}
                if op in {"sum", "total"}:
                    return {"kind": "sum", "value": 0.0}
                if op in {"avg", "average", "mean"}:
                    return {"kind": "mean", "sum": 0.0, "count": 0}
                if op in {"min", "minimum"}:
                    return {"kind": "min", "has_value": False, "value": None}
                if op in {"max", "maximum"}:
                    return {"kind": "max", "has_value": False, "value": None}
                if op in {"first"}:
                    return {"kind": "first", "has_value": False, "value": None}
                if op in {"last"}:
                    return {"kind": "last", "has_value": False, "value": None}
                return {"kind": "unsupported"}

            def _pick_min(current: Any, candidate: Any) -> Any:
                if current is None:
                    return candidate
                if candidate is None:
                    return current
                current_dt = _parse_temporal_value(current)
                candidate_dt = _parse_temporal_value(candidate)
                if current_dt is not None and candidate_dt is not None:
                    return candidate if candidate_dt < current_dt else current
                current_num = self._to_number(current)
                candidate_num = self._to_number(candidate)
                if current_num is not None and candidate_num is not None:
                    return candidate if candidate_num < current_num else current
                try:
                    return candidate if candidate < current else current
                except Exception:
                    return candidate if str(candidate) < str(current) else current

            def _pick_max(current: Any, candidate: Any) -> Any:
                if current is None:
                    return candidate
                if candidate is None:
                    return current
                current_dt = _parse_temporal_value(current)
                candidate_dt = _parse_temporal_value(candidate)
                if current_dt is not None and candidate_dt is not None:
                    return candidate if candidate_dt > current_dt else current
                current_num = self._to_number(current)
                candidate_num = self._to_number(candidate)
                if current_num is not None and candidate_num is not None:
                    return candidate if candidate_num > current_num else current
                try:
                    return candidate if candidate > current else current
                except Exception:
                    return candidate if str(candidate) > str(current) else current

            buckets: Dict[str, Dict[str, Any]] = {}
            order: List[str] = []
            keep_null_key = bool(include_null_key)
            for src in source_rows:
                if not isinstance(src, dict):
                    continue
                key_value, key_found = self._extract_row_value_by_path(src, key_field)
                if not key_found:
                    continue
                if key_value is None and not keep_null_key:
                    continue

                normalized_key_value = key_value
                parsed_key_dt = _parse_temporal_value(key_value)
                if parsed_key_dt is not None:
                    key_date_only_hint = False
                    if isinstance(key_value, str):
                        key_text = key_value.strip()
                        if _looks_date_only_text(key_text):
                            key_date_only_hint = True
                    elif isinstance(key_value, datetime):
                        key_date_only_hint = (
                            key_value.hour == 0
                            and key_value.minute == 0
                            and key_value.second == 0
                            and key_value.microsecond == 0
                        )
                    elif isinstance(key_value, date):
                        key_date_only_hint = True
                    normalized_key_value = _format_temporal_output(parsed_key_dt, key_date_only_hint)

                try:
                    token = json.dumps(normalized_key_value, ensure_ascii=False, sort_keys=True, default=str)
                except Exception:
                    token = str(normalized_key_value)
                if token not in buckets:
                    buckets[token] = {
                        "key": normalized_key_value,
                        "states": [_init_metric_state(spec.get("agg", "count")) for spec in runtime_specs],
                    }
                    order.append(token)

                bucket = buckets[token]
                metric_states = bucket.get("states", [])
                row_path_cache: Dict[str, List[Any]] = {}
                for idx, spec in enumerate(runtime_specs):
                    if idx >= len(metric_states):
                        continue
                    state = metric_states[idx]
                    kind = state.get("kind")
                    if kind == "row_count":
                        state["count"] = int(state.get("count", 0)) + 1
                        continue

                    path = str(spec.get("path") or "").strip()
                    if not path:
                        continue

                    if path in row_path_cache:
                        flat_values = row_path_cache[path]
                    else:
                        raw_value, found = self._extract_row_value_by_path(src, path)
                        if not found:
                            flat_values = []
                        elif isinstance(raw_value, list):
                            flat_values = _flatten_sequence(raw_value)
                        else:
                            flat_values = _flatten_sequence([raw_value])
                        row_path_cache[path] = flat_values

                    if not flat_values:
                        continue

                    if kind == "count":
                        state["count"] = int(state.get("count", 0)) + len(flat_values)
                    elif kind == "count_non_null":
                        current = int(state.get("count", 0))
                        current += len([v for v in flat_values if v is not None and str(v).strip() != ""])
                        state["count"] = current
                    elif kind == "distinct_count":
                        seen = state.get("seen")
                        if not isinstance(seen, set):
                            seen = set()
                            state["seen"] = seen
                        for value in flat_values:
                            token_value = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                            seen.add(token_value)
                    elif kind == "distinct":
                        seen = state.get("seen")
                        values_out = state.get("values")
                        if not isinstance(seen, set):
                            seen = set()
                            state["seen"] = seen
                        if not isinstance(values_out, list):
                            values_out = []
                            state["values"] = values_out
                        for value in flat_values:
                            token_value = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                            if token_value in seen:
                                continue
                            seen.add(token_value)
                            values_out.append(value)
                    elif kind == "value_counts":
                        items = state.get("items")
                        order_tokens = state.get("order")
                        if not isinstance(items, dict):
                            items = {}
                            state["items"] = items
                        if not isinstance(order_tokens, list):
                            order_tokens = []
                            state["order"] = order_tokens
                        for value in flat_values:
                            if value is None:
                                continue
                            token_value = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                            current = items.get(token_value)
                            if not isinstance(current, dict):
                                items[token_value] = {"value": value, "count": 1}
                                order_tokens.append(token_value)
                            else:
                                current["count"] = int(current.get("count", 0)) + 1
                    elif kind == "sum":
                        total = float(state.get("value", 0.0))
                        for value in flat_values:
                            num = self._to_number(value)
                            if num is not None:
                                total += float(num)
                        state["value"] = total
                    elif kind == "mean":
                        total = float(state.get("sum", 0.0))
                        count = int(state.get("count", 0))
                        for value in flat_values:
                            num = self._to_number(value)
                            if num is None:
                                continue
                            total += float(num)
                            count += 1
                        state["sum"] = total
                        state["count"] = count
                    elif kind == "min":
                        current_value = state.get("value")
                        has_value = bool(state.get("has_value", False))
                        for value in flat_values:
                            if value is None:
                                continue
                            current_value = value if not has_value else _pick_min(current_value, value)
                            has_value = True
                        state["value"] = current_value
                        state["has_value"] = has_value
                    elif kind == "max":
                        current_value = state.get("value")
                        has_value = bool(state.get("has_value", False))
                        for value in flat_values:
                            if value is None:
                                continue
                            current_value = value if not has_value else _pick_max(current_value, value)
                            has_value = True
                        state["value"] = current_value
                        state["has_value"] = has_value
                    elif kind == "first":
                        if not bool(state.get("has_value", False)):
                            state["value"] = flat_values[0]
                            state["has_value"] = True
                    elif kind == "last":
                        state["value"] = flat_values[-1]
                        state["has_value"] = True

            out: List[Dict[str, Any]] = []
            group_key_name = str(key_name or "key").strip() or "key"
            for token in order:
                bucket = buckets[token]
                metric_states = bucket.get("states", [])
                row_obj: Dict[str, Any] = {group_key_name: bucket.get("key")}
                for idx, spec in enumerate(runtime_specs):
                    if idx >= len(metric_states):
                        continue
                    state = metric_states[idx]
                    kind = state.get("kind")
                    metric_value: Any = None
                    if kind in {"row_count", "count", "count_non_null"}:
                        metric_value = int(state.get("count", 0))
                    elif kind == "distinct_count":
                        seen = state.get("seen")
                        metric_value = len(seen) if isinstance(seen, set) else 0
                    elif kind == "distinct":
                        values_out = state.get("values")
                        metric_value = values_out if isinstance(values_out, list) else []
                    elif kind == "value_counts":
                        items = state.get("items")
                        order_tokens = state.get("order")
                        if isinstance(items, dict) and isinstance(order_tokens, list):
                            metric_value = [
                                {
                                    "value": items[token].get("value"),
                                    "count": int(items[token].get("count", 0)),
                                }
                                for token in order_tokens
                                if token in items
                            ]
                        else:
                            metric_value = []
                    elif kind == "sum":
                        metric_value = float(state.get("value", 0.0))
                    elif kind == "mean":
                        count = int(state.get("count", 0))
                        metric_value = (float(state.get("sum", 0.0)) / count) if count > 0 else None
                    elif kind in {"min", "max", "first", "last"}:
                        raw_metric = state.get("value") if bool(state.get("has_value", False)) else None
                        if raw_metric is None:
                            metric_value = None
                        else:
                            parsed_metric_dt = _parse_temporal_value(raw_metric)
                            if parsed_metric_dt is not None:
                                date_only_hint = False
                                if isinstance(raw_metric, str):
                                    raw_text = raw_metric.strip()
                                    if _looks_date_only_text(raw_text):
                                        date_only_hint = True
                                elif isinstance(raw_metric, datetime):
                                    date_only_hint = (
                                        raw_metric.hour == 0
                                        and raw_metric.minute == 0
                                        and raw_metric.second == 0
                                        and raw_metric.microsecond == 0
                                    )
                                elif isinstance(raw_metric, date):
                                    date_only_hint = True
                                metric_value = _format_temporal_output(parsed_metric_dt, date_only_hint)
                            else:
                                metric_value = raw_metric

                    if metric_value is None and bool(spec.get("has_default")):
                        metric_value = spec.get("default")
                    row_obj[str(spec.get("name"))] = metric_value
                out.append(row_obj)
            return out
        def _running_sum(values: Any) -> List[Any]:
            return _running(values, "sum")

        def _running_mean(values: Any) -> List[Any]:
            return _running(values, "mean")

        def _running_min(values: Any) -> List[Any]:
            return _running(values, "min")

        def _running_max(values: Any) -> List[Any]:
            return _running(values, "max")

        def _running_count(values: Any) -> List[Any]:
            return _running(values, "count")

        def _running_std(values: Any) -> List[Any]:
            return _running(values, "std")

        def _rolling_sum(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "sum", min_periods)

        def _rolling_mean(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "mean", min_periods)

        def _rolling_min(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "min", min_periods)

        def _rolling_max(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "max", min_periods)

        def _rolling_count(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "count", min_periods)

        def _rolling_std(values: Any, window: Any = 3, min_periods: Any = 1) -> List[Any]:
            return _rolling(values, window, "std", min_periods)

        def _running_all(values: Any, func: Any = "sum") -> List[Any]:
            series = _running(values, func, True)
            return series if isinstance(series, list) else ([series] if series is not None else [])

        def _rolling_all(values: Any, window: Any = 3, func: Any = "mean", min_periods: Any = 1) -> List[Any]:
            series = _rolling(values, window, func, min_periods, True)
            return series if isinstance(series, list) else ([series] if series is not None else [])

        def _if(cond: Any, yes: Any, no: Any) -> Any:
            return yes if bool(cond) else no

        def _contains(haystack: Any, needle: Any) -> bool:
            if haystack is None:
                return False
            return str(needle or "") in str(haystack)

        def _random() -> float:
            return random.random()

        def _randint(*args: Any) -> int:
            # randint()          -> 0..2147483647
            # randint(max)       -> 0..max
            # randint(min, max)  -> min..max
            if len(args) <= 0:
                lo = 0
                hi = 2147483647
            elif len(args) == 1:
                lo = 0
                hi = int(_to_float(args[0], 0.0))
            else:
                lo = int(_to_float(args[0], 0.0))
                hi = int(_to_float(args[1], 0.0))
            if lo > hi:
                lo, hi = hi, lo
            return random.randint(lo, hi)

        context: Dict[str, Any] = {
            "field": _field,
            "get": _field,
            "values": _values,
            "coalesce": _coalesce,
            "if_": _if,
            "iff": _if,
            "contains": _contains,
            "upper": lambda v: None if v is None else str(v).upper(),
            "lower": lambda v: None if v is None else str(v).lower(),
            "title": lambda v: None if v is None else str(v).title(),
            "trim": lambda v: None if v is None else str(v).strip(),
            "length": lambda v: len(v) if v is not None else 0,
            "int": _to_int,
            "float": _to_float,
            "str": lambda v: "" if v is None else str(v),
            "bool": lambda v: bool(v),
            "round": round,
            "abs": abs,
            "random": _random,
            "rand": _random,
            "randint": _randint,
            "min": _min_value,
            "max": _max_value,
            "sum": _sum,
            "mean": _mean,
            "count": _count,
            "agg_if": _agg_if,
            "count_if": _count_if,
            "sum_if": _sum_if,
            "mean_if": _mean_if,
            "min_if": _min_if,
            "max_if": _max_if,
            "distinct_if": _distinct_if,
            "distinct_count_if": _distinct_count_if,
            "count_non_null_if": _count_non_null_if,
            "distinct": _distinct,
            "agg": _agg,
            "std": _std,
            "running": _running,
            "rolling": _rolling,
            "running_all": _running_all,
            "rolling_all": _rolling_all,
            "last": _last,
            "group_profile": _group_profile,
            "group_objects": _group_profile,
            "group_profile_stats": _group_profile_stats,
            "group_profile_minmax": _group_profile_stats,
            "group_aggregate": _group_aggregate,
            "group_metrics": _group_aggregate,
            "running_sum": _running_sum,
            "running_mean": _running_mean,
            "running_min": _running_min,
            "running_max": _running_max,
            "running_count": _running_count,
            "running_std": _running_std,
            "rolling_sum": _rolling_sum,
            "rolling_mean": _rolling_mean,
            "rolling_min": _rolling_min,
            "rolling_max": _rolling_max,
            "rolling_count": _rolling_count,
            "rolling_std": _rolling_std,
            "cumulative_sum": _running_sum,
            "cumulative_mean": _running_mean,
            "pow": pow,
            "sqrt": lambda v: math.sqrt(_to_float(v, 0.0)),
            "log": lambda v, base=math.e: math.log(max(_to_float(v, 0.0), 1e-12), base),
            "exp": lambda v: math.exp(_to_float(v, 0.0)),
            "ceil": lambda v: math.ceil(_to_float(v, 0.0)),
            "floor": lambda v: math.floor(_to_float(v, 0.0)),
            "sin": lambda v: math.sin(_to_float(v, 0.0)),
            "cos": lambda v: math.cos(_to_float(v, 0.0)),
            "tan": lambda v: math.tan(_to_float(v, 0.0)),
            "pi": math.pi,
            "e": math.e,
            "array": lambda *args: list(args),
            "obj": lambda **kwargs: kwargs,
            "json_parse": lambda text: json.loads(str(text or "")),
            "json_dump": lambda value: json.dumps(value, ensure_ascii=False),
            "now": lambda: datetime.utcnow().isoformat(),
            "null": None,
            "None": None,
            "true": True,
            "false": False,
            "True": True,
            "False": False,
            "group_size": group_size,
        }

        # Direct field references for identifier-safe names.
        for k, v in row_obj.items():
            if isinstance(k, str) and k.isidentifier():
                context[k] = v
        if isinstance(row_scope, list) and row_scope:
            first = row_scope[0]
            if isinstance(first, dict):
                for k, v in first.items():
                    if isinstance(k, str) and k.isidentifier() and k not in context:
                        context[k] = v
        for k, v in custom_values.items():
            if isinstance(k, str) and k.isidentifier():
                context[k] = v
            context[k] = v
        if isinstance(extra_context, dict):
            context.update(extra_context)
        return context

    def _eval_expression_ast(self, node: ast.AST, context: Dict[str, Any], depth: int = 0) -> Any:
        if depth > 80:
            raise RuntimeError("Expression too complex")

        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, ast.Name):
            return context.get(node.id)
        if isinstance(node, ast.List):
            return [self._eval_expression_ast(el, context, depth + 1) for el in node.elts]
        if isinstance(node, ast.Tuple):
            return tuple(self._eval_expression_ast(el, context, depth + 1) for el in node.elts)
        if isinstance(node, ast.Dict):
            return {
                self._eval_expression_ast(k, context, depth + 1): self._eval_expression_ast(v, context, depth + 1)
                for k, v in zip(node.keys, node.values)
            }
        if isinstance(node, ast.Subscript):
            target = self._eval_expression_ast(node.value, context, depth + 1)
            if isinstance(node.slice, ast.Slice):
                lower = self._eval_expression_ast(node.slice.lower, context, depth + 1) if node.slice.lower else None
                upper = self._eval_expression_ast(node.slice.upper, context, depth + 1) if node.slice.upper else None
                step = self._eval_expression_ast(node.slice.step, context, depth + 1) if node.slice.step else None
                return target[slice(lower, upper, step)]
            key = self._eval_expression_ast(node.slice, context, depth + 1)
            return target[key]
        if isinstance(node, ast.UnaryOp):
            value = self._eval_expression_ast(node.operand, context, depth + 1)
            if isinstance(node.op, ast.Not):
                return not bool(value)
            if isinstance(node.op, ast.USub):
                return -(value or 0)
            if isinstance(node.op, ast.UAdd):
                return +(value or 0)
            raise RuntimeError("Unsupported unary operator")
        if isinstance(node, ast.BinOp):
            left = self._eval_expression_ast(node.left, context, depth + 1)
            right = self._eval_expression_ast(node.right, context, depth + 1)
            if isinstance(node.op, ast.Add):
                return left + right
            if isinstance(node.op, ast.Sub):
                return left - right
            if isinstance(node.op, ast.Mult):
                return left * right
            if isinstance(node.op, ast.Div):
                return left / right
            if isinstance(node.op, ast.FloorDiv):
                return left // right
            if isinstance(node.op, ast.Mod):
                return left % right
            if isinstance(node.op, ast.Pow):
                return left ** right
            raise RuntimeError("Unsupported binary operator")
        if isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                out = True
                for v in node.values:
                    out = self._eval_expression_ast(v, context, depth + 1)
                    if not out:
                        return out
                return out
            if isinstance(node.op, ast.Or):
                for v in node.values:
                    out = self._eval_expression_ast(v, context, depth + 1)
                    if out:
                        return out
                return out
            raise RuntimeError("Unsupported boolean operator")
        if isinstance(node, ast.Compare):
            left = self._eval_expression_ast(node.left, context, depth + 1)
            for op, comparator in zip(node.ops, node.comparators):
                right = self._eval_expression_ast(comparator, context, depth + 1)
                if isinstance(op, ast.Eq):
                    ok = left == right
                elif isinstance(op, ast.NotEq):
                    ok = left != right
                elif isinstance(op, ast.Gt):
                    ok = self._compare_values(left, right) > 0
                elif isinstance(op, ast.GtE):
                    ok = self._compare_values(left, right) >= 0
                elif isinstance(op, ast.Lt):
                    ok = self._compare_values(left, right) < 0
                elif isinstance(op, ast.LtE):
                    ok = self._compare_values(left, right) <= 0
                elif isinstance(op, ast.In):
                    ok = left in right
                elif isinstance(op, ast.NotIn):
                    ok = left not in right
                else:
                    raise RuntimeError("Unsupported comparison operator")
                if not ok:
                    return False
                left = right
            return True
        if isinstance(node, ast.IfExp):
            cond = self._eval_expression_ast(node.test, context, depth + 1)
            branch = node.body if cond else node.orelse
            return self._eval_expression_ast(branch, context, depth + 1)
        if isinstance(node, ast.Call):
            fn_name = ""
            if isinstance(node.func, ast.Name):
                fn_name = node.func.id
                fn = context.get(fn_name)
                if fn is None:
                    fn = context.get(fn_name.lower())
            else:
                raise RuntimeError("Only named function calls are allowed")
            if not callable(fn):
                if fn_name:
                    raise RuntimeError(f"Function not allowed: {fn_name}")
                raise RuntimeError("Function not allowed")
            args = [self._eval_expression_ast(arg, context, depth + 1) for arg in node.args]
            kwargs = {
                kw.arg: self._eval_expression_ast(kw.value, context, depth + 1)
                for kw in node.keywords
                if kw.arg
            }
            return fn(*args, **kwargs)

        raise RuntimeError(f"Unsupported expression element: {type(node).__name__}")

    def _rewrite_series_expression(self, parsed: ast.AST) -> ast.AST:
        series_fns = {
            "running",
            "rolling",
            "running_sum",
            "running_mean",
            "running_min",
            "running_max",
            "running_count",
            "running_std",
            "rolling_sum",
            "rolling_mean",
            "rolling_min",
            "rolling_max",
            "rolling_count",
            "rolling_std",
            "cumulative_sum",
            "cumulative_mean",
        }
        aggregate_fns = {
            "sum",
            "mean",
            "count",
            "distinct",
            "std",
            "stdev",
            "stddev",
            "agg",
            "min",
            "max",
        }

        class _SeriesArgRewrite(ast.NodeTransformer):
            def visit_Call(self, node: ast.Call) -> Any:
                node = self.generic_visit(node)
                if isinstance(node.func, ast.Name):
                    fn_name = str(node.func.id or "").strip().lower()
                    if fn_name in series_fns and node.args:
                        first = node.args[0]
                        if (
                            isinstance(first, ast.Call)
                            and isinstance(first.func, ast.Name)
                            and str(first.func.id or "").strip().lower() in {"field", "get"}
                        ):
                            first.func.id = "values"
                    elif fn_name in aggregate_fns and node.args:
                        # Keep scalar behavior for min/max(a,b), rewrite only single-arg calls.
                        if fn_name in {"min", "max"} and len(node.args) != 1:
                            return node
                        first = node.args[0]
                        if (
                            isinstance(first, ast.Call)
                            and isinstance(first.func, ast.Name)
                            and str(first.func.id or "").strip().lower() in {"field", "get"}
                        ):
                            first.func.id = "values"
                return node

        transformed = _SeriesArgRewrite().visit(parsed)
        ast.fix_missing_locations(transformed)
        return transformed

    def _evaluate_custom_expression(
        self,
        expression: str,
        row: Any,
        custom_values: Dict[str, Any],
        dataset_rows: Optional[List[Any]] = None,
        row_index: Optional[int] = None,
        context: Optional[Dict[str, Any]] = None,
    ) -> Any:
        expr = str(expression or "").strip()
        if expr.startswith("="):
            expr = expr[1:].strip()
        if not expr:
            return None

        eval_context = context or self._build_expression_context(
            row,
            custom_values,
            dataset_rows=dataset_rows,
            row_index=row_index,
        )
        cached_node = self._expr_ast_cache.get(expr)
        if cached_node is None:
            parsed = ast.parse(expr, mode="eval")
            rewritten = self._rewrite_series_expression(parsed)
            cached_node = rewritten.body
            if len(self._expr_ast_cache) > 8192:
                self._expr_ast_cache.clear()
            self._expr_ast_cache[expr] = cached_node
        return self._eval_expression_ast(cached_node, eval_context)

    def _evaluate_json_template(
        self,
        template_value: Any,
        row: Any,
        custom_values: Dict[str, Any],
        dataset_rows: Optional[List[Any]] = None,
        row_index: Optional[int] = None,
        context: Optional[Dict[str, Any]] = None,
    ) -> Any:
        if template_value is None:
            return None

        obj = template_value
        if isinstance(template_value, str):
            text = template_value.strip()
            if not text:
                return None
            cached_template = self._json_template_cache.get(text)
            if cached_template is None:
                cached_template = json.loads(text)
                if len(self._json_template_cache) > 2048:
                    self._json_template_cache.clear()
                self._json_template_cache[text] = cached_template
            obj = cached_template

        eval_context = context or self._build_expression_context(
            row,
            custom_values,
            dataset_rows=dataset_rows,
            row_index=row_index,
        )

        def walk(value: Any) -> Any:
            if isinstance(value, str):
                text = value.strip()
                if text.startswith("="):
                    return self._evaluate_custom_expression(
                        text[1:],
                        row,
                        custom_values,
                        dataset_rows=dataset_rows,
                        row_index=row_index,
                        context=eval_context,
                    )
                return value
            if isinstance(value, list):
                return [walk(v) for v in value]
            if isinstance(value, dict):
                return {k: walk(v) for k, v in value.items()}
            return value

        return walk(obj)

    def _transform_custom_fields(
        self,
        data: list,
        config: dict,
        custom_specs: List[dict],
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        include_source = bool(config.get("custom_include_source_fields", True))
        primary_key_field = str(
            config.get("custom_primary_key_field")
            or config.get("custom_group_by_field")
            or ""
        ).strip()
        profile_enabled = bool(config.get("custom_profile_enabled", False))
        profile_storage_for_override = self._normalize_profile_storage(
            config.get("custom_profile_storage", "lmdb")
        )
        profile_lmdb_env_path_override = str(
            config.get("custom_profile_lmdb_env_path") or ""
        ).strip()
        if profile_enabled and profile_storage_for_override == "lmdb" and profile_lmdb_env_path_override:
            self._runtime_profile_lmdb_dir_override = profile_lmdb_env_path_override
        else:
            self._runtime_profile_lmdb_dir_override = None
        profile_processing_mode = str(config.get("custom_profile_processing_mode") or "batch").strip().lower()
        if profile_processing_mode not in {"batch", "incremental", "incremental_batch"}:
            profile_processing_mode = "batch"
        is_profile_incremental_mode = profile_processing_mode in {"incremental", "incremental_batch"}
        is_profile_incremental_batch_mode = profile_processing_mode == "incremental_batch"
        profile_emit_mode = str(config.get("custom_profile_emit_mode") or "changed_only").strip().lower()
        if profile_emit_mode not in {"changed_only", "all_entities"}:
            profile_emit_mode = "changed_only"
        profile_required_fields = self._parse_selected_fields(config.get("custom_profile_required_fields", ""))
        profile_event_time_field = str(config.get("custom_profile_event_time_field") or "").strip()
        profile_default_windows = self._parse_profile_windows(config.get("custom_profile_window_days"), [1, 7, 30])
        try:
            profile_retention_days = int(config.get("custom_profile_retention_days", 45))
        except Exception:
            profile_retention_days = 45
        if profile_retention_days <= 0:
            profile_retention_days = 45
        profile_include_change_fields = bool(config.get("custom_profile_include_change_fields", False))
        expression_engine_requested = str(config.get("custom_expression_engine") or "auto").strip().lower()
        if expression_engine_requested not in {"auto", "python", "polars"}:
            expression_engine_requested = "auto"
        expression_engine_active = "python"
        custom_fns_version_requested = str(config.get("custom_fns_version") or "v1").strip().lower()
        if custom_fns_version_requested not in {"v1", "v2"}:
            custom_fns_version_requested = "v1"
        raw_fns_v2_enabled = str(os.getenv("FNS_V2_ENABLED", "0")).strip().lower()
        fns_v2_enabled_global = bool(getattr(self, "_fns_v2_enabled", False)) or raw_fns_v2_enabled in {
            "1", "true", "yes", "on", "y",
        }
        custom_fns_version_active = (
            "v2"
            if custom_fns_version_requested == "v2" and fns_v2_enabled_global
            else "v1"
        )
        raw_fns_v2_row_gate_env = str(
            os.getenv("FNS_V2_ROW_GATE_DEDUPE_ENABLED", "0")
        ).strip().lower()
        fns_v2_row_gate_enabled_global = raw_fns_v2_row_gate_env in {
            "1", "true", "yes", "on", "y",
        }
        row_gate_cfg_raw = config.get("custom_fns_v2_row_gate_dedupe_enabled")
        if row_gate_cfg_raw is None:
            custom_fns_v2_row_gate_dedupe_enabled = fns_v2_row_gate_enabled_global
        elif isinstance(row_gate_cfg_raw, bool):
            custom_fns_v2_row_gate_dedupe_enabled = row_gate_cfg_raw
        elif isinstance(row_gate_cfg_raw, (int, float)):
            custom_fns_v2_row_gate_dedupe_enabled = row_gate_cfg_raw != 0
        elif isinstance(row_gate_cfg_raw, str):
            custom_fns_v2_row_gate_dedupe_enabled = row_gate_cfg_raw.strip().lower() in {
                "1", "true", "yes", "on", "y",
            }
        else:
            custom_fns_v2_row_gate_dedupe_enabled = fns_v2_row_gate_enabled_global
        if custom_fns_version_active != "v2":
            custom_fns_v2_row_gate_dedupe_enabled = False

        result: list = []
        warning_count = 0
        node_warnings: Optional[List[str]] = None
        if isinstance(execution_context, dict):
            existing_warnings = execution_context.get("node_warnings")
            if isinstance(existing_warnings, list):
                node_warnings = existing_warnings
        emit_node_progress = (
            execution_context.get("emit_node_progress")
            if isinstance(execution_context, dict) and callable(execution_context.get("emit_node_progress"))
            else None
        )
        should_abort_cb = (
            execution_context.get("should_abort")
            if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )
        try:
            node_progress_every = int(
                (execution_context or {}).get("node_progress_every", 2000)
            ) if isinstance(execution_context, dict) else 2000
        except Exception:
            node_progress_every = 2000
        node_progress_every = max(1, min(node_progress_every, 50000))
        if is_profile_incremental_mode:
            # Time-driven progress emits are enough for live UX.
            # Keep row-driven checks coarse for throughput.
            node_progress_every = max(500, min(node_progress_every, 5000))
        abort_check_every = 100 if is_profile_incremental_mode else 25

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        def _record_custom_field_warning(message: str) -> None:
            nonlocal warning_count
            text = str(message or "").strip()
            if not text:
                return
            if isinstance(node_warnings, list) and len(node_warnings) < 200:
                node_warnings.append(text)
            if warning_count < 5:
                logger.warning(text)
            warning_count += 1

        if custom_fns_version_requested == "v2" and not fns_v2_enabled_global:
            _record_custom_field_warning(
                "Custom FNS version requested as v2, but FNS_V2_ENABLED is false. Falling back to v1."
            )

        if expression_engine_requested == "polars":
            if _pl is None:
                _record_custom_field_warning(
                    "Polars expression engine was selected but Polars is not installed. "
                    "Falling back to Python engine."
                )
            elif profile_enabled:
                _record_custom_field_warning(
                    "Polars expression engine was selected, but profile/document incremental mode "
                    "currently runs on Python engine for full function compatibility."
                )
            else:
                _record_custom_field_warning(
                    "Polars expression engine was selected. Compatibility path is active; "
                    "Python evaluator is used for full expression-function support."
                )

        base_rows: List[Dict[str, Any]] = [
            row if isinstance(row, dict) else {"value": row}
            for row in data
        ]
        _raise_if_aborted()

        if profile_enabled and not primary_key_field:
            _record_custom_field_warning(
                "Custom profile/document mode requires Primary Key / Group By field. Falling back to regular custom fields mode."
            )
            profile_enabled = False

        if profile_enabled:
            node_id = str((execution_context or {}).get("node_id") or "map_transform")
            pipeline_id_for_profile = str((execution_context or {}).get("pipeline_id") or "").strip()
            profile_storage = self._normalize_profile_storage(
                config.get("custom_profile_storage", "lmdb")
            )
            profile_oracle_cfg: Optional[Dict[str, Any]] = None
            profile_oracle_session: Optional[Dict[str, Any]] = None
            if profile_storage == "oracle":
                context_oracle_cfg = (
                    (execution_context or {}).get("profile_oracle_cfg")
                    if isinstance((execution_context or {}).get("profile_oracle_cfg"), dict)
                    else None
                )
                profile_oracle_cfg = context_oracle_cfg or {
                    "custom_profile_oracle_host": config.get("custom_profile_oracle_host"),
                    "custom_profile_oracle_port": config.get("custom_profile_oracle_port"),
                    "custom_profile_oracle_service_name": config.get("custom_profile_oracle_service_name"),
                    "custom_profile_oracle_sid": config.get("custom_profile_oracle_sid"),
                    "custom_profile_oracle_user": config.get("custom_profile_oracle_user"),
                    "custom_profile_oracle_password": config.get("custom_profile_oracle_password"),
                    "custom_profile_oracle_dsn": config.get("custom_profile_oracle_dsn"),
                    "custom_profile_oracle_table": config.get("custom_profile_oracle_table"),
                    "custom_profile_oracle_write_strategy": config.get("custom_profile_oracle_write_strategy"),
                    "custom_profile_oracle_parallel_workers": config.get("custom_profile_oracle_parallel_workers"),
                    "custom_profile_oracle_parallel_min_tokens": config.get("custom_profile_oracle_parallel_min_tokens"),
                    "custom_profile_oracle_merge_batch_size": config.get("custom_profile_oracle_merge_batch_size"),
                    "custom_profile_oracle_parallel_force": config.get("custom_profile_oracle_parallel_force"),
                }
                context_oracle_session = (execution_context or {}).get("profile_oracle_session")
                if isinstance(context_oracle_session, dict):
                    profile_oracle_session = context_oracle_session
            profile_state_by_node = (
                (execution_context or {}).get("profile_state_by_node")
                if isinstance((execution_context or {}).get("profile_state_by_node"), dict)
                else None
            )
            node_profile_store: Dict[str, Any]
            if isinstance(profile_state_by_node, dict):
                existing_node_state = profile_state_by_node.get(node_id)
                if not isinstance(existing_node_state, dict):
                    existing_node_state = {}
                    profile_state_by_node[node_id] = existing_node_state
                node_profile_store = existing_node_state
            else:
                node_profile_store = {}
            profile_backfill_enabled = False
            profile_backfill_missing_tokens: set = set()
            profile_backfill_existing_tokens: Optional[set] = None
            profile_backfill_existing_tokens_complete = False
            oracle_backfill_preloaded_tokens = 0
            oracle_prefetched_docs: Dict[str, Dict[str, Any]] = {}
            oracle_prefetched_meta: Dict[str, Dict[str, Any]] = {}
            oracle_backfill_candidate_prefetch = False
            if pipeline_id_for_profile and is_profile_incremental_mode:
                profile_backfill_enabled = self._has_profile_state_for_node(
                    pipeline_id_for_profile,
                    node_id,
                    storage=profile_storage,
                    profile_cfg=profile_oracle_cfg,
                    oracle_session=profile_oracle_session,
                )
                if profile_backfill_enabled and profile_storage == "lmdb":
                    try:
                        max_index_tokens = int(
                            config.get("custom_profile_backfill_index_max_tokens")
                            or os.getenv("PROFILE_BACKFILL_INDEX_MAX_TOKENS", "300000")
                        )
                    except Exception:
                        max_index_tokens = 300000
                    max_index_tokens = max(10000, min(max_index_tokens, 2_000_000))
                    profile_backfill_existing_tokens = self._load_lmdb_profile_existing_entity_tokens(
                        pipeline_id_for_profile,
                        node_id,
                        max_tokens=max_index_tokens,
                    )
                    if isinstance(profile_backfill_existing_tokens, set):
                        profile_backfill_existing_tokens_complete = True
                elif profile_backfill_enabled and profile_storage == "oracle":
                    candidate_tokens: List[str] = []
                    candidate_seen: set = set()
                    for profile_row in base_rows:
                        row_obj = profile_row if isinstance(profile_row, dict) else {"value": profile_row}
                        pk_candidate, pk_found = self._extract_row_value_by_path(row_obj, primary_key_field)
                        if not pk_found or pk_candidate is None or str(pk_candidate).strip() == "":
                            continue
                        candidate_token = self._stable_json_token(pk_candidate)
                        if not candidate_token or candidate_token in candidate_seen:
                            continue
                        candidate_seen.add(candidate_token)
                        candidate_tokens.append(candidate_token)

                    if candidate_tokens:
                        try:
                            prefetch_chunk_size = int(
                                config.get("custom_profile_backfill_candidate_prefetch_chunk_size")
                                or os.getenv("PROFILE_BACKFILL_CANDIDATE_PREFETCH_CHUNK_SIZE", "500")
                            )
                        except Exception:
                            prefetch_chunk_size = 500
                        prefetch_chunk_size = max(50, min(prefetch_chunk_size, 900))
                        (
                            oracle_prefetched_docs,
                            oracle_prefetched_meta,
                            oracle_existing_tokens,
                        ) = self._load_oracle_profile_state_for_entity_tokens(
                            pipeline_id_for_profile,
                            node_id,
                            candidate_tokens,
                            profile_cfg=profile_oracle_cfg,
                            oracle_session=profile_oracle_session,
                            chunk_size=prefetch_chunk_size,
                        )
                        profile_backfill_existing_tokens = oracle_existing_tokens
                        profile_backfill_existing_tokens_complete = True
                        oracle_backfill_preloaded_tokens = len(oracle_existing_tokens)
                        oracle_backfill_candidate_prefetch = True

            documents_store = node_profile_store.get("documents")
            if not isinstance(documents_store, dict):
                documents_store = {}
                node_profile_store["documents"] = documents_store

            meta_store = node_profile_store.get("meta")
            if not isinstance(meta_store, dict):
                meta_store = {}
                node_profile_store["meta"] = meta_store

            if oracle_prefetched_docs:
                documents_store.update(oracle_prefetched_docs)
            if oracle_prefetched_meta:
                meta_store.update(oracle_prefetched_meta)

            # Oracle incremental optimization:
            # when existing token cardinality is manageable, preload node profile
            # state once and avoid per-entity backfill reads during row processing.
            if (
                profile_backfill_enabled
                and profile_storage == "oracle"
                and pipeline_id_for_profile
                and is_profile_incremental_mode
                and isinstance(profile_backfill_existing_tokens, set)
                and not oracle_backfill_candidate_prefetch
            ):
                try:
                    preload_max_tokens = int(
                        config.get("custom_profile_backfill_preload_max_tokens")
                        or os.getenv("PROFILE_BACKFILL_PRELOAD_MAX_TOKENS_ORACLE")
                        or os.getenv("PROFILE_BACKFILL_PRELOAD_MAX_TOKENS", "300000")
                    )
                except Exception:
                    preload_max_tokens = 300000
                preload_max_tokens = max(0, min(preload_max_tokens, 2_000_000))
                if (
                    preload_max_tokens > 0
                    and len(profile_backfill_existing_tokens) > 0
                    and len(profile_backfill_existing_tokens) <= preload_max_tokens
                ):
                    preloaded_state = self._load_oracle_profile_state_for_node(
                        pipeline_id_for_profile,
                        node_id,
                        profile_cfg=profile_oracle_cfg,
                    )
                    preloaded_docs = (
                        preloaded_state.get("documents")
                        if isinstance(preloaded_state, dict)
                        else None
                    )
                    preloaded_meta = (
                        preloaded_state.get("meta")
                        if isinstance(preloaded_state, dict)
                        else None
                    )
                    if isinstance(preloaded_docs, dict) and preloaded_docs:
                        documents_store.update(preloaded_docs)
                        oracle_backfill_preloaded_tokens = len(preloaded_docs)
                    if isinstance(preloaded_meta, dict) and preloaded_meta:
                        meta_store.update(preloaded_meta)

            changed_tokens: List[str] = []
            changed_token_set: set = set()
            changed_fields_by_token: Dict[str, List[str]] = {}
            seen_entity_tokens: List[str] = []
            seen_entity_set: set = set()
            seen_entity_count = 0
            entity_value_by_token: Dict[str, Any] = {}
            last_source_by_token: Dict[str, Dict[str, Any]] = {}
            live_persist_warning_emitted = False
            append_unique_state_by_token: Dict[str, Dict[str, Dict[str, Any]]] = {}
            append_unique_cache_mode = str(
                config.get("custom_profile_append_unique_cache_mode") or "auto"
            ).strip().lower()
            if append_unique_cache_mode not in {"auto", "persistent", "row_local"}:
                append_unique_cache_mode = "auto"
            # Incremental profile throughput:
            # keep append_unique cache persistent by default for incremental_batch,
            # and for external profile stores in incremental mode. Auto row-local
            # switching can degrade heavily once profile cardinality grows.
            if append_unique_cache_mode == "auto":
                if profile_processing_mode == "incremental_batch":
                    append_unique_cache_mode = "persistent"
                elif (
                    profile_processing_mode == "incremental"
                    and profile_storage in {"rocksdb", "oracle", "redis"}
                ):
                    append_unique_cache_mode = "persistent"
            append_unique_persistent_cache_enabled = append_unique_cache_mode != "row_local"
            append_unique_cache_prune_warning_emitted = False
            append_unique_cache_row_local_warning_emitted = False
            append_unique_token_last_seen: Dict[str, int] = {}
            append_unique_disable_min_rows_cfg = config.get(
                "custom_profile_append_unique_cache_disable_min_rows",
                None,
            )
            append_unique_cache_disable_min_rows = max(
                1000,
                int(
                    append_unique_disable_min_rows_cfg
                    if append_unique_disable_min_rows_cfg is not None
                    and str(append_unique_disable_min_rows_cfg).strip() != ""
                    else os.getenv(
                        "PROFILE_APPEND_UNIQUE_CACHE_DISABLE_MIN_ROWS",
                        "20000",
                    )
                ),
            )
            append_unique_entity_limit_cfg = config.get(
                "custom_profile_append_unique_cache_entity_limit",
                None,
            )
            append_unique_cache_entity_limit = max(
                1000,
                int(
                    append_unique_entity_limit_cfg
                    if append_unique_entity_limit_cfg is not None
                    and str(append_unique_entity_limit_cfg).strip() != ""
                    else os.getenv(
                        "PROFILE_APPEND_UNIQUE_CACHE_ENTITY_LIMIT",
                        "40000",
                    )
                ),
            )
            append_unique_disable_ratio_cfg = config.get(
                "custom_profile_append_unique_cache_disable_ratio",
                None,
            )
            try:
                append_unique_cache_disable_ratio = float(
                    append_unique_disable_ratio_cfg
                    if append_unique_disable_ratio_cfg is not None
                    and str(append_unique_disable_ratio_cfg).strip() != ""
                    else os.getenv(
                        "PROFILE_APPEND_UNIQUE_CACHE_DISABLE_RATIO",
                        "0.65",
                    )
                )
            except Exception:
                append_unique_cache_disable_ratio = 0.65
            append_unique_cache_disable_ratio = max(0.0, min(append_unique_cache_disable_ratio, 1.0))
            stats_store = node_profile_store.get("stats")
            if not isinstance(stats_store, dict):
                stats_store = {}
                node_profile_store["stats"] = stats_store
            stats_store["custom_fields_expression_engine_requested"] = expression_engine_requested
            stats_store["custom_fields_expression_engine_active"] = expression_engine_active
            stats_store["custom_fields_fns_version_requested"] = custom_fns_version_requested
            stats_store["custom_fields_fns_version_active"] = custom_fns_version_active
            stats_store["custom_fields_fns_v2_dedupe_key_field"] = str(
                config.get("custom_fns_v2_dedupe_key_field") or ""
            ).strip()
            stats_store["custom_fields_fns_v2_on_duplicate"] = str(
                config.get("custom_fns_v2_on_duplicate") or "ignore"
            ).strip().lower()
            stats_store["custom_fields_fns_v2_normalize"] = str(
                config.get("custom_fns_v2_normalize") or "upper_trim"
            ).strip().lower()
            stats_store["custom_fields_fns_v2_invalid_key"] = str(
                config.get("custom_fns_v2_invalid_key") or "skip"
            ).strip().lower()
            stats_store["custom_fields_fns_v2_row_gate_dedupe_enabled"] = bool(
                custom_fns_v2_row_gate_dedupe_enabled
            )
            if (
                custom_fns_v2_row_gate_dedupe_enabled
                and custom_fns_version_active == "v2"
                and not str(config.get("custom_fns_v2_dedupe_key_field") or "").strip()
            ):
                _record_custom_field_warning(
                    "FNS v2 row-level dedupe gate is enabled, but dedupe key field is empty. "
                    "Falling back to per-function dedupe."
                )
            stats_store["custom_fields_append_unique_cache_mode"] = (
                "persistent" if append_unique_persistent_cache_enabled else "row_local"
            )
            stats_store["custom_fields_backfill_index_enabled"] = isinstance(
                profile_backfill_existing_tokens,
                set,
            )
            stats_store["custom_fields_backfill_index_tokens"] = (
                len(profile_backfill_existing_tokens)
                if isinstance(profile_backfill_existing_tokens, set)
                else 0
            )
            stats_store["custom_fields_oracle_backfill_preloaded_tokens"] = int(
                oracle_backfill_preloaded_tokens
            )
            total_input_rows = len(base_rows)
            emit_incremental_rows = bool(total_input_rows <= 5000)
            emit_incremental_rows_cfg = config.get("custom_profile_emit_incremental_rows")
            if emit_incremental_rows_cfg is not None:
                emit_incremental_rows = bool(emit_incremental_rows_cfg)
            incremental_processed_rows = 0
            incremental_validated_rows = 0
            incremental_pending_flush_updates = 0
            incremental_pending_tokens: set = set()
            incremental_flush_count = 0
            last_progress_emit_at = 0.0
            last_profile_flush_at = pytime.monotonic()
            if is_profile_incremental_batch_mode:
                # "Incremental Batch" mode: chunked durability (faster than per-row).
                default_flush_every_rows = 20000
                default_flush_interval_seconds = 2.0
            else:
                default_flush_every_rows = 200 if total_input_rows <= 5000 else 2000
                default_flush_interval_seconds = 1.0 if total_input_rows <= 5000 else 3.0
            flush_every_rows_cfg = config.get("custom_profile_flush_every_rows", None)
            try:
                if flush_every_rows_cfg is not None and str(flush_every_rows_cfg).strip() != "":
                    incremental_flush_every_rows = int(flush_every_rows_cfg)
                else:
                    incremental_flush_every_rows = int(
                        os.getenv("PROFILE_INCREMENTAL_FLUSH_EVERY_ROWS", default_flush_every_rows)
                    )
            except Exception:
                incremental_flush_every_rows = default_flush_every_rows
            if is_profile_incremental_batch_mode:
                incremental_flush_every_rows = max(100, min(incremental_flush_every_rows, 20000))
            else:
                incremental_flush_every_rows = max(1, min(incremental_flush_every_rows, 100000))
            flush_interval_seconds_cfg = config.get("custom_profile_flush_interval_seconds", None)
            try:
                if flush_interval_seconds_cfg is not None and str(flush_interval_seconds_cfg).strip() != "":
                    incremental_flush_interval_seconds = float(flush_interval_seconds_cfg)
                else:
                    incremental_flush_interval_seconds = float(
                        os.getenv("PROFILE_INCREMENTAL_FLUSH_INTERVAL_SECONDS", default_flush_interval_seconds)
                    )
            except Exception:
                incremental_flush_interval_seconds = default_flush_interval_seconds
            if is_profile_incremental_batch_mode:
                incremental_flush_interval_seconds = max(0.5, min(incremental_flush_interval_seconds, 10.0))
                # For KV stores, default to compute-first + terminal persist (faster and
                # similar to deferred persist behavior). Keep Oracle live by default.
                default_live_persist = bool(profile_storage == "oracle")
                live_persist_enabled = bool(
                    config.get("custom_profile_live_persist", default_live_persist)
                )
            else:
                incremental_flush_interval_seconds = max(0.1, min(incremental_flush_interval_seconds, 30.0))
                live_persist_enabled = bool(total_input_rows <= 10000)
            # Oracle profile mode must be visible during runtime (fields created/updated live).
            # Keep a single session per node, but commit on each configured flush boundary.
            oracle_live_commit_enabled = bool(profile_storage == "oracle")
            if is_profile_incremental_mode and oracle_live_commit_enabled:
                live_persist_enabled = True

            def _flush_incremental_profile_state(force: bool = False) -> None:
                nonlocal incremental_pending_flush_updates, incremental_pending_tokens
                nonlocal incremental_flush_count, last_profile_flush_at
                nonlocal live_persist_warning_emitted
                if not is_profile_incremental_mode:
                    return
                if not (
                    pipeline_id_for_profile
                    and isinstance(profile_state_by_node, dict)
                ):
                    return
                if incremental_pending_flush_updates <= 0 and not force:
                    return
                if not force and not live_persist_enabled:
                    return
                now = pytime.monotonic()
                due_rows = incremental_pending_flush_updates >= incremental_flush_every_rows
                due_time = (now - last_profile_flush_at) >= incremental_flush_interval_seconds
                if not force and not due_rows and not due_time:
                    return

                _raise_if_aborted()
                node_state_for_flush = profile_state_by_node.get(node_id)
                if not isinstance(node_state_for_flush, dict):
                    return
                oracle_auto_commit_for_flush = (
                    oracle_live_commit_enabled
                    or not isinstance(profile_oracle_session, dict)
                )
                if profile_storage == "oracle":
                    resolved_oracle_cfg = self._resolve_profile_oracle_config(profile_oracle_cfg)
                    oracle_strategy = self._normalize_oracle_profile_write_strategy(
                        resolved_oracle_cfg.get("write_strategy")
                    )
                    try:
                        oracle_min_tokens = int(resolved_oracle_cfg.get("parallel_min_tokens") or 2000)
                    except Exception:
                        oracle_min_tokens = 2000
                    oracle_min_tokens = max(1, min(oracle_min_tokens, 1_000_000))
                    oracle_parallel_force = bool(resolved_oracle_cfg.get("parallel_force", False))
                    pending_token_count = len(incremental_pending_tokens)
                    oracle_parallel_eligible = bool(
                        oracle_strategy == "parallel_key"
                        and oracle_auto_commit_for_flush
                        and (
                            oracle_parallel_force
                            or pending_token_count >= oracle_min_tokens
                        )
                    )
                    try:
                        oracle_merge_batch = int(resolved_oracle_cfg.get("merge_batch_size") or 500)
                    except Exception:
                        oracle_merge_batch = 500
                    oracle_merge_batch = max(50, min(oracle_merge_batch, 2000))
                    try:
                        oracle_workers_cfg = int(resolved_oracle_cfg.get("parallel_workers") or 4)
                    except Exception:
                        oracle_workers_cfg = 4
                    oracle_workers_cfg = max(2, min(oracle_workers_cfg, 16))
                    oracle_workers_effective = min(
                        oracle_workers_cfg,
                        max(1, int(math.ceil(float(pending_token_count) / float(max(1, oracle_merge_batch)))))
                    )
                    oracle_parallel_eligible = bool(
                        oracle_parallel_eligible and oracle_workers_effective >= 2
                    )
                    stats_store["custom_fields_oracle_parallel_strategy"] = oracle_strategy
                    stats_store["custom_fields_oracle_parallel_min_tokens"] = int(oracle_min_tokens)
                    stats_store["custom_fields_oracle_parallel_pending_tokens"] = int(pending_token_count)
                    stats_store["custom_fields_oracle_parallel_workers_configured"] = int(oracle_workers_cfg)
                    stats_store["custom_fields_oracle_parallel_workers_effective"] = int(oracle_workers_effective)
                    stats_store["custom_fields_oracle_merge_batch_size"] = int(oracle_merge_batch)
                    stats_store["custom_fields_oracle_parallel_force"] = bool(oracle_parallel_force)
                    stats_store["custom_fields_oracle_parallel_last_flush_eligible"] = bool(oracle_parallel_eligible)
                flushed = self._save_profile_state_single_node_by_storage(
                    pipeline_id_for_profile,
                    node_id,
                    node_state_for_flush,
                    changed_tokens=list(incremental_pending_tokens),
                    storage=profile_storage,
                    profile_cfg=profile_oracle_cfg,
                    oracle_session=profile_oracle_session,
                    oracle_auto_commit=oracle_auto_commit_for_flush,
                )
                # Oracle fallback: if shared-session flush failed, retry once
                # using a fresh independent session/transaction so profile docs
                # can still be persisted during runtime.
                if not flushed and profile_storage == "oracle":
                    flushed = self._save_profile_state_single_node_by_storage(
                        pipeline_id_for_profile,
                        node_id,
                        node_state_for_flush,
                        changed_tokens=list(incremental_pending_tokens),
                        storage=profile_storage,
                        profile_cfg=profile_oracle_cfg,
                        oracle_session=None,
                        oracle_auto_commit=True,
                    )
                if flushed:
                    incremental_pending_flush_updates = 0
                    incremental_pending_tokens.clear()
                    incremental_flush_count += 1
                    last_profile_flush_at = now
                    stats_store["custom_fields_incremental_last_flush_at"] = datetime.utcnow().isoformat()
                elif not live_persist_warning_emitted:
                    live_persist_warning_emitted = True
                    _record_custom_field_warning(
                        "Incremental profile live persist failed; final profile-store save will be attempted at pipeline end."
                    )
                if force and not flushed and profile_storage == "oracle":
                    raise RuntimeError(
                        "Oracle profile incremental flush failed. JSON profile document was not persisted. "
                        "Check Oracle profile config/table privileges and node warnings."
                    )

            def _emit_profile_progress(
                force: bool = False,
                emit_progress_event: bool = True,
            ) -> None:
                nonlocal incremental_processed_rows, incremental_validated_rows, last_progress_emit_at
                now = pytime.monotonic()
                should_emit_by_rows = (incremental_processed_rows % node_progress_every == 0)
                should_emit_by_time = (now - last_progress_emit_at) >= 2.0
                if not force and not should_emit_by_rows and not should_emit_by_time:
                    return
                _raise_if_aborted()
                last_progress_emit_at = now
                stats_store["custom_fields_incremental_processed_rows"] = int(incremental_processed_rows)
                stats_store["custom_fields_incremental_validated_rows"] = int(incremental_validated_rows)
                stats_store["custom_fields_incremental_output_rows"] = int(len(result))
                stats_store["custom_fields_incremental_pending_flush_updates"] = int(incremental_pending_flush_updates)
                stats_store["custom_fields_incremental_flush_count"] = int(incremental_flush_count)
                stats_store["custom_fields_incremental_last_updated_at"] = datetime.utcnow().isoformat()
                stats_store["custom_fields_append_unique_cache_entries"] = int(
                    len(append_unique_state_by_token)
                ) if append_unique_persistent_cache_enabled else 0
                stats_store["custom_fields_append_unique_cache_mode"] = (
                    "persistent" if append_unique_persistent_cache_enabled else "row_local"
                )
                if emit_node_progress and is_profile_incremental_mode and emit_progress_event:
                    progress_pct = (
                        100.0
                        if total_input_rows <= 0
                        else min(100.0, (float(incremental_processed_rows) / float(total_input_rows)) * 100.0)
                    )
                    try:
                        emit_node_progress({
                            "processed_rows": int(incremental_processed_rows),
                            "validated_rows": int(incremental_validated_rows),
                            "output_rows": int(len(result)),
                            "message": (
                                f"⟳ Running {str((execution_context or {}).get('node_label') or 'Custom Fields')}… "
                                f"incremental {incremental_processed_rows:,}/{total_input_rows:,} processed "
                                f"({progress_pct:.1f}%) "
                                f"| validated={incremental_validated_rows:,} | output={len(result):,}"
                            ),
                        })
                    except Exception:
                        pass

            for row_idx, base_row in enumerate(base_rows):
                if row_idx == 0 or row_idx % abort_check_every == 0:
                    _raise_if_aborted()
                incremental_processed_rows += 1
                row_obj = base_row if isinstance(base_row, dict) else {"value": base_row}
                row_extract_cache: Dict[str, Tuple[Any, bool]] = {}

                def _row_extract(path: Any) -> Tuple[Any, bool]:
                    path_key = str(path or "").strip()
                    if not path_key:
                        return None, False
                    cached = row_extract_cache.get(path_key)
                    if cached is not None:
                        return cached
                    resolved = self._extract_row_value_by_path(row_obj, path_key)
                    row_extract_cache[path_key] = resolved
                    return resolved

                pk_value, pk_found = _row_extract(primary_key_field)
                if not pk_found or pk_value is None or str(pk_value).strip() == "":
                    _record_custom_field_warning(
                        f"Custom profile row {row_idx + 1} skipped: missing entity key field '{primary_key_field}'."
                    )
                    _emit_profile_progress()
                    continue

                missing_required: List[str] = []
                for required_field in profile_required_fields:
                    req_value, req_found = _row_extract(required_field)
                    if not req_found or req_value is None or str(req_value).strip() == "":
                        missing_required.append(required_field)
                if missing_required:
                    _record_custom_field_warning(
                        f"Custom profile row {row_idx + 1} skipped: missing required fields {', '.join(missing_required)}."
                    )
                    _emit_profile_progress()
                    continue
                incremental_validated_rows += 1

                token = self._stable_json_token(pk_value)
                if token not in seen_entity_set:
                    seen_entity_set.add(token)
                    seen_entity_tokens.append(token)
                    seen_entity_count += 1
                entity_value_by_token[token] = pk_value
                if include_source:
                    last_source_by_token[token] = row_obj

                if (
                    append_unique_persistent_cache_enabled
                    and append_unique_cache_mode == "auto"
                    and incremental_processed_rows >= append_unique_cache_disable_min_rows
                    and incremental_processed_rows % 1000 == 0
                ):
                    distinct_ratio = (
                        float(seen_entity_count) / float(incremental_processed_rows)
                        if incremental_processed_rows > 0
                        else 0.0
                    )
                    avg_rows_per_entity = (
                        float(incremental_processed_rows) / float(max(1, seen_entity_count))
                    )
                    # High-cardinality + low-reuse streams (for example PK=CUSTACCOUNTNUMBER)
                    # perform better with row-local append_unique state.
                    if (
                        distinct_ratio >= append_unique_cache_disable_ratio
                        and avg_rows_per_entity <= 1.35
                        and seen_entity_count >= append_unique_cache_entity_limit
                    ):
                        append_unique_persistent_cache_enabled = False
                        append_unique_state_by_token.clear()
                        append_unique_token_last_seen.clear()
                        stats_store["custom_fields_append_unique_cache_mode"] = "row_local"
                        stats_store["custom_fields_append_unique_cache_switched_at_row"] = int(incremental_processed_rows)
                        stats_store["custom_fields_append_unique_cache_switched_reason"] = (
                            f"high-cardinality low-reuse stream "
                            f"(distinct_ratio={distinct_ratio:.3f}, avg_rows_per_entity={avg_rows_per_entity:.3f})"
                        )
                        if not append_unique_cache_row_local_warning_emitted:
                            append_unique_cache_row_local_warning_emitted = True
                            _record_custom_field_warning(
                                "Custom profile optimization: switched append_unique cache to row-local mode "
                                "for high-cardinality low-reuse stream."
                            )
                    elif len(append_unique_state_by_token) > append_unique_cache_entity_limit:
                        prune_fraction = max(0.05, min(0.5, append_unique_cache_disable_ratio))
                        prune_target = max(
                            256,
                            min(
                                int(max(1, append_unique_cache_entity_limit) * prune_fraction),
                                max(512, append_unique_cache_entity_limit // 2),
                            ),
                        )
                        removed = 0
                        for stale_token, _ in sorted(
                            append_unique_token_last_seen.items(),
                            key=lambda item: item[1],
                        ):
                            if stale_token == token:
                                continue
                            if stale_token in append_unique_state_by_token:
                                append_unique_state_by_token.pop(stale_token, None)
                                append_unique_token_last_seen.pop(stale_token, None)
                                removed += 1
                            if (
                                removed >= prune_target
                                or len(append_unique_state_by_token) <= append_unique_cache_entity_limit
                            ):
                                break
                        if removed > 0:
                            stats_store["custom_fields_append_unique_cache_pruned_at_row"] = int(incremental_processed_rows)
                            stats_store["custom_fields_append_unique_cache_pruned_entries"] = int(removed)
                            stats_store["custom_fields_append_unique_cache_entries"] = int(len(append_unique_state_by_token))
                            if not append_unique_cache_prune_warning_emitted:
                                append_unique_cache_prune_warning_emitted = True
                                _record_custom_field_warning(
                                    "Custom profile optimization: append_unique cache is high-cardinality; "
                                    "applying LRU pruning to keep throughput stable."
                                )

                previous_doc = documents_store.get(token)
                previous_meta = meta_store.get(token)
                if (
                    profile_backfill_enabled
                    and token not in profile_backfill_missing_tokens
                    and (not isinstance(previous_doc, dict) or not isinstance(previous_meta, dict))
                    and (pipeline_id_for_profile and is_profile_incremental_mode)
                ):
                    if (
                        isinstance(profile_backfill_existing_tokens, set)
                        and profile_backfill_existing_tokens_complete
                        and token not in profile_backfill_existing_tokens
                    ):
                        profile_backfill_missing_tokens.add(token)
                    else:
                        loaded_doc, loaded_meta = self._load_profile_state_single_entity(
                            pipeline_id_for_profile,
                            node_id,
                            token,
                            storage=profile_storage,
                            profile_cfg=profile_oracle_cfg,
                            oracle_session=profile_oracle_session,
                        )
                        if isinstance(loaded_doc, dict) and loaded_doc:
                            previous_doc = loaded_doc
                            documents_store[token] = loaded_doc
                        if isinstance(loaded_meta, dict) and loaded_meta:
                            previous_meta = loaded_meta
                            meta_store[token] = loaded_meta
                        if not loaded_doc and not loaded_meta:
                            profile_backfill_missing_tokens.add(token)
                is_new = not isinstance(previous_doc, dict)
                if not isinstance(previous_doc, dict):
                    previous_doc = {}
                if not isinstance(previous_meta, dict):
                    previous_meta = {}

                # Performance-critical path:
                # keep profile/doc updates incremental and in-place per entity
                # instead of deep-copying full documents on every incoming row.
                working_doc: Dict[str, Any] = previous_doc
                working_meta: Dict[str, Any] = previous_meta
                custom_values: Dict[str, Any] = {}
                changed_fields: List[str] = []
                profile_meta_touched = False
                append_unique_cache: Dict[str, Dict[str, Any]]
                if append_unique_persistent_cache_enabled:
                    append_unique_cache = append_unique_state_by_token.setdefault(token, {})
                    append_unique_token_last_seen[token] = incremental_processed_rows
                else:
                    append_unique_cache = {}

                event_time_value = None
                if profile_event_time_field:
                    event_time_value, _ = _row_extract(profile_event_time_field)
                if event_time_value is None:
                    for fallback_time_field in (
                        "txn_time",
                        "transaction_time",
                        "timestamp",
                        "created_at",
                        "updated_at",
                        "SERVERTIME",
                        "TXNDATE",
                    ):
                        fallback_value, found = _row_extract(fallback_time_field)
                        if found and fallback_value is not None and str(fallback_value).strip() != "":
                            event_time_value = fallback_value
                            break
                current_event_dt = self._parse_profile_event_time(event_time_value) or datetime.utcnow()
                current_event_time = current_event_dt.strftime("%Y-%m-%d %H:%M:%S")
                active_profile_field: Dict[str, str] = {"name": "", "mode": "value"}
                _missing = object()
                profile_prev_cache: Dict[str, Any] = {}
                profile_object_path_index: Dict[int, str] = {}

                def _resolve_profile_path(path: Any) -> str:
                    path_text = str(path or "").strip()
                    if not path_text:
                        return path_text

                    # In JSON profile templates, allow shorthand paths:
                    # append_unique('ids', x) will map to "<field_name>.ids".
                    mode = str(active_profile_field.get("mode") or "value").strip().lower()
                    field_name = str(active_profile_field.get("name") or "").strip()
                    if mode != "json" or not field_name:
                        return path_text
                    if path_text == field_name or path_text.startswith(f"{field_name}."):
                        return path_text
                    if path_text in custom_values:
                        return path_text
                    existing_root = self._get_profile_path_value(working_doc, path_text, _missing)
                    if existing_root is not _missing:
                        return path_text
                    scoped = f"{field_name}.{path_text}"
                    existing_scoped = self._get_profile_path_value(working_doc, scoped, _missing)
                    if existing_scoped is not _missing:
                        return scoped
                    return scoped

                def _profile_prev(path: Any = None, default: Any = None) -> Any:
                    if path is None or str(path).strip() == "":
                        cache_key = "__doc__"
                        if cache_key in profile_prev_cache:
                            cached_doc = profile_prev_cache.get(cache_key)
                            return dict(cached_doc) if isinstance(cached_doc, dict) else cached_doc
                        doc_value = dict(working_doc)
                        profile_prev_cache[cache_key] = doc_value
                        return dict(doc_value)

                    path_text = _resolve_profile_path(path)
                    if path_text in profile_prev_cache:
                        cached_value = profile_prev_cache.get(path_text)
                        if isinstance(cached_value, dict):
                            profile_object_path_index[id(cached_value)] = path_text
                            return cached_value
                        if isinstance(cached_value, list):
                            profile_object_path_index[id(cached_value)] = path_text
                            return cached_value
                        return cached_value if cached_value is not None else default

                    if path_text in custom_values:
                        value = custom_values.get(path_text)
                    else:
                        value = self._get_profile_path_value(working_doc, path_text, None)
                    if value is None:
                        return default

                    if isinstance(value, dict):
                        resolved = _resolve_profile_dynamic_value(value, working_meta)
                        if isinstance(resolved, dict):
                            profile_prev_cache[path_text] = resolved
                            profile_object_path_index[id(resolved)] = path_text
                            return resolved
                        profile_prev_cache[path_text] = resolved
                        return resolved
                    if isinstance(value, list):
                        resolved = _resolve_profile_dynamic_value(value, working_meta)
                        if isinstance(resolved, list):
                            profile_prev_cache[path_text] = resolved
                            profile_object_path_index[id(resolved)] = path_text
                            return resolved
                        profile_prev_cache[path_text] = resolved
                        return resolved

                    profile_prev_cache[path_text] = value
                    return value

                def _num(value: Any, default: Any = 0) -> float:
                    n = self._to_number(value)
                    if n is not None:
                        return float(n)
                    d = self._to_number(default)
                    return float(d) if d is not None else 0.0

                def _safe_div(numerator: Any, denominator: Any, default: Any = None) -> Any:
                    den = self._to_number(denominator)
                    if den in (None, 0):
                        return default
                    num = self._to_number(numerator)
                    if num is None:
                        return default
                    return float(num) / float(den)

                def _inc(path_or_value: Any, amount: Any = 1, default: Any = 0) -> Any:
                    if isinstance(path_or_value, str):
                        base_value = _profile_prev(_resolve_profile_path(path_or_value), default)
                    else:
                        base_value = path_or_value
                    total = _num(base_value, default) + _num(amount, 0)
                    return int(total) if float(total).is_integer() else float(total)

                def _map_inc(path_or_map: Any, key: Any, amount: Any = 1, default: Any = 0) -> Dict[str, Any]:
                    if isinstance(path_or_map, str):
                        resolved_path = _resolve_profile_path(path_or_map)
                        base_map = self._get_profile_path_value(working_doc, resolved_path, _missing)
                        if base_map is _missing or not isinstance(base_map, dict):
                            base_map = {}
                    else:
                        base_map = path_or_map
                    current_map = base_map if isinstance(base_map, dict) else {}
                    map_key = str(key) if key is not None else "null"
                    current_value = current_map.get(map_key, default)
                    next_value = _num(current_value, default) + _num(amount, 0)
                    current_map[map_key] = int(next_value) if float(next_value).is_integer() else float(next_value)
                    return current_map

                def _append_unique(
                    path_or_values: Any,
                    value: Any = None,
                    max_items: Any = None,
                    normalize: Any = True,
                ) -> List[Any]:
                    normalize_items = True
                    if isinstance(normalize, bool):
                        normalize_items = normalize
                    elif isinstance(normalize, (int, float)):
                        normalize_items = normalize != 0
                    elif isinstance(normalize, str):
                        norm_flag = normalize.strip().lower()
                        if norm_flag in {"0", "false", "no", "off", "n"}:
                            normalize_items = False

                    def _candidate_value(raw: Any) -> Any:
                        candidate = self._json_safe_value(raw)
                        if normalize_items and isinstance(candidate, str):
                            candidate = candidate.strip()
                        return candidate

                    def _candidate_token(raw: Any) -> str:
                        candidate = _candidate_value(raw)
                        return self._stable_json_token(candidate)

                    if isinstance(path_or_values, str):
                        resolved_path = _resolve_profile_path(path_or_values)
                        cached_items_state = append_unique_cache.get(resolved_path)
                        if isinstance(cached_items_state, dict):
                            current_cached = cached_items_state.get("current")
                            seen_cached = cached_items_state.get("seen")
                            if isinstance(current_cached, list) and isinstance(seen_cached, set):
                                base_items_current = self._get_profile_path_value(working_doc, resolved_path, _missing)
                                if base_items_current is _missing:
                                    base_items_current = current_cached
                                if isinstance(base_items_current, list) and base_items_current is current_cached:
                                    current = current_cached
                                    seen = seen_cached
                                else:
                                    cached_items_state = None
                            else:
                                cached_items_state = None
                        if not isinstance(cached_items_state, dict):
                            base_items = self._get_profile_path_value(working_doc, resolved_path, _missing)
                        # Compatibility fallback:
                        # If expression path points to a parent JSON object path but the current
                        # custom field is a value field (for example name "_customer_ids" with path
                        # "CUSTOMER_INFO._customer_ids"), continue from current field state.
                            if base_items is _missing:
                                current_field_name = str(active_profile_field.get("name") or "").strip()
                                if current_field_name and current_field_name != resolved_path:
                                    fallback_value = self._get_profile_path_value(working_doc, current_field_name, _missing)
                                    if fallback_value is not _missing:
                                        base_items = fallback_value
                            if base_items is _missing:
                                base_items = []
                            current = list(base_items) if isinstance(base_items, list) else []
                            seen = {_candidate_token(v) for v in current}
                            append_unique_cache[resolved_path] = {"current": current, "seen": seen}
                        incoming_values = [value]
                    else:
                        # One-arg form append_unique(values(...)) should return a de-duplicated
                        # flattened list from the provided sequence.
                        if value is None:
                            base_items = []
                            incoming_values = [path_or_values]
                        else:
                            base_items = path_or_values
                            incoming_values = [value]
                        source_path = (
                            profile_object_path_index.get(id(base_items), "")
                            if isinstance(base_items, list)
                            else ""
                        )
                        if source_path:
                            resolved_path = _resolve_profile_path(source_path)
                            cached_items_state = append_unique_cache.get(resolved_path)
                            if isinstance(cached_items_state, dict):
                                current_cached = cached_items_state.get("current")
                                seen_cached = cached_items_state.get("seen")
                                if isinstance(current_cached, list) and isinstance(seen_cached, set):
                                    current = current_cached
                                    seen = seen_cached
                                else:
                                    cached_items_state = None
                            if not isinstance(cached_items_state, dict):
                                current = list(base_items) if isinstance(base_items, list) else []
                                seen = {_candidate_token(v) for v in current}
                                append_unique_cache[resolved_path] = {"current": current, "seen": seen}
                        else:
                            current = list(base_items) if isinstance(base_items, list) else []
                            seen = {_candidate_token(v) for v in current}
                    flattened_incoming = _flatten_profile_values(incoming_values)
                    for incoming in flattened_incoming:
                        if incoming is None:
                            continue
                        token_value = _candidate_token(incoming)
                        if token_value in seen:
                            continue
                        seen.add(token_value)
                        current.append(_candidate_value(incoming))
                    try:
                        cap = int(max_items) if max_items is not None else 0
                    except Exception:
                        cap = 0
                    if cap > 0 and len(current) > cap:
                        current = current[-cap:]
                        seen = {_candidate_token(v) for v in current}
                        if isinstance(path_or_values, str):
                            resolved_path = _resolve_profile_path(path_or_values)
                            append_unique_cache[resolved_path] = {"current": current, "seen": seen}
                    return current

                def _rolling_update(
                    name: Any,
                    value: Any,
                    txn_time: Any = None,
                    windows: Any = None,
                    retention_days: Any = None,
                ) -> Dict[str, Any]:
                    nonlocal profile_meta_touched
                    profile_meta_touched = True
                    metric_name = str(name or "").strip() or "value"
                    window_days = self._parse_profile_windows(windows, profile_default_windows)
                    try:
                        retention = int(retention_days) if retention_days is not None else profile_retention_days
                    except Exception:
                        retention = profile_retention_days
                    if retention <= 0:
                        retention = profile_retention_days
                    max_window = max(window_days) if window_days else 30
                    retention = max(retention, max_window)

                    rolling_root = working_meta.setdefault("rolling", {})
                    if not isinstance(rolling_root, dict):
                        rolling_root = {}
                        working_meta["rolling"] = rolling_root
                    raw_stream = rolling_root.get(metric_name)
                    stream: List[Dict[str, Any]] = []
                    if isinstance(raw_stream, list):
                        for item in raw_stream:
                            if not isinstance(item, dict):
                                continue
                            ts = self._parse_profile_event_time(item.get("ts"))
                            if ts is None:
                                continue
                            stream.append({"ts": ts, "value": self._to_number(item.get("value"))})

                    event_dt = self._parse_profile_event_time(txn_time) or current_event_dt
                    stream.append({"ts": event_dt, "value": self._to_number(value)})
                    cutoff = event_dt - timedelta(days=retention)
                    stream = [item for item in stream if isinstance(item.get("ts"), datetime) and item["ts"] >= cutoff]
                    stream.sort(key=lambda item: item["ts"])

                    rolling_root[metric_name] = [
                        {
                            "ts": item["ts"].strftime("%Y-%m-%d %H:%M:%S"),
                            "value": item.get("value"),
                        }
                        for item in stream
                    ]

                    metrics: Dict[str, Any] = {}
                    for day in window_days:
                        threshold = event_dt - timedelta(days=int(day))
                        window_items = [item for item in stream if item["ts"] >= threshold]
                        nums = [float(item["value"]) for item in window_items if item.get("value") is not None]
                        total = float(sum(nums)) if nums else 0.0
                        metrics[f"d{int(day)}"] = {
                            "count": len(window_items),
                            "sum": total,
                            "avg": (total / len(nums)) if nums else None,
                            "min": min(nums) if nums else None,
                            "max": max(nums) if nums else None,
                            "last": nums[-1] if nums else None,
                            "start_time": threshold.strftime("%Y-%m-%d %H:%M:%S"),
                            "end_time": event_dt.strftime("%Y-%m-%d %H:%M:%S"),
                        }
                    return metrics

                def _flatten_profile_values(value: Any) -> List[Any]:
                    out: List[Any] = []

                    def walk(item: Any) -> None:
                        if isinstance(item, (list, tuple, set)):
                            for sub in item:
                                walk(sub)
                            return
                        out.append(item)

                    walk(value)
                    return out

                def _profile_pick_min(current: Any, incoming: Any) -> Any:
                    if current is None:
                        return incoming
                    if incoming is None:
                        return current
                    cur_dt = self._parse_profile_event_time(current)
                    in_dt = self._parse_profile_event_time(incoming)
                    if cur_dt is not None and in_dt is not None:
                        return incoming if in_dt < cur_dt else current
                    cur_num = self._to_number(current)
                    in_num = self._to_number(incoming)
                    if cur_num is not None and in_num is not None:
                        return incoming if in_num < cur_num else current
                    try:
                        return incoming if str(incoming) < str(current) else current
                    except Exception:
                        return current

                def _profile_pick_max(current: Any, incoming: Any) -> Any:
                    if current is None:
                        return incoming
                    if incoming is None:
                        return current
                    cur_dt = self._parse_profile_event_time(current)
                    in_dt = self._parse_profile_event_time(incoming)
                    if cur_dt is not None and in_dt is not None:
                        return incoming if in_dt > cur_dt else current
                    cur_num = self._to_number(current)
                    in_num = self._to_number(incoming)
                    if cur_num is not None and in_num is not None:
                        return incoming if in_num > cur_num else current
                    try:
                        return incoming if str(incoming) > str(current) else current
                    except Exception:
                        return current

                def _profile_metric_kind(agg_name: Any) -> str:
                    op = str(agg_name or "count").strip().lower()
                    if op in {"rows", "row_count", "size"}:
                        return "row_count"
                    if op in {"count_non_null", "non_null_count"}:
                        return "count_non_null"
                    if op in {"distinct_count", "nunique", "unique_count"}:
                        return "distinct_count"
                    if op in {"distinct", "unique"}:
                        return "distinct"
                    if op in {"value_counts", "count_by_value", "frequency", "freq"}:
                        return "value_counts"
                    if op in {"sum", "total"}:
                        return "sum"
                    if op in {"avg", "average", "mean"}:
                        return "mean"
                    if op in {"min", "minimum"}:
                        return "min"
                    if op in {"max", "maximum"}:
                        return "max"
                    if op == "first":
                        return "first"
                    if op == "last":
                        return "last"
                    return "count"

                def _profile_metric_init(kind: str) -> Dict[str, Any]:
                    if kind in {"count", "count_non_null", "row_count"}:
                        return {"kind": kind, "count": 0}
                    if kind == "sum":
                        return {"kind": kind, "value": 0.0}
                    if kind == "mean":
                        return {"kind": kind, "sum": 0.0, "count": 0}
                    if kind in {"min", "max", "first", "last"}:
                        return {"kind": kind, "has_value": False, "value": None}
                    if kind == "distinct_count":
                        return {"kind": kind, "seen": {}}
                    if kind == "distinct":
                        return {"kind": kind, "seen": {}, "values": []}
                    if kind == "value_counts":
                        return {"kind": kind, "items": {}, "order": []}
                    return {"kind": "count", "count": 0}

                def _profile_metric_update(state: Any, kind: str, raw_value: Any) -> Dict[str, Any]:
                    current_state = state if isinstance(state, dict) else _profile_metric_init(kind)
                    if str(current_state.get("kind") or "") != kind:
                        current_state = _profile_metric_init(kind)

                    if kind == "row_count":
                        current_state["count"] = int(current_state.get("count", 0)) + 1
                        return current_state

                    values = _flatten_profile_values(raw_value)
                    if kind == "count":
                        current_state["count"] = int(current_state.get("count", 0)) + len(values)
                        return current_state

                    if kind == "count_non_null":
                        non_null = len(
                            [v for v in values if v is not None and str(v).strip() != ""]
                        )
                        current_state["count"] = int(current_state.get("count", 0)) + non_null
                        return current_state

                    if kind == "sum":
                        total = float(current_state.get("value", 0.0))
                        for value in values:
                            num = self._to_number(value)
                            if num is not None:
                                total += float(num)
                        current_state["value"] = total
                        return current_state

                    if kind == "mean":
                        total = float(current_state.get("sum", 0.0))
                        count = int(current_state.get("count", 0))
                        for value in values:
                            num = self._to_number(value)
                            if num is None:
                                continue
                            total += float(num)
                            count += 1
                        current_state["sum"] = total
                        current_state["count"] = count
                        return current_state

                    if kind == "min":
                        cur_val = current_state.get("value")
                        has_val = bool(current_state.get("has_value", False))
                        for value in values:
                            if value is None:
                                continue
                            cur_val = value if not has_val else _profile_pick_min(cur_val, value)
                            has_val = True
                        current_state["value"] = cur_val
                        current_state["has_value"] = has_val
                        return current_state

                    if kind == "max":
                        cur_val = current_state.get("value")
                        has_val = bool(current_state.get("has_value", False))
                        for value in values:
                            if value is None:
                                continue
                            cur_val = value if not has_val else _profile_pick_max(cur_val, value)
                            has_val = True
                        current_state["value"] = cur_val
                        current_state["has_value"] = has_val
                        return current_state

                    if kind == "first":
                        if bool(current_state.get("has_value", False)):
                            return current_state
                        for value in values:
                            if value is None:
                                continue
                            current_state["value"] = value
                            current_state["has_value"] = True
                            break
                        return current_state

                    if kind == "last":
                        for value in values:
                            if value is None:
                                continue
                            current_state["value"] = value
                            current_state["has_value"] = True
                        return current_state

                    if kind == "distinct_count":
                        seen = current_state.get("seen")
                        if not isinstance(seen, dict):
                            seen = {}
                            current_state["seen"] = seen
                        for value in values:
                            if value is None:
                                continue
                            seen[self._stable_json_token(value)] = 1
                        return current_state

                    if kind == "distinct":
                        seen = current_state.get("seen")
                        if not isinstance(seen, dict):
                            seen = {}
                            current_state["seen"] = seen
                        out_values = current_state.get("values")
                        if not isinstance(out_values, list):
                            out_values = []
                            current_state["values"] = out_values
                        for value in values:
                            if value is None:
                                continue
                            token_value = self._stable_json_token(value)
                            if token_value in seen:
                                continue
                            seen[token_value] = 1
                            out_values.append(value)
                        return current_state

                    if kind == "value_counts":
                        items = current_state.get("items")
                        if not isinstance(items, dict):
                            items = {}
                            current_state["items"] = items
                        order = current_state.get("order")
                        if not isinstance(order, list):
                            order = []
                            current_state["order"] = order
                        for value in values:
                            if value is None:
                                continue
                            token_value = self._stable_json_token(value)
                            bucket = items.get(token_value)
                            if not isinstance(bucket, dict):
                                items[token_value] = {"value": value, "count": 1}
                                order.append(token_value)
                            else:
                                bucket["count"] = int(bucket.get("count", 0)) + 1
                        return current_state

                    current_state["count"] = int(current_state.get("count", 0)) + len(values)
                    return current_state

                def _profile_metric_finalize(state: Any, kind: str) -> Any:
                    item = state if isinstance(state, dict) else _profile_metric_init(kind)
                    if kind in {"count", "count_non_null", "row_count"}:
                        return int(item.get("count", 0))
                    if kind == "sum":
                        total = float(item.get("value", 0.0))
                        return int(total) if float(total).is_integer() else total
                    if kind == "mean":
                        count = int(item.get("count", 0))
                        if count <= 0:
                            return None
                        return float(item.get("sum", 0.0)) / count
                    if kind in {"min", "max", "first", "last"}:
                        if not bool(item.get("has_value", False)):
                            return None
                        return item.get("value")
                    if kind == "distinct_count":
                        seen = item.get("seen")
                        return len(seen) if isinstance(seen, dict) else 0
                    if kind == "distinct":
                        values_out = item.get("values")
                        return values_out if isinstance(values_out, list) else []
                    if kind == "value_counts":
                        items = item.get("items")
                        order = item.get("order")
                        if not isinstance(items, dict) or not isinstance(order, list):
                            return []
                        return [
                            {
                                "value": items[token].get("value"),
                                "count": int(items[token].get("count", 0)),
                            }
                            for token in order
                            if token in items
                        ]
                    return int(item.get("count", 0))

                # Performance: compile and reconcile group_aggregate metric definitions
                # once per aggregate signature (store_key) per run, instead of per row.
                # This preserves edit-detection across runs while avoiding heavy
                # recompilation/signature work on large incremental profile streams.
                group_aggregate_defs_checked: set = set()

                def _profile_compile_group_metrics(raw_metrics: Any) -> List[Dict[str, Any]]:
                    raw = raw_metrics
                    if isinstance(raw, str):
                        text = raw.strip()
                        if not text:
                            return []
                        try:
                            raw = json.loads(text)
                        except Exception:
                            raw = {}

                    specs: List[Dict[str, Any]] = []
                    seen_names = set()

                    def add_spec(name: Any, conf: Any) -> None:
                        metric_name = str(name or "").strip()
                        if not metric_name:
                            return
                        metric_key = metric_name.lower()
                        if metric_key in seen_names:
                            return
                        seen_names.add(metric_key)

                        agg = "count"
                        metric_mode = "const"
                        metric_path = ""
                        metric_const = None
                        if isinstance(conf, dict):
                            agg = str(
                                conf.get("agg")
                                or conf.get("op")
                                or conf.get("func")
                                or conf.get("operation")
                                or "count"
                            ).strip().lower()
                            if "value" in conf:
                                metric_const = conf.get("value")
                            else:
                                metric_path = str(
                                    conf.get("path")
                                    or conf.get("field")
                                    or conf.get("column")
                                    or ""
                                ).strip()
                                if metric_path:
                                    metric_mode = "path"
                        elif isinstance(conf, list):
                            metric_const = conf[0] if len(conf) > 0 else None
                            agg = str(conf[1] if len(conf) > 1 else "count").strip().lower()
                        elif isinstance(conf, str):
                            text = conf.strip()
                            if ":" in text:
                                maybe_path, maybe_agg = [part.strip() for part in text.split(":", 1)]
                                agg = maybe_agg or "count"
                                if maybe_path:
                                    metric_mode = "path"
                                    metric_path = maybe_path
                            else:
                                agg = text or "count"
                        else:
                            metric_const = conf

                        specs.append(
                            {
                                "name": metric_name,
                                "kind": _profile_metric_kind(agg),
                                "mode": metric_mode,
                                "path": metric_path,
                                "const": metric_const,
                            }
                        )

                    if isinstance(raw, dict):
                        for metric_name, conf in raw.items():
                            add_spec(metric_name, conf)
                    elif isinstance(raw, list):
                        for idx, conf in enumerate(raw):
                            add_spec(f"metric_{idx + 1}", conf)
                    return specs

                def _profile_bind_group_metrics(metric_defs: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
                    out_specs: List[Dict[str, Any]] = []
                    for metric_def in metric_defs:
                        metric_name = str(metric_def.get("name") or "").strip()
                        metric_kind = str(metric_def.get("kind") or "count").strip().lower()
                        if not metric_name:
                            continue
                        mode = str(metric_def.get("mode") or "const").strip().lower()
                        metric_value = metric_def.get("const")
                        if mode == "path":
                            value_path = str(metric_def.get("path") or "").strip()
                            if value_path:
                                metric_value, _ = _row_extract(value_path)
                            else:
                                metric_value = None
                        out_specs.append(
                            {
                                "name": metric_name,
                                "kind": metric_kind,
                                "value": metric_value,
                            }
                        )
                    return out_specs

                def _profile_group_aggregate(
                    key_path: Any,
                    metrics: Any,
                    key_name: Any = "key",
                    include_null_key: Any = False,
                ) -> List[Dict[str, Any]]:
                    nonlocal profile_meta_touched
                    key_field = str(key_path or "").strip()
                    if not key_field:
                        return []

                    profile_field_name = str(active_profile_field.get("name") or "").strip()
                    output_key_name = str(key_name or "key").strip() or "key"
                    # Keep independent state per aggregate call signature so multiple
                    # group_aggregate(...) expressions inside one JSON profile field do
                    # not overwrite each other's buckets/keys.
                    store_key = "||".join(
                        [
                            profile_field_name or "__profile__",
                            key_field,
                            output_key_name,
                        ]
                    )
                    aggregate_root = working_meta.get("group_aggregate")
                    if not isinstance(aggregate_root, dict):
                        aggregate_root = {}
                        working_meta["group_aggregate"] = aggregate_root

                    state = aggregate_root.get(store_key)
                    if not isinstance(state, dict):
                        state = {
                            "groups": {},
                            "order": [],
                            "metric_specs": [],
                            "output_key_name": output_key_name,
                            "dirty": True,
                            "cached_rows": [],
                            "row_index": {},
                            "cache_signature": "",
                        }
                        aggregate_root[store_key] = state
                    else:
                        state["output_key_name"] = output_key_name

                    # Rebuild metric defs from expression input every call and
                    # refresh cached state when definition changed. Without this,
                    # editing an existing group_aggregate expression (e.g. adding
                    # `sum_amount`) keeps using stale metric defs from persisted
                    # profile meta and new metrics never materialize.
                    metric_defs_current = state.get("metric_defs")
                    metric_defs_changed = False
                    if not isinstance(metric_defs_current, list):
                        metric_defs_current = []
                        metric_defs_changed = True
                    if store_key not in group_aggregate_defs_checked:
                        compiled_metric_defs = _profile_compile_group_metrics(metrics)
                        try:
                            prev_signature = json.dumps(
                                metric_defs_current,
                                ensure_ascii=False,
                                sort_keys=True,
                                default=str,
                            )
                        except Exception:
                            prev_signature = str(metric_defs_current)
                        try:
                            next_signature = json.dumps(
                                compiled_metric_defs,
                                ensure_ascii=False,
                                sort_keys=True,
                                default=str,
                            )
                        except Exception:
                            next_signature = str(compiled_metric_defs)
                        if prev_signature != next_signature:
                            metric_defs_changed = True
                            metric_defs_current = compiled_metric_defs
                            state["metric_defs"] = metric_defs_current
                            state["dirty"] = True
                            state["cached_rows"] = []
                            state["row_index"] = {}
                            profile_meta_touched = True
                        group_aggregate_defs_checked.add(store_key)

                    metric_specs = _profile_bind_group_metrics(metric_defs_current)
                    if metric_defs_current:
                        state["metric_specs"] = [
                            {
                                "name": str(item.get("name") or "").strip(),
                                "kind": str(item.get("kind") or "count").strip().lower(),
                            }
                            for item in metric_defs_current
                            if isinstance(item, dict)
                        ]
                        if metric_defs_changed:
                            profile_meta_touched = True
                    else:
                        metric_specs = state.get("metric_specs") if isinstance(state.get("metric_specs"), list) else []

                    metric_specs_final = state.get("metric_specs")
                    if not isinstance(metric_specs_final, list):
                        metric_specs_final = []
                    cache_signature = json.dumps(
                        {
                            "output_key_name": output_key_name,
                            "metric_specs": metric_specs_final,
                        },
                        ensure_ascii=False,
                        sort_keys=True,
                        default=str,
                    )
                    if str(state.get("cache_signature") or "") != cache_signature:
                        state["cache_signature"] = cache_signature
                        state["dirty"] = True
                        state["cached_rows"] = []
                        state["row_index"] = {}

                    key_value, key_found = _row_extract(key_field)
                    keep_null_key = bool(include_null_key)
                    if key_found and (key_value is not None or keep_null_key):
                        groups = state.get("groups")
                        if not isinstance(groups, dict):
                            groups = {}
                            state["groups"] = groups
                        order = state.get("order")
                        if not isinstance(order, list):
                            order = []
                            state["order"] = order

                        token_value = self._stable_json_token(key_value)
                        bucket = groups.get(token_value)
                        if not isinstance(bucket, dict):
                            bucket = {"key": key_value, "metrics": {}}
                            groups[token_value] = bucket
                            order.append(token_value)
                        else:
                            bucket["key"] = key_value

                        bucket_metrics = bucket.get("metrics")
                        if not isinstance(bucket_metrics, dict):
                            bucket_metrics = {}
                            bucket["metrics"] = bucket_metrics

                        for spec in metric_specs:
                            metric_name = str(spec.get("name") or "").strip()
                            metric_kind = str(spec.get("kind") or "count").strip().lower()
                            if not metric_name:
                                continue
                            previous_state = bucket_metrics.get(metric_name)
                            next_state = _profile_metric_update(previous_state, metric_kind, spec.get("value"))
                            bucket_metrics[metric_name] = next_state

                        # Incremental cache update: keep materialized output rows in sync
                        # per touched group instead of rebuilding all groups each row.
                        cached_rows = state.get("cached_rows")
                        if not isinstance(cached_rows, list):
                            cached_rows = []
                            state["cached_rows"] = cached_rows
                        row_index = state.get("row_index")
                        if not isinstance(row_index, dict):
                            row_index = {}
                            state["row_index"] = row_index

                        index_value = row_index.get(token_value)
                        if not isinstance(index_value, int) or index_value < 0 or index_value >= len(cached_rows):
                            index_value = len(cached_rows)
                            row_index[token_value] = index_value
                            cached_rows.append({})

                        row_out: Dict[str, Any] = {output_key_name: bucket.get("key")}
                        for spec in metric_specs_final:
                            metric_name = str(spec.get("name") or "").strip()
                            metric_kind = str(spec.get("kind") or "count").strip().lower()
                            if not metric_name:
                                continue
                            metric_state = bucket_metrics.get(metric_name)
                            row_out[metric_name] = _profile_metric_finalize(metric_state, metric_kind)
                        cached_rows[index_value] = row_out
                        state["dirty"] = False
                        profile_meta_touched = True
                    # Return a lazy placeholder and materialize aggregate arrays only
                    # when emitting/persisting profile docs (not for every row update).
                    return {"__profile_group_aggregate_ref__": store_key}

                def _profile_materialize_group_aggregate(profile_meta: Dict[str, Any], store_key: str) -> List[Dict[str, Any]]:
                    aggregate_root = profile_meta.get("group_aggregate")
                    if not isinstance(aggregate_root, dict):
                        return []
                    state = aggregate_root.get(store_key)
                    if not isinstance(state, dict):
                        return []

                    cached_rows = state.get("cached_rows")
                    if not bool(state.get("dirty", True)) and isinstance(cached_rows, list):
                        return cached_rows

                    groups = state.get("groups")
                    order = state.get("order")
                    if not isinstance(groups, dict) or not isinstance(order, list):
                        state["cached_rows"] = []
                        state["dirty"] = False
                        return []

                    metric_specs_final = state.get("metric_specs")
                    if not isinstance(metric_specs_final, list):
                        metric_specs_final = []
                    output_key = str(state.get("output_key_name") or "key").strip() or "key"

                    out: List[Dict[str, Any]] = []
                    row_index: Dict[str, int] = {}
                    for token in order:
                        bucket = groups.get(token)
                        if not isinstance(bucket, dict):
                            continue
                        bucket_metrics = bucket.get("metrics")
                        if not isinstance(bucket_metrics, dict):
                            bucket_metrics = {}
                        row_out: Dict[str, Any] = {output_key: bucket.get("key")}
                        for spec in metric_specs_final:
                            metric_name = str(spec.get("name") or "").strip()
                            metric_kind = str(spec.get("kind") or "count").strip().lower()
                            if not metric_name:
                                continue
                            metric_state = bucket_metrics.get(metric_name)
                            row_out[metric_name] = _profile_metric_finalize(metric_state, metric_kind)
                        row_index[token] = len(out)
                        out.append(row_out)

                    state["cached_rows"] = out
                    state["row_index"] = row_index
                    state["dirty"] = False
                    return out

                def _resolve_profile_dynamic_value(value: Any, profile_meta: Dict[str, Any]) -> Any:
                    if isinstance(value, dict):
                        if (
                            len(value) == 1
                            and "__profile_group_aggregate_ref__" in value
                            and isinstance(value.get("__profile_group_aggregate_ref__"), str)
                        ):
                            store_key = str(value.get("__profile_group_aggregate_ref__") or "").strip()
                            if not store_key:
                                return []
                            return _profile_materialize_group_aggregate(profile_meta, store_key)
                        return {
                            k: _resolve_profile_dynamic_value(v, profile_meta)
                            for k, v in value.items()
                        }
                    if isinstance(value, list):
                        return [_resolve_profile_dynamic_value(v, profile_meta) for v in value]
                    return value

                fns_v2_extra_context: Dict[str, Any] = {}
                if custom_fns_version_active == "v2":
                    if _build_fns_v2_registry is None:
                        _record_custom_field_warning(
                            "FNS v2 registry module is unavailable. Falling back to v1 helpers."
                        )
                    else:
                        try:
                            fns_v2_default_dedupe_options: Dict[str, Any] = {}
                            dedupe_key_field = str(
                                config.get("custom_fns_v2_dedupe_key_field") or ""
                            ).strip()
                            if dedupe_key_field:
                                dedupe_value, dedupe_found = self._extract_row_value_by_path(
                                    row_obj,
                                    dedupe_key_field,
                                )
                                if not dedupe_found and isinstance(row_obj, dict):
                                    dedupe_value = row_obj.get(dedupe_key_field)
                                    dedupe_found = dedupe_key_field in row_obj
                                if dedupe_found and dedupe_value is not None and str(dedupe_value).strip() != "":
                                    fns_v2_default_dedupe_options["dedupe_key"] = dedupe_value

                            on_duplicate_default = str(
                                config.get("custom_fns_v2_on_duplicate") or "ignore"
                            ).strip().lower()
                            if on_duplicate_default in {"ignore", "skip", "drop"}:
                                fns_v2_default_dedupe_options["on_duplicate"] = "ignore"
                            elif on_duplicate_default in {"update", "overwrite", "replace", "keep_latest"}:
                                fns_v2_default_dedupe_options["on_duplicate"] = "update"
                            else:
                                fns_v2_default_dedupe_options["on_duplicate"] = "ignore"

                            normalize_default = str(
                                config.get("custom_fns_v2_normalize") or "upper_trim"
                            ).strip().lower()
                            if normalize_default in {"upper_trim", "trim_upper"}:
                                fns_v2_default_dedupe_options["normalize"] = "upper_trim"
                            elif normalize_default in {"lower_trim", "trim_lower"}:
                                fns_v2_default_dedupe_options["normalize"] = "lower_trim"
                            elif normalize_default in {"trim", "upper", "lower", "auto"}:
                                fns_v2_default_dedupe_options["normalize"] = normalize_default
                            else:
                                fns_v2_default_dedupe_options["normalize"] = "upper_trim"

                            invalid_key_default = str(
                                config.get("custom_fns_v2_invalid_key") or "skip"
                            ).strip().lower()
                            if invalid_key_default in {"skip", "drop", "ignore"}:
                                fns_v2_default_dedupe_options["invalid_key"] = "skip"
                            elif invalid_key_default in {"allow", "count", "use_null", "null"}:
                                fns_v2_default_dedupe_options["invalid_key"] = "allow"
                            elif invalid_key_default in {"raise", "error", "strict"}:
                                fns_v2_default_dedupe_options["invalid_key"] = "raise"
                            else:
                                fns_v2_default_dedupe_options["invalid_key"] = "skip"

                            fns_v2_extra_context = _build_fns_v2_registry(
                                profile_root=active_profile_field.get("name") or "",
                                working_doc=working_doc,
                                working_meta=working_meta,
                                custom_values=custom_values,
                                resolve_profile_path=_resolve_profile_path,
                                profile_prev=_profile_prev,
                                stable_json_token=self._stable_json_token,
                                to_number=self._to_number,
                                parse_event_time=self._parse_profile_event_time,
                                current_event_dt=current_event_dt,
                                current_event_time=current_event_time,
                                entity_key=pk_value,
                                json_safe_value=self._json_safe_value,
                                v1_inc=_inc,
                                v1_map_inc=_map_inc,
                                v1_append_unique=_append_unique,
                                v1_rolling_update=_rolling_update,
                                default_dedupe_options=fns_v2_default_dedupe_options,
                                row_dedupe_gate_enabled=custom_fns_v2_row_gate_dedupe_enabled,
                            )
                        except Exception as exc:
                            fns_v2_extra_context = {}
                            _record_custom_field_warning(
                                f"FNS v2 initialization failed. Falling back to v1 helpers: {exc}"
                            )

                extra_context = {
                    "prev": _profile_prev,
                    "profile_prev": _profile_prev,
                    "profile_get": _profile_prev,
                    "doc": _profile_prev,
                    "num": _num,
                    "safe_div": _safe_div,
                    "inc": _inc,
                    "map_inc": _map_inc,
                    "append_unique": _append_unique,
                    "appendunique": _append_unique,
                    "appen_unique": _append_unique,
                    "rolling_update": _rolling_update,
                    "rolling_window_update": _rolling_update,
                    "profile_group_aggregate": _profile_group_aggregate,
                    "group_aggregate_profile": _profile_group_aggregate,
                    "group_aggregate": _profile_group_aggregate,
                    "group_metrics": _profile_group_aggregate,
                    "entity_key": pk_value,
                    "entity_id": pk_value,
                    "event_time": current_event_time,
                    "custom_fns_version": custom_fns_version_active,
                }
                if fns_v2_extra_context:
                    extra_context.update(fns_v2_extra_context)
                eval_context = self._build_expression_context(
                    row_obj,
                    custom_values,
                    dataset_rows=[row_obj],
                    row_index=row_idx,
                    extra_context=extra_context,
                )

                # Keep single-pass in profile mode to avoid side-effect duplication
                # for helpers like rolling_update().
                for spec in custom_specs:
                    name = str(spec.get("name") or "").strip()
                    if not name:
                        continue
                    active_profile_field["name"] = name
                    mode = str(spec.get("mode") or "value").lower()
                    active_profile_field["mode"] = mode
                    expression = str(spec.get("expression") or "")
                    template = spec.get("json_template")
                    try:
                        if mode == "json":
                            value = self._evaluate_json_template(
                                template,
                                row_obj,
                                custom_values,
                                dataset_rows=[row_obj],
                                row_index=row_idx,
                                context=eval_context,
                            )
                        else:
                            value = self._evaluate_custom_expression(
                                expression,
                                row_obj,
                                custom_values,
                                dataset_rows=[row_obj],
                                row_index=row_idx,
                                context=eval_context,
                            )
                    except Exception as exc:
                        value = None
                        _record_custom_field_warning(
                            f"Custom profile field '{name}' evaluation failed at row {row_idx + 1}: {exc}"
                        )
                    finally:
                        active_profile_field["name"] = ""
                        active_profile_field["mode"] = "value"

                    if mode != "json":
                        value = self._apply_single_value_output_mode(
                            value,
                            spec.get("single_value_output"),
                        )

                    # Keep per-row profile values raw in memory for speed; convert to
                    # JSON-safe once when emitting/persisting final state.
                    previous_value = self._get_profile_path_value(working_doc, name, _missing)
                    value_to_set = value
                    values_equal = False
                    if previous_value is _missing:
                        values_equal = False
                    elif previous_value is value_to_set:
                        values_equal = True
                    elif isinstance(previous_value, (dict, list)) or isinstance(value_to_set, (dict, list)):
                        # Avoid deep equality on large nested profile docs/lists.
                        values_equal = False
                    else:
                        try:
                            values_equal = previous_value == value_to_set
                        except Exception:
                            values_equal = False
                    if not values_equal:
                        changed_fields.append(name)
                    self._set_profile_path_value(working_doc, name, value_to_set)
                    custom_values[name] = value_to_set
                    eval_context[name] = value_to_set
                    if isinstance(name, str) and name.isidentifier():
                        eval_context[name] = value_to_set

                if self._get_profile_path_value(working_doc, primary_key_field, None) is None:
                    self._set_profile_path_value(working_doc, primary_key_field, self._json_safe_value(pk_value))
                    if primary_key_field not in changed_fields:
                        changed_fields.append(primary_key_field)

                doc_changed = bool(changed_fields)
                meta_changed = bool(profile_meta_touched)
                if doc_changed or meta_changed or is_new:
                    # Keep mutable profile state in-memory during the run to avoid
                    # expensive full JSON-safe conversion on every input row.
                    # Serialization safety is enforced once at execution persist time
                    # (LMDB/runtime save) and when emitting node results.
                    documents_store[token] = working_doc
                    meta_store[token] = working_meta
                    changed_fields_by_token[token] = list(changed_fields)
                    if token not in changed_token_set:
                        changed_token_set.add(token)
                        changed_tokens.append(token)

                if is_profile_incremental_mode and (doc_changed or meta_changed or is_new):
                    incremental_pending_flush_updates += 1
                    incremental_pending_tokens.add(token)
                    if emit_incremental_rows:
                        profile_doc_for_emit = documents_store.get(token)
                        if not isinstance(profile_doc_for_emit, dict):
                            profile_doc_for_emit = working_doc
                        profile_meta_for_emit = meta_store.get(token)
                        if not isinstance(profile_meta_for_emit, dict):
                            profile_meta_for_emit = working_meta
                        resolved_profile_doc = _resolve_profile_dynamic_value(
                            profile_doc_for_emit,
                            profile_meta_for_emit,
                        )
                        if isinstance(resolved_profile_doc, dict):
                            # Keep per-row state raw for speed on large incremental runs.
                            # Materialized docs are persisted once at the end (or during
                            # live persist when explicitly enabled).
                            if live_persist_enabled:
                                documents_store[token] = resolved_profile_doc
                            out_row: Dict[str, Any] = {}
                            if include_source and isinstance(row_obj, dict):
                                out_row.update(row_obj)
                            out_row.update(resolved_profile_doc)
                            if primary_key_field and self._get_profile_path_value(out_row, primary_key_field, None) is None:
                                self._set_profile_path_value(
                                    out_row,
                                    primary_key_field,
                                    self._json_safe_value(pk_value),
                                )
                            if profile_include_change_fields:
                                out_row["_profile_changed_fields"] = list(changed_fields)
                            result.append(self._json_safe_value(out_row))
                    _flush_incremental_profile_state(force=False)
                _emit_profile_progress()

            if (
                profile_storage == "oracle"
                and profile_enabled
                and len(base_rows) > 0
                and len(changed_tokens) == 0
            ):
                _record_custom_field_warning(
                    "Oracle profile persist no-op: processed rows produced no profile changes "
                    "(keys/values already up-to-date)."
                )
                stats_store["custom_fields_oracle_noop"] = True
                stats_store["custom_fields_oracle_noop_reason"] = (
                    "processed_rows_with_zero_changed_tokens"
                )
                stats_store["custom_fields_oracle_changed_tokens"] = 0

            if is_profile_incremental_mode:
                # Materialize lazy aggregate placeholders once per entity before the
                # terminal flush so persisted LMDB docs stay directly consumable.
                for token, profile_doc in list(documents_store.items()):
                    if not isinstance(profile_doc, dict):
                        continue
                    profile_meta = meta_store.get(token)
                    if not isinstance(profile_meta, dict):
                        profile_meta = {}
                    resolved_profile_doc = _resolve_profile_dynamic_value(profile_doc, profile_meta)
                    if isinstance(resolved_profile_doc, dict):
                        documents_store[token] = resolved_profile_doc
                _flush_incremental_profile_state(force=True)
                # Keep final stats updated but avoid emitting an extra terminal
                # "running/progress counter" message once processing is complete.
                _emit_profile_progress(force=True, emit_progress_event=False)
                if emit_incremental_rows:
                    return result

                emit_tokens: List[str]
                if profile_emit_mode == "all_entities":
                    emit_tokens = []
                    seen_emit = set()
                    for token in seen_entity_tokens + list(documents_store.keys()):
                        if token in seen_emit:
                            continue
                        seen_emit.add(token)
                        emit_tokens.append(token)
                else:
                    emit_tokens = list(changed_tokens)

                for token in emit_tokens:
                    _raise_if_aborted()
                    profile_doc = documents_store.get(token)
                    if not isinstance(profile_doc, dict):
                        continue
                    profile_meta = meta_store.get(token)
                    if not isinstance(profile_meta, dict):
                        profile_meta = {}
                    resolved_profile_doc = _resolve_profile_dynamic_value(profile_doc, profile_meta)
                    if not isinstance(resolved_profile_doc, dict):
                        continue
                    out_row: Dict[str, Any] = {}
                    if include_source:
                        source_row = last_source_by_token.get(token)
                        if isinstance(source_row, dict):
                            out_row.update(source_row)
                    out_row.update(resolved_profile_doc)
                    if primary_key_field and self._get_profile_path_value(out_row, primary_key_field, None) is None:
                        self._set_profile_path_value(
                            out_row,
                            primary_key_field,
                            self._json_safe_value(entity_value_by_token.get(token)),
                        )
                    if profile_include_change_fields:
                        out_row["_profile_changed_fields"] = changed_fields_by_token.get(token, [])
                    result.append(self._json_safe_value(out_row))
                return result

            emit_tokens: List[str]
            if profile_emit_mode == "all_entities":
                emit_tokens = []
                seen_emit = set()
                for token in seen_entity_tokens + list(documents_store.keys()):
                    if token in seen_emit:
                        continue
                    seen_emit.add(token)
                    emit_tokens.append(token)
            else:
                emit_tokens = list(changed_tokens)

            for token in emit_tokens:
                _raise_if_aborted()
                profile_doc = documents_store.get(token)
                if not isinstance(profile_doc, dict):
                    continue
                profile_meta = meta_store.get(token)
                if not isinstance(profile_meta, dict):
                    profile_meta = {}
                resolved_profile_doc = _resolve_profile_dynamic_value(profile_doc, profile_meta)
                if not isinstance(resolved_profile_doc, dict):
                    continue
                # Keep materialized profile in state so persisted LMDB documents are
                # directly consumable without placeholder indirection.
                documents_store[token] = resolved_profile_doc
                out_row: Dict[str, Any] = {}
                if include_source:
                    source_row = last_source_by_token.get(token)
                    if isinstance(source_row, dict):
                        out_row.update(source_row)
                out_row.update(resolved_profile_doc)
                if primary_key_field and self._get_profile_path_value(out_row, primary_key_field, None) is None:
                    self._set_profile_path_value(
                        out_row,
                        primary_key_field,
                        self._json_safe_value(entity_value_by_token.get(token)),
                    )
                if profile_include_change_fields:
                    out_row["_profile_changed_fields"] = changed_fields_by_token.get(token, [])
                result.append(self._json_safe_value(out_row))
            return result

        grouped_rows: List[Dict[str, Any]] = []
        if primary_key_field:
            buckets: Dict[str, Dict[str, Any]] = {}
            bucket_order: List[str] = []
            for base_row in base_rows:
                pk_value, pk_found = self._extract_row_value_by_path(base_row, primary_key_field)
                group_value = pk_value if pk_found else None
                try:
                    bucket_key = json.dumps(group_value, ensure_ascii=False, sort_keys=True, default=str)
                except Exception:
                    bucket_key = str(group_value)
                if bucket_key not in buckets:
                    buckets[bucket_key] = {"group_value": group_value, "rows": []}
                    bucket_order.append(bucket_key)
                buckets[bucket_key]["rows"].append(base_row)
            grouped_rows = [buckets[key] for key in bucket_order]
        else:
            grouped_rows = [
                {"group_value": None, "rows": [row], "row_index": idx}
                for idx, row in enumerate(base_rows)
            ]

        for row_idx, group in enumerate(grouped_rows):
            if row_idx == 0 or row_idx % 25 == 0:
                _raise_if_aborted()
            rows = group.get("rows") if isinstance(group, dict) else []
            if not isinstance(rows, list) or not rows:
                continue
            eval_scope: Any = rows if primary_key_field else rows[0]
            eval_row_index = None if primary_key_field else group.get("row_index")
            eval_dataset_rows = rows if primary_key_field else base_rows
            custom_values: Dict[str, Any] = {}

            # Multi-pass evaluation so custom fields can reference other custom fields
            # regardless of UI order (e.g., JSON template referencing a later expression field).
            max_passes = 3 if len(custom_specs) > 1 else 1
            for _pass_idx in range(max_passes):
                changed = False
                eval_context = self._build_expression_context(
                    eval_scope,
                    custom_values,
                    dataset_rows=eval_dataset_rows,
                    row_index=eval_row_index,
                )
                for spec in custom_specs:
                    name = str(spec.get("name") or "").strip()
                    if not name:
                        continue
                    mode = str(spec.get("mode") or "value").lower()
                    expression = str(spec.get("expression") or "")
                    template = spec.get("json_template")

                    try:
                        if mode == "json":
                            value = self._evaluate_json_template(
                                template,
                                eval_scope,
                                custom_values,
                                dataset_rows=eval_dataset_rows,
                                row_index=eval_row_index,
                                context=eval_context,
                            )
                        else:
                            value = self._evaluate_custom_expression(
                                expression,
                                eval_scope,
                                custom_values,
                                dataset_rows=eval_dataset_rows,
                                row_index=eval_row_index,
                                context=eval_context,
                            )
                    except Exception as exc:
                        value = None
                        _record_custom_field_warning(
                            f"Custom field '{name}' evaluation failed at row {row_idx + 1}: {exc}"
                        )

                    if mode != "json":
                        value = self._apply_single_value_output_mode(
                            value,
                            spec.get("single_value_output"),
                        )

                    prev_value = custom_values.get(name, None)
                    if prev_value != value:
                        changed = True
                    custom_values[name] = value
                    eval_context[name] = value
                    if isinstance(name, str) and name.isidentifier():
                        eval_context[name] = value
                if not changed:
                    break

            representative_row = rows[0] if isinstance(rows[0], dict) else {"value": rows[0]}
            out_row = dict(representative_row) if include_source else {}
            if primary_key_field and primary_key_field not in custom_values:
                out_row[primary_key_field] = group.get("group_value") if isinstance(group, dict) else None
            out_row.update(custom_values)
            result.append(out_row)

        return result

    def _transform_custom_fields_parallel_by_profile_key(
        self,
        data: list,
        config: dict,
        custom_specs: List[dict],
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        profile_enabled = bool(config.get("custom_profile_enabled", False))
        profile_storage_hint = self._normalize_profile_storage(
            config.get("custom_profile_storage", "lmdb")
        )
        profile_lmdb_env_path_override = str(
            config.get("custom_profile_lmdb_env_path") or ""
        ).strip()
        if profile_enabled and profile_storage_hint == "lmdb" and profile_lmdb_env_path_override:
            self._runtime_profile_lmdb_dir_override = profile_lmdb_env_path_override
        else:
            self._runtime_profile_lmdb_dir_override = None
        if not profile_enabled or not custom_specs:
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )
        profile_processing_mode = self._normalize_profile_processing_mode(
            config.get("custom_profile_processing_mode", "batch")
        )
        is_profile_incremental_mode = profile_processing_mode in {"incremental", "incremental_batch"}

        profile_storage = profile_storage_hint

        primary_key_field = str(
            config.get("custom_primary_key_field")
            or config.get("custom_group_by_field")
            or ""
        ).strip()
        if not primary_key_field:
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )

        try:
            min_rows = int(
                config.get("custom_profile_compute_min_rows")
                or os.getenv("PROFILE_COMPUTE_MIN_ROWS", "20000")
            )
        except Exception:
            min_rows = 20000
        min_rows = max(1000, min(min_rows, 5_000_000))
        if len(data or []) < min_rows:
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )

        oracle_queue_enabled_cfg = config.get("custom_profile_oracle_queue_enabled", None)
        if oracle_queue_enabled_cfg is None or str(oracle_queue_enabled_cfg).strip() == "":
            oracle_queue_enabled_cfg = os.getenv("PROFILE_ORACLE_QUEUE_ENABLED", "1")
        oracle_queue_enabled = bool(
            is_profile_incremental_mode
            and self._parse_bool_like(oracle_queue_enabled_cfg, True)
        )
        try:
            oracle_queue_maxsize = int(
                config.get("custom_profile_oracle_queue_maxsize")
                or os.getenv("PROFILE_ORACLE_QUEUE_MAXSIZE", "256")
            )
        except Exception:
            oracle_queue_maxsize = 256
        oracle_queue_maxsize = max(8, min(oracle_queue_maxsize, 4096))
        try:
            oracle_queue_enqueue_timeout_seconds = float(
                config.get("custom_profile_oracle_queue_enqueue_timeout_seconds")
                or os.getenv("PROFILE_ORACLE_QUEUE_ENQUEUE_TIMEOUT_SECONDS", "0.2")
            )
        except Exception:
            oracle_queue_enqueue_timeout_seconds = 0.2
        oracle_queue_enqueue_timeout_seconds = max(
            0.01,
            min(oracle_queue_enqueue_timeout_seconds, 5.0),
        )
        oracle_queue_wait_on_force_flush_cfg = config.get(
            "custom_profile_oracle_queue_wait_on_force_flush",
            None,
        )
        if (
            oracle_queue_wait_on_force_flush_cfg is None
            or str(oracle_queue_wait_on_force_flush_cfg).strip() == ""
        ):
            oracle_queue_wait_on_force_flush_cfg = os.getenv(
                "PROFILE_ORACLE_QUEUE_WAIT_ON_FORCE_FLUSH",
                "1",
            )
        oracle_queue_wait_on_force_flush = bool(
            is_profile_incremental_mode
            and self._parse_bool_like(oracle_queue_wait_on_force_flush_cfg, True)
        )
        try:
            oracle_queue_wait_timeout_seconds = float(
                config.get("custom_profile_oracle_queue_wait_timeout_seconds")
                or os.getenv("PROFILE_ORACLE_QUEUE_WAIT_TIMEOUT_SECONDS", "60")
            )
        except Exception:
            oracle_queue_wait_timeout_seconds = 60.0
        oracle_queue_wait_timeout_seconds = max(
            1.0,
            min(oracle_queue_wait_timeout_seconds, 1800.0),
        )

        default_workers = min(8, max(2, int(os.cpu_count() or 4)))
        try:
            workers = int(
                config.get("custom_profile_compute_workers")
                or os.getenv("PROFILE_COMPUTE_WORKERS", str(default_workers))
            )
        except Exception:
            workers = default_workers
        workers = max(2, min(workers, 16))
        compute_executor = self._normalize_profile_compute_executor(
            config.get("custom_profile_compute_executor", "thread")
        )
        if compute_executor == "process":
            workers = max(2, min(workers, max(2, int(os.cpu_count() or 2))))
        # For very large runs, keep a minimum worker floor even if config was set low.
        # This avoids "parallel" mode behaving almost like single-thread execution.
        if len(data or []) >= 200_000 and workers < 4:
            workers = min(8, max(4, default_workers))

        partitions: List[List[Dict[str, Any]]] = [[] for _ in range(workers)]
        partition_tokens: List[set] = [set() for _ in range(workers)]
        fallback_rows: List[Dict[str, Any]] = []
        for raw_row in (data or []):
            row_obj = raw_row if isinstance(raw_row, dict) else {"value": raw_row}
            pk_value, pk_found = self._extract_row_value_by_path(row_obj, primary_key_field)
            if not pk_found or pk_value is None or str(pk_value).strip() == "":
                fallback_rows.append(row_obj)
                continue
            token = self._stable_json_token(pk_value)
            partition_index = abs(hash(token)) % workers
            partitions[partition_index].append(row_obj)
            partition_tokens[partition_index].add(token)
        if fallback_rows:
            partitions[0].extend(fallback_rows)

        active_partitions: List[Tuple[int, List[Dict[str, Any]], set]] = []
        for idx, rows in enumerate(partitions):
            if rows:
                active_partitions.append((idx, rows, partition_tokens[idx]))
        if len(active_partitions) <= 1:
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )

        node_id = str((execution_context or {}).get("node_id") or "map_transform")
        pipeline_id = str((execution_context or {}).get("pipeline_id") or "").strip()
        context_oracle_cfg = (
            (execution_context or {}).get("profile_oracle_cfg")
            if isinstance((execution_context or {}).get("profile_oracle_cfg"), dict)
            else None
        )
        profile_oracle_cfg = context_oracle_cfg or {
            "custom_profile_oracle_host": config.get("custom_profile_oracle_host"),
            "custom_profile_oracle_port": config.get("custom_profile_oracle_port"),
            "custom_profile_oracle_service_name": config.get("custom_profile_oracle_service_name"),
            "custom_profile_oracle_sid": config.get("custom_profile_oracle_sid"),
            "custom_profile_oracle_user": config.get("custom_profile_oracle_user"),
            "custom_profile_oracle_password": config.get("custom_profile_oracle_password"),
            "custom_profile_oracle_dsn": config.get("custom_profile_oracle_dsn"),
            "custom_profile_oracle_table": config.get("custom_profile_oracle_table"),
            "custom_profile_oracle_write_strategy": config.get("custom_profile_oracle_write_strategy"),
            "custom_profile_oracle_parallel_workers": config.get("custom_profile_oracle_parallel_workers"),
            "custom_profile_oracle_parallel_min_tokens": config.get("custom_profile_oracle_parallel_min_tokens"),
            "custom_profile_oracle_merge_batch_size": config.get("custom_profile_oracle_merge_batch_size"),
            "custom_profile_oracle_parallel_force": config.get("custom_profile_oracle_parallel_force"),
        }
        context_oracle_session = (
            (execution_context or {}).get("profile_oracle_session")
            if isinstance((execution_context or {}).get("profile_oracle_session"), dict)
            else None
        )
        emit_node_progress = (
            (execution_context or {}).get("emit_node_progress")
            if isinstance(execution_context, dict) and callable((execution_context or {}).get("emit_node_progress"))
            else None
        )
        should_abort_cb = (
            (execution_context or {}).get("should_abort")
            if isinstance(execution_context, dict) and callable((execution_context or {}).get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            (execution_context or {}).get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable((execution_context or {}).get("raise_if_aborted"))
            else None
        )

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        all_candidate_tokens: List[str] = []
        seen_candidate_tokens: set = set()
        for _, _, tokens in active_partitions:
            for token in tokens:
                if token in seen_candidate_tokens:
                    continue
                seen_candidate_tokens.add(token)
                all_candidate_tokens.append(token)

        prefetched_docs: Dict[str, Dict[str, Any]] = {}
        prefetched_meta: Dict[str, Dict[str, Any]] = {}
        try:
            prefetch_chunk_size = int(
                config.get("custom_profile_backfill_candidate_prefetch_chunk_size")
                or os.getenv("PROFILE_BACKFILL_CANDIDATE_PREFETCH_CHUNK_SIZE", "500")
            )
        except Exception:
            prefetch_chunk_size = 500
        prefetch_chunk_size = max(50, min(prefetch_chunk_size, 900))
        try:
            compute_global_prefetch_max_tokens = int(
                config.get("custom_profile_compute_global_prefetch_max_tokens")
                or os.getenv("PROFILE_COMPUTE_GLOBAL_PREFETCH_MAX_TOKENS", "40000")
            )
        except Exception:
            compute_global_prefetch_max_tokens = 40000
        compute_global_prefetch_max_tokens = max(1000, min(compute_global_prefetch_max_tokens, 2_000_000))
        use_global_prefetch = bool(
            pipeline_id
            and all_candidate_tokens
            and len(all_candidate_tokens) <= compute_global_prefetch_max_tokens
        )

        if use_global_prefetch:
            if emit_node_progress:
                try:
                    emit_node_progress({
                        "processed_rows": 0,
                        "validated_rows": 0,
                        "output_rows": 0,
                        "message": (
                            f"⟳ Running {str((execution_context or {}).get('node_label') or 'Custom Fields')}… "
                            f"loading profile baseline for {len(all_candidate_tokens):,} keys"
                        ),
                    })
                except Exception:
                    pass
            try:
                docs, meta, _existing = self._load_profile_state_for_entity_tokens(
                    pipeline_id,
                    node_id,
                    all_candidate_tokens,
                    storage=profile_storage,
                    profile_cfg=profile_oracle_cfg,
                    oracle_session=context_oracle_session,
                    chunk_size=prefetch_chunk_size,
                )
                if isinstance(docs, dict):
                    prefetched_docs = docs
                if isinstance(meta, dict):
                    prefetched_meta = meta
            except Exception as exc:
                logger.warning(
                    f"Parallel profile compute baseline prefetch failed for pipeline {pipeline_id}, "
                    f"node {node_id}: {exc}"
                )

        partition_config = dict(config or {})
        partition_config["custom_profile_compute_strategy"] = "single"

        processed_rows_total = 0
        validated_rows_total = 0
        output_rows_total = 0
        flush_count_total = 0
        merged_documents: Dict[str, Dict[str, Any]] = {}
        merged_meta: Dict[str, Dict[str, Any]] = {}
        merged_rows: List[Any] = []
        merged_warnings: List[str] = []
        partition_progress_lock = threading.Lock()
        partition_live_progress: Dict[int, Dict[str, int]] = {}

        def _run_partition(partition_info: Tuple[int, List[Dict[str, Any]], set]) -> Dict[str, Any]:
            partition_idx, partition_rows, partition_token_set = partition_info
            local_documents: Dict[str, Any] = {}
            local_meta: Dict[str, Any] = {}
            if use_global_prefetch:
                for token in partition_token_set:
                    doc_value = prefetched_docs.get(token)
                    if isinstance(doc_value, dict):
                        # Token ownership is partitioned by stable hash, so direct reuse
                        # avoids expensive deep-copy overhead.
                        local_documents[token] = doc_value
                    meta_value = prefetched_meta.get(token)
                    if isinstance(meta_value, dict):
                        local_meta[token] = meta_value
            elif pipeline_id and partition_token_set:
                try:
                    partition_docs, partition_meta, _existing = self._load_profile_state_for_entity_tokens(
                        pipeline_id,
                        node_id,
                        list(partition_token_set),
                        storage=profile_storage,
                        profile_cfg=profile_oracle_cfg,
                        oracle_session=None,
                        chunk_size=prefetch_chunk_size,
                    )
                    if isinstance(partition_docs, dict):
                        local_documents = partition_docs
                    if isinstance(partition_meta, dict):
                        local_meta = partition_meta
                except Exception as exc:
                    logger.warning(
                        f"Parallel profile compute partition prefetch failed for pipeline {pipeline_id}, "
                        f"node {node_id}, partition {partition_idx}: {exc}"
                    )
            local_profile_state = {
                node_id: {
                    "documents": local_documents,
                    "meta": local_meta,
                    "stats": {},
                }
            }
            local_node_warnings: List[str] = []

            def _emit_partition_progress(progress_payload: Dict[str, Any]) -> None:
                if not emit_node_progress:
                    return
                processed_now = int(progress_payload.get("processed_rows") or 0)
                validated_now = int(progress_payload.get("validated_rows") or 0)
                output_now = int(progress_payload.get("output_rows") or 0)
                with partition_progress_lock:
                    partition_live_progress[partition_idx] = {
                        "processed": processed_now,
                        "validated": validated_now,
                        "output_rows": output_now,
                    }
                    agg_processed = sum(int(v.get("processed") or 0) for v in partition_live_progress.values())
                    agg_validated = sum(int(v.get("validated") or 0) for v in partition_live_progress.values())
                    agg_output = sum(int(v.get("output_rows") or 0) for v in partition_live_progress.values())
                try:
                    emit_node_progress({
                        "processed_rows": agg_processed,
                        "validated_rows": agg_validated,
                        "output_rows": agg_output,
                        "message": (
                            f"⟳ Running {str((execution_context or {}).get('node_label') or 'Custom Fields')}… "
                            f"parallel incremental {agg_processed:,}/{len(data):,} processed"
                        ),
                    })
                except Exception:
                    pass

            local_execution_context: Dict[str, Any] = {
                "execution_id": (execution_context or {}).get("execution_id"),
                "pipeline_id": "",
                "node_id": node_id,
                "node_label": (execution_context or {}).get("node_label"),
                "mode": (execution_context or {}).get("mode"),
                "stream_iteration": (execution_context or {}).get("stream_iteration"),
                "runtime": (execution_context or {}).get("runtime"),
                "pipeline_state": {},
                "profile_state_by_node": local_profile_state,
                "node_warnings": local_node_warnings,
                "emit_node_progress": _emit_partition_progress,
                "node_progress_every": int((execution_context or {}).get("node_progress_every") or 2000),
                "should_abort": should_abort_cb,
                "raise_if_aborted": raise_if_aborted_cb,
                "profile_oracle_cfg": profile_oracle_cfg,
                "profile_oracle_session": None,
            }
            local_rows = self._transform_custom_fields(
                partition_rows,
                partition_config,
                custom_specs,
                execution_context=local_execution_context,
            )
            local_node_state = local_profile_state.get(node_id)
            if not isinstance(local_node_state, dict):
                local_node_state = {"documents": {}, "meta": {}, "stats": {}}
            local_stats = local_node_state.get("stats") if isinstance(local_node_state.get("stats"), dict) else {}
            try:
                local_processed = int(local_stats.get("custom_fields_incremental_processed_rows") or 0)
            except Exception:
                local_processed = len(partition_rows)
            if local_processed <= 0 and len(partition_rows) > 0:
                local_processed = len(partition_rows)
            try:
                local_validated = int(local_stats.get("custom_fields_incremental_validated_rows") or 0)
            except Exception:
                local_validated = 0
            if local_validated <= 0 and local_processed > 0:
                local_validated = local_processed
            try:
                local_flush_count = int(local_stats.get("custom_fields_incremental_flush_count") or 0)
            except Exception:
                local_flush_count = 0
            return {
                "partition_idx": partition_idx,
                "rows": local_rows if isinstance(local_rows, list) else [],
                "node_state": local_node_state,
                "warnings": local_node_warnings,
                "processed": local_processed,
                "validated": local_validated,
                "output_rows": len(local_rows) if isinstance(local_rows, list) else 0,
                "flush_count": local_flush_count,
            }

        max_workers = max(2, min(workers, len(active_partitions)))
        partition_results: List[Dict[str, Any]] = []
        try:
            if compute_executor == "process":
                process_jobs: List[Dict[str, Any]] = []
                for partition_idx, partition_rows, partition_token_set in active_partitions:
                    partition_prefetched_docs: Dict[str, Dict[str, Any]] = {}
                    partition_prefetched_meta: Dict[str, Dict[str, Any]] = {}
                    if use_global_prefetch:
                        for token in partition_token_set:
                            doc_value = prefetched_docs.get(token)
                            if isinstance(doc_value, dict):
                                partition_prefetched_docs[token] = doc_value
                            meta_value = prefetched_meta.get(token)
                            if isinstance(meta_value, dict):
                                partition_prefetched_meta[token] = meta_value
                    process_jobs.append({
                        "partition_idx": partition_idx,
                        "partition_rows": partition_rows,
                        "partition_tokens": list(partition_token_set),
                        "config": partition_config,
                        "custom_specs": custom_specs,
                        "node_id": node_id,
                        "pipeline_id": pipeline_id,
                        "profile_storage": profile_storage,
                        "profile_oracle_cfg": profile_oracle_cfg,
                        "prefetched_docs": partition_prefetched_docs,
                        "prefetched_meta": partition_prefetched_meta,
                        "prefetch_chunk_size": prefetch_chunk_size,
                        "execution_id": (execution_context or {}).get("execution_id"),
                        "node_label": (execution_context or {}).get("node_label"),
                        "mode": (execution_context or {}).get("mode"),
                        "stream_iteration": (execution_context or {}).get("stream_iteration"),
                        "runtime": (execution_context or {}).get("runtime"),
                        "node_progress_every": int((execution_context or {}).get("node_progress_every") or 2000),
                    })
                executor = ProcessPoolExecutor(max_workers=max_workers)
                abort_shutdown_fast = False
                try:
                    futures = [
                        executor.submit(_run_custom_profile_partition_process_worker, job)
                        for job in process_jobs
                    ]
                    pending = set(futures)
                    while pending:
                        _raise_if_aborted()
                        done, pending = wait(
                            pending,
                            timeout=0.2,
                            return_when=FIRST_COMPLETED,
                        )
                        if not done:
                            continue
                        for future in done:
                            partition_result = future.result()
                            if not isinstance(partition_result, dict):
                                raise RuntimeError("Parallel profile process partition returned invalid result")
                            if not bool(partition_result.get("ok")):
                                raise RuntimeError(
                                    f"Parallel profile process partition failed: "
                                    f"{partition_result.get('error')}"
                                )
                            partition_results.append(partition_result)
                            processed_rows_total += int(partition_result.get("processed") or 0)
                            validated_rows_total += int(partition_result.get("validated") or 0)
                            output_rows_total += int(partition_result.get("output_rows") or 0)
                            flush_count_total += int(partition_result.get("flush_count") or 0)
                            if emit_node_progress:
                                try:
                                    emit_node_progress({
                                        "processed_rows": int(processed_rows_total),
                                        "validated_rows": int(validated_rows_total),
                                        "output_rows": int(output_rows_total),
                                        "message": (
                                            f"⟳ Running {str((execution_context or {}).get('node_label') or 'Custom Fields')}… "
                                            f"parallel incremental {processed_rows_total:,}/{len(data):,} processed"
                                        ),
                                    })
                                except Exception:
                                    pass
                except ExecutionAbortedError:
                    abort_shutdown_fast = True
                    raise
                finally:
                    try:
                        executor.shutdown(
                            wait=not abort_shutdown_fast,
                            cancel_futures=abort_shutdown_fast,
                        )
                    except TypeError:
                        executor.shutdown(wait=not abort_shutdown_fast)
                    if abort_shutdown_fast:
                        _force_terminate_process_pool(executor)
            else:
                executor = ThreadPoolExecutor(max_workers=max_workers)
                abort_shutdown_fast = False
                try:
                    futures = [
                        executor.submit(_run_partition, partition)
                        for partition in active_partitions
                    ]
                    pending = set(futures)
                    while pending:
                        _raise_if_aborted()
                        done, pending = wait(
                            pending,
                            timeout=0.2,
                            return_when=FIRST_COMPLETED,
                        )
                        if not done:
                            continue
                        for future in done:
                            partition_result = future.result()
                            partition_results.append(partition_result)
                            processed_rows_total += int(partition_result.get("processed") or 0)
                            validated_rows_total += int(partition_result.get("validated") or 0)
                            output_rows_total += int(partition_result.get("output_rows") or 0)
                            flush_count_total += int(partition_result.get("flush_count") or 0)
                            if emit_node_progress:
                                try:
                                    emit_node_progress({
                                        "processed_rows": int(processed_rows_total),
                                        "validated_rows": int(validated_rows_total),
                                        "output_rows": int(output_rows_total),
                                        "message": (
                                            f"⟳ Running {str((execution_context or {}).get('node_label') or 'Custom Fields')}… "
                                            f"parallel incremental {processed_rows_total:,}/{len(data):,} processed"
                                        ),
                                    })
                                except Exception:
                                    pass
                except ExecutionAbortedError:
                    abort_shutdown_fast = True
                    raise
                finally:
                    try:
                        executor.shutdown(
                            wait=not abort_shutdown_fast,
                            cancel_futures=abort_shutdown_fast,
                        )
                    except TypeError:
                        executor.shutdown(wait=not abort_shutdown_fast)
        except ExecutionAbortedError:
            raise
        except Exception as exc:
            logger.warning(
                f"Parallel profile compute failed for pipeline {pipeline_id}, node {node_id}; "
                f"falling back to single compute strategy: {exc}"
            )
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )

        partition_results.sort(key=lambda item: int(item.get("partition_idx") or 0))
        for partition_result in partition_results:
            local_node_state = partition_result.get("node_state")
            if isinstance(local_node_state, dict):
                local_docs = local_node_state.get("documents")
                if isinstance(local_docs, dict):
                    merged_documents.update(local_docs)
                local_meta = local_node_state.get("meta")
                if isinstance(local_meta, dict):
                    merged_meta.update(local_meta)
            local_rows = partition_result.get("rows")
            if isinstance(local_rows, list) and local_rows:
                merged_rows.extend(local_rows)
            local_warnings = partition_result.get("warnings")
            if isinstance(local_warnings, list) and local_warnings:
                merged_warnings.extend([str(w) for w in local_warnings if str(w).strip()])

        profile_state_by_node = (
            (execution_context or {}).get("profile_state_by_node")
            if isinstance((execution_context or {}).get("profile_state_by_node"), dict)
            else None
        )
        if isinstance(profile_state_by_node, dict):
            stats_out = {
                "custom_fields_expression_engine_requested": str(
                    config.get("custom_expression_engine") or "auto"
                ).strip().lower(),
                "custom_fields_expression_engine_active": "python",
                "custom_fields_incremental_processed_rows": int(processed_rows_total),
                "custom_fields_incremental_validated_rows": int(validated_rows_total),
                "custom_fields_incremental_output_rows": int(len(merged_rows)),
                "custom_fields_incremental_flush_count": int(flush_count_total),
                "custom_fields_incremental_last_updated_at": datetime.utcnow().isoformat(),
                "custom_fields_compute_strategy": "parallel_by_profile_key",
                "custom_fields_compute_executor": str(compute_executor),
                "custom_fields_profile_storage": str(profile_storage),
                "custom_fields_compute_workers": int(max_workers),
                "custom_fields_compute_partitions": int(len(active_partitions)),
            }
            profile_state_by_node[node_id] = {
                "documents": merged_documents,
                "meta": merged_meta,
                "stats": stats_out,
            }

        if isinstance((execution_context or {}).get("node_warnings"), list):
            warn_target = (execution_context or {}).get("node_warnings")
            warn_seen = set(str(item) for item in warn_target if str(item).strip())
            for warning in merged_warnings:
                if warning in warn_seen:
                    continue
                warn_seen.add(warning)
                if len(warn_target) >= 200:
                    break
                warn_target.append(warning)

        if pipeline_id and (merged_documents or merged_meta):
            changed_tokens = list(
                {
                    str(token).strip()
                    for token in list(merged_documents.keys()) + list(merged_meta.keys())
                    if str(token).strip()
                }
            )
            if profile_storage == "oracle" and len(changed_tokens) == 0:
                if isinstance((execution_context or {}).get("node_warnings"), list):
                    warn_target = (execution_context or {}).get("node_warnings")
                    msg = (
                        "Oracle profile persist no-op: processed rows produced no profile changes "
                        "(keys/values already up-to-date)."
                    )
                    if msg not in warn_target:
                        warn_target.append(msg)
                if isinstance(profile_state_by_node, dict):
                    node_stats = profile_state_by_node.get(node_id, {}).get("stats")
                    if isinstance(node_stats, dict):
                        node_stats["custom_fields_oracle_noop"] = True
                        node_stats["custom_fields_oracle_noop_reason"] = (
                            "processed_rows_with_zero_changed_tokens"
                        )
                        node_stats["custom_fields_oracle_changed_tokens"] = 0
            node_state_payload = {
                "documents": merged_documents,
                "meta": merged_meta,
                "stats": (
                    profile_state_by_node.get(node_id, {}).get("stats", {})
                    if isinstance(profile_state_by_node, dict)
                    else {}
                ),
            }
            persisted = False
            if profile_storage == "oracle" and oracle_queue_enabled and changed_tokens:
                queue_stats_before = self._get_oracle_profile_write_queue_stats(
                    pipeline_id,
                    node_id,
                )
                failed_batches_before = int(queue_stats_before.get("failed_batches") or 0)
                enqueued, enqueue_error = self._enqueue_oracle_profile_write(
                    pipeline_id,
                    node_id,
                    node_state_payload,
                    changed_tokens=changed_tokens,
                    profile_cfg=profile_oracle_cfg,
                    queue_maxsize=oracle_queue_maxsize,
                    enqueue_timeout_seconds=oracle_queue_enqueue_timeout_seconds,
                    oracle_auto_commit=True,
                )
                if enqueued:
                    persisted = True
                    queue_stats_after_enqueue = self._get_oracle_profile_write_queue_stats(
                        pipeline_id,
                        node_id,
                    )
                    queue_timed_out = False
                    if oracle_queue_wait_on_force_flush:
                        drained_stats = self._wait_for_oracle_profile_write_queue_drain(
                            pipeline_id,
                            node_id,
                            timeout_seconds=oracle_queue_wait_timeout_seconds,
                            should_abort=should_abort_cb,
                        )
                        queue_timed_out = bool(drained_stats.get("timed_out", False))
                        queue_stats_after_enqueue = drained_stats
                    queue_failed_batches = int(queue_stats_after_enqueue.get("failed_batches") or 0)
                    queue_worker_alive = bool(queue_stats_after_enqueue.get("worker_alive", False))
                    queue_failed_after_enqueue = queue_failed_batches > failed_batches_before
                    queue_fatal = bool(queue_failed_after_enqueue or not queue_worker_alive)
                    queue_timeout_only = bool(queue_timed_out and not queue_fatal)
                    if queue_fatal:
                        logger.warning(
                            f"Oracle profile queue durability fallback for pipeline {pipeline_id}, node {node_id}: "
                            f"timed_out={queue_timed_out}, worker_alive={queue_worker_alive}, "
                            f"failed_batches_before={failed_batches_before}, failed_batches_after={queue_failed_batches}. "
                            "Applying synchronous persist fallback."
                        )
                        persisted = False
                    elif queue_timeout_only:
                        logger.warning(
                            f"Oracle profile queue wait timed out for pipeline {pipeline_id}, node {node_id}: "
                            f"worker_alive={queue_worker_alive}, failed_batches={queue_failed_batches}. "
                            "Continuing async persist without sync fallback."
                        )
                    if isinstance(profile_state_by_node, dict):
                        node_stats = profile_state_by_node.get(node_id, {}).get("stats")
                        if isinstance(node_stats, dict):
                            node_stats["custom_fields_oracle_queue_enabled"] = True
                            node_stats["custom_fields_oracle_queue_wait_on_force_flush"] = bool(
                                oracle_queue_wait_on_force_flush
                            )
                            node_stats["custom_fields_oracle_queue_wait_timeout_seconds"] = float(
                                oracle_queue_wait_timeout_seconds
                            )
                            node_stats["custom_fields_oracle_queue_depth"] = int(
                                queue_stats_after_enqueue.get("queue_depth") or 0
                            )
                            node_stats["custom_fields_oracle_queue_pending_batches"] = int(
                                queue_stats_after_enqueue.get("pending_batches") or 0
                            )
                            node_stats["custom_fields_oracle_queue_inflight_batches"] = int(
                                queue_stats_after_enqueue.get("inflight_batches") or 0
                            )
                            node_stats["custom_fields_oracle_queue_enqueued_batches"] = int(
                                queue_stats_after_enqueue.get("enqueued_batches") or 0
                            )
                            node_stats["custom_fields_oracle_queue_processed_batches"] = int(
                                queue_stats_after_enqueue.get("processed_batches") or 0
                            )
                            node_stats["custom_fields_oracle_queue_failed_batches"] = int(
                                queue_stats_after_enqueue.get("failed_batches") or 0
                            )
                            node_stats["custom_fields_oracle_queue_worker_alive"] = bool(
                                queue_stats_after_enqueue.get("worker_alive", False)
                            )
                            node_stats["custom_fields_oracle_queue_last_error"] = str(
                                queue_stats_after_enqueue.get("last_error") or ""
                            )
                            node_stats["custom_fields_oracle_queue_wait_timed_out"] = bool(
                                queue_timed_out
                            )
                            node_stats["custom_fields_oracle_queue_timeout_only"] = bool(
                                queue_timeout_only
                            )
                            node_stats["custom_fields_oracle_queue_sync_fallback_applied"] = bool(
                                queue_fatal
                            )
                else:
                    logger.warning(
                        f"Parallel profile enqueue failed for pipeline {pipeline_id}, node {node_id}: "
                        f"{enqueue_error or 'unknown queue error'}. Falling back to sync persist."
                    )

            if not persisted:
                persisted = self._save_profile_state_single_node_by_storage(
                    pipeline_id,
                    node_id,
                    node_state_payload,
                    changed_tokens=changed_tokens,
                    storage=profile_storage,
                    profile_cfg=profile_oracle_cfg,
                    oracle_session=None,
                    oracle_auto_commit=True,
                )
            if not persisted:
                raise RuntimeError(
                    f"Parallel profile compute persist failed for pipeline {pipeline_id}, "
                    f"node {node_id}, storage={profile_storage}."
                )

        return merged_rows

    def _normalize_mlops_mode(self, value: Any) -> str:
        text = str(value or "").strip().lower()
        if text in {"production", "prod", "predict", "prediction", "inference"}:
            return "production"
        return "training"

    def _mlops_runtime_to_scalar(self, value: Any) -> Any:
        if value is None:
            return None
        if isinstance(value, (str, int, float, bool)):
            return value
        if isinstance(value, (datetime, date, time)):
            safe = self._json_safe_value(value)
            return safe if isinstance(safe, (str, int, float, bool)) or safe is None else str(safe)
        if isinstance(value, (list, tuple, set)):
            items = list(value)
            if len(items) == 0:
                return None
            if len(items) == 1:
                return self._mlops_runtime_to_scalar(items[0])
            try:
                return json.dumps(self._json_safe_value(items), ensure_ascii=False)
            except Exception:
                return str(items)
        if isinstance(value, dict):
            try:
                return json.dumps(self._json_safe_value(value), ensure_ascii=False)
            except Exception:
                return str(value)
        safe_value = self._json_safe_value(value)
        if isinstance(safe_value, (str, int, float, bool)) or safe_value is None:
            return safe_value
        try:
            return json.dumps(safe_value, ensure_ascii=False)
        except Exception:
            return str(safe_value)

    def _load_mlops_runtime_model_bundle(self, bundle_cfg: Any) -> Dict[str, Any]:
        bundle_raw = bundle_cfg
        if isinstance(bundle_raw, str):
            text = bundle_raw.strip()
            if not text:
                raise RuntimeError("MLOps runtime model bundle is empty.")
            try:
                bundle_raw = json.loads(text)
            except Exception:
                raise RuntimeError("MLOps runtime model bundle is not valid JSON.") from None
        if not isinstance(bundle_raw, dict):
            raise RuntimeError("MLOps runtime model bundle is missing or invalid.")

        artifact_type = str(
            bundle_raw.get("artifact_type")
            or bundle_raw.get("type")
            or "pickle_gzip_file"
        ).strip().lower()
        artifact_path = str(bundle_raw.get("path") or "").strip()
        if not artifact_path:
            raise RuntimeError("MLOps runtime model bundle path is missing.")

        resolved_path = artifact_path
        if not os.path.isabs(resolved_path):
            resolved_path = os.path.abspath(os.path.join(os.path.dirname(__file__), resolved_path))
        if not os.path.exists(resolved_path):
            raise RuntimeError(f"MLOps runtime model bundle file not found: {resolved_path}")

        try:
            mtime = float(os.path.getmtime(resolved_path))
        except Exception:
            mtime = 0.0
        cache_key = f"{artifact_type}:{resolved_path}:{mtime:.6f}"

        with self._mlops_runtime_model_cache_lock:
            cached = self._mlops_runtime_model_cache.get(cache_key)
            if isinstance(cached, dict):
                return cached

        if artifact_type == "pickle_file":
            with open(resolved_path, "rb") as handle:
                payload = pickle.load(handle)
        else:
            with gzip.open(resolved_path, "rb") as handle:
                payload = pickle.load(handle)

        if not isinstance(payload, dict):
            raise RuntimeError("MLOps runtime model bundle payload is invalid.")

        with self._mlops_runtime_model_cache_lock:
            if len(self._mlops_runtime_model_cache) > 32:
                self._mlops_runtime_model_cache.clear()
            self._mlops_runtime_model_cache[cache_key] = payload
        return payload

    def _set_mlops_runtime_field(self, row: Dict[str, Any], path: str, value: Any) -> None:
        field_path = str(path or "").strip()
        if not field_path:
            return
        safe_value = self._json_safe_value(value)
        if "." in field_path or "[" in field_path:
            self._set_profile_path_value_with_wildcards(row, field_path, safe_value)
            return
        row[field_path] = safe_value

    def _transform_mlops(
        self,
        data: list,
        config: dict,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        rows = data if isinstance(data, list) else []
        mode = self._normalize_mlops_mode((config or {}).get("mlops_mode"))
        if mode != "production":
            return rows

        bundle_cfg = (config or {}).get("mlops_stage3_model_bundle")
        if not bundle_cfg and isinstance((config or {}).get("mlops_stage3_last_run_summary"), dict):
            bundle_cfg = (config or {}).get("mlops_stage3_last_run_summary", {}).get("runtime_model_bundle")
        if not bundle_cfg:
            raise RuntimeError(
                "MLOps node is in production mode but no trained model bundle is available. "
                "Run Stage 3 training and save MLOps Studio first."
            )

        bundle = self._load_mlops_runtime_model_bundle(bundle_cfg)
        raw_feature_fields = bundle.get("feature_fields")
        if not raw_feature_fields:
            raw_feature_fields = (config or {}).get("mlops_stage3_feature_fields")
        if isinstance(raw_feature_fields, str):
            text = raw_feature_fields.strip()
            if text.startswith("[") and text.endswith("]"):
                try:
                    parsed = json.loads(text)
                    raw_feature_fields = parsed
                except Exception:
                    raw_feature_fields = [part.strip() for part in text.split(",") if part.strip()]
            elif text:
                raw_feature_fields = [part.strip() for part in text.split(",") if part.strip()]
            else:
                raw_feature_fields = []
        if not isinstance(raw_feature_fields, (list, tuple, set)):
            raw_feature_fields = []
        feature_fields = [
            str(item or "").strip()
            for item in raw_feature_fields
            if str(item or "").strip()
        ]

        pred_field = str((config or {}).get("mlops_prediction_field") or "prediction").strip() or "prediction"
        score_field = str((config or {}).get("mlops_prediction_score_field") or "prediction_score").strip()

        dict_rows: List[Dict[str, Any]] = [row for row in rows if isinstance(row, dict)]
        predictor_kind = str(bundle.get("predictor_kind") or "pipeline").strip().lower() or "pipeline"
        task_type = str(bundle.get("task_type") or "").strip().lower()
        runtime_metadata = bundle.get("runtime_metadata") if isinstance(bundle.get("runtime_metadata"), dict) else {}

        def _sanitize_field_suffix(value: Any, fallback: str) -> str:
            text = str(value or "").strip()
            if not text:
                text = fallback
            text = re.sub(r"[^0-9A-Za-z_]+", "_", text).strip("_").lower()
            return text or fallback

        def _normalize_forecast_mode(value: Any) -> str:
            raw = str(value or "").strip().lower()
            if raw in {"future_only", "future-only", "future"}:
                return "future_only"
            if raw in {"in_place", "inplace", "in-place", "input_only", "row"}:
                return "in_place"
            return "append_future"

        def _normalize_forecast_frequency(value: Any) -> str:
            raw = str(value or "").strip().upper()
            if raw.startswith("W"):
                return "W"
            if raw.startswith("M"):
                return "M"
            return "D"

        is_forecasting_bundle = (
            task_type == "forecasting"
            or predictor_kind in {"forecasting_sarimax", "forecasting_multi_sarimax"}
        )
        if is_forecasting_bundle:
            try:
                import numpy as _np  # type: ignore
                import pandas as _pd  # type: ignore
            except Exception as exc:
                raise RuntimeError(f"MLOps production forecasting requires pandas/numpy runtime dependencies: {exc}")

            target_fields_raw = runtime_metadata.get("target_fields")
            target_fields: List[str] = []
            if isinstance(target_fields_raw, (list, tuple, set)):
                target_fields = [
                    str(item or "").strip()
                    for item in target_fields_raw
                    if str(item or "").strip()
                ]
            if not target_fields:
                single_target = str(
                    runtime_metadata.get("target_field")
                    or bundle.get("target_field")
                    or ""
                ).strip()
                if single_target:
                    target_fields = [single_target]
            if not target_fields:
                target_fields = [pred_field]

            model_map: Dict[str, Any] = {}
            if predictor_kind == "forecasting_multi_sarimax":
                raw_map = bundle.get("model_pipeline")
                if not isinstance(raw_map, dict) or not raw_map:
                    raise RuntimeError("MLOps forecasting bundle is missing target model map.")
                for idx, target in enumerate(target_fields):
                    model_map[target] = raw_map.get(target)
                    if model_map[target] is None and idx < len(raw_map):
                        try:
                            model_map[target] = list(raw_map.values())[idx]
                        except Exception:
                            model_map[target] = None
            else:
                model_obj = bundle.get("model_pipeline")
                if model_obj is None:
                    raise RuntimeError("MLOps forecasting bundle is missing SARIMAX model object.")
                model_map[target_fields[0]] = model_obj

            forecast_mode = _normalize_forecast_mode(
                (config or {}).get("mlops_forecast_output_mode")
                or runtime_metadata.get("forecast_output_mode")
                or "append_future"
            )
            raw_steps = (
                (config or {}).get("mlops_forecast_runtime_steps")
                or (config or {}).get("mlops_stage3_forecast_horizon")
                or runtime_metadata.get("forecast_horizon")
                or 0
            )
            try:
                forecast_steps = int(float(raw_steps))
            except Exception:
                forecast_steps = 0
            if forecast_steps <= 0:
                forecast_steps = max(1, int(len(dict_rows) if len(dict_rows) > 0 else 30))
            forecast_steps = max(1, min(forecast_steps, 3650))
            in_place_steps = max(0, len(dict_rows))
            steps_to_predict = max(forecast_steps, in_place_steps if in_place_steps > 0 else 0)
            if steps_to_predict <= 0:
                steps_to_predict = forecast_steps

            freq_code = _normalize_forecast_frequency(
                (config or {}).get("mlops_stage3_forecast_frequency")
                or runtime_metadata.get("forecast_frequency")
                or "D"
            )
            date_field = str(
                (config or {}).get("mlops_stage3_forecast_date_field")
                or runtime_metadata.get("forecast_date_field")
                or ""
            ).strip()
            date_output_field = str(
                (config or {}).get("mlops_forecast_output_date_field")
                or (date_field if date_field else "forecast_date")
            ).strip() or "forecast_date"

            fallback_future_dates: List[str] = []
            if date_field:
                parsed_dates: List[Any] = []
                for row in dict_rows:
                    value, found = self._extract_row_value_by_path(row, date_field)
                    if not found:
                        value = row.get(date_field)
                    if isinstance(value, dict):
                        value = None
                    elif hasattr(value, "tolist") and not isinstance(value, (str, bytes)):
                        try:
                            arr = value.tolist()
                        except Exception:
                            arr = None
                        if isinstance(arr, list):
                            value = arr[0] if arr else None
                        elif arr is not None and not isinstance(arr, (dict, list, tuple, set)):
                            value = arr
                    elif isinstance(value, (list, tuple, set)):
                        value = next(iter(value), None)
                    try:
                        dt = _pd.to_datetime(value, errors="coerce")
                    except Exception:
                        dt = _pd.NaT
                    if isinstance(dt, _pd.Series):
                        dt = dt.dropna().iloc[0] if not dt.dropna().empty else _pd.NaT
                    elif isinstance(dt, _pd.DataFrame):
                        non_empty_dt = dt.stack().dropna()
                        dt = non_empty_dt.iloc[0] if not non_empty_dt.empty else _pd.NaT
                    try:
                        if _pd.notna(dt):
                            parsed_dates.append(dt)
                    except Exception:
                        pass
                if parsed_dates:
                    base_dt = max(parsed_dates)
                    try:
                        rng = _pd.date_range(start=base_dt, periods=forecast_steps + 1, freq=freq_code)[1:]
                        fallback_future_dates = [str(item) for item in list(rng)]
                    except Exception:
                        fallback_future_dates = []

            def _series_to_list(value: Any) -> List[Any]:
                if value is None:
                    return []
                if hasattr(value, "tolist"):
                    try:
                        out = value.tolist()
                        if isinstance(out, list):
                            return out
                    except Exception:
                        pass
                if isinstance(value, (list, tuple)):
                    return list(value)
                try:
                    return [value]
                except Exception:
                    return []

            def _forecast_values(model_obj: Any, steps: int) -> Dict[str, Any]:
                if model_obj is None:
                    raise RuntimeError("MLOps forecasting model object is missing for target.")
                preds: List[Any] = []
                scores: List[Any] = []
                dates: List[str] = []
                if hasattr(model_obj, "get_forecast"):
                    forecast_result = model_obj.get_forecast(steps=int(steps))
                    predicted_mean = getattr(forecast_result, "predicted_mean", None)
                    if predicted_mean is None and hasattr(model_obj, "forecast"):
                        predicted_mean = model_obj.forecast(steps=int(steps))
                    preds = _series_to_list(predicted_mean)
                    idx = getattr(predicted_mean, "index", None) if predicted_mean is not None else None
                    if idx is not None:
                        try:
                            dates = [str(item) for item in list(idx)]
                        except Exception:
                            dates = []
                    se_mean = getattr(forecast_result, "se_mean", None)
                    scores = _series_to_list(se_mean)
                elif hasattr(model_obj, "forecast"):
                    predicted_mean = model_obj.forecast(steps=int(steps))
                    preds = _series_to_list(predicted_mean)
                    idx = getattr(predicted_mean, "index", None)
                    if idx is not None:
                        try:
                            dates = [str(item) for item in list(idx)]
                        except Exception:
                            dates = []
                else:
                    raise RuntimeError("MLOps forecasting model does not support forecast/get_forecast.")

                if len(preds) < int(steps):
                    preds = list(preds) + [None] * (int(steps) - len(preds))
                if len(scores) < int(steps):
                    scores = list(scores) + [None] * (int(steps) - len(scores))
                return {
                    "predictions": preds[: int(steps)],
                    "scores": scores[: int(steps)],
                    "dates": dates[: int(steps)],
                }

            target_forecasts: Dict[str, Dict[str, Any]] = {}
            for target in target_fields:
                model_obj = model_map.get(target)
                if model_obj is None and model_map:
                    model_obj = list(model_map.values())[0]
                target_forecasts[target] = _forecast_values(model_obj, steps_to_predict)

            pred_aux_prefix = _sanitize_field_suffix(pred_field, "prediction")
            score_aux_prefix = _sanitize_field_suffix(score_field, "prediction_score") if score_field else "prediction_score"
            is_multi_target = len(target_fields) > 1

            output_rows: List[Any] = []
            if forecast_mode in {"append_future", "in_place"}:
                dict_index = 0
                for row in rows:
                    if not isinstance(row, dict):
                        output_rows.append(row)
                        continue
                    next_row = dict(row)
                    if is_multi_target:
                        pred_map: Dict[str, Any] = {}
                        score_map: Dict[str, Any] = {}
                        for target_idx, target in enumerate(target_fields):
                            fpack = target_forecasts.get(target) or {}
                            target_preds = list(fpack.get("predictions") or [])
                            target_scores = list(fpack.get("scores") or [])
                            target_pred = (
                                self._mlops_runtime_to_scalar(target_preds[dict_index])
                                if dict_index < len(target_preds) else None
                            )
                            pred_map[target] = target_pred
                            target_key = _sanitize_field_suffix(target, f"target_{target_idx + 1}")
                            self._set_mlops_runtime_field(next_row, f"{pred_aux_prefix}_{target_key}", target_pred)
                            if score_field:
                                target_score = (
                                    self._mlops_runtime_to_scalar(target_scores[dict_index])
                                    if dict_index < len(target_scores) else None
                                )
                                score_map[target] = target_score
                                self._set_mlops_runtime_field(next_row, f"{score_aux_prefix}_{target_key}", target_score)
                        self._set_mlops_runtime_field(next_row, pred_field, pred_map)
                        if score_field:
                            self._set_mlops_runtime_field(next_row, score_field, score_map)
                    else:
                        target = target_fields[0]
                        fpack = target_forecasts.get(target) or {}
                        target_preds = list(fpack.get("predictions") or [])
                        target_scores = list(fpack.get("scores") or [])
                        prediction_value = (
                            self._mlops_runtime_to_scalar(target_preds[dict_index])
                            if dict_index < len(target_preds) else None
                        )
                        self._set_mlops_runtime_field(next_row, pred_field, prediction_value)
                        if score_field:
                            score_value = (
                                self._mlops_runtime_to_scalar(target_scores[dict_index])
                                if dict_index < len(target_scores) else None
                            )
                            self._set_mlops_runtime_field(next_row, score_field, score_value)
                    output_rows.append(next_row)
                    dict_index += 1

            if forecast_mode in {"append_future", "future_only"}:
                for step_idx in range(forecast_steps):
                    future_row: Dict[str, Any] = {
                        "mlops_segment": "future_forecast",
                        "mlops_step": int(step_idx + 1),
                    }
                    if date_output_field:
                        forecast_date = None
                        for target in target_fields:
                            target_dates = list((target_forecasts.get(target) or {}).get("dates") or [])
                            if step_idx < len(target_dates) and str(target_dates[step_idx]).strip():
                                forecast_date = str(target_dates[step_idx])
                                break
                        if forecast_date is None and step_idx < len(fallback_future_dates):
                            forecast_date = fallback_future_dates[step_idx]
                        if forecast_date is not None:
                            self._set_mlops_runtime_field(future_row, date_output_field, forecast_date)

                    if is_multi_target:
                        pred_map: Dict[str, Any] = {}
                        score_map: Dict[str, Any] = {}
                        for target_idx, target in enumerate(target_fields):
                            fpack = target_forecasts.get(target) or {}
                            target_preds = list(fpack.get("predictions") or [])
                            target_scores = list(fpack.get("scores") or [])
                            target_pred = (
                                self._mlops_runtime_to_scalar(target_preds[step_idx])
                                if step_idx < len(target_preds) else None
                            )
                            pred_map[target] = target_pred
                            target_key = _sanitize_field_suffix(target, f"target_{target_idx + 1}")
                            self._set_mlops_runtime_field(future_row, f"{pred_aux_prefix}_{target_key}", target_pred)
                            if score_field:
                                target_score = (
                                    self._mlops_runtime_to_scalar(target_scores[step_idx])
                                    if step_idx < len(target_scores) else None
                                )
                                score_map[target] = target_score
                                self._set_mlops_runtime_field(future_row, f"{score_aux_prefix}_{target_key}", target_score)
                        self._set_mlops_runtime_field(future_row, pred_field, pred_map)
                        if score_field:
                            self._set_mlops_runtime_field(future_row, score_field, score_map)
                    else:
                        target = target_fields[0]
                        fpack = target_forecasts.get(target) or {}
                        target_preds = list(fpack.get("predictions") or [])
                        target_scores = list(fpack.get("scores") or [])
                        prediction_value = (
                            self._mlops_runtime_to_scalar(target_preds[step_idx])
                            if step_idx < len(target_preds) else None
                        )
                        self._set_mlops_runtime_field(future_row, pred_field, prediction_value)
                        if score_field:
                            score_value = (
                                self._mlops_runtime_to_scalar(target_scores[step_idx])
                                if step_idx < len(target_scores) else None
                            )
                            self._set_mlops_runtime_field(future_row, score_field, score_value)
                    output_rows.append(future_row)

            if isinstance(execution_context, dict):
                node_warnings = execution_context.get("node_warnings")
                if isinstance(node_warnings, list):
                    mode_msg = (
                        f"MLOps production forecasting applied: mode={forecast_mode}, "
                        f"targets={len(target_fields)}, input_rows={len(dict_rows)}, "
                        f"future_steps={forecast_steps}, prediction_field={pred_field}"
                    )
                    if score_field:
                        mode_msg += f", score_field={score_field}"
                    if mode_msg not in node_warnings:
                        node_warnings.append(mode_msg)
            if forecast_mode == "future_only":
                return [row for row in output_rows if isinstance(row, dict) and row.get("mlops_segment") == "future_forecast"]
            return output_rows

        if not feature_fields:
            raise RuntimeError("MLOps production mode requires feature fields from Stage 3 training.")

        feature_records: List[Dict[str, Any]] = []
        for row in dict_rows:
            record: Dict[str, Any] = {}
            for field_path in feature_fields:
                value, found = self._extract_row_value_by_path(row, field_path)
                if not found:
                    value = row.get(field_path)
                record[field_path] = self._mlops_runtime_to_scalar(value)
            feature_records.append(record)

        if len(feature_records) <= 0:
            return rows

        try:
            import numpy as _np  # type: ignore
            import pandas as _pd  # type: ignore
        except Exception as exc:
            raise RuntimeError(f"MLOps production mode requires pandas/numpy runtime dependencies: {exc}")

        feature_df = _pd.DataFrame(feature_records, columns=feature_fields)
        predictions: List[Any] = []
        scores: List[Any] = []

        if predictor_kind == "components":
            preprocessor = bundle.get("preprocessor")
            estimator = bundle.get("estimator")
            if preprocessor is None or estimator is None:
                raise RuntimeError("MLOps runtime model components are missing preprocessor/estimator.")
            transformed = preprocessor.transform(feature_df)
            pred_arr = estimator.predict(transformed)
            predictions = pred_arr.tolist() if hasattr(pred_arr, "tolist") else list(pred_arr)
            if hasattr(estimator, "predict_proba"):
                proba = estimator.predict_proba(transformed)
                if getattr(proba, "ndim", 0) == 2:
                    scores = [float(_np.max(row)) for row in proba]
            elif task_type == "anomaly_detection" and hasattr(estimator, "decision_function"):
                decision = estimator.decision_function(transformed)
                scores = decision.tolist() if hasattr(decision, "tolist") else list(decision)
        else:
            model_pipeline = bundle.get("model_pipeline")
            if model_pipeline is None:
                raise RuntimeError("MLOps runtime model bundle is missing model pipeline.")
            try:
                pred_arr = model_pipeline.predict(feature_df)
                predictions = pred_arr.tolist() if hasattr(pred_arr, "tolist") else list(pred_arr)
                if hasattr(model_pipeline, "predict_proba"):
                    proba = model_pipeline.predict_proba(feature_df)
                    if getattr(proba, "ndim", 0) == 2:
                        scores = [float(_np.max(row)) for row in proba]
            except Exception as exc:
                # Backward-compat safety: older forecasting bundles may have
                # predictor_kind='pipeline' but carry a SARIMAX fit object.
                if hasattr(model_pipeline, "get_forecast") or hasattr(model_pipeline, "forecast"):
                    forecast_steps = int(len(dict_rows))
                    if hasattr(model_pipeline, "get_forecast"):
                        forecast_result = model_pipeline.get_forecast(steps=forecast_steps)
                        predicted_mean = getattr(forecast_result, "predicted_mean", None)
                        if predicted_mean is not None:
                            predictions = predicted_mean.tolist() if hasattr(predicted_mean, "tolist") else list(predicted_mean)
                        else:
                            fallback_pred = model_pipeline.forecast(steps=forecast_steps)
                            predictions = fallback_pred.tolist() if hasattr(fallback_pred, "tolist") else list(fallback_pred)
                        se_mean = getattr(forecast_result, "se_mean", None)
                        if se_mean is not None:
                            scores = se_mean.tolist() if hasattr(se_mean, "tolist") else list(se_mean)
                    else:
                        fallback_pred = model_pipeline.forecast(steps=forecast_steps)
                        predictions = fallback_pred.tolist() if hasattr(fallback_pred, "tolist") else list(fallback_pred)
                else:
                    raise RuntimeError(f"MLOps production scoring failed: {exc}") from exc

        if len(predictions) != len(dict_rows):
            raise RuntimeError(
                f"MLOps prediction row-count mismatch: predicted={len(predictions)} input={len(dict_rows)}"
            )

        out_rows: List[Any] = []
        dict_index = 0
        for row in rows:
            if not isinstance(row, dict):
                out_rows.append(row)
                continue
            next_row = dict(row)
            prediction_value = self._mlops_runtime_to_scalar(predictions[dict_index])
            self._set_mlops_runtime_field(next_row, pred_field, prediction_value)
            if score_field:
                score_value = None
                if dict_index < len(scores):
                    score_value = self._mlops_runtime_to_scalar(scores[dict_index])
                self._set_mlops_runtime_field(next_row, score_field, score_value)
            out_rows.append(next_row)
            dict_index += 1

        if isinstance(execution_context, dict):
            node_warnings = execution_context.get("node_warnings")
            if isinstance(node_warnings, list):
                mode_msg = (
                    f"MLOps production scoring applied: rows={len(dict_rows)}, "
                    f"prediction_field={pred_field}{', score_field=' + score_field if score_field else ''}"
                )
                if mode_msg not in node_warnings:
                    node_warnings.append(mode_msg)
        return out_rows

    def _transform_map(
        self,
        data: list,
        config: dict,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        custom_specs = self._parse_custom_fields_config(config.get("custom_fields"))
        if not custom_specs and bool(config.get("custom_profile_enabled", False)):
            warn_msg = (
                "Custom profile mode is enabled, but no enabled custom fields were found. "
                "Enable at least one custom field in Custom Fields Studio."
            )
            node_warnings = execution_context.get("node_warnings") if isinstance(execution_context, dict) else None
            if isinstance(node_warnings, list) and warn_msg not in node_warnings:
                node_warnings.append(warn_msg)
            logger.warning(warn_msg)
        if custom_specs:
            compute_strategy = self._normalize_profile_compute_strategy(
                config.get("custom_profile_compute_strategy", "single")
            )
            if (
                bool(config.get("custom_profile_enabled", False))
                and compute_strategy == "parallel_by_profile_key"
            ):
                return self._transform_custom_fields_parallel_by_profile_key(
                    data,
                    config,
                    custom_specs,
                    execution_context=execution_context,
                )
            return self._transform_custom_fields(
                data,
                config,
                custom_specs,
                execution_context=execution_context,
            )

        fields = self._parse_selected_fields(config.get("fields", ""))
        if not fields:
            return data

        should_abort_cb = (
            execution_context.get("should_abort")
            if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        result = []
        matched_count = 0
        for idx, row in enumerate(data):
            if idx == 0 or idx % 500 == 0:
                _raise_if_aborted()
            out_row = {}
            for field in fields:
                value, found = self._extract_row_value_by_path(row, field)
                if found:
                    out_row[field] = value
                    matched_count += 1
            result.append(out_row)
        if matched_count == 0 and data:
            logger.warning("Select Fields matched zero fields; returning input rows unchanged")
            return data
        return result

    def _transform_rename(self, data: list, config: dict) -> list:
        mappings = {}
        for line in config.get("mappings", "").splitlines():
            if ":" in line:
                old, new = line.split(":", 1)
                mappings[old.strip()] = new.strip()
        if not mappings:
            return data
        result = []
        for row in data:
            new_row = {}
            for k, v in row.items():
                new_row[mappings.get(k, k)] = v
            result.append(new_row)
        return result

    def _transform_aggregate(self, data: list, config: dict) -> list:
        import pandas as pd
        if not data:
            return []
        df = pd.DataFrame(data)
        group_by = [f.strip() for f in config.get("group_by", "").split(",") if f.strip()]
        agg_field = config.get("agg_field", "")
        agg_func = config.get("agg_func", "sum")
        if group_by and agg_field and agg_field in df.columns:
            valid_groups = [g for g in group_by if g in df.columns]
            if valid_groups:
                result = df.groupby(valid_groups)[agg_field].agg(agg_func).reset_index()
                return result.to_dict(orient="records")
        return data

    def _transform_join(
        self,
        data: list,
        config: dict,
        incoming_by_source: Optional[Dict[str, list]] = None,
        incoming_order: Optional[List[str]] = None,
    ) -> list:
        import pandas as pd

        by_source = incoming_by_source or {}
        order = [sid for sid in (incoming_order or []) if sid in by_source]

        def _dict_rows(rows: Any) -> list:
            if not isinstance(rows, list):
                return []
            return [row for row in rows if isinstance(row, dict)]

        # Resolve left/right sources from config when provided, else pick first two incoming branches.
        left_source = str(config.get("left_source_node") or "").strip()
        right_source = str(config.get("right_source_node") or "").strip()

        available_sources = order or list(by_source.keys())
        if not left_source or left_source not in by_source:
            left_source = available_sources[0] if available_sources else ""
        if not right_source or right_source not in by_source or right_source == left_source:
            right_source = next((sid for sid in available_sources if sid != left_source), "")

        left_rows = _dict_rows(by_source.get(left_source, []))
        right_rows = _dict_rows(by_source.get(right_source, []))

        # Fallback for legacy/single-input join configs.
        if not left_rows and not right_rows:
            return data

        if not left_rows or not right_rows:
            raise RuntimeError("Join transform requires two connected source branches with tabular rows.")

        left_key = str(config.get("left_key") or "").strip()
        right_key = str(config.get("right_key") or "").strip()
        if not left_key or not right_key:
            raise RuntimeError("Join transform requires both 'left_key' and 'right_key'.")

        join_type_raw = str(config.get("join_type") or "inner").strip().lower()
        join_map = {
            "inner": "inner",
            "left": "left",
            "right": "right",
            "full": "outer",
            "outer": "outer",
        }
        join_type = join_map.get(join_type_raw, "inner")

        left_suffix = str(config.get("left_suffix") or "_left")
        right_suffix = str(config.get("right_suffix") or "_right")

        left_df = pd.DataFrame(left_rows)
        right_df = pd.DataFrame(right_rows)

        if left_key not in left_df.columns:
            raise RuntimeError(f"Left key '{left_key}' not found in left source fields.")
        if right_key not in right_df.columns:
            raise RuntimeError(f"Right key '{right_key}' not found in right source fields.")

        joined = left_df.merge(
            right_df,
            how=join_type,
            left_on=left_key,
            right_on=right_key,
            suffixes=(left_suffix, right_suffix),
            sort=False,
        )
        joined = joined.astype(object).where(pd.notna(joined), None)
        return joined.to_dict(orient="records")

    def _transform_sort(self, data: list, config: dict) -> list:
        field = config.get("field", "")
        order = config.get("order", "asc")
        if not field:
            return data
        return sorted(data, key=lambda x: x.get(field, ""), reverse=(order == "desc"))

    def _transform_deduplicate(self, data: list, config: dict) -> list:
        key_field = config.get("key_field", "")
        seen = set()
        result = []
        for row in data:
            key = row.get(key_field) if key_field else json.dumps(row, sort_keys=True)
            if key not in seen:
                seen.add(key)
                result.append(row)
        return result

    def _parse_duration_seconds(self, raw: Any) -> float:
        text = str(raw or "").strip().lower()
        if not text:
            return 0.0
        try:
            return max(0.0, float(text))
        except Exception:
            pass
        normalized_text = text.replace(" ", "")
        m = re.fullmatch(
            r"(\d+(?:\.\d+)?)(us|µs|microsecond|microseconds|micro|micros|ms|millisecond|milliseconds|s|sec|secs|second|seconds|m|min|mins|minute|minutes|h|hr|hrs|hour|hours|d|day|days)",
            normalized_text,
        )
        if not m:
            return 0.0
        value = float(m.group(1))
        unit = m.group(2)
        if unit in {"us", "µs", "microsecond", "microseconds", "micro", "micros"}:
            return max(0.0, value / 1_000_000.0)
        if unit in {"ms", "millisecond", "milliseconds"}:
            return max(0.0, value / 1000.0)
        if unit in {"s", "sec", "secs", "second", "seconds"}:
            return max(0.0, value)
        if unit in {"m", "min", "mins", "minute", "minutes"}:
            return max(0.0, value * 60.0)
        if unit in {"h", "hr", "hrs", "hour", "hours"}:
            return max(0.0, value * 3600.0)
        if unit in {"d", "day", "days"}:
            return max(0.0, value * 86400.0)
        return 0.0

    def _resolve_delay_seconds(self, config: Dict[str, Any]) -> float:
        if not isinstance(config, dict):
            return 0.0

        raw_text = str(config.get("delay") or config.get("delay_text") or "").strip()
        if raw_text:
            parsed = self._parse_duration_seconds(raw_text)
            if parsed > 0:
                return parsed

        raw_value = config.get("delay_value", config.get("delay_amount", 0))
        try:
            value_num = float(raw_value)
        except Exception:
            value_num = 0.0
        value_num = max(0.0, value_num)

        unit = str(config.get("delay_unit", "s") or "s").strip().lower()
        multipliers = {
            "us": 1.0 / 1_000_000.0,
            "µs": 1.0 / 1_000_000.0,
            "micro": 1.0 / 1_000_000.0,
            "micros": 1.0 / 1_000_000.0,
            "ms": 1.0 / 1000.0,
            "s": 1.0,
            "sec": 1.0,
            "secs": 1.0,
            "m": 60.0,
            "min": 60.0,
            "mins": 60.0,
            "h": 3600.0,
            "hr": 3600.0,
            "hrs": 3600.0,
            "d": 86400.0,
            "day": 86400.0,
            "days": 86400.0,
        }
        factor = multipliers.get(unit, 1.0)
        return max(0.0, value_num * factor)

    async def _sleep_abortable(
        self,
        delay_seconds: float,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> None:
        delay_seconds = max(0.0, float(delay_seconds))
        if delay_seconds <= 0:
            return

        should_abort_cb = (
            execution_context.get("should_abort")
            if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        remaining = float(delay_seconds)
        tick = 0.2
        while remaining > 0:
            _raise_if_aborted()
            sleep_for = min(tick, remaining)
            await asyncio.sleep(sleep_for)
            remaining -= sleep_for
        _raise_if_aborted()

    async def _transform_delay(
        self,
        data: list,
        config: Dict[str, Any],
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        if not isinstance(data, list):
            return data

        emit_node_progress = None
        progress_every = 500
        if isinstance(execution_context, dict):
            if callable(execution_context.get("emit_node_progress")):
                emit_node_progress = execution_context.get("emit_node_progress")
            try:
                progress_every = int(execution_context.get("node_progress_every") or progress_every)
            except Exception:
                progress_every = 500
        progress_every = max(1, min(progress_every, 50000))

        def _emit(message: str, processed: int, validated: int, output_rows: int) -> None:
            if not callable(emit_node_progress):
                return
            try:
                emit_node_progress({
                    "message": message,
                    "processed_rows": int(processed),
                    "validated_rows": int(validated),
                    "output_rows": int(output_rows),
                })
            except Exception:
                pass

        if bool(config.get("passthrough_on_receive", False)):
            _emit(
                "⟳ Delay Transform… passthrough enabled, forwarding immediately",
                len(data),
                len(data),
                len(data),
            )
            return data

        delay_scope = str(config.get("delay_scope") or "batch").strip().lower()
        if delay_scope not in {"batch", "message"}:
            delay_scope = "batch"

        delay_seconds = self._resolve_delay_seconds(config)
        max_delay_seconds = 7.0 * 86400.0
        delay_seconds = max(0.0, min(float(delay_seconds), max_delay_seconds))
        if delay_seconds <= 0:
            _emit(
                "⟳ Delay Transform… delay=0, forwarding immediately",
                len(data),
                len(data),
                len(data),
            )
            return data

        if delay_scope == "message":
            output: List[Any] = []
            total_rows = len(data)
            _emit(
                f"⟳ Delay Transform… delaying each message by {delay_seconds:.6f}s",
                0,
                0,
                0,
            )
            for idx, row in enumerate(data, start=1):
                await self._sleep_abortable(delay_seconds, execution_context=execution_context)
                output.append(row)
                if (idx % progress_every) == 0 or idx == total_rows:
                    _emit(
                        f"⟳ Delay Transform… processed {idx:,}/{total_rows:,} delayed messages",
                        idx,
                        idx,
                        len(output),
                    )
            return output

        _emit(
            f"⟳ Delay Transform… waiting {delay_seconds:.6f}s before forwarding batch",
            0,
            0,
            0,
        )
        await self._sleep_abortable(delay_seconds, execution_context=execution_context)
        _emit(
            f"✓ Delay Transform — forwarded {len(data):,} rows after {delay_seconds:.6f}s",
            len(data),
            len(data),
            len(data),
        )
        return data

    def _transform_cursor_processor(
        self,
        data: list,
        config: dict,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        if not isinstance(data, list) or not data:
            return data

        cursor_field = str(config.get("cursor_field") or "").strip()
        if not cursor_field:
            return data

        dedupe_field = str(config.get("dedupe_field") or "").strip()
        processing_mode_raw = str(config.get("processing_mode") or "batch").strip().lower()
        # Backward compatible alias: one_by_one -> row_by_row.
        processing_mode = "row_by_row" if processing_mode_raw == "one_by_one" else processing_mode_raw
        if processing_mode not in {"batch", "row_by_row"}:
            processing_mode = "batch"
        row_by_row_mode = processing_mode == "row_by_row"
        on_duplicate = str(config.get("on_duplicate") or "drop").strip().lower()
        on_late = str(config.get("on_late") or "drop").strip().lower()
        on_missing_cursor = str(config.get("on_missing_cursor") or "keep").strip().lower()
        status_field = str(config.get("status_field") or "_cursor_status").strip() or "_cursor_status"
        enforce_monotonic = bool(config.get("enforce_monotonic", True))
        allow_equal_cursor = bool(config.get("allow_equal_cursor", False))
        allowed_lateness_seconds = self._parse_duration_seconds(config.get("allowed_lateness", "0s"))
        try:
            dedupe_cache_size = int(config.get("dedupe_cache_size", 10000) or 10000)
        except Exception:
            dedupe_cache_size = 10000
        dedupe_cache_size = max(100, min(dedupe_cache_size, 500000))

        node_id = ""
        pipeline_state: Dict[str, Any] = {}
        if isinstance(execution_context, dict):
            node_id = str(execution_context.get("node_id") or "").strip()
            candidate_state = execution_context.get("pipeline_state")
            if isinstance(candidate_state, dict):
                pipeline_state = candidate_state

        if not node_id or not pipeline_state:
            # Stateless fallback keeps behavior deterministic even outside pipeline execution.
            node_id = "__stateless__"
            pipeline_state = {}

        cursor_state_root = pipeline_state.setdefault("cursor_processor_state", {})
        if not isinstance(cursor_state_root, dict):
            cursor_state_root = {}
            pipeline_state["cursor_processor_state"] = cursor_state_root
        node_state = cursor_state_root.setdefault(node_id, {})
        if not isinstance(node_state, dict):
            node_state = {}
            cursor_state_root[node_id] = node_state

        last_cursor = node_state.get("last_cursor")
        max_seen_dt = node_state.get("max_seen_dt")
        if not isinstance(max_seen_dt, (int, float)):
            max_seen_dt = None

        dedupe_map = node_state.get("dedupe_map")
        if not isinstance(dedupe_map, dict):
            dedupe_map = {}

        emit_node_progress = None
        progress_every = 500
        if isinstance(execution_context, dict):
            if callable(execution_context.get("emit_node_progress")):
                emit_node_progress = execution_context.get("emit_node_progress")
            try:
                progress_every = int(execution_context.get("node_progress_every") or progress_every)
            except Exception:
                progress_every = 500
        progress_every = max(1, min(progress_every, 50000))
        total_input_rows = int(len(data))

        result: List[Any] = []
        accepted = 0
        dropped_old = 0
        dropped_late = 0
        dropped_dup = 0
        missing_cursor = 0
        late_kept = 0

        def _emit_progress_if_needed(processed_rows: int) -> None:
            if (not row_by_row_mode) or (not callable(emit_node_progress)):
                return
            if processed_rows <= 0:
                return
            if (processed_rows % progress_every) != 0 and processed_rows != total_input_rows:
                return
            try:
                emit_node_progress({
                    "processed_rows": int(processed_rows),
                    "validated_rows": int(accepted),
                    "message": (
                        f"⟳ Cursor Processor… processed={processed_rows:,} "
                        f"accepted={accepted:,} dropped={max(0, processed_rows - accepted):,}"
                    ),
                })
            except Exception:
                pass

        for idx, row in enumerate(data, start=1):
            if not isinstance(row, dict):
                result.append(row)
                _emit_progress_if_needed(idx)
                continue

            cursor_value, cursor_found = self._extract_row_value_by_path(row, cursor_field)
            if (not cursor_found) or cursor_value is None:
                missing_cursor += 1
                if on_missing_cursor == "drop":
                    _emit_progress_if_needed(idx)
                    continue
                if on_missing_cursor == "tag":
                    tagged = dict(row)
                    tagged[status_field] = "missing_cursor"
                    result.append(tagged)
                else:
                    result.append(row)
                _emit_progress_if_needed(idx)
                continue

            token_type, token_value = self._comparison_token(cursor_value)
            if token_type == "dt" and isinstance(token_value, (int, float)):
                max_seen_dt = token_value if max_seen_dt is None else max(float(max_seen_dt), float(token_value))

            is_late = False
            if (
                allowed_lateness_seconds > 0
                and token_type == "dt"
                and isinstance(token_value, (int, float))
                and isinstance(max_seen_dt, (int, float))
            ):
                watermark = float(max_seen_dt) - float(allowed_lateness_seconds)
                if float(token_value) < watermark:
                    is_late = True

            if is_late:
                if on_late == "drop":
                    dropped_late += 1
                    _emit_progress_if_needed(idx)
                    continue
                if on_late == "tag":
                    tagged = dict(row)
                    tagged[status_field] = "late"
                    row = tagged
                late_kept += 1

            if dedupe_field:
                dedupe_value, dedupe_found = self._extract_row_value_by_path(row, dedupe_field)
                if dedupe_found and dedupe_value is not None:
                    dedupe_key = str(dedupe_value)
                    prev_cursor_for_key = dedupe_map.get(dedupe_key)
                    if prev_cursor_for_key is not None and self._compare_values(cursor_value, prev_cursor_for_key) == 0:
                        if on_duplicate == "drop":
                            dropped_dup += 1
                            _emit_progress_if_needed(idx)
                            continue
                        tagged = dict(row)
                        tagged[status_field] = "duplicate"
                        row = tagged
                    dedupe_map[dedupe_key] = cursor_value
                    while len(dedupe_map) > dedupe_cache_size:
                        try:
                            oldest = next(iter(dedupe_map))
                        except Exception:
                            break
                        dedupe_map.pop(oldest, None)

            if enforce_monotonic and last_cursor is not None:
                cmp = self._compare_values(cursor_value, last_cursor)
                older_than_checkpoint = cmp < 0 or (cmp == 0 and not allow_equal_cursor)
                if older_than_checkpoint:
                    dropped_old += 1
                    _emit_progress_if_needed(idx)
                    continue

            last_cursor = self._max_value(last_cursor, cursor_value)
            accepted += 1
            result.append(row)
            _emit_progress_if_needed(idx)

        node_state["last_cursor"] = last_cursor
        if isinstance(max_seen_dt, (int, float)):
            node_state["max_seen_dt"] = float(max_seen_dt)
        node_state["dedupe_map"] = dedupe_map
        node_state["stats"] = {
            "accepted": int(accepted),
            "dropped_old": int(dropped_old),
            "dropped_late": int(dropped_late),
            "dropped_duplicate": int(dropped_dup),
            "missing_cursor": int(missing_cursor),
            "late_kept": int(late_kept),
            "input_rows": int(len(data)),
            "output_rows": int(len(result)),
            "cursor_field": cursor_field,
            "dedupe_field": dedupe_field,
            "allowed_lateness_seconds": float(allowed_lateness_seconds),
            "processing_mode": processing_mode,
        }

        return result

    async def _transform_python(self, data: list, config: dict) -> list:
        script = config.get("script", "output = input_data")
        local_vars = {"input_data": data, "output": data}
        exec(script, {"json": json, "__builtins__": __builtins__}, local_vars)
        return local_vars.get("output", data)

    async def _transform_sql(self, data: list, config: dict) -> list:
        try:
            import pandas as pd
            from pandasql import sqldf
            df = pd.DataFrame(data)
            query = config.get("query", "SELECT * FROM df")
            result = sqldf(query, {"df": df})
            return result.to_dict(orient="records")
        except Exception:
            return data

    def _transform_type_convert(self, data: list, config: dict) -> list:
        field = config.get("field", "")
        target_type = config.get("target_type", "string")
        converters = {"string": str, "integer": int, "float": float, "boolean": bool}
        conv = converters.get(target_type, str)
        result = []
        for row in data:
            new_row = dict(row)
            if field in new_row:
                try:
                    new_row[field] = conv(new_row[field])
                except (ValueError, TypeError):
                    pass
            result.append(new_row)
        return result

    def _transform_flatten(self, data: list, config: dict) -> list:
        def flatten(d, parent_key="", sep="_"):
            items = []
            for k, v in d.items():
                new_key = f"{parent_key}{sep}{k}" if parent_key else k
                if isinstance(v, dict):
                    items.extend(flatten(v, new_key, sep).items())
                else:
                    items.append((new_key, v))
            return dict(items)
        return [flatten(row) for row in data]

    def _parse_business_workflow_array_config(self, raw_value: Any) -> List[Any]:
        if isinstance(raw_value, list):
            return raw_value
        if isinstance(raw_value, str):
            text = raw_value.strip()
            if not text:
                return []
            try:
                parsed = json.loads(text)
                return parsed if isinstance(parsed, list) else []
            except Exception:
                return []
        return []

    def _normalize_business_workflow_nodes(self, raw_nodes: Any) -> List[Dict[str, Any]]:
        rows = self._parse_business_workflow_array_config(raw_nodes)
        normalized: List[Dict[str, Any]] = []
        for idx, item in enumerate(rows):
            if not isinstance(item, dict):
                continue
            node_id = str(item.get("id") or f"bw_node_{idx + 1}").strip()
            if not node_id:
                continue
            node_data = item.get("data") if isinstance(item.get("data"), dict) else {}
            node_type = str(
                node_data.get("nodeType")
                or item.get("nodeType")
                or item.get("type")
                or ""
            ).strip()
            if not node_type:
                continue
            label = str(
                node_data.get("label")
                or item.get("label")
                or node_type
            ).strip() or node_type
            node_cfg = node_data.get("config")
            if not isinstance(node_cfg, dict):
                node_cfg = item.get("config") if isinstance(item.get("config"), dict) else {}
            normalized.append({
                "id": node_id,
                "node_type": node_type,
                "label": label,
                "config": dict(node_cfg),
            })
        return normalized

    def _normalize_business_workflow_edges(self, raw_edges: Any) -> List[Dict[str, str]]:
        rows = self._parse_business_workflow_array_config(raw_edges)
        normalized: List[Dict[str, str]] = []
        seen: set[str] = set()
        for idx, item in enumerate(rows):
            if not isinstance(item, dict):
                continue
            source = str(item.get("source") or "").strip()
            target = str(item.get("target") or "").strip()
            if not source or not target:
                continue
            source_handle = str(item.get("sourceHandle") or "output").strip() or "output"
            target_handle = str(item.get("targetHandle") or "input").strip() or "input"
            uniq = f"{source}|{source_handle}|{target}|{target_handle}"
            if uniq in seen:
                continue
            seen.add(uniq)
            normalized.append({
                "id": str(item.get("id") or f"bw_edge_{idx + 1}_{source}_{target}").strip(),
                "source": source,
                "target": target,
                "source_handle": source_handle,
                "target_handle": target_handle,
            })
        return normalized

    async def _transform_business_workflow(
        self,
        data: list,
        config: dict,
        incoming_by_source: Optional[Dict[str, list]] = None,
        incoming_order: Optional[List[str]] = None,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        rows = data if isinstance(data, list) else []
        node_cfg = config if isinstance(config, dict) else {}
        workflow_mode = str(node_cfg.get("workflow_mode") or "embedded").strip().lower()
        embedded_enabled = self._parse_bool_like(
            node_cfg.get("embedded_workflow_enabled", True),
            True,
        )

        node_warnings = execution_context.get("node_warnings") if isinstance(execution_context, dict) else None

        def _warn(msg: str) -> None:
            logger.warning(msg)
            if isinstance(node_warnings, list) and msg not in node_warnings:
                node_warnings.append(msg)

        if workflow_mode == "external":
            workflow_id = str(node_cfg.get("workflow_id") or "").strip()
            _warn(
                f"Business workflow node external mode is not executed inline by ETL engine. "
                f"Workflow '{workflow_id or 'N/A'}' passed through upstream rows."
            )
            return rows

        if not embedded_enabled:
            return rows

        child_nodes = self._normalize_business_workflow_nodes(node_cfg.get("embedded_workflow_nodes"))
        child_edges = self._normalize_business_workflow_edges(node_cfg.get("embedded_workflow_edges"))
        if not child_nodes:
            return rows

        include_input_payload = self._parse_bool_like(
            node_cfg.get("include_input_payload", True),
            True,
        )
        invoke_mode = str(node_cfg.get("invoke_mode") or "once_per_batch").strip().lower()
        per_row_mode = invoke_mode in {"per_row", "row_by_row", "one_by_one"}
        try:
            max_instances = int(node_cfg.get("max_instances", 10000) or 10000)
        except Exception:
            max_instances = 10000
        max_instances = max(1, min(max_instances, 100000))

        custom_vars_raw = node_cfg.get("custom_variables_json")
        custom_vars: Dict[str, Any] = {}
        if isinstance(custom_vars_raw, dict):
            custom_vars = dict(custom_vars_raw)
        elif isinstance(custom_vars_raw, str):
            text = custom_vars_raw.strip()
            if text:
                try:
                    parsed_vars = json.loads(text)
                    if isinstance(parsed_vars, dict):
                        custom_vars = parsed_vars
                except Exception:
                    _warn("Business workflow custom variables JSON is invalid; ignored.")

        parent_node_id = ""
        parent_node_label = "Business Workflow"
        if isinstance(execution_context, dict):
            parent_node_id = str(execution_context.get("node_id") or "").strip()
            parent_node_label = str(
                execution_context.get("node_label")
                or execution_context.get("node_id")
                or parent_node_label
            ).strip() or parent_node_label

        emit_node_progress = (
            execution_context.get("emit_node_progress")
            if isinstance(execution_context, dict) and callable(execution_context.get("emit_node_progress"))
            else None
        )
        raise_if_aborted = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _build_input_rows(base_rows: List[Any], instance_index: int, instance_total: int) -> List[Any]:
            prepared: List[Any] = []
            for raw in base_rows:
                if isinstance(raw, dict):
                    row_obj = dict(raw)
                else:
                    row_obj = {"value": raw}
                if custom_vars:
                    row_obj.setdefault("_workflow_vars", self._json_safe_value(custom_vars))
                prepared.append(row_obj)
            return prepared

        if per_row_mode:
            iterable_rows = rows if include_input_payload else ([{} for _ in rows] if rows else [])
            total_instances = min(len(iterable_rows), max_instances)
            if len(iterable_rows) > total_instances:
                _warn(
                    f"Business workflow invoke_mode=per_row hit max_instances={max_instances}. "
                    f"Processed {total_instances} row instance(s), skipped {len(iterable_rows) - total_instances}."
                )
            out_rows: List[Any] = []
            for idx in range(total_instances):
                if callable(raise_if_aborted):
                    raise_if_aborted()
                input_rows = _build_input_rows([iterable_rows[idx]], idx + 1, total_instances)
                node_id_prefix = (
                    f"{parent_node_id or 'business_workflow'}::i{idx + 1}"
                )
                child_output = await self._run_business_workflow_embedded(
                    input_rows=input_rows,
                    child_nodes=child_nodes,
                    child_edges=child_edges,
                    execution_context=execution_context,
                    node_id_prefix=node_id_prefix,
                )
                if isinstance(child_output, list):
                    out_rows.extend(child_output)
                elif child_output is not None:
                    out_rows.append(child_output)
                if callable(emit_node_progress):
                    try:
                        emit_node_progress({
                            "processed_rows": idx + 1,
                            "validated_rows": idx + 1,
                            "output_rows": len(out_rows),
                            "message": (
                                f"⟳ Running {parent_node_label}… child instances "
                                f"{idx + 1:,}/{total_instances:,}"
                            ),
                        })
                    except Exception:
                        pass
            return out_rows

        if include_input_payload:
            base_rows = rows
        else:
            # Keep one synthetic row so child logic can still run via _workflow_vars.
            base_rows = [{}]
        input_rows = _build_input_rows(base_rows, 1, 1)
        node_id_prefix = parent_node_id or "business_workflow"
        return await self._run_business_workflow_embedded(
            input_rows=input_rows,
            child_nodes=child_nodes,
            child_edges=child_edges,
            execution_context=execution_context,
            node_id_prefix=node_id_prefix,
        )

    async def _run_business_workflow_embedded(
        self,
        input_rows: List[Any],
        child_nodes: List[Dict[str, Any]],
        child_edges: List[Dict[str, str]],
        execution_context: Optional[Dict[str, Any]] = None,
        node_id_prefix: str = "business_workflow",
    ) -> list:
        if not child_nodes:
            return input_rows if isinstance(input_rows, list) else []

        depth = 0
        if isinstance(execution_context, dict):
            try:
                depth = int(execution_context.get("business_workflow_depth") or 0)
            except Exception:
                depth = 0
        if depth >= 8:
            raise ValueError("Nested business workflow depth limit reached (max 8).")

        child_nodes_by_id: Dict[str, Dict[str, Any]] = {}
        for item in child_nodes:
            if not isinstance(item, dict):
                continue
            node_id = str(item.get("id") or "").strip()
            if not node_id:
                continue
            child_nodes_by_id[node_id] = item
        if not child_nodes_by_id:
            return input_rows if isinstance(input_rows, list) else []

        in_degree: Dict[str, int] = {node_id: 0 for node_id in child_nodes_by_id.keys()}
        outgoing_edges: Dict[str, List[Dict[str, str]]] = {node_id: [] for node_id in child_nodes_by_id.keys()}
        incoming_edges: Dict[str, List[Dict[str, str]]] = {node_id: [] for node_id in child_nodes_by_id.keys()}
        filtered_edges: List[Dict[str, str]] = []
        for edge in child_edges:
            if not isinstance(edge, dict):
                continue
            source = str(edge.get("source") or "").strip()
            target = str(edge.get("target") or "").strip()
            if source not in child_nodes_by_id or target not in child_nodes_by_id:
                continue
            filtered_edge = {
                "id": str(edge.get("id") or "").strip(),
                "source": source,
                "target": target,
                "source_handle": str(edge.get("source_handle") or "output").strip() or "output",
                "target_handle": str(edge.get("target_handle") or "input").strip() or "input",
            }
            filtered_edges.append(filtered_edge)
            outgoing_edges[source].append(filtered_edge)
            incoming_edges[target].append(filtered_edge)
            in_degree[target] = int(in_degree.get(target, 0)) + 1

        queue: List[str] = [node_id for node_id, deg in in_degree.items() if deg == 0]
        topo_order: List[str] = []
        while queue:
            node_id = queue.pop(0)
            topo_order.append(node_id)
            for edge in outgoing_edges.get(node_id, []):
                target = str(edge.get("target") or "").strip()
                if target not in in_degree:
                    continue
                in_degree[target] = int(in_degree.get(target, 0)) - 1
                if in_degree[target] == 0:
                    queue.append(target)
        if len(topo_order) != len(child_nodes_by_id):
            seen = set(topo_order)
            for node in child_nodes:
                node_id = str(node.get("id") or "").strip()
                if node_id and node_id not in seen:
                    topo_order.append(node_id)

        child_results: Dict[str, list] = {}
        child_results_by_handle: Dict[str, Dict[str, list]] = {}
        emit_embedded_node_event = (
            execution_context.get("emit_embedded_node_event")
            if isinstance(execution_context, dict) and callable(execution_context.get("emit_embedded_node_event"))
            else None
        )

        raise_if_aborted = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _sample_rows(rows: Any, limit: int = 5) -> List[Dict[str, Any]]:
            if limit <= 0 or not isinstance(rows, list) or not rows:
                return []
            sample: List[Dict[str, Any]] = []
            for item in rows:
                if len(sample) >= limit:
                    break
                safe = self._json_safe_value(item)
                if isinstance(safe, dict):
                    sample.append(safe)
                elif safe is not None:
                    sample.append({"value": safe})
            return sample

        for node_id in topo_order:
            if callable(raise_if_aborted):
                raise_if_aborted()
            node_payload = child_nodes_by_id.get(node_id) or {}
            node_type = str(node_payload.get("node_type") or "").strip()
            node_label = str(node_payload.get("label") or node_id).strip() or node_id
            node_cfg = node_payload.get("config") if isinstance(node_payload.get("config"), dict) else {}

            upstream_data: List[Any] = []
            incoming_by_source: Dict[str, list] = {}
            incoming_order: List[str] = []
            seen_bindings: set[tuple[str, str]] = set()
            target_incoming = incoming_edges.get(node_id, [])
            for edge in target_incoming:
                source_id = str(edge.get("source") or "").strip()
                source_handle = str(edge.get("source_handle") or "output").strip() or "output"
                if source_id not in child_results:
                    continue
                source_node_payload = child_nodes_by_id.get(source_id) or {}
                source_node_type = str(source_node_payload.get("node_type") or "").strip()
                source_node_cfg = (
                    source_node_payload.get("config")
                    if isinstance(source_node_payload.get("config"), dict)
                    else {}
                )
                source_routing_mode = str(
                    source_node_cfg.get("condition_routing_mode") or ""
                ).strip().lower()
                if (
                    source_handle == "output"
                    and source_node_type == "condition_node"
                    and source_routing_mode == "case"
                ):
                    # CASE routes should use explicit case_* handles only.
                    continue
                binding = (source_id, source_handle)
                if binding in seen_bindings:
                    continue
                seen_bindings.add(binding)
                source_bundle = child_results_by_handle.get(source_id) or {}
                source_rows = source_bundle.get(source_handle)
                if source_rows is None and source_handle == "output":
                    source_rows = child_results.get(source_id)
                if source_rows is None:
                    source_rows = []
                if not isinstance(source_rows, list):
                    source_rows = [source_rows] if source_rows is not None else []
                existing_rows = incoming_by_source.get(source_id, [])
                existing_rows.extend(source_rows)
                incoming_by_source[source_id] = existing_rows
                if source_id not in incoming_order:
                    incoming_order.append(source_id)
                upstream_data.extend(source_rows)

            if not target_incoming:
                parent_rows = input_rows if isinstance(input_rows, list) else []
                upstream_data = list(parent_rows)
                incoming_by_source = {"__parent__": list(parent_rows)}
                incoming_order = ["__parent__"]

            child_exec_ctx = dict(execution_context or {})
            child_exec_ctx["node_id"] = f"{node_id_prefix}::{node_id}"
            child_exec_ctx["node_label"] = node_label
            child_exec_ctx["business_workflow_depth"] = depth + 1
            child_exec_ctx["business_workflow_parent_node_id"] = node_id_prefix
            child_runtime_node_id = str(child_exec_ctx.get("node_id") or "").strip() or f"{node_id_prefix}::{node_id}"

            if callable(emit_embedded_node_event):
                maybe_coro = emit_embedded_node_event({
                    "type": "node_start",
                    "node_id": child_runtime_node_id,
                    "node_label": node_label,
                    "status": "running",
                    "rows": len(upstream_data) if isinstance(upstream_data, list) else 0,
                    "message": f"⟳ Running {node_label}…",
                    "input_sample": _sample_rows(upstream_data),
                    "output_sample": [],
                })
                if asyncio.iscoroutine(maybe_coro):
                    await maybe_coro

            try:
                output = await self._execute_node(
                    node_type,
                    node_cfg,
                    upstream_data,
                    incoming_by_source=incoming_by_source,
                    incoming_order=incoming_order,
                    execution_context=child_exec_ctx,
                )
            except Exception as child_exc:
                if callable(emit_embedded_node_event):
                    maybe_coro = emit_embedded_node_event({
                        "type": "node_error",
                        "node_id": child_runtime_node_id,
                        "node_label": node_label,
                        "status": "error",
                        "rows": 0,
                        "message": f"✗ {node_label} failed: {child_exc}",
                        "input_sample": _sample_rows(upstream_data),
                        "output_sample": [],
                    })
                    if asyncio.iscoroutine(maybe_coro):
                        await maybe_coro
                raise

            if node_type == "condition_node":
                routing_mode = str(node_cfg.get("condition_routing_mode") or "").strip().lower()
                condition_input_rows = upstream_data if isinstance(upstream_data, list) else []
                if routing_mode == "case":
                    case_split = self._flow_condition_case_routes_split(condition_input_rows, node_cfg)
                    output_rows = case_split.get("output")
                    output = output_rows if isinstance(output_rows, list) else []
                    child_results_by_handle[node_id] = case_split
                else:
                    true_rows, false_rows = self._flow_condition_split(condition_input_rows, node_cfg)
                    output = true_rows
                    child_results_by_handle[node_id] = {
                        "output": true_rows,
                        "output_false": false_rows,
                    }
            else:
                child_results_by_handle[node_id] = {
                    "output": output if isinstance(output, list) else [],
                    "output_false": [],
                }
            child_results[node_id] = output if isinstance(output, list) else []

            if callable(emit_embedded_node_event):
                output_rows = output if isinstance(output, list) else []
                maybe_coro = emit_embedded_node_event({
                    "type": "node_success",
                    "node_id": child_runtime_node_id,
                    "node_label": node_label,
                    "status": "success",
                    "rows": len(output_rows),
                    "message": (
                        f"✓ {node_label} — {len(output_rows):,} rows"
                        if output_rows
                        else f"✓ {node_label} completed"
                    ),
                    "input_sample": _sample_rows(upstream_data),
                    "output_sample": _sample_rows(output_rows),
                })
                if asyncio.iscoroutine(maybe_coro):
                    await maybe_coro

        sink_ids = [
            node_id
            for node_id in topo_order
            if len(outgoing_edges.get(node_id, [])) == 0
        ]
        if not sink_ids and topo_order:
            sink_ids = [topo_order[-1]]

        final_rows: List[Any] = []
        for sink_id in sink_ids:
            sink_rows = child_results.get(sink_id)
            if isinstance(sink_rows, list):
                final_rows.extend(sink_rows)
        return final_rows

    def _business_to_number(self, value: Any) -> Optional[float]:
        if value is None:
            return None
        if isinstance(value, bool):
            return float(int(value))
        if isinstance(value, (int, float)):
            return float(value)
        text = str(value).strip().replace(",", "")
        if not text:
            return None
        try:
            return float(text)
        except Exception:
            return None

    def _business_parse_recipient_list(self, raw_value: str) -> List[str]:
        text = str(raw_value or "").strip()
        if not text:
            return []
        parts = re.split(r"[;,]", text)
        unique: List[str] = []
        seen: set[str] = set()
        for part in parts:
            email = str(part or "").strip()
            if not email:
                continue
            lowered = email.lower()
            if lowered in seen:
                continue
            seen.add(lowered)
            unique.append(email)
        return unique

    def _business_parse_subject_body(self, text: str) -> Tuple[Optional[str], str]:
        raw = str(text or "").strip()
        if not raw:
            return None, ""

        subject: Optional[str] = None
        body = raw
        subject_match = re.search(r"(?im)^\s*subject\s*:\s*(.+)$", raw)
        if subject_match:
            subject = str(subject_match.group(1) or "").strip() or None

        body_match = re.search(r"(?is)^\s*(?:subject\s*:.*\n)?\s*body\s*:\s*(.+)$", raw)
        if body_match:
            body = str(body_match.group(1) or "").strip()
        elif subject_match:
            trimmed = re.sub(r"(?im)^\s*subject\s*:.+\n?", "", raw, count=1).strip()
            body = re.sub(r"(?im)^\s*body\s*:\s*", "", trimmed, count=1).strip() or trimmed
        return subject, body

    def _business_compose_upstream_text(self, rows: List[dict]) -> str:
        clean_rows = [r for r in rows if isinstance(r, dict)]
        for row in clean_rows:
            for key in ("response", "body", "summary", "text", "message"):
                value = row.get(key)
                if value is None:
                    continue
                rendered = str(value).strip()
                if rendered:
                    return rendered
        if clean_rows:
            try:
                sample = json.dumps(clean_rows[:1], ensure_ascii=False, default=str)
            except Exception:
                sample = str(clean_rows[0])
            return sample[:4000]
        return ""

    def _business_config_value(
        self,
        config: Dict[str, Any],
        key: str,
        env_names: List[str],
        default: Any = "",
    ) -> Any:
        value = config.get(key) if isinstance(config, dict) else None
        if value not in (None, ""):
            return value
        for env_name in env_names:
            env_value = os.getenv(env_name)
            if env_value not in (None, ""):
                return env_value
        return default

    def _business_prepare_whatsapp_text(self, content: str) -> str:
        text = str(content or "").strip()
        if not text:
            return ""
        # Strip markdown fence when present.
        fenced = re.match(r"(?is)^```(?:html?)?\s*(.*?)\s*```$", text)
        if fenced:
            text = str(fenced.group(1) or "").strip()
        # Basic HTML tag strip for text mode.
        text = re.sub(r"(?is)<(script|style).*?>.*?</\1>", "", text)
        text = re.sub(r"(?i)<br\s*/?>", "\n", text)
        text = re.sub(r"(?is)<[^>]+>", "", text)
        text = text.replace("\r\n", "\n").replace("\r", "\n")
        return text.strip()

    def _business_lookup_template_value(self, context: Dict[str, Any], token: str) -> Any:
        current: Any = context
        for part in [p for p in str(token or "").split(".") if p]:
            if not isinstance(current, dict):
                return ""
            current = current.get(part)
        return current

    def _business_render_whatsapp_placeholders(self, value: Any, context: Dict[str, Any]) -> Any:
        if isinstance(value, str):
            template = str(value)

            def _replace(match: re.Match[str]) -> str:
                token = str(match.group(1) or "").strip()
                replacement = self._business_lookup_template_value(context, token)
                if isinstance(replacement, (dict, list)):
                    try:
                        return json.dumps(replacement, ensure_ascii=False)
                    except Exception:
                        return str(replacement)
                return "" if replacement is None else str(replacement)

            return re.sub(r"\{\{\s*([a-zA-Z0-9_.-]+)\s*\}\}", _replace, template)
        if isinstance(value, list):
            return [self._business_render_whatsapp_placeholders(item, context) for item in value]
        if isinstance(value, dict):
            return {str(k): self._business_render_whatsapp_placeholders(v, context) for k, v in value.items()}
        return value

    def _transform_business_analytics(self, data: list, _config: dict) -> list:
        clean_rows = [r for r in data if isinstance(r, dict)]
        if not clean_rows:
            return [{
                "summary": "No rows available for analytics.",
                "row_count": 0,
                "column_count": 0,
                "numeric_column_count": 0,
            }]

        columns = list(clean_rows[0].keys())
        numeric_columns: Dict[str, List[float]] = {}
        for col in columns:
            vals: List[float] = []
            for row in clean_rows:
                val = self._business_to_number(row.get(col))
                if val is not None:
                    vals.append(val)
            if vals:
                numeric_columns[col] = vals

        summary = {
            "summary": (
                f"Processed {len(clean_rows)} rows across {len(columns)} columns; "
                f"{len(numeric_columns)} numeric columns profiled."
            ),
            "row_count": len(clean_rows),
            "column_count": len(columns),
            "numeric_column_count": len(numeric_columns),
        }
        analytics_rows: List[Dict[str, Any]] = [summary]
        for col, values in list(numeric_columns.items())[:12]:
            col_sum = float(sum(values))
            col_avg = col_sum / max(len(values), 1)
            analytics_rows.append({
                "metric": col,
                "count": len(values),
                "min": round(min(values), 6),
                "max": round(max(values), 6),
                "avg": round(col_avg, 6),
                "sum": round(col_sum, 6),
            })
        return analytics_rows

    def _dest_business_mail_writer(self, config: dict, data: list) -> list:
        to_email_raw = str(config.get("to_email") or "").strip()
        recipients = self._business_parse_recipient_list(to_email_raw)
        if not recipients:
            raise ValueError("Mail Writer requires at least one recipient in 'To'.")

        configured_subject = str(config.get("subject") or "").strip()
        body_template = str(config.get("body_template") or "").strip()
        upstream_text = self._business_compose_upstream_text([row for row in data if isinstance(row, dict)])
        body_source = body_template or upstream_text or "No upstream content available."
        parsed_subject, parsed_body = self._business_parse_subject_body(body_source)
        subject = configured_subject or parsed_subject or "Business workflow recommendation"
        body_text = parsed_body or body_source

        send_mode = str(config.get("send_mode") or "draft").strip().lower() or "draft"
        should_send = send_mode in {"send", "enabled", "on"}
        generated_at = datetime.utcnow().isoformat()

        if should_send:
            smtp_host = str(self._business_config_value(config, "smtp_host", ["BUSINESS_SMTP_HOST", "SMTP_HOST"], "")).strip()
            smtp_user = str(self._business_config_value(config, "smtp_username", ["BUSINESS_SMTP_USERNAME", "SMTP_USERNAME"], "")).strip()
            smtp_password = str(self._business_config_value(config, "smtp_password", ["BUSINESS_SMTP_PASSWORD", "SMTP_PASSWORD"], "")).strip()
            from_email = str(
                self._business_config_value(
                    config,
                    "from_email",
                    ["BUSINESS_SMTP_FROM_EMAIL", "SMTP_FROM_EMAIL", "BUSINESS_MAIL_FROM_EMAIL"],
                    smtp_user,
                )
            ).strip()
            smtp_security = str(
                self._business_config_value(config, "smtp_security", ["BUSINESS_SMTP_SECURITY", "SMTP_SECURITY"], "tls")
            ).strip().lower() or "tls"
            if smtp_security not in {"tls", "ssl", "none"}:
                smtp_security = "tls"
            port_default = 465 if smtp_security == "ssl" else 587
            smtp_port_num = self._business_to_number(
                self._business_config_value(config, "smtp_port", ["BUSINESS_SMTP_PORT", "SMTP_PORT"], port_default)
            )
            smtp_port = int(smtp_port_num) if smtp_port_num else int(port_default)

            if not smtp_host:
                raise ValueError("SMTP host is not configured.")
            if not from_email:
                raise ValueError("Sender email is not configured.")
            if smtp_user and not smtp_password:
                raise ValueError("SMTP password is required when SMTP username is provided.")
            if smtp_host.lower() == "smtp.gmail.com" and smtp_password:
                smtp_password = re.sub(r"\s+", "", smtp_password)

            message = EmailMessage()
            message["From"] = from_email
            message["To"] = ", ".join(recipients)
            message["Subject"] = subject
            message.set_content(body_text)

            if smtp_security == "ssl":
                with smtplib.SMTP_SSL(smtp_host, smtp_port, timeout=30, context=ssl.create_default_context()) as server:
                    if smtp_user:
                        server.login(smtp_user, smtp_password)
                    server.send_message(message)
            else:
                with smtplib.SMTP(smtp_host, smtp_port, timeout=30) as server:
                    server.ehlo()
                    if smtp_security == "tls":
                        server.starttls(context=ssl.create_default_context())
                        server.ehlo()
                    if smtp_user:
                        server.login(smtp_user, smtp_password)
                    server.send_message(message)
            status = "sent"
        else:
            status = "draft"

        return [{
            "to": ", ".join(recipients),
            "subject": subject,
            "body": body_text,
            "status": status,
            "generated_at": generated_at,
            "source_rows": len([row for row in data if isinstance(row, dict)]),
        }]

    async def _dest_business_whatsapp_sender(self, config: dict, data: list) -> list:
        to_phone = re.sub(r"\D+", "", str(config.get("to_phone") or config.get("to") or "").strip())
        if not to_phone:
            raise ValueError("WhatsApp Sender requires a recipient phone number in 'To Phone Number'.")

        send_mode = str(config.get("send_mode") or "draft").strip().lower() or "draft"
        message_type = str(config.get("message_type") or "template").strip().lower() or "template"
        if message_type not in {"template", "text"}:
            message_type = "template"
        template_name = str(config.get("template_name") or "hello_world").strip() or "hello_world"
        template_language = str(config.get("template_language") or "en_US").strip() or "en_US"
        preview_url = bool(config.get("preview_url", False))
        request_payload_json = str(config.get("request_payload_json") or "").strip()

        upstream_text = self._business_compose_upstream_text([row for row in data if isinstance(row, dict)])
        text_body = self._business_prepare_whatsapp_text(
            str(config.get("text_body") or "").strip() or upstream_text or "No upstream content available."
        )
        generated_at = datetime.utcnow().isoformat()

        context = {
            "to_phone": to_phone,
            "message_type": message_type,
            "template_name": template_name,
            "template_language": template_language,
            "text_body": text_body,
            "upstream_text": upstream_text,
            "generated_at": generated_at,
        }

        payload: Dict[str, Any]
        if request_payload_json:
            try:
                parsed_payload = json.loads(request_payload_json)
            except Exception as exc:
                raise ValueError(f"Request JSON Payload is invalid JSON: {exc}") from exc
            if not isinstance(parsed_payload, dict):
                raise ValueError("Request JSON Payload must be a JSON object.")
            rendered_payload = self._business_render_whatsapp_placeholders(parsed_payload, context)
            payload = rendered_payload if isinstance(rendered_payload, dict) else {}
            payload.setdefault("messaging_product", "whatsapp")
            payload.setdefault("to", to_phone)
            payload.setdefault("type", message_type)
        else:
            payload = {"messaging_product": "whatsapp", "to": to_phone}
            if message_type == "template":
                payload["type"] = "template"
                payload["template"] = {
                    "name": template_name,
                    "language": {"code": template_language},
                }
            else:
                payload["type"] = "text"
                payload["text"] = {"preview_url": preview_url, "body": text_body}

        if send_mode not in {"send", "enabled", "on"}:
            return [{
                "to": to_phone,
                "status": "draft",
                "message_type": str(payload.get("type") or message_type),
                "request_payload": payload,
                "generated_at": generated_at,
                "source_rows": len([row for row in data if isinstance(row, dict)]),
            }]

        phone_number_id = str(
            self._business_config_value(
                config,
                "phone_number_id",
                ["BUSINESS_WHATSAPP_PHONE_NUMBER_ID", "WHATSAPP_PHONE_NUMBER_ID"],
                "",
            )
        ).strip()
        access_token = str(
            self._business_config_value(
                config,
                "access_token",
                ["BUSINESS_WHATSAPP_ACCESS_TOKEN", "WHATSAPP_ACCESS_TOKEN", "META_WHATSAPP_ACCESS_TOKEN"],
                "",
            )
        ).strip()
        api_version = str(
            self._business_config_value(
                config,
                "api_version",
                ["BUSINESS_WHATSAPP_API_VERSION", "WHATSAPP_API_VERSION"],
                "v25.0",
            )
        ).strip().strip("/") or "v25.0"
        base_url = str(
            self._business_config_value(
                config,
                "base_url",
                ["BUSINESS_WHATSAPP_BASE_URL", "WHATSAPP_BASE_URL"],
                "https://graph.facebook.com",
            )
        ).strip().rstrip("/")

        if not phone_number_id:
            raise ValueError("WhatsApp phone number id is missing.")
        if not access_token:
            raise ValueError("WhatsApp access token is missing.")

        endpoint = f"{base_url}/{api_version}/{phone_number_id}/messages"
        headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": "application/json",
        }
        import httpx
        async with httpx.AsyncClient(timeout=30) as client:
            response = await client.post(endpoint, headers=headers, json=payload)

        response_text = str(response.text or "").strip()
        if response.status_code >= 400:
            compact_detail = response_text if len(response_text) <= 500 else f"{response_text[:500]}..."
            raise ValueError(f"WhatsApp send failed ({response.status_code}): {compact_detail}")

        try:
            response_json = response.json()
        except Exception:
            response_json = {}

        message_id: Optional[str] = None
        messages = response_json.get("messages") if isinstance(response_json, dict) else None
        if isinstance(messages, list) and messages and isinstance(messages[0], dict):
            message_id = str(messages[0].get("id") or "").strip() or None

        return [{
            "to": str(payload.get("to") or to_phone),
            "status": "sent",
            "message_type": str(payload.get("type") or message_type),
            "request_payload": payload,
            "whatsapp_response": response_json if isinstance(response_json, dict) else {},
            "generated_at": generated_at,
            "endpoint": endpoint,
            "api_status_code": int(response.status_code),
            "message_id": message_id,
            "source_rows": len([row for row in data if isinstance(row, dict)]),
        }]

    def _flow_condition(self, data: list, config: dict) -> list:
        return self._transform_filter(data, config)

    # ─── PATH RESOLVER ─────────────────────────────────────────────────────────

    def _resolve_output_path(self, raw_path: str, default_ext: str) -> str:
        """
        Resolve the output path for a destination node.

        Rules:
        - Empty / None        → write to backend/outputs/<timestamp><ext>
        - __local__://…       → browser picked a local folder; write to backend/outputs/<filename>
                                 (the frontend will then copy it to the local folder via File System Access API)
        - Absolute path (/…)  → use as-is (server must have write permission)
        - Relative path:
          - plain filename     → write to backend/outputs/<filename>
          - path with folders  → resolve relative to current working directory and use it directly
        """
        import os
        from datetime import datetime

        OUTPUTS_DIR = os.path.join(os.path.dirname(__file__), "outputs")
        os.makedirs(OUTPUTS_DIR, exist_ok=True)

        if not raw_path:
            fname = f"output_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}{default_ext}"
            return os.path.join(OUTPUTS_DIR, fname)

        if raw_path.startswith("__local__://"):
            # Extract just the filename the browser chose
            fname = raw_path.replace("__local__://", "").rsplit("/", 1)[-1]
            if not fname:
                fname = f"output_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}{default_ext}"
            return os.path.join(OUTPUTS_DIR, fname)

        expanded = os.path.expanduser(str(raw_path).strip())

        if os.path.isabs(expanded):
            # Absolute server path — use directly
            os.makedirs(os.path.dirname(expanded) or OUTPUTS_DIR, exist_ok=True)
            return expanded

        # Relative path:
        # - "result.csv" -> backend/outputs/result.csv
        # - "exports/result.csv" or "./exports/result.csv" -> <cwd>/exports/result.csv
        normalized = expanded.replace("\\", "/")
        has_subdir = "/" in normalized.strip("./")
        if has_subdir or expanded.startswith("."):
            rel_target = os.path.abspath(expanded)
            root, ext = os.path.splitext(rel_target)
            if not ext:
                rel_target = f"{root}{default_ext}"
            os.makedirs(os.path.dirname(rel_target) or OUTPUTS_DIR, exist_ok=True)
            return rel_target

        # Plain relative filename — keep writing inside backend outputs/
        fname = os.path.basename(expanded) or f"output_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}{default_ext}"
        return os.path.join(OUTPUTS_DIR, fname)

    # ─── DESTINATION IMPLEMENTATIONS ──────────────────────────────────────────

    async def _execute_destination(
        self,
        node_type: str,
        config: dict,
        data: list,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        """Load data into destination systems."""
        import pandas as pd, os
        logger.info(f"Loading {len(data)} rows to {node_type}")
        should_abort_cb = (
            execution_context.get("should_abort")
            if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
            else None
        )
        raise_if_aborted_cb = (
            execution_context.get("raise_if_aborted")
            if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
            else None
        )

        def _raise_if_aborted() -> None:
            if callable(raise_if_aborted_cb):
                raise_if_aborted_cb()
                return
            if callable(should_abort_cb):
                try:
                    if bool(should_abort_cb()):
                        raise ExecutionAbortedError("Execution aborted by user.")
                except ExecutionAbortedError:
                    raise
                except Exception:
                    pass

        _raise_if_aborted()

        if not data:
            return [{"status": "loaded", "rows": 0, "destination": node_type, "note": "No data to write"}]

        df = pd.DataFrame(data)

        # ── File destinations ───────────────────────────────────────────────
        if node_type == "csv_destination":
            out_path = self._resolve_output_path(config.get("file_path", ""), ".csv")
            delimiter = config.get("delimiter", ",") or ","
            encoding = str(config.get("encoding", "utf-8") or "utf-8").strip() or "utf-8"
            include_header = bool(config.get("include_header", True))
            write_mode = str(config.get("write_mode", "replace") or "replace").strip().lower()
            flush_mode = str(config.get("flush_mode", "batch") or "batch").strip().lower()
            if write_mode not in {"replace", "append"}:
                write_mode = "replace"
            if flush_mode not in {"batch", "row"}:
                flush_mode = "batch"

            file_exists = os.path.exists(out_path)
            file_non_empty = False
            if file_exists:
                try:
                    file_non_empty = os.path.getsize(out_path) > 0
                except Exception:
                    file_non_empty = False

            append_mode = write_mode == "append"
            open_mode = "a" if append_mode else "w"
            write_header = include_header and (not append_mode or not file_non_empty)

            if flush_mode == "row":
                columns = [str(col) for col in df.columns]
                records = df.to_dict(orient="records")
                with open(out_path, open_mode, encoding=encoding, newline="") as handle:
                    writer = csv.DictWriter(handle, fieldnames=columns, delimiter=delimiter, extrasaction="ignore")
                    if write_header:
                        writer.writeheader()
                    for row in records:
                        _raise_if_aborted()
                        if isinstance(row, dict):
                            normalized_row: Dict[str, Any] = {}
                            for col in columns:
                                value = row.get(col)
                                try:
                                    normalized_row[col] = "" if pd.isna(value) else value
                                except Exception:
                                    normalized_row[col] = value
                            writer.writerow(normalized_row)
                        else:
                            writer.writerow({col: "" for col in columns})
            else:
                df.to_csv(
                    out_path,
                    index=False,
                    sep=delimiter,
                    mode=open_mode,
                    header=write_header,
                    encoding=encoding,
                )
            logger.info(f"✅ CSV written: {out_path} ({len(df)} rows)")
            return [{
                "status": "written",
                "rows": len(df),
                "path": out_path,
                "write_mode": write_mode,
                "flush_mode": flush_mode,
            }]

        elif node_type == "json_destination":
            out_path = self._resolve_output_path(config.get("file_path", ""), ".json")
            orient = config.get("orient", "records") or "records"
            try:
                indent = int(config.get("indent", 2))
            except Exception:
                indent = 2
            indent = max(0, min(indent, 8))

            date_format = str(config.get("date_format", "iso") or "iso").strip().lower()
            if date_format not in {"iso", "epoch"}:
                date_format = "iso"

            date_unit = str(config.get("date_unit", "ms") or "ms").strip().lower()
            if date_unit not in {"s", "ms", "us", "ns"}:
                date_unit = "ms"
            datetime_output_pattern = str(
                config.get("datetime_output_pattern", "%Y-%d-%m %H:%M:%S") or "%Y-%d-%m %H:%M:%S"
            ).strip() or "%Y-%d-%m %H:%M:%S"

            date_only_midnight = bool(config.get("date_only_midnight", True))
            df_json = df.copy()
            if date_format == "iso" and date_only_midnight and not df_json.empty:
                for col in list(df_json.columns):
                    series = df_json[col]
                    if pd.api.types.is_datetime64_any_dtype(series):
                        dt = pd.to_datetime(series, errors="coerce")
                        valid = dt.dropna()
                        if valid.empty:
                            continue
                        is_midnight = (
                            (valid.dt.hour == 0)
                            & (valid.dt.minute == 0)
                            & (valid.dt.second == 0)
                            & (valid.dt.microsecond == 0)
                        )
                        if bool(is_midnight.all()):
                            df_json[col] = dt.dt.strftime("%Y-%m-%d").where(dt.notna(), None)
                        else:
                            df_json[col] = dt.dt.strftime(datetime_output_pattern).where(dt.notna(), None)
                        continue
                    if pd.api.types.is_object_dtype(series):
                        non_null = series.dropna()
                        if non_null.empty:
                            continue
                        temporal_sample = non_null.head(100)
                        has_temporal = any(
                            isinstance(v, (datetime, date, time, pd.Timestamp))
                            for v in temporal_sample
                        )
                        if not has_temporal:
                            continue

                        def _normalize_temporal_obj(value: Any) -> Any:
                            if value is None:
                                return None
                            if isinstance(value, float) and math.isnan(value):
                                return None
                            if isinstance(value, pd.Timestamp):
                                try:
                                    value = value.to_pydatetime()
                                except Exception:
                                    return str(value)
                            if isinstance(value, datetime):
                                if (
                                    value.hour == 0
                                    and value.minute == 0
                                    and value.second == 0
                                    and value.microsecond == 0
                                ):
                                    return value.date().isoformat()
                                return value.strftime(datetime_output_pattern)
                            if isinstance(value, date):
                                return value.isoformat()
                            if isinstance(value, time):
                                return value.isoformat()
                            return value

                        df_json[col] = series.map(_normalize_temporal_obj)

            df_json.to_json(
                out_path,
                orient=orient,
                indent=indent,
                force_ascii=False,
                date_format=date_format,
                date_unit=date_unit,
                default_handler=str,
            )
            logger.info(f"✅ JSON written: {out_path} ({len(df)} rows)")
            return [{"status": "written", "rows": len(df), "path": out_path}]

        elif node_type == "excel_destination":
            raw = config.get("file_path", "")
            if raw and not raw.startswith("__local__://") and not raw.endswith((".xlsx", ".xls")):
                raw += ".xlsx"
            out_path = self._resolve_output_path(raw, ".xlsx")
            sheet = config.get("sheet", "Sheet1") or "Sheet1"
            df.to_excel(out_path, index=False, sheet_name=str(sheet))
            logger.info(f"✅ Excel written: {out_path} ({len(df)} rows)")
            return [{"status": "written", "rows": len(df), "path": out_path}]

        # ── Database destinations ───────────────────────────────────────────
        elif node_type == "postgres_destination":
            return await self._dest_postgres(config, df)

        elif node_type == "mysql_destination":
            return await self._dest_mysql(config, df)

        elif node_type == "oracle_destination":
            return await self._dest_oracle(config, df, execution_context=execution_context)

        elif node_type == "mongodb_destination":
            return await self._dest_mongodb(config, data)

        elif node_type == "elasticsearch_destination":
            return await self._dest_elasticsearch(config, data)

        elif node_type == "redis_destination":
            return await self._dest_redis(config, data)

        elif node_type == "s3_destination":
            return await self._dest_s3(config, df)

        elif node_type == "rest_api_destination":
            return await self._dest_rest_api(config, data)

        elif node_type == "business_mail_writer":
            return self._dest_business_mail_writer(config, data)

        elif node_type == "business_whatsapp_sender":
            return await self._dest_business_whatsapp_sender(config, data)

        # Fallback
        logger.warning(f"No handler for destination {node_type}, skipping write")
        return [{"status": "skipped", "rows": len(data), "destination": node_type}]

    async def _dest_postgres(self, config: dict, df) -> list:
        try:
            from sqlalchemy import create_engine
            url = (f"postgresql+psycopg2://{config.get('user','')}:{config.get('password','')}@"
                   f"{config.get('host','localhost')}:{config.get('port', 5432)}/{config.get('database','')}")
            engine = create_engine(url)
            table = config.get("table", "etl_output")
            mode = "replace" if config.get("if_exists", "append") == "replace" else "append"
            df.to_sql(table, engine, if_exists=mode, index=False)
            return [{"status": "loaded", "rows": len(df), "table": table}]
        except Exception as e:
            raise RuntimeError(f"PostgreSQL write failed: {e}")

    async def _dest_mysql(self, config: dict, df) -> list:
        try:
            from sqlalchemy import create_engine
            url = (f"mysql+pymysql://{config.get('user','')}:{config.get('password','')}@"
                   f"{config.get('host','localhost')}:{config.get('port', 3306)}/{config.get('database','')}")
            engine = create_engine(url)
            table = config.get("table", "etl_output")
            mode = "replace" if config.get("if_exists", "append") == "replace" else "append"
            df.to_sql(table, engine, if_exists=mode, index=False)
            return [{"status": "loaded", "rows": len(df), "table": table}]
        except Exception as e:
            raise RuntimeError(f"MySQL write failed: {e}")

    def _build_oracle_dsn(self, config: dict) -> str:
        dsn_raw = config.get("dsn")
        dsn = str(dsn_raw).strip() if dsn_raw is not None else ""
        if dsn:
            return dsn

        host_raw = config.get("host")
        host = str(host_raw).strip() if host_raw is not None else ""
        host = host or "localhost"
        port_raw = config.get("port", 1521)
        try:
            port = int(str(port_raw).strip())
        except Exception:
            port = 1521
        service_raw = config.get("service_name")
        if service_raw is None or str(service_raw).strip() == "":
            service_raw = config.get("database")
        service_name = str(service_raw).strip() if service_raw is not None else ""
        sid_raw = config.get("sid")
        sid = str(sid_raw).strip() if sid_raw is not None else ""

        if service_name:
            return f"{host}:{port}/{service_name}"
        if sid:
            return f"{host}:{port}:{sid}"
        return f"{host}:{port}/ORCLCDB"

    def _build_sqlalchemy_oracle_url(self, config: dict) -> str:
        user_raw = config.get("user")
        password_raw = config.get("password")
        user = quote_plus(str(user_raw).strip() if user_raw is not None else "")
        password = quote_plus(str(password_raw) if password_raw is not None else "")

        dsn_raw = config.get("dsn")
        dsn = str(dsn_raw).strip() if dsn_raw is not None else ""
        if dsn:
            return f"oracle+oracledb://{user}:{password}@{dsn}"

        host_raw = config.get("host")
        host = str(host_raw).strip() if host_raw is not None else ""
        host = host or "localhost"
        port_raw = config.get("port", 1521)
        try:
            port = int(str(port_raw).strip())
        except Exception:
            port = 1521
        service_raw = config.get("service_name")
        if service_raw is None or str(service_raw).strip() == "":
            service_raw = config.get("database")
        service_name = str(service_raw).strip() if service_raw is not None else ""
        sid_raw = config.get("sid")
        sid = str(sid_raw).strip() if sid_raw is not None else ""

        if service_name:
            return (
                f"oracle+oracledb://{user}:{password}@{host}:{port}/"
                f"?service_name={quote_plus(service_name)}"
            )
        if sid:
            return (
                f"oracle+oracledb://{user}:{password}@{host}:{port}/"
                f"?sid={quote_plus(sid)}"
            )
        return f"oracle+oracledb://{user}:{password}@{host}:{port}/?service_name=ORCLCDB"

    def _dest_oracle_sync(
        self,
        config: dict,
        df,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        engine = None
        engine_cache_key: Optional[str] = None
        try:
            from sqlalchemy import types as sql_types
            from sqlalchemy.dialects import oracle as oracle_types
            import pandas as pd

            def _parse_bool_like(value: Any, default: bool = False) -> bool:
                if isinstance(value, bool):
                    return value
                if isinstance(value, (int, float)):
                    return value != 0
                if isinstance(value, str):
                    norm = value.strip().lower()
                    if norm in {"1", "true", "yes", "y", "on"}:
                        return True
                    if norm in {"0", "false", "no", "n", "off"}:
                        return False
                return default

            should_abort_cb = (
                execution_context.get("should_abort")
                if isinstance(execution_context, dict) and callable(execution_context.get("should_abort"))
                else None
            )
            raise_if_aborted_cb = (
                execution_context.get("raise_if_aborted")
                if isinstance(execution_context, dict) and callable(execution_context.get("raise_if_aborted"))
                else None
            )

            def _raise_if_aborted() -> None:
                if callable(raise_if_aborted_cb):
                    raise_if_aborted_cb()
                    return
                if callable(should_abort_cb):
                    try:
                        if bool(should_abort_cb()):
                            raise ExecutionAbortedError("Execution aborted by user.")
                    except ExecutionAbortedError:
                        raise
                    except Exception:
                        pass

            def _parse_oracle_mappings(value: Any) -> List[Dict[str, Any]]:
                raw = value
                if isinstance(raw, str):
                    text = raw.strip()
                    if not text:
                        return []
                    try:
                        raw = json.loads(text)
                    except Exception:
                        return []
                if not isinstance(raw, list):
                    return []
                out: List[Dict[str, Any]] = []
                for item in raw:
                    if not isinstance(item, dict):
                        continue
                    source = str(item.get("source", item.get("from", ""))).strip()
                    destination = str(item.get("destination", item.get("to", ""))).strip()
                    enabled = _parse_bool_like(item.get("enabled", True), True)
                    if not source and not destination:
                        continue
                    out.append({
                        "source": source,
                        "destination": destination,
                        "enabled": enabled,
                    })
                return out

            def _split_sql_statements(sql_script: str) -> List[str]:
                text = str(sql_script or "").strip()
                if not text:
                    return []
                statements: List[str] = []
                buf: List[str] = []
                quote: Optional[str] = None
                prev_ch = ""
                for ch in text:
                    if ch in {"'", '"'} and prev_ch != "\\":
                        if quote is None:
                            quote = ch
                        elif quote == ch:
                            quote = None
                    if ch == ";" and quote is None:
                        stmt = "".join(buf).strip()
                        if stmt:
                            statements.append(stmt)
                        buf = []
                    else:
                        buf.append(ch)
                    prev_ch = ch
                tail = "".join(buf).strip()
                if tail:
                    statements.append(tail)
                return statements

            def _parse_key_columns(value: Any) -> List[str]:
                if isinstance(value, list):
                    parts = [str(v).strip() for v in value]
                elif isinstance(value, str):
                    text = value.strip()
                    if not text:
                        parts = []
                    else:
                        try:
                            parsed = json.loads(text)
                            if isinstance(parsed, list):
                                parts = [str(v).strip() for v in parsed]
                            else:
                                parts = [p.strip() for p in text.replace("\n", ",").split(",")]
                        except Exception:
                            parts = [p.strip() for p in text.replace("\n", ",").split(",")]
                else:
                    parts = []

                out: List[str] = []
                seen: set = set()
                for item in parts:
                    if not item:
                        continue
                    key = item.lower()
                    if key in seen:
                        continue
                    seen.add(key)
                    out.append(item)
                return out

            def _quote_ident(name: str) -> str:
                return '"' + str(name or "").replace('"', '""') + '"'

            def _json_safe(value: Any) -> Any:
                if value is None:
                    return None
                if isinstance(value, float) and math.isnan(value):
                    return None
                if isinstance(value, (str, int, float, bool)):
                    return value
                if isinstance(value, datetime):
                    if (
                        value.hour == 0
                        and value.minute == 0
                        and value.second == 0
                        and value.microsecond == 0
                    ):
                        return value.date().isoformat()
                    return value.strftime("%Y-%d-%m %H:%M:%S")
                if isinstance(value, date):
                    return value.isoformat()
                if isinstance(value, time):
                    return value.isoformat()
                if isinstance(value, pd.Timestamp):
                    try:
                        py_dt = value.to_pydatetime()
                        if (
                            py_dt.hour == 0
                            and py_dt.minute == 0
                            and py_dt.second == 0
                            and py_dt.microsecond == 0
                        ):
                            return py_dt.date().isoformat()
                        return py_dt.strftime("%Y-%d-%m %H:%M:%S")
                    except Exception:
                        return str(value)
                if isinstance(value, dict):
                    return {str(k): _json_safe(v) for k, v in value.items()}
                if isinstance(value, (list, tuple, set)):
                    return [_json_safe(v) for v in value]
                try:
                    if pd.isna(value):
                        return None
                except Exception:
                    pass
                return str(value)

            def _normalize_value(value: Any) -> Any:
                if value is None:
                    return None
                if isinstance(value, float) and math.isnan(value):
                    return None
                if isinstance(value, dict):
                    return json.dumps(_json_safe(value), ensure_ascii=False)
                if isinstance(value, (list, tuple)):
                    return json.dumps(_json_safe(list(value)), ensure_ascii=False)
                if isinstance(value, set):
                    return json.dumps(_json_safe(list(value)), ensure_ascii=False)
                if isinstance(value, pd.Timestamp):
                    return value.to_pydatetime()
                if isinstance(value, (datetime, date, time)):
                    return value
                try:
                    if pd.isna(value):
                        return None
                except Exception:
                    pass
                return value

            def _is_missing_key_value(value: Any) -> bool:
                normalized = _normalize_value(value)
                if normalized is None:
                    return True
                if isinstance(normalized, str) and normalized.strip() == "":
                    return True
                return False

            def _is_oracle_unique_violation(exc: Exception) -> bool:
                text = str(exc or "")
                if "ORA-00001" in text:
                    return True
                lower = text.lower()
                return "unique constraint" in lower and "violated" in lower

            url = self._build_sqlalchemy_oracle_url(config)
            reuse_connection_cfg = config.get(
                "oracle_reuse_connection",
                os.getenv("ORACLE_DESTINATION_REUSE_CONNECTION", "1"),
            )
            reuse_connection = _parse_bool_like(reuse_connection_cfg, True)
            engine, engine_cache_key = self._get_oracle_destination_engine(
                url,
                execution_context=execution_context,
                reuse_connection=reuse_connection,
            )
            table = config.get("table", "ETL_OUTPUT")
            schema = config.get("schema") or None
            if_exists = (config.get("if_exists", "append") or "append").lower()
            if if_exists not in {"append", "replace", "fail"}:
                if_exists = "append"
            operation = str(config.get("oracle_operation", "insert") or "insert").strip().lower()
            if operation not in {"insert", "update", "upsert"}:
                operation = "insert"
            skip_null_key_rows_cfg = config.get(
                "oracle_skip_null_key_rows",
                os.getenv("ORACLE_DESTINATION_SKIP_NULL_KEY_ROWS", "1"),
            )
            skip_null_key_rows = _parse_bool_like(skip_null_key_rows_cfg, True)

            df_to_write = df.copy()
            mappings = _parse_oracle_mappings(config.get("oracle_column_mappings"))
            mapped_only = _parse_bool_like(config.get("oracle_only_mapped_columns"), False)
            pre_sql = str(config.get("oracle_pre_sql") or "").strip()
            post_sql = str(config.get("oracle_post_sql") or "").strip()

            enabled_mappings = [m for m in mappings if m.get("enabled", True)]
            duplicate_dest = sorted({
                m["destination"]
                for m in enabled_mappings
                if m.get("destination")
                and sum(1 for x in enabled_mappings if x.get("destination") == m.get("destination")) > 1
            })
            if duplicate_dest:
                raise RuntimeError(
                    "Oracle mapping contains duplicate destination columns: "
                    + ", ".join(duplicate_dest[:10])
                )

            rename_map: Dict[str, str] = {}
            rename_map_by_source_name: Dict[str, str] = {}
            mapped_sources: List[str] = []
            input_columns = [str(col) for col in df_to_write.columns]
            input_columns_by_lower: Dict[str, str] = {}
            for col in input_columns:
                key = str(col or "").strip().lower()
                if key and key not in input_columns_by_lower:
                    input_columns_by_lower[key] = col
            for row in enabled_mappings:
                src = str(row.get("source") or "").strip()
                dst = str(row.get("destination") or "").strip()
                if not src or not dst:
                    continue
                src_resolved = src if src in df_to_write.columns else input_columns_by_lower.get(src.lower())
                if not src_resolved or src_resolved not in df_to_write.columns:
                    continue
                rename_map[src_resolved] = dst
                rename_map_by_source_name[src] = dst
                mapped_sources.append(src_resolved)

            mapped_sources = list(dict.fromkeys(mapped_sources))
            has_mapping_config = len(mappings) > 0
            if has_mapping_config:
                if not mapped_sources:
                    incoming_cols_preview = ", ".join(input_columns[:25])
                    if len(input_columns) > 25:
                        incoming_cols_preview += ", ..."
                    raise RuntimeError(
                        "Oracle mapping is configured, but no enabled source->destination mapping matched input columns. "
                        f"Mapped sources={ [str(m.get('source') or '').strip() for m in enabled_mappings] } | "
                        f"Incoming columns={incoming_cols_preview}"
                    )
                # When mapping is configured, treat it as explicit selection:
                # only mapped columns are inserted to avoid accidental writes.
                df_to_write = df_to_write[mapped_sources].rename(columns=rename_map)
                mapped_only = True
            elif mapped_only:
                raise RuntimeError(
                    "Mapped-only mode is enabled, but no Oracle column mappings are configured."
                )

            key_columns = _parse_key_columns(config.get("oracle_key_columns"))
            if rename_map and key_columns:
                # Allow key columns configured with original source names.
                key_columns = [
                    rename_map_by_source_name.get(col, rename_map.get(col, col))
                    for col in key_columns
                ]
                key_columns = _parse_key_columns(key_columns)

            dtype_map = {}
            for col, dtype in df_to_write.dtypes.items():
                if pd.api.types.is_integer_dtype(dtype):
                    dtype_map[col] = sql_types.BigInteger()
                elif pd.api.types.is_float_dtype(dtype):
                    dtype_map[col] = oracle_types.FLOAT(binary_precision=126)
                elif pd.api.types.is_bool_dtype(dtype):
                    dtype_map[col] = sql_types.Integer()
                elif pd.api.types.is_datetime64_any_dtype(dtype):
                    dtype_map[col] = sql_types.DateTime()
                else:
                    dtype_map[col] = sql_types.Text()

            pre_statements = _split_sql_statements(pre_sql)
            post_statements = _split_sql_statements(post_sql)
            rows_written = 0
            updated_rows = 0
            inserted_rows = 0
            skipped_null_key_rows = 0
            df_to_write_prepared = df_to_write.copy()
            # Oracle driver cannot bind raw Python dict/list/set values.
            # Normalize all values once so INSERT path (to_sql) remains robust.
            for col in list(df_to_write_prepared.columns):
                series = df_to_write_prepared[col]
                if (
                    pd.api.types.is_object_dtype(series)
                    or pd.api.types.is_string_dtype(series)
                    or pd.api.types.is_datetime64_any_dtype(series)
                ):
                    df_to_write_prepared[col] = series.map(_normalize_value)

            # Optional guard for insert mode:
            # if key columns are configured, skip rows having null/blank key values
            # instead of failing the whole batch with ORA-01400.
            if operation == "insert" and key_columns:
                missing_insert_keys = [col for col in key_columns if col not in df_to_write_prepared.columns]
                if missing_insert_keys:
                    raise RuntimeError(
                        "Key columns not found in mapped output: " + ", ".join(missing_insert_keys[:20])
                    )
                keep_mask = pd.Series([True] * len(df_to_write_prepared), index=df_to_write_prepared.index)
                for col in key_columns:
                    series = df_to_write_prepared[col]
                    col_mask = series.notna()
                    if pd.api.types.is_object_dtype(series) or pd.api.types.is_string_dtype(series):
                        col_mask = col_mask & series.map(
                            lambda v: not (isinstance(v, str) and v.strip() == "")
                        )
                    keep_mask = keep_mask & col_mask
                original_len = int(len(df_to_write_prepared))
                if original_len > 0:
                    df_to_write_prepared = df_to_write_prepared.loc[keep_mask].copy()
                    skipped_null_key_rows = max(0, original_len - int(len(df_to_write_prepared)))

            with engine.begin() as conn:
                _raise_if_aborted()
                for stmt in pre_statements:
                    _raise_if_aborted()
                    conn.exec_driver_sql(stmt)

                if operation == "insert":
                    df_to_write_prepared.to_sql(
                        table,
                        conn,
                        if_exists=if_exists,
                        index=False,
                        schema=schema,
                        dtype=dtype_map,
                    )
                    rows_written = len(df_to_write_prepared)
                    inserted_rows = rows_written
                else:
                    if not key_columns:
                        raise RuntimeError(
                            f"Oracle operation '{operation}' requires key columns (oracle_key_columns)."
                        )
                    missing_keys = [col for col in key_columns if col not in df_to_write.columns]
                    if missing_keys:
                        raise RuntimeError(
                            "Key columns not found in mapped output: " + ", ".join(missing_keys[:20])
                        )
                    set_columns = [col for col in df_to_write.columns if col not in key_columns]
                    if not set_columns and operation == "update":
                        raise RuntimeError(
                            f"Oracle operation '{operation}' requires at least one non-key column to update."
                        )

                    table_expr = _quote_ident(table)
                    if schema:
                        table_expr = f"{_quote_ident(schema)}.{table_expr}"

                    update_sql = None
                    if set_columns:
                        set_pairs = [f"{_quote_ident(col)} = :s_{idx}" for idx, col in enumerate(set_columns)]
                        where_pairs = [f"{_quote_ident(col)} = :k_{idx}" for idx, col in enumerate(key_columns)]
                        update_sql = (
                            f"UPDATE {table_expr} "
                            f"SET {', '.join(set_pairs)} "
                            f"WHERE {' AND '.join(where_pairs)}"
                        )

                    insert_cols = list(df_to_write.columns)
                    insert_col_expr = ", ".join(_quote_ident(col) for col in insert_cols)
                    insert_bind_expr = ", ".join(f":i_{idx}" for idx, _ in enumerate(insert_cols))
                    insert_sql = f"INSERT INTO {table_expr} ({insert_col_expr}) VALUES ({insert_bind_expr})"

                    normalized_rows = (
                        df_to_write_prepared
                        .where(pd.notnull(df_to_write_prepared), None)
                        .to_dict(orient="records")
                    )
                    for row_idx, rec in enumerate(normalized_rows):
                        if row_idx == 0 or row_idx % 50 == 0:
                            _raise_if_aborted()
                        null_keys = [k for k in key_columns if _normalize_value(rec.get(k)) is None]
                        if null_keys:
                            if skip_null_key_rows:
                                skipped_null_key_rows += 1
                                continue
                            raise RuntimeError(
                                f"Row {row_idx + 1} has null key values for {', '.join(null_keys)}; cannot {operation}."
                            )

                        if update_sql is not None:
                            update_params: Dict[str, Any] = {}
                            for idx, col in enumerate(set_columns):
                                update_params[f"s_{idx}"] = _normalize_value(rec.get(col))
                            for idx, col in enumerate(key_columns):
                                update_params[f"k_{idx}"] = _normalize_value(rec.get(col))

                            result = conn.exec_driver_sql(update_sql, update_params)
                            affected = int(result.rowcount or 0)
                            if affected > 0:
                                updated_rows += affected
                                rows_written += affected
                                continue

                        if operation == "upsert":
                            insert_params = {
                                f"i_{idx}": _normalize_value(rec.get(col))
                                for idx, col in enumerate(insert_cols)
                            }
                            try:
                                conn.exec_driver_sql(insert_sql, insert_params)
                                inserted_rows += 1
                                rows_written += 1
                            except Exception as insert_exc:
                                if _is_oracle_unique_violation(insert_exc):
                                    continue
                                raise

                for stmt in post_statements:
                    _raise_if_aborted()
                    conn.exec_driver_sql(stmt)

            status = "loaded"
            note = ""
            if skipped_null_key_rows > 0:
                note = f"Skipped {int(skipped_null_key_rows)} row(s) with null key values."
                if rows_written <= 0:
                    status = "loaded_with_warnings"
            return [{
                "status": status,
                "rows": rows_written,
                "table": table,
                "schema": schema,
                "operation": operation,
                "if_exists": if_exists if operation == "insert" else None,
                "key_columns": key_columns if operation in {"update", "upsert"} else [],
                "mapped_columns": len(rename_map),
                "mapped_only": mapped_only,
                "updated_rows": updated_rows,
                "inserted_rows": inserted_rows,
                "skipped_null_key_rows": int(skipped_null_key_rows),
                "pre_sql_statements": len(pre_statements),
                "post_sql_statements": len(post_statements),
                "note": note,
            }]
        except ExecutionAbortedError:
            raise
        except Exception as e:
            raise RuntimeError(f"Oracle write failed: {e}")
        finally:
            if engine is not None and engine_cache_key is None:
                try:
                    engine.dispose()
                except Exception:
                    pass

    async def _dest_oracle(
        self,
        config: dict,
        df,
        execution_context: Optional[Dict[str, Any]] = None,
    ) -> list:
        exec_ctx = execution_context if isinstance(execution_context, dict) else {}
        queue_worker_mode = bool(exec_ctx.get("oracle_destination_queue_worker", False))
        force_sync_cfg = config.get(
            "oracle_destination_force_sync",
            config.get("oracle_force_sync", os.getenv("ORACLE_DESTINATION_FORCE_SYNC", "1")),
        )
        force_sync = bool(self._parse_bool_like(force_sync_cfg, True))
        async_enabled_cfg = config.get(
            "oracle_destination_async_enabled",
            config.get("oracle_async_enabled", os.getenv("ORACLE_DESTINATION_ASYNC_ENABLED", "0")),
        )
        async_enabled = bool(self._parse_bool_like(async_enabled_cfg, False))
        if force_sync:
            async_enabled = False

        if async_enabled and not queue_worker_mode:
            pipeline_id = str(exec_ctx.get("pipeline_id") or "").strip() or "__pipeline__"
            node_id = str(exec_ctx.get("node_id") or "").strip() or "__oracle_destination__"
            execution_id = str(exec_ctx.get("execution_id") or "").strip() or "__execution__"
            wait_on_execution_end_cfg = config.get(
                "oracle_destination_async_wait_on_execution_end",
                config.get(
                    "oracle_async_wait_on_execution_end",
                    os.getenv("ORACLE_DESTINATION_ASYNC_WAIT_ON_EXECUTION_END", "1"),
                ),
            )
            wait_on_execution_end = bool(self._parse_bool_like(wait_on_execution_end_cfg, True))
            try:
                wait_timeout_seconds = float(
                    config.get("oracle_destination_async_wait_timeout_seconds")
                    or config.get("oracle_async_wait_timeout_seconds")
                    or os.getenv("ORACLE_DESTINATION_ASYNC_WAIT_TIMEOUT_SECONDS", "3600")
                )
            except Exception:
                wait_timeout_seconds = 3600.0
            wait_timeout_seconds = max(1.0, min(wait_timeout_seconds, 86400.0))
            try:
                queue_maxsize = int(
                    config.get("oracle_destination_async_queue_maxsize")
                    or config.get("oracle_async_queue_maxsize")
                    or os.getenv("ORACLE_DESTINATION_ASYNC_QUEUE_MAXSIZE", "8")
                )
            except Exception:
                queue_maxsize = 8
            queue_maxsize = max(1, min(queue_maxsize, 128))
            try:
                enqueue_timeout_seconds = float(
                    config.get("oracle_destination_async_enqueue_timeout_seconds")
                    or config.get("oracle_async_enqueue_timeout_seconds")
                    or os.getenv("ORACLE_DESTINATION_ASYNC_ENQUEUE_TIMEOUT_SECONDS", "0.2")
                )
            except Exception:
                enqueue_timeout_seconds = 0.2
            enqueue_timeout_seconds = max(0.01, min(enqueue_timeout_seconds, 5.0))

            enqueued, enqueue_error = self._enqueue_oracle_destination_write(
                pipeline_id=pipeline_id,
                node_id=node_id,
                execution_id=execution_id,
                config=config,
                df=df,
                execution_context={
                    "pipeline_id": pipeline_id,
                    "node_id": node_id,
                    "execution_id": execution_id,
                    "oracle_destination_queue_worker": True,
                    "should_abort": exec_ctx.get("should_abort"),
                    "raise_if_aborted": exec_ctx.get("raise_if_aborted"),
                },
                queue_maxsize=queue_maxsize,
                enqueue_timeout_seconds=enqueue_timeout_seconds,
            )
            if enqueued:
                stats = self._get_oracle_destination_write_queue_stats(
                    pipeline_id=pipeline_id,
                    node_id=node_id,
                    execution_id=execution_id,
                )
                table = config.get("table", "ETL_OUTPUT")
                schema = config.get("schema") or None
                operation = str(config.get("oracle_operation", "insert") or "insert").strip().lower()
                if operation not in {"insert", "update", "upsert"}:
                    operation = "insert"
                if_exists = (config.get("if_exists", "append") or "append").lower()
                if if_exists not in {"append", "replace", "fail"}:
                    if_exists = "append"
                return [{
                    "status": "queued",
                    "rows": len(df),
                    "table": table,
                    "schema": schema,
                    "operation": operation,
                    "if_exists": if_exists if operation == "insert" else None,
                    "async_processing": True,
                    "queue_depth": int(stats.get("queue_depth") or 0),
                    "pending_jobs": int(stats.get("pending_jobs") or 0),
                    "inflight_jobs": int(stats.get("inflight_jobs") or 0),
                    "failed_jobs": int(stats.get("failed_jobs") or 0),
                    "worker_alive": bool(stats.get("worker_alive", False)),
                    "queue_pipeline_id": pipeline_id,
                    "queue_node_id": node_id,
                    "queue_execution_id": execution_id,
                    "wait_on_execution_end": bool(wait_on_execution_end),
                    "wait_timeout_seconds": float(wait_timeout_seconds),
                    "note": (
                        "Oracle write queued in background (info-only). "
                        "Downstream nodes continue immediately."
                    ),
                }]
            fallback_sync_cfg = config.get(
                "oracle_destination_async_fallback_sync",
                config.get("oracle_async_fallback_sync", os.getenv("ORACLE_DESTINATION_ASYNC_FALLBACK_SYNC", "0")),
            )
            fallback_sync = bool(self._parse_bool_like(fallback_sync_cfg, False))
            table = config.get("table", "ETL_OUTPUT")
            schema = config.get("schema") or None
            operation = str(config.get("oracle_operation", "insert") or "insert").strip().lower()
            if operation not in {"insert", "update", "upsert"}:
                operation = "insert"
            if_exists = (config.get("if_exists", "append") or "append").lower()
            if if_exists not in {"append", "replace", "fail"}:
                if_exists = "append"
            if not fallback_sync:
                logger.warning(
                    "Oracle destination async enqueue failed for "
                    f"pipeline={pipeline_id}, node={node_id}: {enqueue_error}. "
                    "Write skipped to keep pipeline non-blocking."
                )
                return [{
                    "status": "queue_error",
                    "rows": len(df),
                    "table": table,
                    "schema": schema,
                    "operation": operation,
                    "if_exists": if_exists if operation == "insert" else None,
                    "async_processing": True,
                    "queue_error": str(enqueue_error or "oracle_destination_queue_enqueue_failed"),
                    "queue_pipeline_id": pipeline_id,
                    "queue_node_id": node_id,
                    "queue_execution_id": execution_id,
                    "wait_on_execution_end": bool(wait_on_execution_end),
                    "wait_timeout_seconds": float(wait_timeout_seconds),
                    "note": (
                        "Oracle async queue enqueue failed; write skipped to keep flow non-blocking. "
                        "Check backend logs/queue settings."
                    ),
                }]
            logger.warning(
                "Oracle destination async enqueue failed for "
                f"pipeline={pipeline_id}, node={node_id}: {enqueue_error}. "
                "Falling back to synchronous write because oracle_destination_async_fallback_sync is enabled."
            )

        return self._dest_oracle_sync(config, df, execution_context=execution_context)

    async def _dest_mongodb(self, config: dict, data: list) -> list:
        try:
            from pymongo import MongoClient
            client = MongoClient(config.get("connection_string", "mongodb://localhost:27017"))
            db = client[config.get("database", "etl")]
            collection = db[config.get("collection", "output")]
            if config.get("drop_first", False):
                collection.drop()
            collection.insert_many(data)
            return [{"status": "loaded", "rows": len(data), "collection": config.get("collection")}]
        except Exception as e:
            raise RuntimeError(f"MongoDB write failed: {e}")

    async def _dest_elasticsearch(self, config: dict, data: list) -> list:
        try:
            from elasticsearch import Elasticsearch
            from elasticsearch.helpers import bulk
            es = Elasticsearch(config.get("hosts", ["http://localhost:9200"]))
            index = config.get("index", "etl_output")
            actions = [{"_index": index, "_source": doc} for doc in data]
            bulk(es, actions)
            return [{"status": "loaded", "rows": len(data), "index": index}]
        except Exception as e:
            raise RuntimeError(f"Elasticsearch write failed: {e}")

    async def _dest_redis(self, config: dict, data: list) -> list:
        try:
            import redis as redis_lib
            r = redis_lib.Redis(
                host=config.get("host", "localhost"),
                port=int(config.get("port", 6379)),
                password=config.get("password"),
                decode_responses=True
            )
            key_prefix = config.get("key_prefix", "etl:")
            for i, doc in enumerate(data):
                r.set(f"{key_prefix}{i}", json.dumps(doc))
            return [{"status": "loaded", "rows": len(data)}]
        except Exception as e:
            raise RuntimeError(f"Redis write failed: {e}")

    async def _dest_s3(self, config: dict, df) -> list:
        try:
            import boto3, io
            s3 = boto3.client(
                "s3",
                aws_access_key_id=config.get("access_key"),
                aws_secret_access_key=config.get("secret_key"),
                region_name=config.get("region", "us-east-1")
            )
            key = config.get("key", "etl_output.csv")
            buf = io.BytesIO()
            if key.endswith(".parquet"):
                df.to_parquet(buf, index=False)
            elif key.endswith(".json"):
                df.to_json(buf, orient="records", indent=2)
            else:
                df.to_csv(buf, index=False)
            buf.seek(0)
            s3.upload_fileobj(buf, config.get("bucket", ""), key)
            return [{"status": "uploaded", "rows": len(df), "key": key}]
        except Exception as e:
            raise RuntimeError(f"S3 write failed: {e}")

    async def _dest_rest_api(self, config: dict, data: list) -> list:
        try:
            import httpx
            url = config.get("url", "")
            headers = json.loads(config.get("headers", "{}"))
            async with httpx.AsyncClient() as client:
                resp = await client.post(url, json=data, headers=headers, timeout=30)
                resp.raise_for_status()
            return [{"status": "posted", "rows": len(data), "http_status": resp.status_code}]
        except Exception as e:
            raise RuntimeError(f"REST API write failed: {e}")

    # ─── MOCK DATA ────────────────────────────────────────────────────────────

    def _mock_data(self, config: dict, source_type: str) -> list:
        """Generate realistic mock data for demo/testing purposes."""
        import random
        size = int(config.get("limit", config.get("max_records", 25)))
        size = min(size, 50)

        base = {
            "postgres": lambda i: {"id": i, "name": f"User {i}", "email": f"user{i}@example.com",
                                    "created_at": f"2024-0{(i%9)+1}-{(i%28)+1:02d}", "revenue": round(random.uniform(100, 9999), 2)},
            "mysql": lambda i: {"id": i, "product": f"Product {i}", "category": random.choice(["A","B","C"]),
                                 "price": round(random.uniform(5, 500), 2), "stock": random.randint(0, 1000)},
            "oracle": lambda i: {"ID": i, "CUSTOMER_NAME": f"Customer {i}", "ACCOUNT_TYPE": random.choice(["SAVINGS", "CURRENT"]),
                                 "BALANCE": round(random.uniform(1000, 100000), 2), "BRANCH_CODE": f"BR{i % 100:03d}"},
            "mongodb": lambda i: {"_id": str(uuid.uuid4()), "user": f"user_{i}", "action": random.choice(["click","view","purchase"]),
                                   "timestamp": f"2024-03-{(i%28)+1:02d}T12:00:00Z"},
            "redis": lambda i: {"key": f"session:{uuid.uuid4().hex[:8]}", "value": f"token_{i}"},
            "elasticsearch": lambda i: {"doc_id": str(uuid.uuid4()), "title": f"Document {i}",
                                         "content": f"Sample content for document {i}", "score": round(random.random(), 4)},
            "csv": lambda i: {"row_id": i, "col_a": f"value_{i}", "col_b": random.randint(1, 100),
                               "col_c": round(random.uniform(0, 1), 4)},
            "json": lambda i: {"id": i, "data": {"nested_key": f"val_{i}", "count": i * 10}},
            "excel": lambda i: {"sheet_row": i, "name": f"Item {i}", "amount": random.randint(100, 9999),
                                  "status": random.choice(["active","inactive","pending"])},
            "xml": lambda i: {"element": f"elem_{i}", "attribute": f"attr_val_{i}"},
            "parquet": lambda i: {"partition": i // 10, "record_id": i, "metric": round(random.gauss(50, 15), 2)},
            "rest_api": lambda i: {"id": i, "title": f"Record {i}", "body": f"Content {i}",
                                    "userId": (i % 10) + 1},
            "graphql": lambda i: {"node_id": str(uuid.uuid4()), "field1": f"value_{i}", "count": i},
            "s3": lambda i: {"s3_key": f"data/part-{i:05d}.parquet", "size_bytes": random.randint(1024, 1048576),
                             "last_modified": f"2024-03-{(i%28)+1:02d}"},
            "kafka": lambda i: {"offset": i, "partition": i % 4, "topic": config.get("topic","events"),
                                 "payload": {"event": random.choice(["created","updated","deleted"]), "id": str(uuid.uuid4())}},
        }
        gen = base.get(source_type, lambda i: {"id": i, "value": f"item_{i}"})
        return [gen(i) for i in range(1, size + 1)]
